function clampPort(value: unknown, fallback = 8212): number {
  const numeric = Math.floor(Number(value));
  if (!Number.isFinite(numeric)) return fallback;
  return Math.max(1, Math.min(65535, numeric));
}

function finiteNumberOrFallback(value: unknown, fallback: number): number {
  if (value === null || value === undefined || value === '') return fallback;
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function normalizeBindHost(value: unknown, fallback = '127.0.0.1'): string {
  const raw = String(value || '').trim();
  if (!raw) return fallback;
  if (raw === 'localhost') return '127.0.0.1';
  if (raw === '127.0.0.1' || raw === '0.0.0.0' || raw === '::' || raw === '::1') return raw;
  if (/^[a-z0-9.-]+$/i.test(raw) || /^[0-9a-f:.]+$/i.test(raw)) return raw;
  return fallback;
}

function loadRemoteBootstrapSettings(): { bindHost?: string; port?: number } {
  try {
    if (!existsSync(REMOTE_BOOTSTRAP_SETTINGS_PATH)) return {};
    const parsed = JSON.parse(readFileSync(REMOTE_BOOTSTRAP_SETTINGS_PATH, 'utf-8')) as Record<string, unknown>;
    return {
      bindHost: normalizeBindHost(parsed.bindHost, ''),
      port: parsed.port ? clampPort(parsed.port) : undefined,
    };
  } catch {
    return {};
  }
}

