async function loadStoredApiKeys() {
  const canonical = await loadApiKeys(CONFIG_PATH);
  if (LEGACY_CONFIG_PATH === CONFIG_PATH || !existsSync(LEGACY_CONFIG_PATH)) {
    return canonical;
  }
  const legacy = await loadApiKeys(LEGACY_CONFIG_PATH);
  const merged = { ...legacy, ...canonical };
  const canonicalToken = String(canonical.civitai?.apiToken || canonical.civitai?.apiKey || '').trim();
  const legacyToken = String(legacy.civitai?.apiToken || legacy.civitai?.apiKey || '').trim();
  if (!canonicalToken && legacyToken) {
    merged.civitai = { apiToken: legacyToken };
  }
  if (Object.keys(legacy).length > 0) {
    await saveApiKeys(CONFIG_PATH, merged).catch((error) => {
      console.warn('[API Keys] Failed to migrate legacy api-keys.json:', error);
    });
  }
  return merged;
}

async function saveStoredApiKeys(config: Awaited<ReturnType<typeof loadApiKeys>>) {
  await saveApiKeys(CONFIG_PATH, config);
}

type DatasetConceptCaptionSettings = {
  triggerTags: string;
  prependTags: string;
  captionMode: 'tags' | 'natural';
  modelRepo: string;
  naturalModelRepo: string;
  naturalDevice: 'auto' | 'cpu' | 'cuda';
  naturalMaxNewTokens: number;
  generalThreshold: number;
  characterThreshold: number;
  ratingThreshold: number;
  generalMcutEnabled: boolean;
  characterMcutEnabled: boolean;
  includeGeneralTags: boolean;
  includeCharacterTags: boolean;
  includeCopyrightTags: boolean;
  includeArtistTags: boolean;
  includeMetaTags: boolean;
  includeRatingTags: boolean;
  maxTags: number;
  preserveExisting: boolean;
  replaceUnderscoresWithSpaces: boolean;
  updatedAt?: number;
};

const DATASET_CONCEPT_SETTINGS_FILE = '.umbra-concept-settings.json';

function getConceptDisplayNameFromFolder(conceptFolder: string): string {
  const match = String(conceptFolder || '').match(/^\d+_(?:reg_)?(.+)$/);
  return (match?.[1] || conceptFolder || '').trim();
}

function createDefaultDatasetConceptSettings(_datasetName: string, conceptFolder: string): DatasetConceptCaptionSettings {
  return {
    triggerTags: getConceptDisplayNameFromFolder(conceptFolder),
    prependTags: '',
    captionMode: 'tags',
    modelRepo: 'SmilingWolf/wd-vit-tagger-v3',
    naturalModelRepo: 'prithivMLmods/Qwen2-VL-2B-Abliterated-Caption-it',
    naturalDevice: 'auto',
    naturalMaxNewTokens: 192,
    generalThreshold: 0.35,
    characterThreshold: 0.85,
    ratingThreshold: 0.25,
    generalMcutEnabled: false,
    characterMcutEnabled: false,
    includeGeneralTags: true,
    includeCharacterTags: true,
    includeCopyrightTags: false,
    includeArtistTags: false,
    includeMetaTags: false,
    includeRatingTags: false,
    maxTags: 120,
    preserveExisting: true,
    replaceUnderscoresWithSpaces: false,
  };
}

function normalizeDatasetConceptSettings(
  input: Record<string, unknown> | null | undefined,
  datasetName: string,
  conceptFolder: string,
): DatasetConceptCaptionSettings {
  const defaults = createDefaultDatasetConceptSettings(datasetName, conceptFolder);
  const parseBool = (value: unknown, fallback: boolean): boolean => {
    if (typeof value === 'boolean') return value;
    if (typeof value === 'number') return value !== 0;
    if (typeof value === 'string') {
      const lowered = value.trim().toLowerCase();
      if (['1', 'true', 'yes', 'on'].includes(lowered)) return true;
      if (['0', 'false', 'no', 'off'].includes(lowered)) return false;
    }
    return fallback;
  };
  const parseNumber = (value: unknown, fallback: number, min: number, max: number): number => {
    const parsed = typeof value === 'number' ? value : Number(String(value ?? '').trim());
    if (!Number.isFinite(parsed)) return fallback;
    return Math.max(min, Math.min(max, parsed));
  };
  const parseInteger = (value: unknown, fallback: number, min: number, max: number): number => {
    const parsed = Number(String(value ?? '').trim());
    if (!Number.isFinite(parsed)) return fallback;
    return Math.max(min, Math.min(max, Math.floor(parsed)));
  };
  return {
    triggerTags: String(input?.triggerTags ?? defaults.triggerTags).trim(),
    prependTags: String(input?.prependTags ?? defaults.prependTags).trim(),
    captionMode: input?.captionMode === 'natural' ? 'natural' : 'tags',
    modelRepo: String(input?.modelRepo || defaults.modelRepo).trim() || defaults.modelRepo,
    naturalModelRepo: String(input?.naturalModelRepo || defaults.naturalModelRepo).trim() || defaults.naturalModelRepo,
    naturalDevice: input?.naturalDevice === 'cpu' || input?.naturalDevice === 'cuda' ? input.naturalDevice : 'auto',
    naturalMaxNewTokens: parseInteger(input?.naturalMaxNewTokens, defaults.naturalMaxNewTokens, 32, 512),
    generalThreshold: parseNumber(input?.generalThreshold, defaults.generalThreshold, 0, 1),
    characterThreshold: parseNumber(input?.characterThreshold, defaults.characterThreshold, 0, 1),
    ratingThreshold: parseNumber(input?.ratingThreshold, defaults.ratingThreshold, 0, 1),
    generalMcutEnabled: parseBool(input?.generalMcutEnabled, defaults.generalMcutEnabled),
    characterMcutEnabled: parseBool(input?.characterMcutEnabled, defaults.characterMcutEnabled),
    includeGeneralTags: parseBool(input?.includeGeneralTags, defaults.includeGeneralTags),
    includeCharacterTags: parseBool(input?.includeCharacterTags, defaults.includeCharacterTags),
    includeCopyrightTags: parseBool(input?.includeCopyrightTags, defaults.includeCopyrightTags),
    includeArtistTags: parseBool(input?.includeArtistTags, defaults.includeArtistTags),
    includeMetaTags: parseBool(input?.includeMetaTags, defaults.includeMetaTags),
    includeRatingTags: parseBool(input?.includeRatingTags, defaults.includeRatingTags),
    maxTags: parseInteger(input?.maxTags, defaults.maxTags, 1, 500),
    preserveExisting: parseBool(input?.preserveExisting, defaults.preserveExisting),
    replaceUnderscoresWithSpaces: parseBool(input?.replaceUnderscoresWithSpaces, defaults.replaceUnderscoresWithSpaces),
    updatedAt: Number.isFinite(Number(input?.updatedAt)) ? Number(input?.updatedAt) : undefined,
  };
}

async function readDatasetConceptSettings(datasetName: string, conceptFolder: string, conceptPath: string): Promise<DatasetConceptCaptionSettings> {
  const settingsPath = join(conceptPath, DATASET_CONCEPT_SETTINGS_FILE);
  try {
    if (!existsSync(settingsPath)) return createDefaultDatasetConceptSettings(datasetName, conceptFolder);
    const parsed = JSON.parse(await fs.readFile(settingsPath, 'utf8')) as Record<string, unknown>;
    return normalizeDatasetConceptSettings(parsed, datasetName, conceptFolder);
  } catch {
    return createDefaultDatasetConceptSettings(datasetName, conceptFolder);
  }
}

async function writeDatasetConceptSettings(
  datasetName: string,
  conceptFolder: string,
  conceptPath: string,
  settings: Record<string, unknown>,
): Promise<DatasetConceptCaptionSettings> {
  const normalized = normalizeDatasetConceptSettings(settings, datasetName, conceptFolder);
  const saved = { ...normalized, updatedAt: Date.now() };
  await fs.writeFile(join(conceptPath, DATASET_CONCEPT_SETTINGS_FILE), `${JSON.stringify(saved, null, 2)}\n`, 'utf8');
  return saved;
}

function normalizeBooruMediaUrl(value: unknown): URL | null {
  const raw = String(value || '').trim();
  if (!raw) return null;
  try {
    const parsed = new URL(raw);
    if (parsed.protocol !== 'https:' && parsed.protocol !== 'http:') return null;
    const hostname = parsed.hostname.toLowerCase();
    const allowedHostSuffixes = [
      'donmai.us',
      'gelbooru.com',
      'rule34.xxx',
      'e621.net',
    ];
    if (!allowedHostSuffixes.some((suffix) => hostname === suffix || hostname.endsWith(`.${suffix}`))) return null;
    return parsed;
  } catch {
    return null;
  }
}

async function handleBooruImageProxy(req: Request, url: URL): Promise<Response> {
  const targetUrl = normalizeBooruMediaUrl(url.searchParams.get('url'));
  if (!targetUrl) return json({ error: 'Only configured Data Forge source media can be proxied.' }, 400);

  const requestHeaders: Record<string, string> = {
    'User-Agent': 'UmbraStudio (Data Forge; local application)',
    'Accept': req.headers.get('accept') || 'image/avif,image/webp,image/apng,image/svg+xml,image/*,*/*;q=0.8',
  };
  const range = String(req.headers.get('range') || '').trim();
  if (range) requestHeaders.Range = range;

  let upstream: Response;
  try {
    upstream = await fetch(targetUrl.toString(), {
      headers: requestHeaders,
      signal: AbortSignal.timeout(20000),
    });
  } catch (error: any) {
    return json({ error: error?.message || 'Failed to fetch booru media.' }, 502);
  }

  if (!upstream.ok && upstream.status !== 206) {
    return json({ error: `Booru media request failed: ${upstream.status}` }, upstream.status >= 400 ? upstream.status : 502);
  }

  const responseHeaders = new Headers();
  const passthroughHeaders = [
    'content-type',
    'content-length',
    'content-range',
    'accept-ranges',
    'last-modified',
    'etag',
  ];
  for (const header of passthroughHeaders) {
    const value = upstream.headers.get(header);
    if (value) responseHeaders.set(header, value);
  }
  responseHeaders.set('Cache-Control', 'public, max-age=3600, stale-while-revalidate=86400');
  responseHeaders.set('X-Umbra-Booru-Proxy', '1');

  return new Response(upstream.body, {
    status: upstream.status,
    headers: responseHeaders,
  });
}

type DatasetResearchMode = 'character' | 'artist' | 'concept';
type DatasetResearchCategory = 'general' | 'character' | 'copyright' | 'artist' | 'meta' | 'unknown';

function normalizeDatasetResearchTag(value: unknown): string {
  return String(value || '')
    .trim()
    .replace(/,/g, ' ')
    .replace(/\s+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function addDatasetResearchTags(
  counts: Map<string, { tag: string; count: number; category: DatasetResearchCategory }>,
  raw: unknown,
  category: DatasetResearchCategory,
) {
  const tags = String(raw || '').split(/\s+/).map((entry) => entry.trim()).filter(Boolean);
  for (const tag of tags) {
    const normalized = normalizeDatasetResearchTag(tag);
    if (!normalized) continue;
    const key = normalized.toLowerCase();
    const existing = counts.get(key);
    if (existing) existing.count += 1;
    else counts.set(key, { tag: normalized, count: 1, category });
  }
}

function datasetResearchTopTags(
  counts: Map<string, { tag: string; count: number; category: DatasetResearchCategory }>,
  postCount: number,
  category?: DatasetResearchCategory,
  limit = 40,
) {
  return Array.from(counts.values())
    .filter((entry) => !category || entry.category === category)
    .sort((a, b) => b.count - a.count || a.tag.localeCompare(b.tag))
    .slice(0, limit)
    .map((entry) => ({
      ...entry,
      percent: postCount > 0 ? Math.round((entry.count / postCount) * 1000) / 10 : 0,
    }));
}

function isDatasetResearchAdultTag(tag: string): boolean {
  const normalized = String(tag || '').toLowerCase();
  return [
    'nude',
    'naked',
    'nipples',
    'breasts',
    'pussy',
    'penis',
    'sex',
    'cum',
    'masturbation',
    'fellatio',
    'paizuri',
    'spread_legs',
    'ass',
    'anus',
    'vaginal',
    'anal',
    'areola',
    'erection',
    'ejaculation',
    'cum_in',
  ].some((needle) => normalized === needle || normalized.includes(needle));
}

async function fetchDanbooruResearchPosts(tags: string, limit: number, apiConfig?: Awaited<ReturnType<typeof loadStoredApiKeys>>['danbooru']) {
  const headers: Record<string, string> = { 'User-Agent': 'UmbraStudio/1.0 (dataset-research)' };
  if (apiConfig?.username && apiConfig?.apiKey) {
    headers.Authorization = `Basic ${Buffer.from(`${apiConfig.username}:${apiConfig.apiKey}`).toString('base64')}`;
  }

  const posts: any[] = [];
  const safeLimit = Math.max(20, Math.min(500, Math.floor(limit || 200)));
  const perPage = Math.min(100, safeLimit);
  const pages = Math.ceil(safeLimit / perPage);
  for (let page = 1; page <= pages; page += 1) {
    const params = new URLSearchParams({
      tags,
      limit: String(Math.min(perPage, safeLimit - posts.length)),
      page: String(page),
    });
    const res = await fetch(`https://danbooru.donmai.us/posts.json?${params}`, { headers });
    if (!res.ok) {
      const errorText = await res.text().catch(() => '');
      throw new Error(`Danbooru research request failed: ${res.status}${errorText ? ` ${errorText.slice(0, 120)}` : ''}`);
    }
    const data = await res.json() as any[];
    posts.push(...data);
    if (data.length < perPage || posts.length >= safeLimit) break;
  }
  return posts.slice(0, safeLimit);
}

async function handleBooruDatasetResearch(url: URL): Promise<Response> {
  const startedAt = Date.now();
  try {
    const source = String(url.searchParams.get('source') || 'danbooru').trim().toLowerCase();
    if (source !== 'danbooru') {
      return json({ error: 'Dataset research currently supports Danbooru metadata.' }, 400);
    }
    const mode = String(url.searchParams.get('mode') || 'character').trim().toLowerCase() as DatasetResearchMode;
    const queryTag = normalizeDatasetResearchTag(url.searchParams.get('query'));
    const extraTags = String(url.searchParams.get('extraTags') || '').trim().replace(/,/g, ' ').replace(/\s+/g, ' ');
    const limit = Math.max(20, Math.min(500, Number(url.searchParams.get('limit') || 200)));
    if (!queryTag) return json({ error: 'Missing research query' }, 400);

    const apiKeys = await loadStoredApiKeys();
    const searchTags = [queryTag, extraTags].filter(Boolean).join(' ').trim();
    const posts = await fetchDanbooruResearchPosts(searchTags, limit, apiKeys.danbooru);
    const counts = new Map<string, { tag: string; count: number; category: DatasetResearchCategory }>();
    const ratings: Record<string, number> = {};

    for (const post of posts) {
      addDatasetResearchTags(counts, post.tag_string_general, 'general');
      addDatasetResearchTags(counts, post.tag_string_character, 'character');
      addDatasetResearchTags(counts, post.tag_string_copyright, 'copyright');
      addDatasetResearchTags(counts, post.tag_string_artist, 'artist');
      addDatasetResearchTags(counts, post.tag_string_meta, 'meta');
      const rating = String(post.rating || '').trim() || 'unknown';
      ratings[rating] = (ratings[rating] || 0) + 1;
    }

    const postCount = posts.length;
    const allTop = datasetResearchTopTags(counts, postCount, undefined, 120);
    const excludedCore = new Set([
      queryTag.toLowerCase(),
      ...extraTags.split(/\s+/).map((entry) => entry.toLowerCase()).filter(Boolean),
    ]);
    const identityCategory: DatasetResearchCategory = mode === 'artist' ? 'artist' : mode === 'character' ? 'character' : 'general';
    const identityTags = datasetResearchTopTags(counts, postCount, identityCategory, 30).filter((entry) => !excludedCore.has(entry.tag.toLowerCase()));
    const generalTags = datasetResearchTopTags(counts, postCount, 'general', 80).filter((entry) => !excludedCore.has(entry.tag.toLowerCase()));
    const coreTags = generalTags.filter((entry) => entry.percent >= 55).slice(0, 24);
    const variableTags = generalTags.filter((entry) => entry.percent >= 5 && entry.percent < 55).slice(0, 64);
    const biasTags = allTop
      .filter((entry) => entry.percent >= 35 && !excludedCore.has(entry.tag.toLowerCase()))
      .slice(0, 36);
    const adultTags = generalTags.filter((entry) => isDatasetResearchAdultTag(entry.tag)).slice(0, 64);

    const response = json({
      ok: true,
      source,
      mode,
      query: queryTag,
      searchTags,
      postCount,
      limit,
      sourceUrl: `https://danbooru.donmai.us/posts?tags=${encodeURIComponent(searchTags)}`,
      suggestedTrigger: queryTag,
      buckets: {
        identity: identityTags,
        core: coreTags,
        variable: variableTags,
        bias: biasTags,
        adult: adultTags,
        general: datasetResearchTopTags(counts, postCount, 'general', 60),
        character: datasetResearchTopTags(counts, postCount, 'character', 40),
        artist: datasetResearchTopTags(counts, postCount, 'artist', 40),
        copyright: datasetResearchTopTags(counts, postCount, 'copyright', 30),
        meta: datasetResearchTopTags(counts, postCount, 'meta', 30),
      },
      ratings,
    });
    console.log(`[Booru] Research completed query="${searchTags}" posts=${postCount} ms=${Date.now() - startedAt}`);
    return response;
  } catch (error: any) {
    console.error('[Booru] Dataset research error:', error);
    return json({ error: error?.message || 'Dataset research failed' }, 500);
  }
}

function sanitizeCsvFileName(value: unknown, fallback: string): string {
  const raw = String(value || fallback).trim() || fallback;
  const withExt = raw.toLowerCase().endsWith('.csv') ? raw : `${raw}.csv`;
  return basename(withExt).replace(/[<>:"/\\|?*\x00-\x1f]/g, '-').replace(/\s+/g, '-');
}

function resolveDanbooruCsvScriptPath(): string {
  const candidates = [
    join(ROOT_DIR, 'scripts', 'danbooru-character-attributes-csv.mjs'),
    join(SOURCE_DIR, 'scripts', 'danbooru-character-attributes-csv.mjs'),
    join(ROOT_DIR, 'resources', 'app', 'scripts', 'danbooru-character-attributes-csv.mjs'),
  ];
  const scriptPath = candidates.find((candidate) => existsSync(candidate));
  if (!scriptPath) throw new Error('Danbooru CSV generator script was not found.');
  return scriptPath;
}

type DanbooruDatasetGeneratorJob = {
  id: string;
  mode: string;
  outFile: string;
  outputPath: string;
  args: string[];
  stdout: string;
  stderr: string;
  preview: string;
  running: boolean;
  startedAt: number;
  finishedAt: number | null;
  exitCode: number | null;
  error: string;
  animaArtistTokens: boolean;
  tagCategory: string;
};

const danbooruDatasetGeneratorJobs = new Map<string, DanbooruDatasetGeneratorJob>();

function buildDanbooruDatasetGeneratorCommand(body: Record<string, unknown>) {
  const mode = String(body.mode || 'character-attributes');
  const args: string[] = [];
  const outputDir = mode === 'tags'
    ? join(USER_DIR, 'PowerPrompter', 'CSV', 'tags')
    : join(USER_DIR, 'PowerPrompter', 'CSV', 'Characters');
  const outFile = join(outputDir, sanitizeCsvFileName(body.outputFileName, mode === 'tags' ? 'danbooru-tags.csv' : 'danbooru-character-attributes.csv'));

  const pushNumber = (flag: string, value: unknown, fallback: number, min: number, max: number) => {
    const numeric = Math.max(min, Math.min(max, Math.round(Number(value) || fallback)));
    args.push(flag, String(numeric));
  };
  const pushLimit = (value: unknown, fallback: number) => {
    const raw = String(value ?? '').trim().toLowerCase();
    if (raw === 'all') {
      args.push('--all');
      return;
    }
    const numeric = Math.max(1, Math.min(50000, Math.round(Number(value) || fallback)));
    args.push('--limit', String(numeric));
  };

  if (mode === 'tags') {
    args.push('--tags');
    const category = String(body.tagCategory ?? '0');
    args.push('--tag-category', /^[015]$/.test(category) ? category : '0');
    pushLimit(body.limit, 1000);
    pushNumber('--min-tag-posts', body.minTagPosts, 150, 0, 10000000);
  } else {
    const source = String(body.characterSource || 'danbooru');
    if (source === 'single') {
      const tag = normalizeDatasetResearchTag(body.tag);
      if (!tag) throw new Error('Character tag is required.');
      args.push('--tag', tag);
    } else if (source === 'series') {
      const series = normalizeDatasetResearchTag(body.seriesTag);
      if (!series) throw new Error('Series/copyright tag is required.');
      args.push('--series', series);
      pushNumber('--series-post-sample', body.seriesPostSample, 200, 1, 5000);
    } else {
      args.push('--character-source', 'danbooru');
    }
    pushLimit(body.limit, 100);
    pushNumber('--post-sample', body.postSample, 100, 1, 200);
    pushNumber('--max-attributes', body.maxAttributes, 12, 1, 80);
    pushNumber('--min-character-posts', body.minCharacterPosts, 100, 0, 10000000);
    const minFrequency = Math.max(0, Math.min(1, Number(body.minFrequency) || 0.12));
    args.push('--min-frequency', String(minFrequency));
    const postFilter = String(body.postFilter || '').trim();
    if (postFilter) args.push('--post-filter', postFilter);
    pushNumber('--concurrency', body.concurrency, 4, 1, 5);
    if (body.appendCopyright === false) args.push('--no-append-copyright');
  }

  if (body.removeUnderscores === true) args.push('--remove-underscores');
  args.push('--out-file', outFile);

  return {
    mode,
    outFile,
    outputDir,
    args,
    animaArtistTokens: mode === 'tags' && String(body.tagCategory ?? '0') === '1' && body.animaArtistTokens === true,
    tagCategory: String(body.tagCategory ?? '0'),
  };
}

async function updateDanbooruDatasetGeneratorPreview(job: DanbooruDatasetGeneratorJob) {
  if (!existsSync(job.outFile)) return;
  job.preview = (await fs.readFile(job.outFile, 'utf8').catch(() => '')).split(/\r?\n/).slice(0, 80).join('\n');
}

async function applyAnimaArtistTokenTransform(outFile: string) {
  const source = await fs.readFile(outFile, 'utf8');
  const lines = source.split(/\r?\n/);
  const transformed = lines.map((line, index) => {
    if (index === 0 || !line.trim()) return line;
    const firstComma = line.indexOf(',');
    const rawTag = firstComma >= 0 ? line.slice(0, firstComma) : line;
    const rest = firstComma >= 0 ? line.slice(firstComma) : '';
    const token = `@${rawTag.replace(/^"|"$/g, '').replace(/["\s_]+/g, '')}`;
    return `${token}${rest}`;
  }).join('\n');
  await fs.writeFile(outFile, transformed, 'utf8');
}

async function readGeneratorStream(stream: ReadableStream<Uint8Array> | null, onChunk: (text: string) => void) {
  if (!stream) return;
  const reader = stream.getReader();
  const decoder = new TextDecoder();
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    onChunk(decoder.decode(value, { stream: true }));
  }
  const tail = decoder.decode();
  if (tail) onChunk(tail);
}

async function runDanbooruDatasetGeneratorJob(job: DanbooruDatasetGeneratorJob) {
  const startedAt = Date.now();
  try {
    console.log(`[Booru] Dataset generator started id=${job.id}`);
    const scriptPath = resolveDanbooruCsvScriptPath();
    const proc = Bun.spawn([process.execPath || 'bun', scriptPath, ...job.args], {
      cwd: ROOT_DIR,
      env: { ...process.env, UMBRA_ROOT: ROOT_DIR },
      stdout: 'pipe',
      stderr: 'pipe',
    });
    const previewTimer = setInterval(() => {
      void updateDanbooruDatasetGeneratorPreview(job).catch(() => {});
    }, 1000);
    const [exitCode] = await Promise.all([
      proc.exited,
      readGeneratorStream(proc.stdout, (chunk) => { job.stdout += chunk; }),
      readGeneratorStream(proc.stderr, (chunk) => { job.stderr += chunk; }),
    ]);
    clearInterval(previewTimer);
    job.exitCode = exitCode;
    if (exitCode === 0 && job.animaArtistTokens && existsSync(job.outFile)) {
      await applyAnimaArtistTokenTransform(job.outFile);
    }
    await updateDanbooruDatasetGeneratorPreview(job).catch(() => {});
    if (exitCode !== 0) {
      job.error = job.stderr.trim() || job.stdout.trim() || `Generator exited with code ${exitCode}`;
      console.error(`[Booru] Dataset generator failed id=${job.id} exit=${exitCode} ms=${Date.now() - startedAt}: ${job.error.slice(0, 180)}`);
    } else {
      console.log(`[Booru] Dataset generator completed id=${job.id} ms=${Date.now() - startedAt}`);
    }
  } catch (error: any) {
    job.error = error?.message || 'Danbooru Dataset Generator failed';
    console.error(`[Booru] Dataset generator failed id=${job.id} ms=${Date.now() - startedAt}: ${job.error}`);
  } finally {
    job.running = false;
    job.finishedAt = Date.now();
  }
}

function serializeDanbooruDatasetGeneratorJob(job: DanbooruDatasetGeneratorJob) {
  return {
    ok: true,
    id: job.id,
    mode: job.mode,
    running: job.running,
    startedAt: job.startedAt,
    finishedAt: job.finishedAt,
    exitCode: job.exitCode,
    error: job.error,
    outputPath: job.outputPath,
    stdout: job.stdout,
    stderr: job.stderr,
    preview: job.preview,
    args: job.args,
  };
}

async function handleBooruDatasetGeneratorRun(req: Request): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as Record<string, unknown>;
    const command = buildDanbooruDatasetGeneratorCommand(body);
    await fs.mkdir(command.outputDir, { recursive: true });
    const id = crypto.randomUUID();
    const job: DanbooruDatasetGeneratorJob = {
      id,
      mode: command.mode,
      outFile: command.outFile,
      outputPath: toClientPath(command.outFile),
      args: command.args,
      stdout: '',
      stderr: '',
      preview: '',
      running: true,
      startedAt: Date.now(),
      finishedAt: null,
      exitCode: null,
      error: '',
      animaArtistTokens: command.animaArtistTokens,
      tagCategory: command.tagCategory,
    };
    danbooruDatasetGeneratorJobs.set(id, job);
    void runDanbooruDatasetGeneratorJob(job);
    return json(serializeDanbooruDatasetGeneratorJob(job));
  } catch (error: any) {
    console.error('[Booru] Dataset generator error:', error);
    return json({ error: error?.message || 'Danbooru Dataset Generator failed' }, 500);
  }
}

async function handleBooruDatasetGeneratorStatus(url: URL): Promise<Response> {
  const id = String(url.searchParams.get('id') || '').trim();
  const job = danbooruDatasetGeneratorJobs.get(id);
  if (!job) return json({ error: 'Generator job not found' }, 404);
  await updateDanbooruDatasetGeneratorPreview(job).catch(() => {});
  return json(serializeDanbooruDatasetGeneratorJob(job));
}

