  getDefaultOutputRootPath,
  getConfiguredTrashStoragePath,
  getResolvedTrashStorageDir,
  normalizeOutputPathInput,
  resolvePathCandidate,
  getConfiguredExternalRoots,
  isPathInsideAllowedRoots,
  toClientPath,
  sanitizeDatasetSegment,
