function handlePrompterMessage(ws: ServerWebSocket<unknown>, data: any) {
  const type = String(data?.type || '').trim();
  if (!type) return;

  if (type === 'ping') {
    sendWs(ws, { type: 'pong' });
    return;
  }

  if (type === 'register') {
    const meta = getPrompterMeta(ws);
    meta.role = normalizePrompterRole(data?.role);
    meta.source = String(data?.source || 'unknown');
    if (meta.role === 'comfy_bridge') {
      const bridge = normalizePrompterBridgeCatalogEntry(data, {
        bridgeId: meta.bridgeId,
        workflowId: meta.workflowId,
        workflowName: meta.workflowName,
        compatible: meta.compatible,
        missing: meta.missing,
        updatedAt: meta.updatedAt,
      });
      meta.bridgeId = bridge.bridgeId;
      meta.workflowId = bridge.workflowId;
      meta.workflowName = bridge.workflowName;
      meta.compatible = bridge.compatible;
      meta.missing = bridge.missing;
      meta.updatedAt = bridge.updatedAt;
    }
    prompterClientMeta.set(ws, meta);
    sendWs(ws, { type: 'registered', role: meta.role, source: meta.source });
    if (meta.role === 'comfy_bridge') {
      sendWs(ws, { type: 'prompter_sync', state: prompterSyncState });
      broadcastBridgeCatalogToPowerPrompterClients();
    }
    if (meta.role === 'powerprompter') {
      sendBridgeCatalogToClient(ws);
      sendPowerPrompterQueueControllerSnapshotToClient(ws);
      void ensurePowerPrompterDocumentSession()
        .then(() => {
          sendWs(ws, clonePowerPrompterDocumentSession('client_registered'));
        })
        .catch(() => undefined);
    }
    return;
  }

  if (type === 'document_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    void ensurePowerPrompterDocumentSession(String(data?.file || '').trim() || null)
      .then(() => {
        sendWs(ws, clonePowerPrompterDocumentSession('document_requested'));
      })
      .catch((error: any) => {
        sendWs(ws, { type: 'document_error', error: error?.message || 'Failed to load Power Prompter document session' });
      });
    return;
  }

  if (type === 'document_open') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    void openPowerPrompterDocumentSession(String(data?.file || '').trim(), {
      sourceClientId: String(data?.clientId || '').trim(),
      preferredSourceWs: ws,
      reason: 'document_opened',
    }).catch((error: any) => {
      sendWs(ws, { type: 'document_error', error: error?.message || 'Failed to open Power Prompter document' });
    });
    return;
  }

  if (type === 'document_update' || type === 'document_save') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    void updatePowerPrompterDocumentSession(String(data?.file || '').trim(), data?.document, {
      save: type === 'document_save' || data?.save === true,
      intent: String(data?.intent || (type === 'document_save' ? 'session-autosave' : 'session-update')).trim(),
      sourceClientId: String(data?.clientId || '').trim(),
      preferredSourceWs: ws,
      reason: type === 'document_save' ? 'document_saved' : 'document_updated',
    }).then((session) => {
      sendWs(ws, { type: type === 'document_save' ? 'document_save_result' : 'document_update_result', success: true, session });
    }).catch((error: any) => {
      sendWs(ws, { type: type === 'document_save' ? 'document_save_result' : 'document_update_result', success: false, error: error?.message || 'Failed to update Power Prompter document' });
    });
    return;
  }

  if (type === 'bridge_catalog_request') {
    sendBridgeCatalogToClient(ws);
    const meta = getPrompterMeta(ws);
    if (meta.role === 'powerprompter') {
      sendPowerPrompterQueueControllerSnapshotToClient(ws, 'bridge_catalog_request');
    }
    return;
  }

  if (type === 'bridge_state') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const bridge = normalizePrompterBridgeCatalogEntry(data, {
      bridgeId: meta.bridgeId,
      workflowId: meta.workflowId,
      workflowName: meta.workflowName,
      compatible: meta.compatible,
      missing: meta.missing,
      updatedAt: meta.updatedAt,
    });
    meta.bridgeId = bridge.bridgeId;
    meta.workflowId = bridge.workflowId;
    meta.workflowName = bridge.workflowName;
    meta.compatible = bridge.compatible;
    meta.missing = bridge.missing;
    meta.updatedAt = bridge.updatedAt;
    prompterClientMeta.set(ws, meta);
    broadcastBridgeCatalogToPowerPrompterClients();
    return;
  }

  if (type === 'prompter_sync') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    const prompts = sanitizePrompterPromptLines(data?.state?.prompts ?? data?.prompts ?? []);
    const activePrompt = String(data?.state?.activePrompt ?? data?.activePrompt ?? '').trim();
    const joinedPrompt = String(data?.state?.joinedPrompt ?? data?.joinedPrompt ?? '').trim();
    const fileValueRaw = data?.state?.file ?? data?.file ?? null;
    const file = fileValueRaw == null ? null : String(fileValueRaw);
    const generation = normalizePPGenerationControls(data?.state?.generation ?? data?.generation);

    prompterSyncState = {
      file,
      prompts,
      activePrompt,
      joinedPrompt,
      generation,
      updatedAt: Date.now(),
    };
    broadcastPrompterSyncToComfy();
    return;
  }

  if (type === 'queue_request' || type === 'batch_start') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    const payload = type === 'batch_start'
      ? {
        ...data,
        prompts: Array.isArray(data?.prompts)
          ? data.prompts.map((entry: any) => String(entry?.positive || '')).filter((value: string) => value.trim().length > 0)
          : [],
      }
      : data;
    handlePrompterQueueRequest(ws, payload);
    return;
  }

  if (type === 'queue_batch_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    const requestId = String(data?.requestId || crypto.randomUUID());
    void handlePrompterApiWorkflowQueueBatchRequest(ws, data, requestId).catch((error: any) => {
      sendWs(ws, {
        type: 'queue_batch_forwarded',
        requestId,
        success: false,
        error: String(error?.message || 'Failed to enqueue generation pipeline batch.'),
        acceptedRequestIds: [],
      });
    });
    return;
  }

  if (
    type === 'queue_pause'
    || type === 'queue_resume'
    || type === 'queue_cancel'
    || type === 'queue_clear_future'
    || type === 'queue_interrupt_active'
  ) {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    forwardPrompterQueueControl(ws, data, type);
    return;
  }

  if (type === 'queue_delay_update' || type === 'queue_reorder' || type === 'queue_prompt_remove') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    forwardPrompterQueueMessageToComfyTarget(ws, data, type);
    return;
  }

  if (type === 'lora_catalog_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    handlePrompterLoraRequest(ws, data, 'lora_catalog_request', 'lora_catalog_result');
    return;
  }

  if (type === 'lora_info_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    handlePrompterLoraRequest(ws, data, 'lora_info_request', 'lora_info_result');
    return;
  }

  if (type === 'model_catalog_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    handlePrompterModelRequest(ws, data, 'model_catalog_request', 'model_catalog_result');
    return;
  }

  if (type === 'model_info_request') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'powerprompter') return;
    handlePrompterModelRequest(ws, data, 'model_info_request', 'model_info_result');
    return;
  }

  if (type === 'queue_result') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    if (!requestId) return;
    appendPowerPrompterQueueLog('queue_result_from_bridge', {
      ...summarizePrompterQueueMessage(data),
      bridgeId: meta.bridgeId || '',
      bridgeSource: meta.source,
    });
    const pending = prompterPendingQueueRequests.get(requestId);
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (pending) {
      requestSourceClient = pending.sourceWs;
      sendWs(pending.sourceWs, data);
    }
    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }
    if (data?.success === false) {
      prompterPendingQueueRequests.delete(requestId);
    }
    return;
  }

  if (type === 'queue_delay_result' || type === 'queue_reorder_result' || type === 'queue_prompt_remove_result') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    if (!requestId) return;
    const backendHandledRequestIds = backendHandledPowerPrompterQueueControlRequests.get(requestId) || [];
    if (backendHandledRequestIds.length > 0) {
      backendHandledPowerPrompterQueueControlRequests.delete(requestId);
    }
    const payload = type === 'queue_prompt_remove_result' && backendHandledRequestIds.length > 0
      ? {
        ...data,
        success: true,
        applied: true,
        backendHandled: true,
        removedRequestIds: Array.isArray((data as any)?.removedRequestIds) && (data as any).removedRequestIds.length > 0
          ? (data as any).removedRequestIds
          : backendHandledRequestIds,
      }
      : data;
    appendPowerPrompterQueueLog('queue_mutation_result_from_bridge', {
      ...summarizePrompterQueueMessage(payload),
      bridgeId: meta.bridgeId || '',
      bridgeSource: meta.source,
      backendHandledRequestIds,
    });
    const pending = prompterPendingQueueRequests.get(requestId);
    if (pending) {
      sendWs(pending.sourceWs, payload);
    }
    prompterPendingQueueRequests.delete(requestId);
    return;
  }

  if (type === 'queue_progress') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    appendPowerPrompterQueueLog('queue_progress_from_bridge', {
      ...summarizePrompterQueueMessage(data),
      bridgeId: meta.bridgeId || '',
      bridgeSource: meta.source,
    });
    emitPowerPrompterRuntimeTerminalLog('queue_progress', data);
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = prompterPendingQueueRequests.get(requestId)?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }

    return;
  }

  if (type === 'queue_saved_outputs') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    appendPowerPrompterQueueLog('queue_saved_outputs_from_bridge', {
      ...summarizePrompterQueueMessage(data),
      bridgeId: meta.bridgeId || '',
      bridgeSource: meta.source,
    });
    emitPowerPrompterRuntimeTerminalLog('queue_saved_outputs', data);
    const pendingRequest = requestId ? prompterPendingQueueRequests.get(requestId) || null : null;
    void tagPowerPrompterSavedOutputs(data, pendingRequest);
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = pendingRequest?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }
    return;
  }

  if (
    type === 'queue_pause_state'
    || type === 'queue_pause_result'
    || type === 'queue_cancel_result'
    || type === 'queue_clear_future_result'
    || type === 'queue_interrupt_result'
  ) {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '').trim();
    const backendHandledRequestIds = requestId
      ? backendHandledPowerPrompterQueueControlRequests.get(requestId) || []
      : [];
    if (requestId && type !== 'queue_pause_state') {
      backendHandledPowerPrompterQueueControlRequests.delete(requestId);
    }
    const payload = data?.success === false && backendHandledRequestIds.length > 0
      ? {
        ...data,
        success: true,
        backendHandled: true,
        ...(type === 'queue_cancel_result' ? { requestIds: backendHandledRequestIds } : {}),
        ...(type === 'queue_clear_future_result' ? { clearedRequestIds: backendHandledRequestIds } : {}),
        ...(type === 'queue_interrupt_result' ? { requestIds: backendHandledRequestIds } : {}),
      }
      : data;
    appendPowerPrompterQueueLog('queue_control_result_from_bridge', {
      ...summarizePrompterQueueMessage(payload),
      bridgeId: meta.bridgeId || '',
      bridgeSource: meta.source,
      backendHandledRequestIds,
    });
    for (const target of getPowerPrompterTargets()) {
      sendWs(target, payload);
    }
    return;
  }

  if (type === 'generation_preview') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = prompterPendingQueueRequests.get(requestId)?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }
    return;
  }

  if (type === 'job_progress' || type === 'job_idle') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    if (type === 'job_progress') {
      emitPowerPrompterRuntimeTerminalLog('job_progress', data);
    }
    if (type === 'job_idle') {
      appendPowerPrompterQueueLog('job_idle_from_bridge', {
        ...summarizePrompterQueueMessage(data),
        bridgeId: meta.bridgeId || '',
        bridgeSource: meta.source,
      });
    }
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = prompterPendingQueueRequests.get(requestId)?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }

    if (type === 'job_idle' && requestId) {
      prompterPendingQueueRequests.delete(requestId);
    }
    return;
  }

  if (type === 'lora_catalog_result' || type === 'lora_info_result') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = prompterPendingLoraRequests.get(requestId)?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }

    if (requestId) {
      prompterPendingLoraRequests.delete(requestId);
    }
    return;
  }

  if (type === 'model_catalog_result' || type === 'model_info_result') {
    const meta = getPrompterMeta(ws);
    if (meta.role !== 'comfy_bridge') return;
    const requestId = String(data?.requestId || '');
    let requestSourceClient: ServerWebSocket<unknown> | null = null;
    if (requestId) {
      requestSourceClient = prompterPendingModelRequests.get(requestId)?.sourceWs || null;
    }

    if (requestSourceClient && requestSourceClient.readyState === 1) {
      sendWs(requestSourceClient, data);
    }

    for (const target of getPowerPrompterTargets()) {
      if (target === requestSourceClient) continue;
      sendWs(target, data);
    }

    if (requestId) {
      prompterPendingModelRequests.delete(requestId);
    }
    return;
  }
}

let systemBroadcastTimer: Timer | null = null;
let pendingOutputChangeTimer: Timer | null = null;
const pendingOutputChangePaths = new Set<string>();
const pendingOutputChangeReasons = new Set<string>();

function flushPendingOutputChanges() {
  if (pendingOutputChangeTimer) {
    clearTimeout(pendingOutputChangeTimer);
    pendingOutputChangeTimer = null;
  }
  if (pendingOutputChangePaths.size <= 0) return;

  const paths = Array.from(pendingOutputChangePaths);
  const reasons = Array.from(pendingOutputChangeReasons);
  pendingOutputChangePaths.clear();
  pendingOutputChangeReasons.clear();

  const primaryReason = reasons[0] || 'invalidate';
  const msg = JSON.stringify({
    type: 'output_paths_changed',
    data: {
      paths,
      reason: primaryReason,
      reasons,
      at: Date.now(),
    },
  });

  for (const ws of wsClients.output) {
    try { if (ws.readyState === 1) ws.send(msg); } catch { }
  }
}

function queueOutputPathsChanged(
  paths: Array<string | null | undefined>,
  reason = 'invalidate',
) {
  for (const rawPath of paths) {
    const normalized = normalizeFsListPathKey(String(rawPath || ''));
    if (!normalized) continue;
    pendingOutputChangePaths.add(normalized);
  }
  if (pendingOutputChangePaths.size <= 0) return;
  pendingOutputChangeReasons.add(String(reason || 'invalidate'));

  if (pendingOutputChangeTimer) return;
  pendingOutputChangeTimer = setTimeout(() => {
    flushPendingOutputChanges();
  }, 120);
}

function startSystemBroadcast() {
  if (systemBroadcastTimer) return;

  const broadcast = async () => {
    if (wsClients.system.size === 0) {
      systemBroadcastTimer = null;
      return;
    }

    try {
      const stats = await getSystemStats();
      const msg = JSON.stringify({ type: 'system_stats', data: stats });
      for (const ws of wsClients.system) {
        try { if (ws.readyState === 1) ws.send(msg); } catch { }
      }
    } catch { }

    systemBroadcastTimer = setTimeout(broadcast, 2000);
  };

  broadcast();
}

// Log throttling to prevent frontend flooding during tool startup
const logBuffer: Map<string, { messages: string[]; timer: NodeJS.Timeout | null }> = new Map();
const LOG_BATCH_INTERVAL = 100; // ms - batch logs every 100ms
const LOG_BATCH_SIZE = 50; // max messages per batch
const LOG_MESSAGE_MAX_CHARS = 4000;
const LOG_BATCH_MAX_CHARS = 64000;

function clampLogMessage(message: unknown): string {
  const text = String(message ?? '');
  if (text.length <= LOG_MESSAGE_MAX_CHARS) return text;
  return `${text.slice(0, LOG_MESSAGE_MAX_CHARS)}\n...[truncated ${text.length - LOG_MESSAGE_MAX_CHARS} chars]`;
}

function broadcastToClients(type: string, data: any) {
  // For backend logs, use throttling to prevent flooding
  if (type === 'backend_log' && data.backend) {
    const key = `${data.backend}_${data.stream || 'stdout'}`;

    if (!logBuffer.has(key)) {
      logBuffer.set(key, { messages: [], timer: null });
    }

    const buffer = logBuffer.get(key)!;
    buffer.messages.push(clampLogMessage(data.message));

    // If buffer is full, flush immediately
    if (buffer.messages.length >= LOG_BATCH_SIZE) {
      flushLogBuffer(key);
      return;
    }

    // Set up timer to flush if not already set
    if (!buffer.timer) {
      buffer.timer = setTimeout(() => flushLogBuffer(key), LOG_BATCH_INTERVAL);
    }
    return;
  }

  // For all other types, broadcast immediately
  const msg = JSON.stringify({ type, data });
  const clients = type.startsWith('log') ? wsClients.logs : wsClients.system;
  for (const ws of clients) {
    try { if (ws.readyState === 1) ws.send(msg); } catch { }
  }
}

function flushLogBuffer(key: string) {
  const buffer = logBuffer.get(key);
  if (!buffer || buffer.messages.length === 0) return;

  // Clear timer
  if (buffer.timer) {
    clearTimeout(buffer.timer);
    buffer.timer = null;
  }

  // Batch messages
  const [backend, stream] = key.split('_');
  let batchedMessage = buffer.messages.join('\n');
  if (batchedMessage.length > LOG_BATCH_MAX_CHARS) {
    batchedMessage = `${batchedMessage.slice(0, LOG_BATCH_MAX_CHARS)}\n...[log batch truncated]`;
  }
  buffer.messages = [];

  // Send batched message
  const msg = JSON.stringify({
    type: 'backend_log',
    data: { backend, stream, message: batchedMessage, batched: true }
  });

  for (const ws of wsClients.logs) {
    try { if (ws.readyState === 1) ws.send(msg); } catch { }
  }
}

function handleWsConnection(ws: ServerWebSocket<unknown>, endpoint: string) {
  if (endpoint === '/ws/system') {
    wsClients.system.add(ws);
    logWsLifecycle(`[WS] System client connected (${wsClients.system.size} total)`);
    Promise.resolve(getSystemStats()).then(stats => {
      try { ws.send(JSON.stringify({ type: 'system_stats', data: stats })); } catch { }
    });
    startSystemBroadcast();
  } else if (endpoint === '/ws/logs') {
    wsClients.logs.add(ws);
    logWsLifecycle(`[WS] Logs client connected (${wsClients.logs.size} total)`);
  } else if (endpoint === '/ws/generation') {
    wsClients.generation.add(ws);
    logWsLifecycle(`[WS] Generation client connected (${wsClients.generation.size} total)`);
  } else if (endpoint === '/ws/output') {
    wsClients.output.add(ws);
    logWsLifecycle(`[WS] Output client connected (${wsClients.output.size} total)`);
  } else if (endpoint === '/ws/prompter') {
    wsClients.prompter.add(ws);
    prompterClientMeta.set(ws, {
      role: 'unknown',
      source: 'unknown',
      remote: (ws.data as any)?.remoteClient === true,
    });
    logWsLifecycle(`[WS] Prompter client connected (${wsClients.prompter.size} total)`);
  } else if (endpoint === '/ws/comfy-preview') {
    if (!APPBAR_COMFY_PREVIEW_ENABLED) {
      try { ws.close(); } catch {}
      return;
    }
    wsClients.comfyPreview.add(ws);
    logWsLifecycle(`[WS] Comfy preview client connected (${wsClients.comfyPreview.size} total)`);
    if (appbarComfyPreviewLastPayload) {
      sendWs(ws, {
        type: 'comfy_generation_preview',
        data: appbarComfyPreviewLastPayload,
      });
    }
  } else if (endpoint === '/ws/ui-session') {
    wsClients.uiSession.add(ws);
    logWsLifecycle(`[WS] UI session client connected (${wsClients.uiSession.size} total)`);
    void sendUiSessionSnapshotToClient(ws).catch(() => undefined);
  }
}

function handleWsDisconnection(ws: ServerWebSocket<unknown>, endpoint: string) {
  if (endpoint === '/ws/system') {
    wsClients.system.delete(ws);
    logWsLifecycle(`[WS] System client disconnected (${wsClients.system.size} remaining)`);
    if (wsClients.system.size === 0 && systemBroadcastTimer) {
      clearTimeout(systemBroadcastTimer);
      systemBroadcastTimer = null;
    }
  } else if (endpoint === '/ws/logs') {
    wsClients.logs.delete(ws);
  } else if (endpoint === '/ws/generation') {
    wsClients.generation.delete(ws);
  } else if (endpoint === '/ws/output') {
    wsClients.output.delete(ws);
  } else if (endpoint === '/ws/prompter') {
    const meta = prompterClientMeta.get(ws);
    const shouldBroadcastBridgeCatalog = meta?.role === 'comfy_bridge';
    wsClients.prompter.delete(ws);
    prompterClientMeta.delete(ws);
    if (shouldBroadcastBridgeCatalog) {
      failPrompterRequestsForBridge(ws, 'ComfyUI bridge disconnected before the request completed.');
    } else {
      dropPrompterRequestsForSource(ws);
    }
    if (shouldBroadcastBridgeCatalog) {
      broadcastBridgeCatalogToPowerPrompterClients();
    }
  } else if (endpoint === '/ws/comfy-preview') {
    wsClients.comfyPreview.delete(ws);
    logWsLifecycle(`[WS] Comfy preview client disconnected (${wsClients.comfyPreview.size} remaining)`);
  } else if (endpoint === '/ws/ui-session') {
    wsClients.uiSession.delete(ws);
    logWsLifecycle(`[WS] UI session client disconnected (${wsClients.uiSession.size} remaining)`);
  }
}

