function appendBackendStreamLog(backend: DurableBackend, stream: 'stdout' | 'stderr' | 'lifecycle', message: string) {
  if (!isBackendDiagnosticLoggingEnabled()) return;
  ensureLogDir();
  const clean = truncateLogText(stripAnsi(message).trimEnd(), 12000);
  if (!clean) return;
  const line = `[${new Date().toISOString()}] [${stream}] ${clean}\n`;
  void fs.appendFile(join(LOG_DIR, `${backend}-backend-${processLogDate()}.log`), line, 'utf-8').catch(() => {});
}

const COMFY_PROGRESS_LOG_MIN_INTERVAL_MS = 2500;
const comfyProgressLogLastAt: Record<'stdout' | 'stderr', number> = { stdout: 0, stderr: 0 };
const POWER_PROMPTER_PROGRESS_LOG_MIN_INTERVAL_MS = 4000;
const powerPrompterProgressLogState = new Map<string, { bucket: number; lastAt: number }>();
const powerPrompterPauseStateLogState = new Map<string, string>();

function isNoisyComfyProgressLine(line: string): boolean {
  const clean = stripAnsi(line).trim();
  if (!clean) return true;
  return /(?:^|\s)\d{1,3}%\|.*\|/.test(clean)
    || /\bit\/s\b/.test(clean)
    || /Model Initializ(?:ing|ation complete)/i.test(clean);
}

function shouldEmitComfyProcessLine(stream: 'stdout' | 'stderr', line: string): boolean {
  if (process.env.UMBRA_TERMINAL_MODE === 'visible') return true;
  if (!isNoisyComfyProgressLine(line)) return true;
  const now = Date.now();
  const lastAt = comfyProgressLogLastAt[stream] || 0;
  if (now - lastAt < COMFY_PROGRESS_LOG_MIN_INTERVAL_MS) return false;
  comfyProgressLogLastAt[stream] = now;
  return true;
}

function appendPowerPrompterQueueLog(event: string, details: Record<string, unknown> = {}) {
  if (!isBackendDiagnosticLoggingEnabled()) return;
  ensureLogDir();
  const entry = {
    timestamp: new Date().toISOString(),
    event,
    ...details,
  };
  try {
    appendFileSync(join(LOG_DIR, `powerprompter-queue-${processLogDate()}.jsonl`), `${JSON.stringify(entry)}\n`, 'utf-8');
  } catch {
    // Best-effort diagnostic log.
  }
  emitPowerPrompterTerminalLog(event, details);
}

function formatPowerPrompterRequestId(rawValue: unknown): string {
  const id = String(rawValue || '').trim();
  if (!id) return 'unknown';
  return id.length <= 8 ? id : id.slice(0, 8);
}

function formatPowerPrompterCount(rawValue: unknown, fallback = 0): number {
  const numeric = Number(rawValue);
  return Number.isFinite(numeric) ? Math.max(0, Math.floor(numeric)) : fallback;
}

function emitPowerPrompterTerminalLine(message: string) {
  const clean = stripAnsi(String(message || '').trim());
  if (!clean) return;
  console.log(`\x1b[35m[PowerPrompter]\x1b[0m ${clean}`);
}

function emitPowerPrompterTerminalLog(event: string, details: Record<string, unknown> = {}) {
  const requestId = formatPowerPrompterRequestId(details.requestId);
  const type = String(details.type || '').trim();
  const promptCount = formatPowerPrompterCount(details.promptCount);
  const total = formatPowerPrompterCount(details.total);
  const queued = formatPowerPrompterCount(details.queued);
  const completed = formatPowerPrompterCount(details.completed);
  const target = String(details.targetSource || details.bridgeSource || details.queueTargetType || '').trim();
  const suffix = target ? ` target=${target}` : '';

  if (event === 'queue_forward_request') {
    emitPowerPrompterTerminalLine(`Queued group req=${requestId} prompts=${promptCount}${suffix}`);
    return;
  }

  if (event === 'queue_result_from_bridge') {
    if (details.success === false) {
      emitPowerPrompterTerminalLine(`Queue failed req=${requestId} error="${truncateLogText(details.error || 'Unknown error', 240)}"`);
      return;
    }
    emitPowerPrompterTerminalLine(`Bridge accepted req=${requestId} queued=${queued || total || promptCount}${total ? `/${total}` : ''}`);
    return;
  }

  if (event === 'job_idle_from_bridge') {
    const reason = String(details.reason || '').trim();
    emitPowerPrompterTerminalLine(`Group finished req=${requestId} completed=${completed || total}${total ? `/${total}` : ''}${reason ? ` reason=${reason}` : ''}`);
    return;
  }

  if (event === 'queue_control_forwarded') {
    const requestIdCount = formatPowerPrompterCount(details.requestIdCount);
    emitPowerPrompterTerminalLine(`Control sent type=${type || 'queue_control'} requestIds=${requestIdCount}${suffix}`);
    return;
  }

  if (event === 'queue_control_result_from_bridge') {
    if (type === 'queue_pause_state') {
      const bridgeId = String(details.bridgeId || 'bridge').trim();
      const paused = details.paused === true;
      const pendingCount = formatPowerPrompterCount(details.pendingCount);
      const activeCount = Array.isArray(details.activeRequestIds) ? details.activeRequestIds.length : 0;
      const signature = `${paused}:${pendingCount}:${activeCount}`;
      if (powerPrompterPauseStateLogState.get(bridgeId) === signature) return;
      powerPrompterPauseStateLogState.set(bridgeId, signature);
      emitPowerPrompterTerminalLine(`Bridge state ${paused ? 'paused' : 'running'} active=${activeCount} pending=${pendingCount}`);
      return;
    }
    if (details.success === false) {
      emitPowerPrompterTerminalLine(`Control failed type=${type || 'queue_control'} req=${requestId} error="${truncateLogText(details.error || 'Unknown error', 240)}"`);
      return;
    }
    emitPowerPrompterTerminalLine(`Control applied type=${type || 'queue_control'} req=${requestId}`);
  }
}

function emitPowerPrompterRuntimeTerminalLog(type: string, data: any) {
  const requestId = formatPowerPrompterRequestId(data?.requestId);
  if (type === 'queue_progress') {
    const promptIndex = formatPowerPrompterCount(data?.promptIndex);
    const completed = formatPowerPrompterCount(data?.completed);
    const total = formatPowerPrompterCount(data?.total);
    const source = String(data?.source || '').trim();
    emitPowerPrompterTerminalLine(
      `Prompt complete req=${requestId} prompt=${promptIndex + 1}${total ? `/${total}` : ''} completed=${completed || promptIndex + 1}${total ? `/${total}` : ''}${source ? ` source=${source}` : ''}`
    );
    return;
  }

  if (type === 'job_progress') {
    const step = formatPowerPrompterCount(data?.step);
    const maxStep = formatPowerPrompterCount(data?.maxStep);
    if (maxStep <= 0) return;
    const promptIndex = formatPowerPrompterCount(data?.promptIndex);
    const total = formatPowerPrompterCount(data?.total);
    const percent = Math.max(0, Math.min(100, Math.floor((step / Math.max(1, maxStep)) * 100)));
    const bucket = Math.floor(percent / 10) * 10;
    const key = `${String(data?.requestId || '').trim()}:${promptIndex}`;
    const now = Date.now();
    const previous = powerPrompterProgressLogState.get(key);
    if (previous && previous.bucket === bucket && now - previous.lastAt < POWER_PROMPTER_PROGRESS_LOG_MIN_INTERVAL_MS) return;
    powerPrompterProgressLogState.set(key, { bucket, lastAt: now });
    emitPowerPrompterTerminalLine(`Running req=${requestId} prompt=${promptIndex + 1}${total ? `/${total}` : ''} step=${step}/${maxStep} ${percent}%`);
    return;
  }

  if (type === 'queue_saved_outputs') {
    const outputCount = Array.isArray(data?.outputs) ? data.outputs.length : 0;
    if (outputCount <= 0) return;
    const promptIndex = formatPowerPrompterCount(data?.promptIndex);
    const promptSetLabel = String(data?.promptSetLabel || '').trim();
    emitPowerPrompterTerminalLine(`Saved output req=${requestId} prompt=${promptIndex + 1} files=${outputCount}${promptSetLabel ? ` ${promptSetLabel}` : ''}`);
  }
}

async function tagPowerPrompterSavedOutputs(data: any, pending: PrompterPendingRequest | null | undefined) {
  const outputs = Array.isArray(data?.outputs) ? data.outputs : [];
  if (outputs.length === 0) return;

  const promptIndexRaw = Number(data?.promptIndex);
  const promptIndex = Number.isFinite(promptIndexRaw) ? Math.max(0, Math.floor(promptIndexRaw)) : 0;
  const eventSetId = clampPPQueueSetId(data?.promptSetId ?? data?.setId ?? pending?.promptSetIds?.[promptIndex] ?? 1);
  const eventSetTag = normalizeFsTag(`set ${eventSetId}`);
  const eventTags = normalizePowerPrompterSavedOutputTags(data?.tags, eventSetTag);
  const filesByFolder = new Map<string, GalleryFileInput[]>();
  const tagsByPath = new Map<string, string[]>();

  for (const output of outputs) {
    const item = output && typeof output === 'object' ? output as Record<string, unknown> : {};
    const resolved = await resolvePowerPrompterSavedOutputForGallery(item);
    if (!resolved) continue;
    const itemSetId = clampPPQueueSetId(item.promptSetId ?? item.setId ?? eventSetId);
    const itemSetTag = normalizeFsTag(`set ${itemSetId}`);
    const itemTags = normalizePowerPrompterSavedOutputTags(item.tags, itemSetTag, eventTags);
    if (itemTags.length === 0) continue;

    const existing = filesByFolder.get(resolved.file.folderPath) || [];
    existing.push(resolved.file);
    filesByFolder.set(resolved.file.folderPath, existing);
    tagsByPath.set(resolved.file.path, itemTags);
  }

  if (filesByFolder.size === 0 || tagsByPath.size === 0) return;

  try {
    for (const [folderPath, files] of filesByFolder.entries()) {
      galleryDb.upsertFolderFiles(folderPath, files);
    }

    const pathsByTag = new Map<string, string[]>();
    for (const [pathValue, tags] of tagsByPath.entries()) {
      for (const tag of tags) {
        if (!tag) continue;
        const paths = pathsByTag.get(tag) || [];
        paths.push(pathValue);
        pathsByTag.set(tag, paths);
      }
    }

    let taggedCount = 0;
    for (const [tag, paths] of pathsByTag.entries()) {
      const uids = galleryDb.resolveUidsForPaths(paths);
      if (uids.length === 0) continue;
      const tagged = galleryDb.addTagsToFiles(uids, [tag]);
      taggedCount += tagged.size;
    }

    if (taggedCount > 0) {
      emitPowerPrompterTerminalLine(`Tagged output set=${eventSetTag} files=${taggedCount}`);
    }
  } catch (error) {
    console.warn('[PowerPrompter] Failed to auto-tag saved outputs:', error);
  }
}

function normalizePowerPrompterSavedOutputTags(
  rawTags: unknown,
  fallbackSetTag: string,
  inheritedTags: string[] = [],
): string[] {
  const values = Array.isArray(rawTags) ? rawTags : [];
  const normalized = [
    fallbackSetTag,
    ...inheritedTags,
    ...values,
  ]
    .map((entry) => normalizeFsTag(entry))
    .filter(Boolean);
  return Array.from(new Set(normalized));
}

async function resolvePowerPrompterSavedOutputForGallery(output: Record<string, unknown>): Promise<{ file: GalleryFileInput } | null> {
  const explicitPath = String(output.fullpath || output.fullPath || output.path || '').trim();
  const filename = String(output.filename || output.name || '').trim();
  const subfolder = normalizeOutputPathInput(String(output.subfolder || '').trim());
  const candidate = explicitPath
    || (filename ? normalizeOutputPathInput(`${getDefaultOutputRootPath()}${subfolder ? `/${subfolder}` : ''}/${filename}`) : '');
  if (!candidate) return null;

  const resolved = resolvePath(candidate);
  if (!resolved || !isPathInsideAllowedRoots(resolved.fullPath)) return null;

  let stats: Awaited<ReturnType<typeof fs.stat>>;
  try {
    stats = await fs.stat(resolved.fullPath);
  } catch {
    return null;
  }
  if (!stats.isFile()) return null;

  const clientPath = normalizeOutputPathInput(toClientPath(resolved.fullPath));
  const folderPath = normalizeOutputPathInput(dirname(clientPath).replace(/\\/g, '/'));
  if (!clientPath || !folderPath || folderPath === '.') return null;

  return {
    file: {
      path: clientPath,
      folderPath,
      name: filename || basename(clientPath),
      type: inferGalleryMediaType(clientPath, output.type),
      size: Math.max(0, Number(stats.size || 0)),
      createdMs: Math.max(0, Math.floor(Number(stats.birthtimeMs || stats.ctimeMs || stats.mtimeMs || Date.now()))),
      modifiedMs: Math.max(0, Math.floor(Number(stats.mtimeMs || Date.now()))),
    },
  };
}

function appendPowerPrompterDiagnosticsLog(event: string, details: Record<string, unknown> = {}) {
  if (!isBackendDiagnosticLoggingEnabled()) return;
  ensureLogDir();
  const entry = {
    timestamp: new Date().toISOString(),
    event,
    ...details,
  };
  try {
    void fs.appendFile(
      join(LOG_DIR, `powerprompter-diagnostics-${processLogDate()}.jsonl`),
      `${JSON.stringify(entry)}\n`,
      'utf-8'
    ).catch(() => {
      // Best-effort diagnostic log.
    });
  } catch {
    // Best-effort diagnostic log.
  }
  const detail = details?.detail && typeof details.detail === 'object'
    ? details.detail as Record<string, unknown>
    : {};
  if (event.startsWith('promptBuild:') && event.includes(':slow')) {
    const elapsedMs = formatPowerPrompterCount(detail.elapsedMs);
    const promptCount = formatPowerPrompterCount(detail.promptCount);
    const setPromptCount = formatPowerPrompterCount(detail.setPromptCount);
    const allPromptCount = formatPowerPrompterCount(detail.allPromptCount);
    emitPowerPrompterTerminalLine(
      `Slow prompt build event=${event} elapsed=${elapsedMs}ms prompts=${promptCount || setPromptCount}${allPromptCount ? ` all=${allPromptCount}` : ''}`
    );
  }
}

function summarizePrompterQueueMessage(data: any): Record<string, unknown> {
  const prompts = Array.isArray(data?.prompts) ? data.prompts : [];
  const requestIds = Array.isArray(data?.requestIds)
    ? collectPrompterRequestIds(data.requestIds)
    : [];
  const promptRemovals = Array.isArray(data?.promptRemovals) ? data.promptRemovals : [];
  return {
    type: String(data?.type || ''),
    requestId: String(data?.requestId || ''),
    requestIds,
    requestIdCount: requestIds.length,
    uniqueRequestIdCount: new Set(requestIds).size,
    activeRequestId: String(data?.activeRequestId || ''),
    targetBridgeId: String(data?.targetBridgeId || ''),
    queueTargetType: String(data?.queueTargetType || ''),
    apiWorkflowId: String(data?.apiWorkflowId || ''),
    promptCount: prompts.length,
    promptIndex: Number.isFinite(Number(data?.promptIndex)) ? Number(data.promptIndex) : undefined,
    mode: String(data?.mode || ''),
    success: typeof data?.success === 'boolean' ? data.success : undefined,
    paused: typeof data?.paused === 'boolean' ? data.paused : undefined,
    canceled: typeof data?.canceled === 'boolean' ? data.canceled : undefined,
    queued: Number.isFinite(Number(data?.queued)) ? Number(data.queued) : undefined,
    total: Number.isFinite(Number(data?.total)) ? Number(data.total) : undefined,
    completed: Number.isFinite(Number(data?.completed)) ? Number(data.completed) : undefined,
    step: Number.isFinite(Number(data?.step)) ? Number(data.step) : undefined,
    maxStep: Number.isFinite(Number(data?.maxStep)) ? Number(data.maxStep) : undefined,
    pendingCount: Number.isFinite(Number(data?.pendingCount)) ? Number(data.pendingCount) : undefined,
    activeRequestIds: Array.isArray(data?.activeRequestIds) ? data.activeRequestIds.map((entry: unknown) => String(entry || '').trim()).filter(Boolean) : undefined,
    dispatchDelayMs: Number.isFinite(Number(data?.dispatchDelayMs)) ? Number(data.dispatchDelayMs) : undefined,
    promptRemovalCount: promptRemovals.length,
    outputCount: Array.isArray(data?.outputs) ? data.outputs.length : undefined,
    reason: data?.reason ? truncateLogText(data.reason, 200) : undefined,
    source: data?.source ? truncateLogText(data.source, 200) : undefined,
    error: data?.error ? truncateLogText(data.error, 1000) : undefined,
  };
}

function uniquePositivePids(pids: Array<number | null | undefined>): number[] {
  return Array.from(new Set(
    pids
      .map((pid) => Number(pid))
      .filter((pid) => Number.isFinite(pid) && pid > 0)
  ));
}

function sleep(ms: number) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function isPidAlive(pid: number): boolean {
  try {
    process.kill(pid, 0);
    return true;
  } catch {
    return false;
  }
}

async function waitForPidExit(pid: number, timeoutMs = 5000): Promise<boolean> {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    if (!isPidAlive(pid)) return true;
    await sleep(100);
  }
  return !isPidAlive(pid);
}

async function stopProcessTree(proc: ChildProcess | null, label: string): Promise<boolean> {
  if (!proc?.pid) return true;
  const pid = proc.pid;

  if (!isPidAlive(pid)) return true;

  try {
    if (IS_WINDOWS) {
      spawnSync('taskkill', ['/PID', String(pid), '/T', '/F'], { stdio: 'ignore', shell: true });
      return await waitForPidExit(pid, 4000);
    }

    try { proc.kill('SIGINT'); } catch { }
    if (await waitForPidExit(pid, 8000)) return true;

    spawnSync('pkill', ['-TERM', '-P', String(pid)], { stdio: 'ignore' });
    try { proc.kill('SIGTERM'); } catch { }

    if (await waitForPidExit(pid, 6000)) return true;

    spawnSync('pkill', ['-KILL', '-P', String(pid)], { stdio: 'ignore' });
    try { proc.kill('SIGKILL'); } catch { }

    return await waitForPidExit(pid, 3000);
  } catch (err: any) {
    console.error(`[${label}] Failed to stop process tree:`, err?.message || err);
    return false;
  }
}

async function stopByPort(port: number, label: string): Promise<boolean> {
  const wasOpen = await isPortOpen(port);
  if (!wasOpen) return true;

  try {
    if (IS_WINDOWS) {
      const ps = [
        '$ErrorActionPreference = "SilentlyContinue"',
        `$pids = Get-NetTCPConnection -LocalPort ${port} -State Listen | Select-Object -ExpandProperty OwningProcess -Unique`,
        'foreach ($pidValue in $pids) {',
        '  try { Stop-Process -Id $pidValue -Force -ErrorAction SilentlyContinue } catch {}',
        '}',
      ].join('; ');
      spawnSync(
        'powershell',
        ['-NoProfile', '-NonInteractive', '-ExecutionPolicy', 'Bypass', '-Command', ps],
        { stdio: 'ignore' }
      );
      await sleep(1200);
      return !(await isPortOpen(port));
    }

    spawnSync('bash', ['-lc', `lsof -ti tcp:${port} 2>/dev/null | xargs -r kill -TERM; fuser -k -TERM ${port}/tcp >/dev/null 2>&1 || true`], { stdio: 'ignore' });
    await sleep(1200);
    if (await isPortOpen(port)) {
      spawnSync('bash', ['-lc', `lsof -ti tcp:${port} 2>/dev/null | xargs -r kill -KILL; fuser -k -KILL ${port}/tcp >/dev/null 2>&1 || true`], { stdio: 'ignore' });
      await sleep(800);
    }
    return !(await isPortOpen(port));
  } catch (err: any) {
    console.error(`[${label}] Failed to stop by port ${port}:`, err?.message || err);
    return false;
  }
}

function isPortOpen(port: number, timeoutMs = 1000): Promise<boolean> {
  const normalizedPort = Math.floor(Number(port));
  if (!Number.isFinite(normalizedPort) || normalizedPort < 1 || normalizedPort > 65535) {
    return Promise.resolve(false);
  }

  return new Promise((resolveOpen) => {
    let settled = false;
    let socket: ReturnType<typeof createConnection> | null = null;
    const finish = (open: boolean) => {
      if (settled) return;
      settled = true;
      if (socket) {
        socket.removeAllListeners();
        socket.destroy();
      }
      resolveOpen(open);
    };

    try {
      socket = createConnection({ host: '127.0.0.1', port: normalizedPort });
      socket.setTimeout(Math.max(100, Math.floor(Number(timeoutMs) || 1000)));
      socket.once('connect', () => finish(true));
      socket.once('timeout', () => finish(false));
      socket.once('error', () => finish(false));
    } catch {
      finish(false);
    }
  });
}

function getComfySignatureNeedles(): string[] {
  const config = getBackendConfig().comfyui;
  const needles = new Set<string>();

  const cwdRaw = String(config.cwd || '').trim();
  if (cwdRaw) {
    const normalizedCwd = resolve(cwdRaw).replace(/\\/g, '/').toLowerCase();
    if (normalizedCwd) {
      needles.add(normalizedCwd);
      needles.add(`${normalizedCwd}/main.py`);
    }
  }

  const mainArgRaw = String(config.args?.[0] || '').trim();
  if (mainArgRaw) {
    const resolvedMain = isAbsolute(mainArgRaw)
      ? resolve(mainArgRaw)
      : resolve(cwdRaw || ROOT_DIR, mainArgRaw);
    const normalizedMain = resolvedMain.replace(/\\/g, '/').toLowerCase();
    if (normalizedMain) needles.add(normalizedMain);
  }

  needles.add('/tools/comfyui/');
  return Array.from(needles).filter((entry) => entry.length > 0);
}

function listWindowsPidsByCommandNeedles(needles: string[]): number[] {
  if (needles.length === 0) return [];
  const quotedNeedles = needles
    .map((entry) => `'${entry.replace(/'/g, "''")}'`)
    .join(', ');
  const script = `
$needles = @(${quotedNeedles})
$matches = @()
Get-CimInstance Win32_Process -ErrorAction SilentlyContinue | ForEach-Object {
  $pid = [int]$_.ProcessId
  if ($pid -le 0) { return }
  $cmd = [string]$_.CommandLine
  if ([string]::IsNullOrWhiteSpace($cmd)) { return }
  $scan = $cmd.ToLowerInvariant().Replace('\\','/')
  $matched = $false
  foreach ($needle in $needles) {
    if ($needle -and $scan.Contains($needle)) { $matched = $true; break }
  }
  if ($matched) { $matches += $pid }
}
$matches | Sort-Object -Unique | ForEach-Object { Write-Output $_ }
`;
  const result = spawnSync('powershell', [
    '-NoProfile',
    '-NonInteractive',
    '-ExecutionPolicy', 'Bypass',
    '-Command', script,
  ], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
    timeout: 1500,
  });
  return String(result.stdout || '')
    .split(/\r?\n/)
    .map((line) => Number(line.trim()))
    .filter((pid) => Number.isFinite(pid) && pid > 0)
    .filter((pid, idx, arr) => arr.indexOf(pid) === idx);
}

function listPosixPidsByCommandNeedles(needles: string[]): number[] {
  if (needles.length === 0) return [];
  const result = spawnSync('ps', ['-eo', 'pid=,args='], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  const output = String(result.stdout || '');
  if (!output.trim()) return [];
  const matches = new Set<number>();
  for (const rawLine of output.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line) continue;
    const firstSpace = line.indexOf(' ');
    if (firstSpace <= 0) continue;
    const pid = Number(line.slice(0, firstSpace).trim());
    if (!Number.isFinite(pid) || pid <= 0) continue;
    const cmd = line.slice(firstSpace + 1).toLowerCase().replace(/\\/g, '/');
    if (needles.some((needle) => cmd.includes(needle))) {
      matches.add(pid);
    }
  }
  return Array.from(matches);
}

function listComfyPidsBySignature(): number[] {
  const needles = getComfySignatureNeedles();
  return IS_WINDOWS ? listWindowsPidsByCommandNeedles(needles) : listPosixPidsByCommandNeedles(needles);
}

function listWindowsPidsByPort(port: number): number[] {
  if (!Number.isFinite(port) || port <= 0) return [];
  const script = `
$pids = Get-NetTCPConnection -LocalPort ${Math.floor(port)} -State Listen -ErrorAction SilentlyContinue |
  Select-Object -ExpandProperty OwningProcess -Unique
$pids | Sort-Object -Unique | ForEach-Object { Write-Output $_ }
`;
  const result = spawnSync('powershell', [
    '-NoProfile',
    '-NonInteractive',
    '-ExecutionPolicy', 'Bypass',
    '-Command', script,
  ], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  return String(result.stdout || '')
    .split(/\r?\n/)
    .map((line) => Number(line.trim()))
    .filter((pid) => Number.isFinite(pid) && pid > 0)
    .filter((pid, idx, arr) => arr.indexOf(pid) === idx);
}

function listPosixPidsByPort(port: number): number[] {
  if (!Number.isFinite(port) || port <= 0) return [];
  const result = spawnSync('bash', ['-lc', `lsof -ti tcp:${Math.floor(port)} -sTCP:LISTEN 2>/dev/null || true`], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  return String(result.stdout || '')
    .split(/\r?\n/)
    .map((line) => Number(line.trim()))
    .filter((pid) => Number.isFinite(pid) && pid > 0)
    .filter((pid, idx, arr) => arr.indexOf(pid) === idx);
}

function listPidsByPort(port: number): number[] {
  return IS_WINDOWS ? listWindowsPidsByPort(port) : listPosixPidsByPort(port);
}

function stopPids(pids: number[], label: string): boolean {
  const uniquePids = uniquePositivePids(pids).filter((pid) => pid !== process.pid);
  if (uniquePids.length === 0) return true;
  let allStopped = true;
  for (const pid of uniquePids) {
    try {
      if (IS_WINDOWS) {
        spawnSync('taskkill', ['/PID', String(pid), '/T', '/F'], { stdio: 'ignore', shell: true });
      } else {
        spawnSync('kill', ['-TERM', String(pid)], { stdio: 'ignore' });
      }
    } catch (error: any) {
      allStopped = false;
      console.warn(`[${label}] Failed to request process stop for PID ${pid}:`, error?.message || error);
    }
  }
  return allStopped;
}

type BackendProcessOwnershipKind = 'owned' | 'external-compatible' | 'unknown-port' | 'stopped';

interface ComfyProcessOwnershipSnapshot {
  port: number;
  trackedPid: number | null;
  trackedAlive: boolean;
  signaturePids: number[];
  portPids: number[];
  ownedPids: number[];
  externalPids: number[];
  unknownPortPids: number[];
  portOpen: boolean;
  kind: BackendProcessOwnershipKind;
}

let comfyOwnershipSnapshotCache: { sampledAt: number; snapshot: ComfyProcessOwnershipSnapshot } | null = null;
const COMFY_OWNERSHIP_SNAPSHOT_CACHE_MS = 30000;

function getComfyProcessOwnershipSnapshot(options: { force?: boolean } = {}): ComfyProcessOwnershipSnapshot {
  const now = Date.now();
  if (
    !options.force
    && comfyOwnershipSnapshotCache
    && now - comfyOwnershipSnapshotCache.sampledAt < COMFY_OWNERSHIP_SNAPSHOT_CACHE_MS
  ) {
    return comfyOwnershipSnapshotCache.snapshot;
  }
  const port = getBackendConfig().comfyui.port;
  const trackedPid = comfyProcess?.pid ?? null;
  const trackedAlive = isChildProcessAlive(comfyProcess);
  const signaturePids = listComfyPidsBySignature().filter((pid) => pid !== process.pid);
  const portPids = listPidsByPort(port).filter((pid) => pid !== process.pid);
  const ownedPidSet = new Set<number>();
  if (trackedAlive && trackedPid) ownedPidSet.add(trackedPid);
  for (const pid of signaturePids) ownedPidSet.add(pid);
  const ownedPids = Array.from(ownedPidSet);
  const unknownPortPids = portPids.filter((pid) => !ownedPidSet.has(pid));
  const externalPids = signaturePids.filter((pid) => pid !== trackedPid);
  const kind: BackendProcessOwnershipKind = trackedAlive
    ? 'owned'
    : (signaturePids.length > 0 && portPids.length > 0)
      ? 'external-compatible'
      : unknownPortPids.length > 0
        ? 'unknown-port'
        : 'stopped';
  const snapshot = {
    port,
    trackedPid: trackedPid ?? null,
    trackedAlive,
    signaturePids,
    portPids,
    ownedPids,
    externalPids,
    unknownPortPids,
    portOpen: portPids.length > 0,
    kind,
  };
  comfyOwnershipSnapshotCache = { sampledAt: now, snapshot };
  return snapshot;
}

function parsePowerShellJsonArray<T>(stdout: string): T[] {
  const trimmed = stdout.trim();
  if (!trimmed) return [];
  try {
    const parsed = JSON.parse(trimmed);
    return Array.isArray(parsed) ? parsed : [parsed];
  } catch {
    return [];
  }
}

function getWindowsProcessSnapshots(pids: number[]): ProcessSnapshot[] {
  const uniquePids = uniquePositivePids(pids);
  if (uniquePids.length === 0) return [];
  const quotedPids = uniquePids.join(', ');
  const script = `
$targetPids = @(${quotedPids})
Get-CimInstance Win32_Process -ErrorAction SilentlyContinue | Where-Object {
  $targetPids -contains [int]$_.ProcessId
} | ForEach-Object {
  [pscustomobject]@{
    pid = [int]$_.ProcessId
    name = [string]$_.Name
    workingSetBytes = [int64]$_.WorkingSetSize
    privateBytes = [int64]$_.PrivatePageCount
    virtualBytes = [int64]$_.VirtualSize
    commandLine = [string]$_.CommandLine
  }
} | ConvertTo-Json -Compress
`;
  const result = spawnSync('powershell', [
    '-NoProfile',
    '-NonInteractive',
    '-ExecutionPolicy', 'Bypass',
    '-Command', script,
  ], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
    timeout: 1500,
  });
  return parsePowerShellJsonArray<ProcessSnapshot>(String(result.stdout || ''));
}

function getPosixProcessSnapshots(pids: number[]): ProcessSnapshot[] {
  const uniquePids = uniquePositivePids(pids);
  if (uniquePids.length === 0) return [];
  const result = spawnSync('ps', ['-o', 'pid=,rss=,vsz=,comm=,args=', '-p', uniquePids.join(',')], {
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  return String(result.stdout || '')
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line): ProcessSnapshot | null => {
      const match = line.match(/^(\d+)\s+(\d+)\s+(\d+)\s+(\S+)\s*(.*)$/);
      if (!match) return null;
      return {
        pid: Number(match[1]),
        workingSetBytes: Number(match[2]) * 1024,
        virtualBytes: Number(match[3]) * 1024,
        name: match[4],
        commandLine: match[5] || undefined,
      };
    })
    .filter((entry): entry is ProcessSnapshot => Boolean(entry));
}

function getProcessSnapshots(pids: number[]): ProcessSnapshot[] {
  const snapshots = IS_WINDOWS ? getWindowsProcessSnapshots(pids) : getPosixProcessSnapshots(pids);
  return snapshots.map((entry) => ({
    ...entry,
    commandLine: entry.commandLine ? truncateLogText(entry.commandLine, 1000) : entry.commandLine,
  }));
}

function logBackendProcessSnapshot(
  backend: DurableBackend,
  reason: string,
  pids: Array<number | null | undefined>,
  extraDetails: Record<string, unknown> = {}
) {
  const uniquePids = uniquePositivePids(pids);
  const processes = getProcessSnapshots(uniquePids);
  appendBackendLifecycleLog(backend, 'process_snapshot', {
    reason,
    pids: uniquePids,
    processes,
    ...extraDetails,
  });
}

function clearComfyProcessTelemetry() {
  if (!comfyProcessTelemetryTimer) return;
  clearInterval(comfyProcessTelemetryTimer);
  comfyProcessTelemetryTimer = null;
}

function clearGalleryProcessTelemetry() {
  if (!galleryProcessTelemetryTimer) return;
  clearInterval(galleryProcessTelemetryTimer);
  galleryProcessTelemetryTimer = null;
}

function startComfyProcessTelemetry() {
  clearComfyProcessTelemetry();
  const capture = (reason: string) => {
    const pids = uniquePositivePids([comfyProcess?.pid, ...listComfyPidsBySignature()]);
    if (pids.length === 0) return;
    logBackendProcessSnapshot('comfyui', reason, pids, {
      trackedPid: comfyProcess?.pid ?? null,
      uptimeMs: comfyStartTime ? Date.now() - comfyStartTime : null,
    });
  };
  const postStartTimer = setTimeout(() => capture('post_start'), 2500);
  (postStartTimer as any).unref?.();
  if (!isBackendDiagnosticLoggingEnabled()) return;
  comfyProcessTelemetryTimer = setInterval(() => capture('interval'), 60000);
  (comfyProcessTelemetryTimer as any).unref?.();
}

function startGalleryProcessTelemetry() {
  clearGalleryProcessTelemetry();
  const capture = (reason: string) => {
    if (!galleryBridgeProcess?.pid) return;
    logBackendProcessSnapshot('gallery', reason, [galleryBridgeProcess.pid], {
      trackedPid: galleryBridgeProcess.pid,
      uptimeMs: galleryBridgeStartTime ? Date.now() - galleryBridgeStartTime : null,
    });
  };
  const postStartTimer = setTimeout(() => capture('post_start'), 2500);
  (postStartTimer as any).unref?.();
  if (!isBackendDiagnosticLoggingEnabled()) return;
  galleryProcessTelemetryTimer = setInterval(() => capture('interval'), 60000);
  (galleryProcessTelemetryTimer as any).unref?.();
}

function invalidateComfyLaunchCapabilityCache() {
  comfyLaunchCapabilityCache = null;
  comfySageAvailabilityCache = null;
}

function stripAnsi(text: string): string {
  return text.replace(/\x1B\[[0-?]*[ -/]*[@-~]/g, '');
}

function parseVerifyFailure(line: string): ToolActionJob['verifyFailure'] | null {
  const clean = stripAnsi(line).trim();
  if (!clean.startsWith(VERIFY_FAIL_MARKER)) return null;
  const payload = clean.slice(VERIFY_FAIL_MARKER.length);
  try {
    const parsed = JSON.parse(payload) as ToolActionJob['verifyFailure'];
    if (!parsed?.code || !parsed?.title) return null;
    return parsed;
  } catch {
    return null;
  }
}

function createToolAction(action: string, args: string[], tool?: 'comfyui' | 'aitoolkit') {
  const id = crypto.randomUUID();
  const bunBin = process.execPath || 'bun';
  const job: ToolActionJob = {
    id,
    action,
    tool,
    startedAt: Date.now(),
    status: 'running',
    logs: []
  };
  toolActionJobs.set(id, job);

  const proc = spawn(bunBin, ['setup-tools.ts', ...args], {
    cwd: SOURCE_DIR,
    env: {
      ...process.env,
      UMBRA_ROOT: ROOT_DIR
    },
    stdio: ['ignore', 'pipe', 'pipe']
  });

  const appendLog = (line: string, stream: 'stdout' | 'stderr') => {
    const parsedVerifyFailure = parseVerifyFailure(line);
    if (parsedVerifyFailure) {
      job.verifyFailure = parsedVerifyFailure;
      const nextStep = parsedVerifyFailure.nextSteps?.[0];
      job.error = nextStep
        ? `${parsedVerifyFailure.title} (${parsedVerifyFailure.code}) - ${nextStep}`
        : `${parsedVerifyFailure.title} (${parsedVerifyFailure.code})`;
      return;
    }

    job.logs.push(line);
    if (job.logs.length > 200) job.logs = job.logs.slice(-200);
    broadcastToClients('log_tool_action', {
      actionId: id,
      action,
      tool: tool || null,
      stream,
      message: line
    });
  };

  const appendChunk = (chunk: any, stream: 'stdout' | 'stderr') => {
    const text = String(chunk ?? '');
    if (!text.trim()) return;
    const lines = text.split('\n').map((line) => line.trim()).filter(Boolean);
    for (const line of lines) appendLog(line, stream);
  };

  proc.stdout?.on('data', (chunk) => {
    appendChunk(chunk, 'stdout');
    const text = String(chunk).trim();
    if (text && isBackendDiagnosticLoggingEnabled()) console.log(`[ToolAction:${id}] ${text}`);
  });

  proc.stderr?.on('data', (chunk) => {
    appendChunk(chunk, 'stderr');
    const text = String(chunk).trim();
    if (text && isBackendDiagnosticLoggingEnabled()) console.warn(`[ToolAction:${id}] ${text}`);
  });

  let completionWatchdog: NodeJS.Timeout | null = null;
  let finalized = false;
  const finalizeJob = (code: number | null, processError?: Error) => {
    if (finalized) return;
    finalized = true;
    if (completionWatchdog) {
      clearInterval(completionWatchdog);
      completionWatchdog = null;
    }
    job.exitCode = code;
    job.endedAt = Date.now();
    job.status = !processError && code === 0 ? 'completed' : 'failed';
    if (processError) {
      job.error = processError.message || 'spawn failed';
    } else if (code !== 0) {
      job.error = job.error || `setup-tools exited with code ${code ?? 'unknown'}`;
    }
    if (code === 0 && tool === 'comfyui' && action === 'install_sageattention') {
      try {
        settingsManager.updateAppSettings({ 'comfyui.attentionBackend': 'sage' });
      } catch (error) {
        console.warn('[ComfyUI] Failed to set Sage attention as default after install:', error);
      }
    }
    if (tool === 'comfyui') {
      invalidateComfyLaunchCapabilityCache();
      if (!isChildProcessAlive(comfyProcess)) {
        comfyProcess = null;
        comfyStartTime = null;
      }
    } else if (tool === 'aitoolkit') {
      aitoolkitNodeCapabilityCache = null;
      if (!isChildProcessAlive(aitoolkitProcess)) {
        aitoolkitProcess = null;
        aitoolkitStartTime = null;
      }
    }
    broadcastToClients('log_tool_action_status', {
      actionId: id,
      action,
      tool: tool || null,
      status: job.status,
      exitCode: code,
      error: job.error,
      verifyFailure: job.verifyFailure
    });
  };

  proc.once('exit', (code) => finalizeJob(code));
  proc.once('close', (code) => finalizeJob(code));
  proc.once('error', (err) => finalizeJob(null, err));
  completionWatchdog = setInterval(() => {
    if (proc.exitCode !== null) finalizeJob(proc.exitCode);
  }, 1000);
  (completionWatchdog as any).unref?.();

  return job;
}

// ============================================
// TOOL AUTO-DETECTION
// ============================================

interface DetectedTool {
  name: string;
  path: string;
  detected: boolean;
  pythonPath?: string;
  executable?: string;
  args?: string[];
  mainScript?: string;
  uiPath?: string;
}

function getAppSettings(): Record<string, unknown> {
  return settingsManager.getAppSettings();
}

function getAppSettingString(key: string, fallback = ''): string {
  const value = getAppSettings()[key];
  if (typeof value !== 'string') return fallback;
  return value.trim();
}

function isBackendDiagnosticLoggingEnabled(): boolean {
  if (process.env.UMBRA_DIAGNOSTICS === '1' || process.env.UMBRA_DIAGNOSTICS === 'true') return true;
  return getAppSettings()['advanced.diagnosticLogging'] === true;
}

function resolveConfiguredPath(input: string): string {
  if (!input) return '';
  if (input.startsWith('~')) {
    const home = process.env.HOME || process.env.USERPROFILE || '';
    return home ? join(home, input.slice(1)) : input;
  }
  if (isAbsolute(input)) return input;
  return resolve(ROOT_DIR, input);
}

interface ComfySecurityApplyResult {
  applied: boolean;
  changed: boolean;
  path?: string;
  level?: string;
  error?: string;
}

const COMFY_SECURITY_LEVELS = new Set(['strong', 'normal', 'normal-', 'weak']);
const COMFY_ATTENTION_BACKENDS = new Set(['default', 'sage', 'flash', 'pytorch', 'split', 'quad']);

function normalizeComfySecurityLevel(raw: unknown): string | null {
  const value = String(raw ?? '').trim().toLowerCase();
  if (!value) return null;
  if (!COMFY_SECURITY_LEVELS.has(value)) return null;
  return value;
}

function normalizeComfyAttentionBackend(raw: unknown): string {
  const value = String(raw ?? '').trim().toLowerCase();
  if (!value || !COMFY_ATTENTION_BACKENDS.has(value)) return 'default';
  return value;
}

function upsertComfySecurityLevelInIni(rawConfig: string, level: string): string {
  const eol = rawConfig.includes('\r\n') ? '\r\n' : '\n';
  const lines = rawConfig.length > 0 ? rawConfig.split(/\r?\n/) : [];
  let replaced = false;
  const updatedLines = lines.map((line) => {
    if (/^\s*security_level\s*=.*$/i.test(line)) {
      replaced = true;
      return `security_level = ${level}`;
    }
    return line;
  });

  if (replaced) return updatedLines.join(eol);

  const defaultSectionIndex = updatedLines.findIndex((line) => /^\s*\[default\]\s*$/i.test(line));
  if (defaultSectionIndex >= 0) {
    updatedLines.splice(defaultSectionIndex + 1, 0, `security_level = ${level}`);
    return updatedLines.join(eol);
  }

  if (updatedLines.length > 0 && updatedLines[updatedLines.length - 1].trim() !== '') {
    updatedLines.push('');
  }
  updatedLines.push('[default]');
  updatedLines.push(`security_level = ${level}`);
  return updatedLines.join(eol);
}

function safeStat(pathValue: string) {
  try {
    return statSync(pathValue);
  } catch {
    return null;
  }
}

function isExistingDirectory(pathValue: string): boolean {
  if (!existsSync(pathValue)) return false;
  const stat = safeStat(pathValue);
  return Boolean(stat?.isDirectory());
}

function isExistingFile(pathValue: string): boolean {
  if (!existsSync(pathValue)) return false;
  const stat = safeStat(pathValue);
  return Boolean(stat?.isFile());
}

function applyComfySecurityLevelSetting(preferredComfyRoot = ''): ComfySecurityApplyResult {
  const level = normalizeComfySecurityLevel(getAppSettings()['comfyui.securityLevel']) || 'normal';
  let comfyRoot = preferredComfyRoot ? resolve(preferredComfyRoot) : '';

  if (!comfyRoot) {
    const configuredPath = resolveConfiguredPath(getAppSettingString('comfyui.path'));
    if (configuredPath && isExistingDirectory(configuredPath)) {
      comfyRoot = configuredPath;
    }
  }

  if (!comfyRoot) {
    const detectedPath = findToolDir(['comfyui', 'comfy']);
    if (detectedPath) comfyRoot = detectedPath;
  }

  if (!comfyRoot || !isExistingDirectory(comfyRoot)) {
    return { applied: false, changed: false, level, error: 'ComfyUI path is not available yet.' };
  }

  const modernManagerConfigPath = join(comfyRoot, 'user', '__manager', 'config.ini');
  const legacyManagerConfigPath = join(comfyRoot, 'user', 'default', 'ComfyUI-Manager', 'config.ini');
  const targetConfigPath = existsSync(modernManagerConfigPath)
    ? modernManagerConfigPath
    : existsSync(legacyManagerConfigPath)
      ? legacyManagerConfigPath
      : modernManagerConfigPath;

  try {
    mkdirSync(dirname(targetConfigPath), { recursive: true });
    const current = existsSync(targetConfigPath) ? readFileSync(targetConfigPath, 'utf-8') : '';
    const updated = upsertComfySecurityLevelInIni(current, level);
    const changed = updated !== current;
    if (changed) {
      writeFileSync(targetConfigPath, `${updated.endsWith('\n') ? updated : `${updated}\n`}`, 'utf-8');
      console.log(`[ComfyUI] Applied security_level=${level} to ${targetConfigPath}`);
    }
    return { applied: true, changed, path: targetConfigPath, level };
  } catch (error: any) {
    const message = error?.message || 'Failed to write ComfyUI config.ini';
    console.warn(`[ComfyUI] Failed to apply security_level: ${message}`);
    return { applied: false, changed: false, path: targetConfigPath, level, error: message };
  }
}

function parseHostPortFromUrl(urlValue: string, fallbackHost: string, fallbackPort: number): { host: string; port: number } {
  const trimmed = String(urlValue || '').trim();
  if (!trimmed) return { host: fallbackHost, port: fallbackPort };

  try {
    const withProtocol = trimmed.includes('://') ? trimmed : `http://${trimmed}`;
    const parsed = new URL(withProtocol);
    const host = parsed.hostname || fallbackHost;
    const parsedPort = Number(parsed.port);
    const port = Number.isFinite(parsedPort) && parsedPort > 0 ? parsedPort : fallbackPort;
    return { host, port };
  } catch {
    return { host: fallbackHost, port: fallbackPort };
  }
}

function findToolDir(patterns: string[]): string | null {
  if (!existsSync(TOOLS_DIR)) return null;

  try {
    const entries = readdirSync(TOOLS_DIR, { withFileTypes: true })
      .filter((entry) => entry.isDirectory())
      .map((entry) => entry.name)
      .filter((name) => !name.startsWith('.'));
    for (const pattern of patterns) {
      const normalized = pattern.toLowerCase();
      const exactMatch = entries.find((entry: string) => entry.toLowerCase() === normalized);
      if (exactMatch) return join(TOOLS_DIR, exactMatch);

      const startsWithMatch = entries.find((entry: string) => entry.toLowerCase().startsWith(normalized));
      if (startsWithMatch) return join(TOOLS_DIR, startsWithMatch);

      const containsMatch = entries.find((entry: string) => entry.toLowerCase().includes(normalized));
      if (containsMatch) return join(TOOLS_DIR, containsMatch);
    }
  } catch { }
  return null;
}

function findPythonInVenv(toolPath: string): string | null {
  const candidates = IS_WINDOWS
    ? ['venv\\Scripts\\python.exe', 'env\\Scripts\\python.exe', '.venv\\Scripts\\python.exe']
    : ['venv/bin/python', 'env/bin/python', '.venv/bin/python'];

  for (const candidate of candidates) {
    const fullPath = join(toolPath, candidate);
    if (existsSync(fullPath)) return fullPath;
  }
  return null;
}

function hasShellCommand(command: string): boolean {
  try {
    const checker = IS_WINDOWS ? 'where' : 'which';
    const result = spawnSync(checker, [command], { encoding: 'utf-8', shell: true });
    return result.status === 0;
  } catch {
    return false;
  }
}

function getAIToolkitNodeCapability() {
  const now = Date.now();
  if (aitoolkitNodeCapabilityCache && now - aitoolkitNodeCapabilityCache.checkedAt < 60_000) {
    return aitoolkitNodeCapabilityCache;
  }

  let version = '';
  let major = 0;
  if (hasShellCommand('node') && hasShellCommand('npm')) {
    try {
      const result = spawnSync('node', ['--version'], { encoding: 'utf-8', shell: true, windowsHide: true });
      version = String(result.stdout || result.stderr || '').trim();
      major = Number(version.match(/v?(\d+)/i)?.[1] || 0);
    } catch {
      version = '';
      major = 0;
    }
  }

  aitoolkitNodeCapabilityCache = {
    available: major >= 20,
    version,
    major,
    checkedAt: now,
  };
  return aitoolkitNodeCapabilityCache;
}

interface PythonCommandCandidate {
  command: string;
  prefixArgs: string[];
}

interface WaifuTaggerRunOptions {
  imagePath: string;
  modelRepo: string;
  generalThreshold: number;
  characterThreshold: number;
  ratingThreshold: number;
  generalMcutEnabled: boolean;
  characterMcutEnabled: boolean;
  maxTags: number;
}

interface NaturalCaptionRunOptions {
  imagePaths: string[];
  modelRepo: string;
  device: 'auto' | 'cpu' | 'cuda';
  maxNewTokens: number;
}

function parseJsonFromProcessOutput(raw: string): any {
  const trimmed = String(raw || '').trim();
  if (!trimmed) throw new Error('No JSON output');
  try {
    return JSON.parse(trimmed);
  } catch {
    const lines = trimmed.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    for (let i = lines.length - 1; i >= 0; i -= 1) {
      try {
        return JSON.parse(lines[i]);
      } catch { }
    }
  }
  throw new Error('Invalid JSON output');
}

function detectWaifuTaggerImageFormat(buffer: Buffer): string | null {
  if (!buffer || buffer.length < 12) return null;
  if (buffer[0] === 0xFF && buffer[1] === 0xD8 && buffer[2] === 0xFF) return 'jpeg';
  if (
    buffer[0] === 0x89
    && buffer[1] === 0x50
    && buffer[2] === 0x4E
    && buffer[3] === 0x47
    && buffer[4] === 0x0D
    && buffer[5] === 0x0A
    && buffer[6] === 0x1A
    && buffer[7] === 0x0A
  ) return 'png';
  const header4 = buffer.subarray(0, 4).toString('ascii');
  const header6 = buffer.subarray(0, 6).toString('ascii');
  const webp = header4 === 'RIFF' && buffer.subarray(8, 12).toString('ascii') === 'WEBP';
  if (webp) return 'webp';
  if (header6 === 'GIF87a' || header6 === 'GIF89a') return 'gif';
  if (buffer[0] === 0x42 && buffer[1] === 0x4D) return 'bmp';
  return null;
}

function getPythonCommandCandidates(): PythonCommandCandidate[] {
  const candidates: PythonCommandCandidate[] = [];
  const pushCandidate = (command: string, prefixArgs: string[] = []) => {
    const cleaned = String(command || '').trim();
    if (!cleaned) return;
    const key = `${cleaned}::${prefixArgs.join(' ')}`;
    if (candidates.some((entry) => `${entry.command}::${entry.prefixArgs.join(' ')}` === key)) return;
    candidates.push({ command: cleaned, prefixArgs });
  };
  const pushBundledRuntimePython = () => {
    const runtimeCandidates = IS_WINDOWS
      ? [
        join(ROOT_DIR, 'Runtime', 'Python311', 'python.exe'),
        join(ROOT_DIR, 'Runtime', 'Python311', 'Scripts', 'python.exe'),
        join(ROOT_DIR, 'resources', 'app', 'Runtime', 'Python311', 'python.exe'),
        join(ROOT_DIR, 'resources', 'app', 'Runtime', 'Python311', 'Scripts', 'python.exe'),
        join(ROOT_DIR, '..', 'Runtime', 'Python311', 'python.exe'),
        join(ROOT_DIR, '..', 'Runtime', 'Python311', 'Scripts', 'python.exe'),
        join(ROOT_DIR, '..', '..', 'Runtime', 'Python311', 'python.exe'),
        join(ROOT_DIR, '..', '..', 'Runtime', 'Python311', 'Scripts', 'python.exe'),
      ]
      : [
        join(ROOT_DIR, 'Runtime', 'Python311', 'bin', 'python3.11'),
        join(ROOT_DIR, 'Runtime', 'Python311', 'bin', 'python3'),
        join(ROOT_DIR, 'Runtime', 'Python311', 'bin', 'python'),
        join(ROOT_DIR, 'resources', 'app', 'Runtime', 'Python311', 'bin', 'python3.11'),
        join(ROOT_DIR, '..', 'Runtime', 'Python311', 'bin', 'python3.11'),
        join(ROOT_DIR, '..', '..', 'Runtime', 'Python311', 'bin', 'python3.11'),
      ];

    for (const runtimePython of runtimeCandidates) {
      if (existsSync(runtimePython)) pushCandidate(runtimePython);
    }
  };

  const configured = String(process.env.UMBRA_PYTHON || '').trim();
  if (configured) {
    if (configured.includes('/') || configured.includes('\\')) {
      if (existsSync(configured)) pushCandidate(configured);
    } else if (hasShellCommand(configured)) {
      pushCandidate(configured);
    }
  }

  // Prefer Umbra's helper venv first so Waifu dependencies are deterministic and isolated.
  const helperPython = findPythonInVenv(join(ROOT_DIR, 'Runtime', 'PythonHelpers'));
  if (helperPython) pushCandidate(helperPython);

  pushBundledRuntimePython();

  const comfyDir = findToolDir(['comfyui']);
  if (comfyDir) {
    const venvPython = findPythonInVenv(comfyDir);
    if (venvPython) pushCandidate(venvPython);
  }

  if (IS_WINDOWS) {
    if (hasShellCommand('python')) pushCandidate('python');
    if (hasShellCommand('py')) pushCandidate('py', ['-3']);
    if (hasShellCommand('python3')) pushCandidate('python3');
  } else {
    if (hasShellCommand('python3')) pushCandidate('python3');
    if (hasShellCommand('python')) pushCandidate('python');
  }

  if (candidates.length === 0) {
    pushCandidate(IS_WINDOWS ? 'python' : 'python3');
  }

  return candidates;
}

async function runCommandCapture(command: string, args: string[], cwd: string): Promise<{
  code: number | null;
  stdout: string;
  stderr: string;
  error?: string;
}> {
  return new Promise((resolve) => {
    let stdout = '';
    let stderr = '';
    let settled = false;

    try {
      const proc = spawn(command, args, {
        cwd,
        env: { ...process.env },
        stdio: ['ignore', 'pipe', 'pipe'],
      });

      proc.stdout?.on('data', (chunk) => {
        stdout += String(chunk ?? '');
      });
      proc.stderr?.on('data', (chunk) => {
        stderr += String(chunk ?? '');
      });

      proc.on('error', (err: any) => {
        if (settled) return;
        settled = true;
        resolve({
          code: null,
          stdout,
          stderr,
          error: err?.message || 'Spawn failed',
        });
      });

      proc.on('close', (code) => {
        if (settled) return;
        settled = true;
        resolve({ code, stdout, stderr });
      });
    } catch (error: any) {
      resolve({
        code: null,
        stdout,
        stderr,
        error: error?.message || 'Spawn failed',
      });
    }
  });
}

async function runWaifuTagger(options: WaifuTaggerRunOptions): Promise<any> {
  const startedAt = Date.now();
  console.log(`[WaifuTagger] Started image="${basename(options.imagePath)}" model="${options.modelRepo}"`);
  const resolveBundledPath = (...segments: string[]): string => {
    const relativePath = join(...segments);
    const candidates = [
      join(ROOT_DIR, relativePath),
      join(ROOT_DIR, 'resources', 'app', relativePath),
      join(SOURCE_DIR, relativePath),
    ];
    for (const candidate of candidates) {
      if (existsSync(candidate)) return candidate;
    }
    return candidates[0];
  };

  const scriptPath = resolveBundledPath('backend', 'python', 'waifu_tagger.py');
  if (!existsSync(scriptPath)) {
    throw new Error(`Tagger script not found: ${scriptPath}`);
  }

  const configuredLocalRoot = String(process.env.UMBRA_WAIFU_MODEL_ROOT || '').trim();
  const localModelRoot = configuredLocalRoot || resolveBundledPath('User', 'Models', 'WaifuTagger');

  const scriptArgs = [
    scriptPath,
    '--image', options.imagePath,
    '--model', options.modelRepo,
    '--general-threshold', String(options.generalThreshold),
    '--character-threshold', String(options.characterThreshold),
    '--rating-threshold', String(options.ratingThreshold),
    '--max-tags', String(options.maxTags),
    '--local-model-root', localModelRoot,
  ];
  if (options.generalMcutEnabled) scriptArgs.push('--general-mcut-enabled');
  if (options.characterMcutEnabled) scriptArgs.push('--character-mcut-enabled');

  const candidates = getPythonCommandCandidates();
  const failures: string[] = [];

  for (const candidate of candidates) {
    const args = [...candidate.prefixArgs, ...scriptArgs];
    const run = await runCommandCapture(candidate.command, args, ROOT_DIR);
    const commandLabel = [candidate.command, ...candidate.prefixArgs].join(' ');

    if (run.error) {
      failures.push(`${commandLabel}: ${run.error}`);
      continue;
    }

    const outputText = `${run.stdout || ''}\n${run.stderr || ''}`.trim();
    if (run.code !== 0) {
      failures.push(`${commandLabel}: ${outputText || `exit ${run.code}`}`);
      continue;
    }

    try {
      const parsed = parseJsonFromProcessOutput(run.stdout || outputText);
      const tagCount = Array.isArray(parsed?.tags)
        ? parsed.tags.length
        : Array.isArray(parsed?.generalTags)
          ? parsed.generalTags.length
          : Number(parsed?.tagCount || 0);
      console.log(`[WaifuTagger] Completed image="${basename(options.imagePath)}" tags=${Number.isFinite(tagCount) ? tagCount : 0} ms=${Date.now() - startedAt}`);
      return parsed;
    } catch (error: any) {
      failures.push(`${commandLabel}: ${error?.message || 'Invalid JSON response'}`);
    }
  }

  console.error(`[WaifuTagger] Failed image="${basename(options.imagePath)}" ms=${Date.now() - startedAt}`);
  throw new Error(`Waifu tagger failed. ${failures.slice(-3).join(' | ')}`);
}

async function runNaturalCaptioner(options: NaturalCaptionRunOptions): Promise<any> {
  const startedAt = Date.now();
  const resolveBundledPath = (...segments: string[]): string => {
    const relativePath = join(...segments);
    const candidates = [
      join(ROOT_DIR, relativePath),
      join(ROOT_DIR, 'resources', 'app', relativePath),
      join(SOURCE_DIR, relativePath),
    ];
    return candidates.find((candidate) => existsSync(candidate)) || candidates[0];
  };
  const scriptPath = resolveBundledPath('backend', 'python', 'natural_captioner.py');
  if (!existsSync(scriptPath)) throw new Error(`Natural caption script not found: ${scriptPath}`);

  const modelFolder = String(options.modelRepo || '').split('/').pop()?.replace(/[^a-zA-Z0-9._-]/g, '') || '';
  const configuredModelRoot = String(process.env.UMBRA_CAPTION_MODEL_ROOT || '').trim();
  const modelRoot = configuredModelRoot || resolveBundledPath('User', 'Models', 'DataForgeCaption');
  const modelPath = join(modelRoot, modelFolder);
  if (!modelFolder || !existsSync(join(modelPath, 'config.json'))) {
    throw new Error(`Natural caption model is not installed at ${modelPath}. Run "bun run models:caption:download" from the Umbra source folder.`);
  }

  const tempDir = resolveBundledPath('User', 'Temp');
  await fs.mkdir(tempDir, { recursive: true });
  const manifestPath = join(tempDir, `dataforge-caption-${Date.now()}-${randomBytes(5).toString('hex')}.json`);
  await fs.writeFile(manifestPath, JSON.stringify({
    images: options.imagePaths.map((imagePath) => ({
      filename: basename(imagePath),
      path: imagePath,
    })),
  }), 'utf8');

  const scriptArgs = [
    scriptPath,
    '--manifest', manifestPath,
    '--model-path', modelPath,
    '--device', options.device,
    '--max-new-tokens', String(options.maxNewTokens),
  ];
  const failures: string[] = [];
  try {
    for (const candidate of getPythonCommandCandidates()) {
      const args = [...candidate.prefixArgs, ...scriptArgs];
      const run = await runCommandCapture(candidate.command, args, ROOT_DIR);
      const commandLabel = [candidate.command, ...candidate.prefixArgs].join(' ');
      if (run.error) {
        failures.push(`${commandLabel}: ${run.error}`);
        continue;
      }
      const outputText = `${run.stdout || ''}\n${run.stderr || ''}`.trim();
      if (run.code !== 0) {
        failures.push(`${commandLabel}: ${outputText || `exit ${run.code}`}`);
        continue;
      }
      try {
        const parsed = parseJsonFromProcessOutput(run.stdout || outputText);
        if (!Array.isArray(parsed?.results)) throw new Error('Caption process returned no results');
        console.log(`[NaturalCaption] Completed images=${options.imagePaths.length} model="${options.modelRepo}" device=${parsed.device || options.device} ms=${Date.now() - startedAt}`);
        return parsed;
      } catch (error: any) {
        failures.push(`${commandLabel}: ${error?.message || 'Invalid JSON response'}`);
      }
    }
  } finally {
    await fs.rm(manifestPath, { force: true }).catch(() => undefined);
  }

  console.error(`[NaturalCaption] Failed images=${options.imagePaths.length} ms=${Date.now() - startedAt}`);
  throw new Error(`Natural captioner failed. ${failures.slice(-3).join(' | ')}`);
}

function detectComfyUI(): DetectedTool {
  const configuredPath = resolveConfiguredPath(getAppSettingString('comfyui.path'));
  const configuredCandidate = configuredPath
    ? (isExistingFile(configuredPath) ? dirname(configuredPath) : configuredPath)
    : '';
  const toolPath = configuredCandidate || findToolDir(['comfyui', 'comfy']);
  if (!toolPath) return { name: 'comfyui', path: '', detected: false };

  // Check for main.py
  let mainScript = join(toolPath, 'main.py');
  if (!existsSync(mainScript)) mainScript = join(toolPath, 'source', 'main.py');
  if (!existsSync(mainScript)) return { name: 'comfyui', path: toolPath, detected: false };

  const pythonPath = findPythonInVenv(toolPath);
  if (!pythonPath) return { name: 'comfyui', path: toolPath, detected: false };

  return { name: 'comfyui', path: toolPath, detected: true, pythonPath, mainScript };
}

function detectAIToolkit(): DetectedTool {
  const configuredPath = resolveConfiguredPath(getAppSettingString('aitoolkit.path'));
  const toolPath = configuredPath || findToolDir(['ai-toolkit', 'aitoolkit', 'AI-Toolkit']) || '';
  if (!toolPath || !isExistingDirectory(toolPath)) {
    return { name: 'aitoolkit', path: toolPath, detected: false };
  }

  const uiPath = join(toolPath, 'ui');
  const packageJsonPath = join(uiPath, 'package.json');
  const pythonPath = findPythonInVenv(toolPath);
  if (!existsSync(packageJsonPath) || !pythonPath) {
    return { name: 'aitoolkit', path: toolPath, detected: false, pythonPath: pythonPath || undefined, uiPath };
  }

  return { name: 'aitoolkit', path: toolPath, detected: true, pythonPath, uiPath };
}

function detectAllTools() {
  return {
    comfyui: detectComfyUI(),
    aitoolkit: detectAIToolkit(),
  };
}

function resolveComfyLaunchCapability(comfy: DetectedTool): ComfyLaunchCapability | null {
  if (!comfy.detected || !comfy.pythonPath || !comfy.mainScript || !comfy.path) return null;

  const cacheKey = `${comfy.pythonPath}|${comfy.mainScript}`;
  if (comfyLaunchCapabilityCache?.key === cacheKey) {
    return comfyLaunchCapabilityCache;
  }

  let supportsCorsHeader = true;
  let supportsDisableAutoLaunch = true;

  try {
    const helpResult = spawnSync(comfy.pythonPath, [comfy.mainScript, '--help'], {
      cwd: comfy.path,
      encoding: 'utf-8',
      timeout: 2000
    });
    const helpText = `${helpResult.stdout || ''}\n${helpResult.stderr || ''}`.toLowerCase();
    if (helpText.trim()) {
      supportsCorsHeader = helpText.includes('--enable-cors-header');
      supportsDisableAutoLaunch = helpText.includes('--disable-auto-launch');
    }
  } catch {
    // Keep defaults (true) so launch behavior stays permissive if capability probing fails.
  }

  const resolved: ComfyLaunchCapability = {
    key: cacheKey,
    supportsCorsHeader,
    supportsDisableAutoLaunch,
    checkedAt: Date.now()
  };
  comfyLaunchCapabilityCache = resolved;

  if (!supportsCorsHeader) {
    console.warn('[ComfyUI] Selected build does not expose --enable-cors-header; launching without explicit CORS flag.');
  }
  if (!supportsDisableAutoLaunch) {
    console.warn('[ComfyUI] Selected build does not expose --disable-auto-launch; launching without this flag.');
  }

  return resolved;
}

function isComfySageAttentionAvailable(comfy: DetectedTool): boolean {
  if (!comfy.detected || !comfy.pythonPath || !comfy.path) return false;
  const cacheKey = `${comfy.pythonPath}|${comfy.path}`;
  const now = Date.now();
  if (comfySageAvailabilityCache?.key === cacheKey && (now - comfySageAvailabilityCache.checkedAt) < 60_000) {
    return comfySageAvailabilityCache.available;
  }

  let available = false;
  try {
    const result = spawnSync(
      comfy.pythonPath,
      ['-c', "import importlib.util,sys;sys.stdout.write('1' if importlib.util.find_spec('sageattention') else '0')"],
      {
        cwd: comfy.path,
        encoding: 'utf-8',
        timeout: 1500,
      },
    );
    available = result.status === 0 && String(result.stdout || '').trim() === '1';
  } catch {
    available = false;
  }

  comfySageAvailabilityCache = { key: cacheKey, available, checkedAt: now };
  return available;
}

function findVideoHelperSuiteDir(customNodesRoot: string): string | null {
  try {
    const entries = readdirSync(customNodesRoot, { withFileTypes: true });
    const match = entries.find((entry) => entry.isDirectory() && entry.name.toLowerCase() === 'comfyui-videohelpersuite');
    return match ? join(customNodesRoot, match.name) : null;
  } catch {
    return null;
  }
}

function applyComfyFrontendCompatibilityPatches(comfyRoot: string): void {
  const normalizedRoot = String(comfyRoot || '').trim();
  if (!normalizedRoot) return;

  const customNodesRoot = join(normalizedRoot, 'custom_nodes');
  const vhsDir = findVideoHelperSuiteDir(customNodesRoot);
  if (!vhsDir) return;

  const vhsCorePath = join(vhsDir, 'web', 'js', 'VHS.core.js');
  if (!existsSync(vhsCorePath)) return;

  try {
    const source = readFileSync(vhsCorePath, 'utf-8');
    const replacements: Array<[string, string]> = [
      [
        'helpDOM.addHelp(this, nodeType, description)',
        'if (typeof helpDOM?.addHelp === "function") { helpDOM.addHelp(this, nodeType, description) }',
      ],
      [
        "url = url.replace('%2503d', '001')",
        "url = String(url ?? '').replace('%2503d', '001')",
      ],
      [
        "options = options.map((o) => o.replace('.','\\0'))",
        "options = options.map((o) => String(o ?? '').replace('.','\\0'))",
      ],
      [
        "options = options.map((o) => o.replace('\\0','.'))",
        "options = options.map((o) => String(o ?? '').replace('\\0','.'))",
      ],
    ];

    let patched = source;
    let applied = 0;
    for (const [needle, replacement] of replacements) {
      if (!patched.includes(needle)) continue;
      patched = patched.replace(needle, replacement);
      applied += 1;
    }

    if (applied === 0 || patched === source) return;

    writeFileSync(vhsCorePath, patched, 'utf-8');
    console.log(`[ComfyUI] Applied ${applied} VHS compatibility patch(es) for embedded workflow stability.`);
  } catch (error: any) {
    console.warn(`[ComfyUI] Failed to apply VHS compatibility patch: ${error?.message || error}`);
  }
}



// ============================================
// UPDATE CHECKING SYSTEM
// ============================================

interface UpdateInfo {
  tool: string;
  currentVersion: string;
  latestVersion: string;
  hasUpdate: boolean;
  updateType: 'pytorch' | 'tool';
  details?: string;
}

interface UpdateCache {
  lastChecked: number;
  pytorch: { cudaVersion: string; latestVersion: string; versions: string[] };
  tools: UpdateInfo[];
}

let updateCache: UpdateCache | null = null;
const UPDATE_CACHE_TTL = 3600000; // 1 hour

// Detect GPU architecture for CUDA version selection
function detectGPUArchitecture(): 'blackwell' | 'modern' | 'legacy' {
  // Check nvidia-smi for GPU name
  try {
    const { spawnSync } = require('child_process');
    const result = spawnSync('nvidia-smi', ['--query-gpu=name', '--format=csv,noheader'], { encoding: 'utf-8' });
    if (result.status === 0 && result.stdout) {
      const gpuName = result.stdout.trim();
      // Blackwell: RTX 50xx series (sm_120)
      if (/RTX\s*50[0-9]{2}/i.test(gpuName) || /Blackwell/i.test(gpuName)) {
        return 'blackwell';
      }
    }
  } catch { }
  return 'modern';
}

async function fetchLatestPyTorchVersion(): Promise<{ cudaVersion: string; latestVersion: string; versions: string[] }> {
  const arch = detectGPUArchitecture();
  const cudaVersion = arch === 'blackwell' ? 'cu130' : 'cu126';

  try {
    const indexUrl = `https://download.pytorch.org/whl/${cudaVersion}/torch/`;
    const response = await fetch(indexUrl, {
      headers: { 'User-Agent': 'UmbraLab/1.0' },
      signal: AbortSignal.timeout(10000)
    });

    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const html = await response.text();

    // Parse version numbers from wheel filenames
    const versionPattern = /torch-(\d+\.\d+\.\d+)\+/g;
    const versions = new Set<string>();
    let match;
    while ((match = versionPattern.exec(html)) !== null) {
      versions.add(match[1]);
    }

    // Sort versions descending
    const sortedVersions = Array.from(versions).sort((a, b) => {
      const [aMaj, aMin, aPatch] = a.split('.').map(Number);
      const [bMaj, bMin, bPatch] = b.split('.').map(Number);
      if (aMaj !== bMaj) return bMaj - aMaj;
      if (aMin !== bMin) return bMin - aMin;
      return bPatch - aPatch;
    });

    return { cudaVersion, latestVersion: sortedVersions[0] || '2.9.1', versions: sortedVersions };
  } catch (e) {
    console.log('[UpdateCheck] Failed to fetch PyTorch versions:', e);
    return { cudaVersion, latestVersion: '2.9.1', versions: ['2.9.1'] };
  }
}

function getPyTorchVersionInVenv(toolPath: string): string | null {
  const pipPath = IS_WINDOWS
    ? join(toolPath, 'venv', 'Scripts', 'pip.exe')
    : join(toolPath, 'venv', 'bin', 'pip');

  if (!existsSync(pipPath)) return null;

  try {
    const { spawnSync } = require('child_process');
    const result = spawnSync(pipPath, ['show', 'torch'], { encoding: 'utf-8', timeout: 10000 });
    const versionMatch = result.stdout?.match(/Version:\s*(\d+\.\d+\.\d+)/);
    return versionMatch?.[1] || null;
  } catch {
    return null;
  }
}

async function getGitLatestCommit(repoUrl: string, branch?: string): Promise<string | null> {
  try {
    // Use GitHub API for public repos
    const match = repoUrl.match(/github\.com\/([^\/]+)\/([^\/\.]+)/);
    if (!match) return null;

    const [, owner, repo] = match;
    const target = new URL(`https://api.github.com/repos/${owner}/${repo}/commits`);
    target.searchParams.set('per_page', '1');
    const normalizedBranch = String(branch || '').trim();
    if (normalizedBranch) target.searchParams.set('sha', normalizedBranch);
    const response = await fetch(target, {
      headers: { 'User-Agent': 'UmbraLab/1.0' },
      signal: AbortSignal.timeout(10000)
    });

    if (!response.ok) return null;
    const commits = await response.json() as any[];
    return commits[0]?.sha?.substring(0, 7) || null;
  } catch {
    return null;
  }
}

function getLocalGitCommit(toolPath: string): string | null {
  try {
    const { spawnSync } = require('child_process');
    const result = spawnSync('git', ['rev-parse', '--short', 'HEAD'], {
      cwd: toolPath,
      encoding: 'utf-8',
      timeout: 5000
    });
    return result.status === 0 ? result.stdout?.trim() : null;
  } catch {
    return null;
  }
}

type ToolVersionTarget = 'comfyui';

interface ToolVersionEntry {
  ref: string;
  commit: string;
  date: string | null;
  subject: string | null;
}

interface ToolVersionCatalog {
  path: string;
  currentRef: string;
  currentCommit: string;
  versions: ToolVersionEntry[];
  available: boolean;
  unavailableReason?: string | null;
}

function getGitHubRepoParts(repoUrl: string): { owner: string; repo: string } | null {
  const match = repoUrl.match(/github\.com[:/]([^/]+)\/([^/.]+)(?:\.git)?$/i);
  if (!match) return null;
  return { owner: match[1], repo: match[2] };
}

async function fetchGitHubCommitVersions(repoUrl: string, branch: string, limit: number): Promise<ToolVersionEntry[]> {
  const repoParts = getGitHubRepoParts(repoUrl);
  if (!repoParts) return [];
  const safeLimit = Math.max(1, Math.min(limit, 100));
  const apiUrl = `https://api.github.com/repos/${encodeURIComponent(repoParts.owner)}/${encodeURIComponent(repoParts.repo)}/commits?sha=${encodeURIComponent(branch)}&per_page=${safeLimit}`;
  try {
    const response = await fetch(apiUrl, {
      headers: {
        'Accept': 'application/vnd.github+json',
        'User-Agent': 'Umbra-Studio-Version-Catalog',
      },
      signal: AbortSignal.timeout(12000),
    });
    if (!response.ok) return [];
    const payload = await response.json();
    if (!Array.isArray(payload)) return [];
    return payload
      .map((entry: any): ToolVersionEntry | null => {
        const sha = String(entry?.sha || '').trim();
        if (!sha) return null;
        const shortSha = sha.slice(0, 7);
        const commit = entry?.commit || {};
        return {
          ref: shortSha,
          commit: shortSha,
          date: String(commit?.committer?.date || commit?.author?.date || '').trim() || null,
          subject: String(commit?.message || '').split('\n')[0]?.trim() || 'Remote commit',
        };
      })
      .filter(Boolean) as ToolVersionEntry[];
  } catch {
    return [];
  }
}

function isPathWithin(parent: string, target: string): boolean {
  const rel = relative(resolve(parent), resolve(target));
  return rel === '' || (!rel.startsWith('..') && !isAbsolute(rel));
}

function getToolVersionConfig(tool: ToolVersionTarget): {
  tool: DetectedTool;
  portablePath: string;
  remoteRepo: string;
  remoteBranch?: string;
  displayName: string;
} {
  if (tool === 'comfyui') {
    return {
      tool: detectComfyUI(),
      portablePath: resolve(join(ROOT_DIR, 'Tools', 'ComfyUI')),
      remoteRepo: 'https://github.com/comfyanonymous/ComfyUI.git',
      remoteBranch: 'master',
      displayName: 'ComfyUI',
    };
  }
  throw new Error(`Unsupported tool version target: ${tool}`);
}

function getPortablePathForToolVersionTarget(tool: ToolVersionTarget): string {
  return getToolVersionConfig(tool).portablePath;
}

async function getToolVersionCatalog(tool: ToolVersionTarget, limit = 300): Promise<ToolVersionCatalog> {
  const config = getToolVersionConfig(tool);
  const safeLimit = Math.max(1, Math.min(Number(limit) || 300, 1000));
  const toolPath = config.tool.path ? resolve(config.tool.path) : config.portablePath;
  const hasLocalGitCheckout = existsSync(join(toolPath, '.git'));

  if (hasLocalGitCheckout) {
    const versions: ToolVersionEntry[] = [];
    const seenRefs = new Set<string>();

    // Best effort: refresh refs so the version list includes newest tags.
    if (config.remoteBranch) {
      await runGitCommand(['fetch', '--tags', '--force', '--prune', 'origin', config.remoteBranch], toolPath);
    } else {
      await runGitCommand(['fetch', '--tags', '--force', '--prune', 'origin'], toolPath);
    }

    const currentCommitRes = await runGitCommand(['rev-parse', '--short', 'HEAD'], toolPath);
    const currentTagRes = await runGitCommand(['describe', '--tags', '--exact-match'], toolPath);
    const currentCommit = currentCommitRes.ok ? currentCommitRes.stdout : '';
    const currentRef = currentTagRes.ok && currentTagRes.stdout
      ? currentTagRes.stdout
      : (currentCommit || 'unknown');

    const tagRes = await runGitCommand(
      ['for-each-ref', '--sort=-creatordate', '--format=%(refname:strip=2)|%(objectname:short)|%(creatordate:iso8601)|%(subject)', 'refs/tags'],
      toolPath
    );

    if (tagRes.ok && tagRes.stdout) {
      const lines = tagRes.stdout.split('\n').map((line) => line.trim()).filter(Boolean);
      for (const line of lines) {
        const [ref, commit, date, ...subjectParts] = line.split('|');
        const normalizedRef = String(ref || '').trim();
        if (!normalizedRef || seenRefs.has(normalizedRef)) continue;
        seenRefs.add(normalizedRef);
        versions.push({
          ref: normalizedRef,
          commit: String(commit || '').trim(),
          date: String(date || '').trim() || null,
          subject: subjectParts.join('|').trim() || null,
        });
        if (versions.length >= safeLimit) break;
      }
    }

    if (versions.length === 0) {
      const commitRes = await runGitCommand(
        ['log', `--max-count=${safeLimit}`, '--date=iso8601', '--pretty=format:%h|%ad|%s'],
        toolPath
      );
      if (commitRes.ok && commitRes.stdout) {
        const lines = commitRes.stdout.split('\n').map((line) => line.trim()).filter(Boolean);
        for (const line of lines) {
          const [commit, date, ...subjectParts] = line.split('|');
          const hash = String(commit || '').trim();
          if (!hash || seenRefs.has(hash)) continue;
          seenRefs.add(hash);
          versions.push({
            ref: hash,
            commit: hash,
            date: String(date || '').trim() || null,
            subject: subjectParts.join('|').trim() || null,
          });
        }
      }
    }

    const remoteCommitVersions = await fetchGitHubCommitVersions(
      config.remoteRepo,
      config.remoteBranch || 'master',
      Math.min(safeLimit, 100)
    );
    if (remoteCommitVersions.length > 0) {
      const remoteVersionsToPrepend: ToolVersionEntry[] = [];
      for (const version of remoteCommitVersions) {
        const normalizedRef = String(version.ref || '').trim();
        const normalizedCommit = String(version.commit || '').trim();
        if (!normalizedRef || seenRefs.has(normalizedRef) || seenRefs.has(normalizedCommit)) continue;
        seenRefs.add(normalizedRef);
        if (normalizedCommit) seenRefs.add(normalizedCommit);
        remoteVersionsToPrepend.push(version);
      }
      versions.unshift(...remoteVersionsToPrepend);
      if (versions.length > safeLimit) versions.length = safeLimit;
    }

    if (currentRef && !seenRefs.has(currentRef)) {
      versions.unshift({
        ref: currentRef,
        commit: currentCommit || currentRef,
        date: null,
        subject: 'Current checkout',
      });
    }

    return {
      path: toolPath,
      currentRef,
      currentCommit,
      versions,
      available: true,
      unavailableReason: null,
    };
  }

  const remoteTagRes = await runGitCommand(['ls-remote', '--tags', '--refs', config.remoteRepo], ROOT_DIR);
  let remoteLines = remoteTagRes.ok && remoteTagRes.stdout
    ? remoteTagRes.stdout.split('\n').map((line) => line.trim()).filter(Boolean)
    : [];
  let remoteRefKind: 'tag' | 'head' = 'tag';

  if (remoteLines.length === 0) {
    const defaultBranch = config.remoteBranch || 'main';
    const remoteCommitVersions = await fetchGitHubCommitVersions(config.remoteRepo, defaultBranch, safeLimit);
    if (remoteCommitVersions.length > 0) {
      return {
        path: config.portablePath,
        currentRef: '',
        currentCommit: '',
        versions: remoteCommitVersions,
        available: true,
        unavailableReason: null,
      };
    }

    const remoteHeadRes = await runGitCommand(['ls-remote', '--heads', config.remoteRepo], ROOT_DIR);
    remoteLines = remoteHeadRes.ok && remoteHeadRes.stdout
      ? remoteHeadRes.stdout.split('\n').map((line) => line.trim()).filter(Boolean)
      : [];
    remoteRefKind = 'head';
  }

  if (remoteLines.length === 0) {
    return {
      path: toolPath,
      currentRef: '',
      currentCommit: '',
      versions: [],
      available: false,
      unavailableReason: `${config.displayName} version catalog is unavailable until a git checkout is installed.`,
    };
  }

  const versions: ToolVersionEntry[] = [];
  const seenRefs = new Set<string>();
  for (const line of remoteLines.reverse()) {
    const [commitRaw, refRaw] = line.split(/\s+/);
    const rawRef = String(refRaw || '').trim();
    const ref = remoteRefKind === 'head'
      ? `origin/${rawRef.replace(/^refs\/heads\//, '').trim()}`
      : rawRef.replace(/^refs\/tags\//, '').trim();
    const commit = String(commitRaw || '').trim();
    if (!ref || seenRefs.has(ref)) continue;
    seenRefs.add(ref);
    versions.push({
      ref,
      commit: commit.slice(0, 7),
      date: null,
      subject: remoteRefKind === 'head' ? 'Remote branch' : null,
    });
    if (versions.length >= safeLimit) break;
  }

  if (versions.length === 0) {
    return {
      path: config.portablePath,
      currentRef: '',
      currentCommit: '',
      versions: [],
      available: false,
      unavailableReason: `${config.displayName} does not currently expose any switchable versions.`,
    };
  }

  return {
    path: config.portablePath,
    currentRef: '',
    currentCommit: '',
    versions,
    available: true,
    unavailableReason: null,
  };
}

async function getComfyVersionCatalog(limit = 300): Promise<ToolVersionCatalog | null> {
  return getToolVersionCatalog('comfyui', limit);
}

type GitCommandResult = {
  ok: boolean;
  code: number;
  stdout: string;
  stderr: string;
};

async function runGitCommand(args: string[], cwd = ROOT_DIR): Promise<GitCommandResult> {
  try {
    const proc = Bun.spawn(['git', '-C', cwd, ...args], {
      stdout: 'pipe',
      stderr: 'pipe',
      env: process.env,
    });
    const [code, stdout, stderr] = await Promise.all([
      proc.exited,
      new Response(proc.stdout).text(),
      new Response(proc.stderr).text(),
    ]);
    return {
      ok: code === 0,
      code,
      stdout: stdout.trim(),
      stderr: stderr.trim(),
    };
  } catch (error: any) {
    return {
      ok: false,
      code: -1,
      stdout: '',
      stderr: error?.message || 'Failed to run git command',
    };
  }
}

async function isGitInstalled(): Promise<boolean> {
  try {
    const proc = Bun.spawn(['git', '--version'], { stdout: 'ignore', stderr: 'ignore', env: process.env });
    const code = await proc.exited;
    return code === 0;
  } catch {
    return false;
  }
}

const APP_UPDATE_PROTECTED_PATHS = Object.freeze([
  'User/',
  'Tools/',
]);

const DEFAULT_RELEASE_FEED_URL = String(process.env.UMBRA_RELEASE_FEED_URL || '').trim();

type ReleaseChannel = 'stable' | 'beta';

type ReleaseManifest = {
  version: string;
  packageUrl: string;
  channel: ReleaseChannel;
  notes?: string;
  publishedAt?: string;
  releaseNotesUrl?: string;
  sha256?: string;
  packageName?: string;
  feedUrl: string;
};

let cachedAppVersion: string | null = null;

function getCurrentAppVersion(): string {
  if (cachedAppVersion) return cachedAppVersion;
  try {
    const packageJsonPath = join(ROOT_DIR, 'package.json');
    const raw = JSON.parse(readFileSync(packageJsonPath, 'utf-8')) as Record<string, unknown>;
    const version = String(raw.version || '').trim();
    cachedAppVersion = version || '0.0.0';
    return cachedAppVersion;
  } catch {
    cachedAppVersion = '0.0.0';
    return cachedAppVersion;
  }
}

function normalizeVersionSegment(value: string): number {
  const numeric = Number.parseInt(value.replace(/[^\d].*$/, ''), 10);
  return Number.isFinite(numeric) ? numeric : 0;
}

function compareSemverVersions(left: string, right: string): number {
  const leftParts = String(left || '').replace(/^v/i, '').split('.');
  const rightParts = String(right || '').replace(/^v/i, '').split('.');
  const max = Math.max(leftParts.length, rightParts.length, 3);
  for (let index = 0; index < max; index += 1) {
    const leftValue = normalizeVersionSegment(leftParts[index] || '0');
    const rightValue = normalizeVersionSegment(rightParts[index] || '0');
    if (leftValue > rightValue) return 1;
    if (leftValue < rightValue) return -1;
  }
  return 0;
}

function getEffectiveReleaseFeedUrl(configuredFeedUrl: string, channel: ReleaseChannel): string {
  const candidate = (configuredFeedUrl || DEFAULT_RELEASE_FEED_URL || '').trim();
  if (!candidate) return '';
  return candidate.replace(/\{channel\}/gi, channel);
}

function normalizeReleaseNotes(value: unknown): string | undefined {
  if (typeof value === 'string') {
    const trimmed = value.trim();
    return trimmed || undefined;
  }
  if (Array.isArray(value)) {
    const joined = value.map((item) => String(item || '').trim()).filter(Boolean).join('\n');
    return joined || undefined;
  }
  return undefined;
}

function normalizeReleaseManifest(raw: unknown, feedUrl: string, channel: ReleaseChannel): ReleaseManifest {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
    throw new Error('Release feed did not return a valid JSON object.');
  }

  const rootRecord = raw as Record<string, unknown>;
  const nestedCandidate = (
    (rootRecord.channels && typeof rootRecord.channels === 'object' && !Array.isArray(rootRecord.channels))
      ? (rootRecord.channels as Record<string, unknown>)[channel]
      : undefined
  ) || rootRecord[channel];
  const channelRecord = (nestedCandidate && typeof nestedCandidate === 'object' && !Array.isArray(nestedCandidate))
    ? nestedCandidate as Record<string, unknown>
    : null;

  const source = channelRecord ? { ...rootRecord, ...channelRecord } : rootRecord;
  const version = String(source.version || rootRecord.version || '').trim();
  const packageUrlRaw = String(
    source.packageUrl
    || source.downloadUrl
    || source.url
    || ''
  ).trim();

  if (!version) {
    throw new Error('Release manifest is missing a version.');
  }
  if (!packageUrlRaw) {
    throw new Error('Release manifest is missing a package URL.');
  }

  const packageUrl = new URL(packageUrlRaw, feedUrl).toString();
  const packageName = String(source.packageName || basename(new URL(packageUrl).pathname) || '').trim() || undefined;
  const releaseNotesUrlRaw = String(source.releaseNotesUrl || source.notesUrl || '').trim();

  return {
    version,
    packageUrl,
    channel,
    notes: normalizeReleaseNotes(source.notes ?? source.changelog ?? source.description),
    publishedAt: String(source.publishedAt || source.releaseDate || source.date || '').trim() || undefined,
    releaseNotesUrl: releaseNotesUrlRaw ? new URL(releaseNotesUrlRaw, feedUrl).toString() : undefined,
    sha256: String(source.sha256 || source.hash || '').trim() || undefined,
    packageName,
    feedUrl,
  };
}

async function fetchReleaseManifest(channel: ReleaseChannel, configuredFeedUrl: string) {
  const feedUrl = getEffectiveReleaseFeedUrl(configuredFeedUrl, channel);
  if (!feedUrl) {
    return {
      ok: false as const,
      feedUrl: '',
      error: 'Release feed URL is not configured.',
    };
  }

  let response: Response;
  try {
    response = await fetch(feedUrl, {
      headers: {
        Accept: 'application/json',
        'Cache-Control': 'no-cache',
      },
    });
  } catch (error: any) {
    return {
      ok: false as const,
      feedUrl,
      error: error?.message || 'Failed to contact release feed.',
    };
  }

  if (!response.ok) {
    let detail = '';
    try {
      detail = (await response.text()).slice(0, 200).trim();
    } catch {
      detail = '';
    }
    return {
      ok: false as const,
      feedUrl,
      error: detail
        ? `Release feed returned ${response.status}: ${detail}`
        : `Release feed returned ${response.status}.`,
    };
  }

  try {
    const payload = await response.json();
    const manifest = normalizeReleaseManifest(payload, feedUrl, channel);
    return {
      ok: true as const,
      feedUrl,
      manifest,
    };
  } catch (error: any) {
    return {
      ok: false as const,
      feedUrl,
      error: error?.message || 'Release feed JSON is invalid.',
    };
  }
}

async function getLatestReleaseStagingInfo() {
  const stagingRoot = join(USER_DIR, 'Config', 'UpdateStaging');
  try {
    const entries = await fs.readdir(stagingRoot, { withFileTypes: true });
    const dirs = entries.filter((entry) => entry.isDirectory());
    if (dirs.length === 0) return null;
    const withTimes = await Promise.all(dirs.map(async (entry) => {
      const fullPath = join(stagingRoot, entry.name);
      const stat = await fs.stat(fullPath);
      return { name: entry.name, fullPath, mtimeMs: stat.mtimeMs };
    }));
    withTimes.sort((a, b) => b.mtimeMs - a.mtimeMs);
    const latest = withTimes[0];
    return {
      stagingPath: latest.fullPath,
      stagedAt: new Date(latest.mtimeMs).toISOString(),
    };
  } catch {
    return null;
  }
}

async function getUmbraAppReleaseStatus(options: { refresh?: boolean } = {}, protection = getAppUpdateProtectionSummary()) {
  const currentVersion = getCurrentAppVersion();
  const manifestResult = await fetchReleaseManifest(protection.releaseChannel as ReleaseChannel, String(protection.releaseFeedUrl || ''));
  const latestStaging = await getLatestReleaseStagingInfo();

  if (!manifestResult.ok) {
    return {
      ...protection,
      releaseUpdaterImplemented: true,
      gitInstalled: await isGitInstalled(),
      repoDetected: false,
      updateSourceReady: false,
      branch: null as string | null,
      remote: null as string | null,
      trackingBranch: null as string | null,
      clean: true,
      ahead: 0,
      behind: 0,
      needsUpdate: false,
      currentVersion,
      latestVersion: currentVersion,
      releaseFeedResolvedUrl: manifestResult.feedUrl,
      message: manifestResult.error,
      ...(latestStaging || {}),
    };
  }

  const { manifest } = manifestResult;
  const needsUpdate = compareSemverVersions(currentVersion, manifest.version) < 0;
  return {
    ...protection,
    releaseUpdaterImplemented: true,
    gitInstalled: await isGitInstalled(),
    repoDetected: false,
    updateSourceReady: true,
    branch: null as string | null,
    remote: null as string | null,
    trackingBranch: null as string | null,
    clean: true,
    ahead: 0,
    behind: needsUpdate ? 1 : 0,
    needsUpdate,
    currentVersion,
    latestVersion: manifest.version,
    packageUrl: manifest.packageUrl,
    packageName: manifest.packageName,
    sha256: manifest.sha256,
    publishedAt: manifest.publishedAt,
    releaseNotesUrl: manifest.releaseNotesUrl,
    releaseNotes: manifest.notes,
    releaseFeedResolvedUrl: manifest.feedUrl,
    message: needsUpdate ? 'A new portable release is ready to download and stage.' : 'Umbra Studio is up to date on this release channel.',
    ...(latestStaging || {}),
  };
}

function getAppUpdateProtectionSummary() {
  const appSettings = settingsManager.getAppSettings() as Record<string, unknown>;
  const configuredMode = appSettings['appUpdate.mode'] === 'release' ? 'release' : 'source';
  const configuredChannel = appSettings['appUpdate.releaseChannel'] === 'beta' ? 'beta' : 'stable';
  const configuredFeedUrl = typeof appSettings['appUpdate.feedUrl'] === 'string'
    ? String(appSettings['appUpdate.feedUrl'] || '').trim()
    : '';
  return {
    updateStrategy: configuredMode === 'release' ? 'release-channel' : 'git-pull-source',
    updaterMode: configuredMode,
    releaseChannel: configuredChannel,
    releaseFeedUrl: configuredFeedUrl,
    releaseUpdaterImplemented: false,
    preservesUserData: true,
    preservesInstalledTools: true,
    protectedPaths: [...APP_UPDATE_PROTECTED_PATHS],
  };
}

async function createAppUpdateSafetyBackup(status?: Record<string, unknown>) {
  const backupDir = join(USER_DIR, 'Config', 'UpdateBackups');
  mkdirSync(backupDir, { recursive: true });
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = join(backupDir, `app-update-${stamp}.json`);
  const payload = {
    createdAt: new Date().toISOString(),
    rootDir: ROOT_DIR,
    protection: getAppUpdateProtectionSummary(),
    gitStatus: status || null,
    settingsBundle: await loadUserSettingsBundleSnapshot(),
  };
  writeFileSync(backupPath, JSON.stringify(payload, null, 2), 'utf-8');
  return backupPath;
}

async function stageReleaseUpdatePackage(manifest: ReleaseManifest, status?: Record<string, unknown>) {
  const stageRoot = join(USER_DIR, 'Config', 'UpdateStaging');
  mkdirSync(stageRoot, { recursive: true });
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const safeVersion = manifest.version.replace(/[^a-z0-9._-]+/gi, '-');
  const stagingDir = join(stageRoot, `${safeVersion}-${stamp}`);
  mkdirSync(stagingDir, { recursive: true });

  const packageName = manifest.packageName || basename(new URL(manifest.packageUrl).pathname) || `umbra-${safeVersion}.zip`;
  const packagePath = join(stagingDir, packageName);
  const metadataPath = join(stagingDir, 'release-manifest.json');
  const instructionsPath = join(stagingDir, 'HOW_TO_APPLY.txt');

  const response = await fetch(manifest.packageUrl, {
    headers: {
      'Cache-Control': 'no-cache',
    },
  });
  if (!response.ok) {
    let detail = '';
    try {
      detail = (await response.text()).slice(0, 200).trim();
    } catch {
      detail = '';
    }
    throw new Error(detail
      ? `Release package download failed (${response.status}): ${detail}`
      : `Release package download failed (${response.status}).`);
  }

  await Bun.write(packagePath, response);

  let actualSha256 = '';
  try {
    const data = await fs.readFile(packagePath);
    actualSha256 = createHash('sha256').update(data).digest('hex');
    if (manifest.sha256 && actualSha256.toLowerCase() !== manifest.sha256.toLowerCase()) {
      throw new Error('Downloaded package failed SHA-256 verification.');
    }
  } catch (error) {
    await fs.rm(stagingDir, { recursive: true, force: true }).catch(() => undefined);
    throw error;
  }

  const metadata = {
    stagedAt: new Date().toISOString(),
    manifest,
    packagePath,
    packageSha256: actualSha256,
    protection: getAppUpdateProtectionSummary(),
    statusSnapshot: status || null,
  };
  writeFileSync(metadataPath, JSON.stringify(metadata, null, 2), 'utf-8');
  writeFileSync(
    instructionsPath,
    [
      'Umbra Studio portable release update staged successfully.',
      '',
      `Version: ${manifest.version}`,
      `Package: ${packagePath}`,
      '',
      'Protected paths that must not be replaced:',
      ...APP_UPDATE_PROTECTED_PATHS.map((entry) => `- ${entry}`),
      '',
      'Recommended next step:',
      '1. Close Umbra Studio.',
      '2. Apply the staged release package over the app install, skipping protected paths.',
      '3. Reopen Umbra Studio.',
    ].join('\n'),
    'utf-8',
  );

  return {
    stagingDir,
    packagePath,
    metadataPath,
    instructionsPath,
    packageSha256: actualSha256,
  };
}

async function getUmbraAppGitStatus(options: { refresh?: boolean } = {}) {
  const protection = getAppUpdateProtectionSummary();
  if (protection.updaterMode === 'release') {
    return getUmbraAppReleaseStatus(options, protection);
  }
  const gitInstalled = await isGitInstalled();
  if (!gitInstalled) {
    return {
      ...protection,
      currentVersion: getCurrentAppVersion(),
      gitInstalled: false,
      repoDetected: false,
      updateSourceReady: false,
      branch: null as string | null,
      remote: null as string | null,
      clean: false,
      ahead: 0,
      behind: 0,
      needsUpdate: false,
      message: 'Git is required to update Umbra Studio.',
    };
  }

  const repoCheck = await runGitCommand(['rev-parse', '--is-inside-work-tree']);
  if (!repoCheck.ok || repoCheck.stdout !== 'true') {
    return {
      ...protection,
      currentVersion: getCurrentAppVersion(),
      gitInstalled: true,
      repoDetected: false,
      updateSourceReady: false,
      branch: null as string | null,
      remote: null as string | null,
      clean: false,
      ahead: 0,
      behind: 0,
      needsUpdate: false,
      message: 'Update source is not configured for this Umbra Studio installation.',
    };
  }

  if (options.refresh) {
    await runGitCommand(['fetch', '--all', '--prune']);
  }

  const statusRes = await runGitCommand(['status', '--porcelain=2', '--branch']);
  const remoteRes = await runGitCommand(['remote', 'get-url', 'origin']);
  const upstreamRes = await runGitCommand(['rev-parse', '--abbrev-ref', '--symbolic-full-name', '@{u}']);

  const statusLines = statusRes.stdout.split('\n').map((line) => line.trim()).filter(Boolean);
  const branchLine = statusLines.find((line) => line.startsWith('# branch.head ')) || '';
  const abLine = statusLines.find((line) => line.startsWith('# branch.ab ')) || '';

  const branch = branchLine.replace('# branch.head ', '').trim() || null;
  const abMatch = abLine.match(/\+(\d+)\s+-(\d+)/);
  const ahead = abMatch ? Number(abMatch[1]) : 0;
  const behind = abMatch ? Number(abMatch[2]) : 0;
  const clean = statusLines.every((line) => line.startsWith('#'));

  const remote = remoteRes.ok ? remoteRes.stdout : null;
  const trackingBranch = upstreamRes.ok ? upstreamRes.stdout : null;
  const updateSourceReady = Boolean(remote && trackingBranch);

  return {
    ...protection,
    currentVersion: getCurrentAppVersion(),
    gitInstalled: true,
    repoDetected: true,
    updateSourceReady,
    branch,
    remote,
    trackingBranch,
    clean,
    ahead,
    behind,
    needsUpdate: behind > 0,
    message: updateSourceReady
      ? undefined
      : 'Update source is not fully configured. Reinstall or relink your Umbra Studio update source.',
  };
}

function compareVersions(current: string, latest: string): boolean {
  const [curMaj, curMin, curPatch] = current.split('.').map(Number);
  const [latMaj, latMin, latPatch] = latest.split('.').map(Number);

  if (latMaj > curMaj) return true;
  if (latMaj === curMaj && latMin > curMin) return true;
  if (latMaj === curMaj && latMin === curMin && latPatch > curPatch) return true;
  return false;
}

async function checkAllUpdates(): Promise<UpdateCache> {
  // Return cached results if fresh
  if (updateCache && (Date.now() - updateCache.lastChecked) < UPDATE_CACHE_TTL) {
    return updateCache;
  }

  console.log('[UpdateCheck] Checking for updates...');
  const updates: UpdateInfo[] = [];
  const detected = detectAllTools();

  // Fetch latest PyTorch version
  const pytorchInfo = await fetchLatestPyTorchVersion();

  // Check PyTorch in each tool
  const toolsWithPython = [
    { key: 'comfyui', name: 'ComfyUI', path: detected.comfyui.path, detected: detected.comfyui.detected },
    { key: 'aitoolkit', name: 'AI-Toolkit', path: detected.aitoolkit.path, detected: detected.aitoolkit.detected },
  ];

  for (const tool of toolsWithPython) {
    if (!tool.detected || !tool.path) continue;

    const currentPyTorch = getPyTorchVersionInVenv(tool.path);
    if (currentPyTorch) {
      const hasUpdate = compareVersions(currentPyTorch, pytorchInfo.latestVersion);
      updates.push({
        tool: tool.name,
        currentVersion: currentPyTorch,
        latestVersion: pytorchInfo.latestVersion,
        hasUpdate,
        updateType: 'pytorch',
        details: `CUDA ${pytorchInfo.cudaVersion}`
      });
    }
  }

  // Check tool versions (git for ComfyUI)
  if (detected.comfyui.detected && detected.comfyui.path) {
    const localCommit = getLocalGitCommit(detected.comfyui.path);
    const remoteCommit = await getGitLatestCommit('https://github.com/comfyanonymous/ComfyUI');
    const commitsMatch = Boolean(
      localCommit
      && remoteCommit
      && (localCommit.startsWith(remoteCommit) || remoteCommit.startsWith(localCommit))
    );
    if (localCommit && remoteCommit && !commitsMatch) {
      updates.push({
        tool: 'ComfyUI',
        currentVersion: localCommit,
        latestVersion: remoteCommit,
        hasUpdate: true,
        updateType: 'tool',
        details: 'git pull to update'
      });
    }
  }

  if (detected.aitoolkit.detected && detected.aitoolkit.path) {
    const localCommit = getLocalGitCommit(detected.aitoolkit.path);
    const remoteCommit = await getGitLatestCommit('https://github.com/ostris/ai-toolkit');
    const commitsMatch = Boolean(
      localCommit
      && remoteCommit
      && (localCommit.startsWith(remoteCommit) || remoteCommit.startsWith(localCommit))
    );
    if (localCommit && remoteCommit && !commitsMatch) {
      updates.push({
        tool: 'AI-Toolkit',
        currentVersion: localCommit,
        latestVersion: remoteCommit,
        hasUpdate: true,
        updateType: 'tool',
        details: 'git pull to update'
      });
    }
  }

  updateCache = {
    lastChecked: Date.now(),
    pytorch: pytorchInfo,
    tools: updates
  };

  const pendingUpdates = updates.filter(u => u.hasUpdate);
  if (pendingUpdates.length > 0) {
    console.log(`[UpdateCheck] Found ${pendingUpdates.length} available update(s):`);
    pendingUpdates.forEach(u => console.log(`  - ${u.tool}: ${u.currentVersion} → ${u.latestVersion} (${u.updateType})`));
  } else {
    console.log('[UpdateCheck] All tools are up to date');
  }

  return updateCache;
}

// Check updates on startup (async, non-blocking)
setTimeout(() => checkAllUpdates().catch(console.error), 5000);


function getBackendConfig() {
  const settings = settingsManager.getSettings();
  const detected = detectAllTools();

  // ComfyUI config
  const comfy = detected.comfyui;
  const comfyDefaultPort = settings?.servers?.comfyui?.port || 8188;
  const comfyDefaultHost = settings?.servers?.comfyui?.host || '127.0.0.1';
  const comfyUrl = getAppSettingString('comfyui.url');
  const comfyTarget = parseHostPortFromUrl(comfyUrl, comfyDefaultHost, comfyDefaultPort);
  const comfyPort = comfyTarget.port;
  const comfyHost = comfyTarget.host;
  const comfyLaunchHost = !IS_UMBRA_DEV_MODE && isLoopbackHostname(comfyHost)
    ? '0.0.0.0'
    : comfyHost;
  const comfyLaunchCapability = resolveComfyLaunchCapability(comfy);

  const comfyArgs = comfy.detected ? [
    comfy.mainScript!,
    '--listen', comfyLaunchHost,
    '--port', comfyPort.toString()
  ] : [];

  if (comfy.detected && (comfyLaunchCapability?.supportsCorsHeader ?? true)) {
    comfyArgs.push('--enable-cors-header', DEFAULT_CORS_ORIGIN);
  }
  if (comfy.detected && (comfyLaunchCapability?.supportsDisableAutoLaunch ?? true)) {
    comfyArgs.push('--disable-auto-launch');
  }
  if (comfy.detected) {
    const requestedAttentionBackend = normalizeComfyAttentionBackend(getAppSettings()['comfyui.attentionBackend']);
    const attentionBackend = requestedAttentionBackend === 'default' && isComfySageAttentionAvailable(comfy)
      ? 'sage'
      : requestedAttentionBackend;
    if (attentionBackend === 'sage') comfyArgs.push('--use-sage-attention');
    else if (attentionBackend === 'flash') comfyArgs.push('--use-flash-attention');
    else if (attentionBackend === 'pytorch') comfyArgs.push('--use-pytorch-cross-attention');
    else if (attentionBackend === 'split') comfyArgs.push('--use-split-cross-attention');
    else if (attentionBackend === 'quad') comfyArgs.push('--use-quad-cross-attention');
  }

  const aitoolkit = detected.aitoolkit;
  const aitoolkitUrlSetting = getAppSettingString('aitoolkit.url', 'http://127.0.0.1:8675');
  const aitoolkitTarget = parseHostPortFromUrl(aitoolkitUrlSetting, '127.0.0.1', 8675);
  const aitoolkitLaunchHost = '127.0.0.1';
  let aitoolkitUrl = `http://${aitoolkitTarget.host}:${aitoolkitTarget.port}/`;
  try {
    aitoolkitUrl = new URL(aitoolkitUrlSetting || aitoolkitUrl).toString();
  } catch {
    // Use the normalized fallback URL above.
  }

  return {
    comfyui: {
      detected: comfy.detected,
      port: comfyPort,
      host: comfyHost,
      launchHost: comfyLaunchHost,
      executable: comfy.pythonPath || '',
      args: comfyArgs,
      cwd: comfy.path
    },
    aitoolkit: {
      detected: aitoolkit.detected,
      port: aitoolkitTarget.port,
      host: aitoolkitTarget.host,
      launchHost: aitoolkitLaunchHost,
      url: aitoolkitUrl,
      executable: IS_WINDOWS ? 'node.exe' : 'node',
      args: [
        join(aitoolkit.uiPath || '', 'node_modules', 'concurrently', 'dist', 'bin', 'concurrently.js'),
        '--restart-tries', '-1',
        '--restart-after', '1000',
        '-n', 'WORKER,UI',
        'node dist/cron/worker.js',
        `next start --hostname ${aitoolkitLaunchHost} --port ${aitoolkitTarget.port}`,
      ],
      cwd: aitoolkit.uiPath || ''
    }
  };
}

async function startComfyUI() {
  try {
    if (isChildProcessAlive(comfyProcess)) {
      return { success: true, message: 'Already running' };
    }
    if (comfyProcess) {
      console.warn('\x1b[36m[ComfyUI]\x1b[0m Clearing stale tracked process handle before relaunch.');
      clearComfyProcessTelemetry();
      comfyProcess = null;
      comfyStartTime = null;
    }

    const config = getBackendConfig().comfyui;
    if (!config.detected || config.args.length === 0) {
      return { success: false, error: 'ComfyUI install is missing or incomplete. Run Reinstall ComfyUI to repair runtime and launch configuration.' };
    }

    const ownership = getComfyProcessOwnershipSnapshot({ force: true });
    if (ownership.kind === 'external-compatible') {
      appendBackendLifecycleLog('comfyui', 'start_adopted_external_compatible', ownership as unknown as Record<string, unknown>);
      return {
        success: true,
        message: 'Already running',
        running: true,
        healthy: ownership.portOpen,
        ownership: ownership.kind,
        pid: null,
        port: ownership.port,
      };
    }
    if (ownership.kind === 'unknown-port') {
      appendBackendLifecycleLog('comfyui', 'start_blocked_unknown_port_owner', ownership as unknown as Record<string, unknown>);
      logBackendProcessSnapshot('comfyui', 'unknown_port_owner', ownership.unknownPortPids, { port: ownership.port });
      return {
        success: false,
        error: `Port ${ownership.port} is already in use by an unknown process. Stop the stale server or change the ComfyUI port before launching.`,
        running: true,
        healthy: false,
        ownership: ownership.kind,
        port: ownership.port,
        portPids: ownership.portPids,
      };
    }

    applyComfyFrontendCompatibilityPatches(config.cwd || '');

    const securityApply = applyComfySecurityLevelSetting(config.cwd || '');
    if (!securityApply.applied && securityApply.error) {
      console.warn(`\x1b[36m[ComfyUI]\x1b[0m Failed to apply security_level before launch: ${securityApply.error}`);
    }

    const checkPath = config.executable === 'bash' ? config.args[0] : config.executable;
    if (!existsSync(checkPath)) {
      return { success: false, error: `Executable not found: ${checkPath || '(empty path)'}` };
    }

    console.log('\x1b[36m[ComfyUI]\x1b[0m Starting...');
    console.log('\x1b[36m[ComfyUI]\x1b[0m Command:', config.executable, config.args.join(' '));
    console.log('\x1b[36m[ComfyUI]\x1b[0m CWD:', config.cwd);
    appendBackendLifecycleLog('comfyui', 'start_requested', {
      executable: config.executable,
      args: config.args,
      cwd: config.cwd,
      port: config.port,
    });
    appendBackendStreamLog('comfyui', 'lifecycle', `Starting: ${config.executable} ${config.args.join(' ')}`);

    const comfyEnv: NodeJS.ProcessEnv = { ...process.env, PYTHONUNBUFFERED: '1' };
  const configuredExternalOutput = resolveConfiguredPath(String(settingsManager.getAppSettings()['comfyui.externalOutputPath'] || '').trim());
    if (configuredExternalOutput) {
      comfyEnv.UMBRA_EXTERNAL_OUTPUT_DIR = resolvePathCandidate(configuredExternalOutput);
    }

    comfyProcess = spawn(config.executable, config.args, {
      cwd: config.cwd,
      env: comfyEnv,
      stdio: ['ignore', 'pipe', 'pipe']
    });
    comfyOwnershipSnapshotCache = null;
    comfyStartTime = Date.now();
    appendBackendLifecycleLog('comfyui', 'started', {
      pid: comfyProcess.pid ?? null,
      executable: config.executable,
      args: config.args,
      cwd: config.cwd,
      port: config.port,
    });
    startComfyProcessTelemetry();

    comfyProcess.on('error', (err) => {
      console.error(`\x1b[36m[COMFYUI]\x1b[0m \x1b[31mSpawn error: ${err.message}\x1b[0m`);
      appendBackendLifecycleLog('comfyui', 'spawn_error', {
        pid: comfyProcess?.pid ?? null,
        message: err.message,
        stack: err.stack,
      });
      appendBackendStreamLog('comfyui', 'stderr', `Spawn error: ${err.message}`);
      broadcastToClients('backend_log', { backend: 'comfyui', stream: 'stderr', message: `Spawn error: ${err.message}` });
      failPrompterRequestsForBridge(null, `ComfyUI failed to start: ${err.message}`);
      broadcastBridgeCatalogToPowerPrompterClients();
      clearComfyProcessTelemetry();
      comfyProcess = null;
      comfyStartTime = null;
      comfyOwnershipSnapshotCache = null;
    });

    comfyProcess.stdout?.on('data', (data) => {
      const lines = data.toString().trim().split(/\r?\n|\r/);
      lines.forEach((line: string) => {
        if (line.trim()) {
          if (!shouldEmitComfyProcessLine('stdout', line)) return;
          console.log(`\x1b[36m[COMFYUI]\x1b[0m ${line}`);
          appendBackendStreamLog('comfyui', 'stdout', line);
          broadcastToClients('backend_log', { backend: 'comfyui', stream: 'stdout', message: line });
        }
      });
    });

    comfyProcess.stderr?.on('data', (data) => {
      const lines = data.toString().trim().split(/\r?\n|\r/);
      lines.forEach((line: string) => {
        if (line.trim()) {
          if (!shouldEmitComfyProcessLine('stderr', line)) return;
          console.error(`\x1b[36m[COMFYUI]\x1b[0m \x1b[31m${line}\x1b[0m`);
          appendBackendStreamLog('comfyui', 'stderr', line);
          broadcastToClients('backend_log', { backend: 'comfyui', stream: 'stderr', message: line });
        }
      });
    });

    comfyProcess.on('exit', (code, signal) => {
      const uptimeMs = comfyStartTime ? Date.now() - comfyStartTime : null;
      const trackedPid = comfyProcess?.pid ?? null;
      const message = `Process exited with code ${code}${signal ? ` signal ${signal}` : ''}`;
      console.log(`\x1b[36m[COMFYUI]\x1b[0m ${message}`);
      appendBackendLifecycleLog('comfyui', 'exit', {
        pid: trackedPid,
        code,
        signal,
        uptimeMs,
      });
      appendBackendStreamLog('comfyui', 'lifecycle', message);
      broadcastToClients('backend_log', { backend: 'comfyui', stream: 'stderr', message });
      failPrompterRequestsForBridge(null, `ComfyUI exited before queued work completed (code ${code ?? 'unknown'}).`);
      broadcastBridgeCatalogToPowerPrompterClients();
      flushLogBuffer('comfyui_stdout');
      flushLogBuffer('comfyui_stderr');
      clearComfyProcessTelemetry();
      comfyProcess = null;
      comfyStartTime = null;
      comfyOwnershipSnapshotCache = null;
    });

    return { success: true, message: 'Started' };
  } catch (error: any) {
    const message = String(error?.message || 'Failed to launch ComfyUI');
    console.error(`[ComfyUI] startComfyUI failed: ${message}`, error);
    appendBackendLifecycleLog('comfyui', 'start_failed', {
      message,
      stack: error?.stack,
    });
    return { success: false, error: message };
  }
}

async function stopComfyUI() {
  const ownership = getComfyProcessOwnershipSnapshot({ force: true });
  const tracked = comfyProcess;
  const trackedPid = tracked?.pid ?? null;
  let hadRunning = ownership.portOpen || ownership.trackedAlive || ownership.ownedPids.length > 0;
  let stopped = true;

  appendBackendLifecycleLog('comfyui', 'stop_requested', {
    trackedPid,
    port: ownership.port,
    ownership: ownership.kind,
    portPids: ownership.portPids,
    ownedPids: ownership.ownedPids,
    unknownPortPids: ownership.unknownPortPids,
    uptimeMs: comfyStartTime ? Date.now() - comfyStartTime : null,
  });
  logBackendProcessSnapshot('comfyui', 'before_stop', ownership.ownedPids, {
    port: ownership.port,
    trackedPid,
    ownership: ownership.kind,
  });

  if (ownership.kind === 'unknown-port') {
    return {
      success: false,
      error: `Port ${ownership.port} is owned by an unknown process. Umbra will not stop it automatically.`,
      running: true,
      healthy: ownership.portOpen,
      ownership: ownership.kind,
      port: ownership.port,
      portPids: ownership.portPids,
    };
  }

  if (ownership.kind === 'external-compatible' && !ownership.trackedAlive) {
    return {
      success: true,
      message: 'External ComfyUI left running',
      running: true,
      healthy: ownership.portOpen,
      ownership: ownership.kind,
      port: ownership.port,
      portPids: ownership.portPids,
    };
  }

  if (isChildProcessAlive(tracked)) {
    stopped = await stopProcessTree(tracked, 'ComfyUI');
  }

  const remainingOwnedPids = getComfyProcessOwnershipSnapshot({ force: true }).ownedPids
    .filter((pid) => pid !== process.pid)
    .filter((pid) => pid !== trackedPid);
  if (remainingOwnedPids.length > 0) {
    stopped = stopPids(remainingOwnedPids, 'ComfyUI') && stopped;
    await sleep(800);
  }

  comfyProcess = null;
  comfyStartTime = null;
  comfyOwnershipSnapshotCache = null;
  clearComfyProcessTelemetry();

  const after = getComfyProcessOwnershipSnapshot({ force: true });
  const stillOwned = after.kind === 'owned' || (after.ownedPids.length > 0 && after.portOpen);
  appendBackendLifecycleLog('comfyui', stillOwned ? 'stop_incomplete' : 'stop_completed', {
    trackedPid,
    port: after.port,
    before: ownership.kind,
    after: after.kind,
    hadRunning,
    stopped,
    portOpen: after.portOpen,
    portPids: after.portPids,
    ownedPids: after.ownedPids,
  });

  if (stillOwned) {
    return {
      success: false,
      error: 'Failed to fully stop ComfyUI',
      running: true,
      healthy: after.portOpen,
      ownership: after.kind,
      port: after.port,
      portPids: after.portPids,
    };
  }

  return {
    success: true,
    message: hadRunning ? 'ComfyUI stopped' : 'ComfyUI already stopped',
    running: false,
    healthy: false,
    ownership: after.kind,
    port: after.port,
    stopped,
  };
}

async function startAIToolkit() {
  try {
    if (isChildProcessAlive(aitoolkitProcess)) {
      return { success: true, message: 'AI-Toolkit is already running', running: true, healthy: true };
    }
    if (aitoolkitProcess) {
      aitoolkitProcess = null;
      aitoolkitStartTime = null;
    }

    const config = getBackendConfig().aitoolkit;
    if (!config.detected || !config.cwd || !existsSync(join(config.cwd, 'package.json'))) {
      return {
        success: false,
        error: 'AI-Toolkit is missing or incomplete. Install or repair it from the Data Forge AI-Toolkit tab.'
      };
    }

    if (await isPortOpen(config.port, 700)) {
      return {
        success: true,
        message: `An existing server is already available on AI-Toolkit port ${config.port}`,
        running: true,
        healthy: true,
        external: true,
        port: config.port,
      };
    }

    const nodeCapability = getAIToolkitNodeCapability();
    if (!nodeCapability.available) {
      return { success: false, error: `AI-Toolkit requires Node.js 20 or newer. Detected: ${nodeCapability.version || 'not installed'}.` };
    }
    if (!existsSync(join(config.cwd, 'node_modules'))) {
      return { success: false, error: 'AI-Toolkit UI dependencies are not installed. Run Repair Install from the Data Forge tab.' };
    }
    if (!existsSync(join(config.cwd, '.next', 'BUILD_ID')) || !existsSync(join(config.cwd, 'dist', 'cron', 'worker.js'))) {
      return { success: false, error: 'AI-Toolkit production assets are missing. Run Repair Install from the Data Forge tab.' };
    }

    const toolRoot = dirname(config.cwd);
    const venvBin = IS_WINDOWS ? join(toolRoot, 'venv', 'Scripts') : join(toolRoot, 'venv', 'bin');
    const localNodeBin = join(config.cwd, 'node_modules', '.bin');
    const inheritedPath = String(process.env.PATH || process.env.Path || '');
    const pathSeparator = IS_WINDOWS ? ';' : ':';

    console.log('\x1b[32m[AI-Toolkit]\x1b[0m Starting...');
    appendBackendLifecycleLog('aitoolkit', 'start_requested', {
      executable: config.executable,
      args: config.args,
      cwd: config.cwd,
      port: config.port,
      nodeVersion: nodeCapability.version,
    });
    appendBackendStreamLog('aitoolkit', 'lifecycle', `Starting: ${config.executable} ${config.args.join(' ')}`);

    const spawnedProcess = spawn(config.executable, config.args, {
      cwd: config.cwd,
      shell: false,
      windowsHide: true,
      env: {
        ...process.env,
        PORT: String(config.port),
        HOSTNAME: config.launchHost,
        VIRTUAL_ENV: join(toolRoot, 'venv'),
        PATH: [venvBin, localNodeBin, inheritedPath].filter(Boolean).join(pathSeparator),
        Path: [venvBin, localNodeBin, inheritedPath].filter(Boolean).join(pathSeparator),
        PYTHONUNBUFFERED: '1',
      },
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    aitoolkitProcess = spawnedProcess;
    aitoolkitStartTime = Date.now();
    appendBackendLifecycleLog('aitoolkit', 'started', {
      pid: spawnedProcess.pid ?? null,
      cwd: config.cwd,
      port: config.port,
    });

    spawnedProcess.on('error', (error) => {
      const message = `Spawn error: ${error.message}`;
      console.error(`\x1b[32m[AI-TOOLKIT]\x1b[0m \x1b[31m${message}\x1b[0m`);
      appendBackendLifecycleLog('aitoolkit', 'spawn_error', {
        pid: spawnedProcess.pid ?? null,
        message: error.message,
        stack: error.stack,
      });
      appendBackendStreamLog('aitoolkit', 'stderr', message);
      broadcastToClients('backend_log', { backend: 'aitoolkit', stream: 'stderr', message });
      if (aitoolkitProcess === spawnedProcess) {
        aitoolkitProcess = null;
        aitoolkitStartTime = null;
      }
    });

    const pipeOutput = (stream: 'stdout' | 'stderr', chunk: unknown) => {
      const lines = String(chunk ?? '').split(/\r?\n|\r/).map((line) => line.trim()).filter(Boolean);
      for (const line of lines) {
        if (stream === 'stderr') console.error(`\x1b[32m[AI-TOOLKIT]\x1b[0m \x1b[31m${line}\x1b[0m`);
        else console.log(`\x1b[32m[AI-TOOLKIT]\x1b[0m ${line}`);
        appendBackendStreamLog('aitoolkit', stream, line);
        broadcastToClients('backend_log', { backend: 'aitoolkit', stream, message: line });
      }
    };
    spawnedProcess.stdout?.on('data', (chunk) => pipeOutput('stdout', chunk));
    spawnedProcess.stderr?.on('data', (chunk) => pipeOutput('stderr', chunk));
    spawnedProcess.on('exit', (code, signal) => {
      const message = `Process exited with code ${code ?? 'unknown'}${signal ? ` (${signal})` : ''}`;
      console.log(`\x1b[32m[AI-TOOLKIT]\x1b[0m ${message}`);
      appendBackendLifecycleLog('aitoolkit', 'exited', {
        pid: spawnedProcess.pid ?? null,
        code,
        signal,
      });
      appendBackendStreamLog('aitoolkit', code === 0 ? 'lifecycle' : 'stderr', message);
      broadcastToClients('backend_log', { backend: 'aitoolkit', stream: code === 0 ? 'stdout' : 'stderr', message });
      if (aitoolkitProcess === spawnedProcess) {
        aitoolkitProcess = null;
        aitoolkitStartTime = null;
      }
    });

    return { success: true, message: 'AI-Toolkit starting', running: true, healthy: false, port: config.port };
  } catch (error: any) {
    const message = String(error?.message || 'Failed to launch AI-Toolkit');
    appendBackendLifecycleLog('aitoolkit', 'start_failed', { message, stack: error?.stack });
    return { success: false, error: message };
  }
}

async function stopAIToolkit() {
  const config = getBackendConfig().aitoolkit;
  const trackedProcess = aitoolkitProcess;
  const wasTracked = isChildProcessAlive(trackedProcess);
  const portWasOpen = await isPortOpen(config.port, 700);

  if (!wasTracked) {
    aitoolkitProcess = null;
    aitoolkitStartTime = null;
    return {
      success: true,
      message: portWasOpen ? 'External AI-Toolkit server left running' : 'AI-Toolkit is already stopped',
      running: portWasOpen,
      healthy: portWasOpen,
      external: portWasOpen,
      port: config.port,
    };
  }

  appendBackendLifecycleLog('aitoolkit', 'stop_requested', {
    pid: trackedProcess?.pid ?? null,
    port: config.port,
    uptimeMs: aitoolkitStartTime ? Date.now() - aitoolkitStartTime : null,
  });
  const stopped = await stopProcessTree(trackedProcess, 'AI-Toolkit');
  aitoolkitProcess = null;
  aitoolkitStartTime = null;
  await sleep(300);
  const stillOpen = await isPortOpen(config.port, 700);
  appendBackendLifecycleLog('aitoolkit', stillOpen ? 'stop_incomplete' : 'stop_completed', {
    pid: trackedProcess?.pid ?? null,
    port: config.port,
    stopped,
    stillOpen,
  });
  if (stillOpen) {
    return { success: false, error: 'AI-Toolkit stopped, but its configured port is still in use.', running: true, healthy: true, port: config.port };
  }
  return { success: true, message: 'AI-Toolkit stopped', running: false, healthy: false, port: config.port };
}

async function startGalleryBridge() {
  if (galleryBridgeStartInFlight) {
    return galleryBridgeStartInFlight;
  }
  galleryBridgeStartInFlight = startGalleryBridgeInternal().finally(() => {
    galleryBridgeStartInFlight = null;
  });
  return galleryBridgeStartInFlight;
}

async function startGalleryBridgeInternal() {
  if (isChildProcessAlive(galleryBridgeProcess)) {
    const healthy = await isGalleryBridgeHealthy();
    if (!healthy) {
      appendBackendLifecycleLog('gallery', 'unhealthy_tracked_process_detected', {
        pid: galleryBridgeProcess?.pid ?? null,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
      });
      galleryBridgeDesired = true;
      return {
        success: true,
        message: 'Gallery bridge process is running but health check failed; using fallback until it responds',
        running: true,
        healthy: false,
        pid: galleryBridgeProcess?.pid ?? null,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
        url: GALLERY_IN_PROCESS_WORKSPACE_URL,
        mode: 'split-process-unhealthy',
      };
    } else {
      galleryBridgeDesired = true;
      galleryBridgeWatchdogFailures = 0;
      startGalleryBridgeWatchdog();
      return {
        success: true,
        message: 'Gallery bridge already running',
        running: true,
        healthy,
        pid: galleryBridgeProcess?.pid ?? null,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
        url: getGalleryWorkspaceUrl(),
        mode: 'split-process',
      };
    }
  }

  if (await isGalleryBridgeHealthy()) {
    galleryBridgeProcess = null;
    galleryBridgeStartTime = null;
    galleryBridgeDesired = true;
    galleryBridgeWatchdogFailures = 0;
    startGalleryBridgeWatchdog();
    appendBackendLifecycleLog('gallery', 'external_process_detected', {
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: getGalleryWorkspaceUrl(),
    });
    return {
      success: true,
      message: 'Gallery bridge already running (external process)',
      running: true,
      healthy: true,
      pid: null,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: getGalleryWorkspaceUrl(),
      mode: 'split-process',
    };
  }

  const occupiedGalleryPortPids = listPidsByPort(GALLERY_BRIDGE_PORT).filter((pid) => pid !== process.pid);
  if (occupiedGalleryPortPids.length > 0) {
    appendBackendLifecycleLog('gallery', 'unhealthy_port_listener_detected', {
      port: GALLERY_BRIDGE_PORT,
      pids: occupiedGalleryPortPids,
    });
    const released = await stopByPort(GALLERY_BRIDGE_PORT, 'Gallery bridge');
    appendBackendLifecycleLog('gallery', released ? 'unhealthy_port_listener_released' : 'unhealthy_port_listener_release_failed', {
      port: GALLERY_BRIDGE_PORT,
      pids: occupiedGalleryPortPids,
    });
    if (!released) {
      return {
        success: false,
        error: `Gallery bridge port ${GALLERY_BRIDGE_PORT} is occupied by an unhealthy process`,
        running: false,
        healthy: false,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
        url: GALLERY_IN_PROCESS_WORKSPACE_URL,
        mode: 'split-process',
      };
    }
  }

  if (!existsSync(GALLERY_BRIDGE_SERVER_ENTRY)) {
    return {
      success: false,
      error: `Gallery bridge entry not found: ${GALLERY_BRIDGE_SERVER_ENTRY}`,
      running: false,
      healthy: false,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: GALLERY_IN_PROCESS_WORKSPACE_URL,
      mode: 'split-process',
    };
  }

  try {
    const bunBin = process.execPath || 'bun';
    galleryBridgeDesired = true;
    appendBackendLifecycleLog('gallery', 'start_requested', {
      executable: bunBin,
      args: [GALLERY_BRIDGE_SERVER_ENTRY],
      cwd: ROOT_DIR,
      host: GALLERY_BRIDGE_HOST,
      port: GALLERY_BRIDGE_PORT,
    });
    appendBackendStreamLog('gallery', 'lifecycle', `Starting: ${bunBin} ${GALLERY_BRIDGE_SERVER_ENTRY}`);
    const proc = spawn(bunBin, [GALLERY_BRIDGE_SERVER_ENTRY], {
      cwd: ROOT_DIR,
      env: {
        ...process.env,
        UMBRA_ROOT: ROOT_DIR,
        UMBRA_BRIDGE_URL: `http://127.0.0.1:${PORT}`,
        UMBRA_GALLERY_HOST: GALLERY_BRIDGE_HOST,
        UMBRA_GALLERY_PORT: String(GALLERY_BRIDGE_PORT),
        UMBRA_DIAGNOSTICS: isBackendDiagnosticLoggingEnabled() ? '1' : '',
      },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    galleryBridgeProcess = proc;
    galleryBridgeStartTime = Date.now();
    appendBackendLifecycleLog('gallery', 'started', {
      pid: proc.pid ?? null,
      executable: bunBin,
      args: [GALLERY_BRIDGE_SERVER_ENTRY],
      cwd: ROOT_DIR,
      host: GALLERY_BRIDGE_HOST,
      port: GALLERY_BRIDGE_PORT,
    });
    startGalleryProcessTelemetry();

    proc.on('error', (err) => {
      const message = `Spawn error: ${err.message}`;
      console.error(`\x1b[33m[GALLERY]\x1b[0m \x1b[31m${message}\x1b[0m`);
      appendBackendLifecycleLog('gallery', 'spawn_error', {
        pid: proc.pid ?? null,
        message: err.message,
        stack: err.stack,
      });
      appendBackendStreamLog('gallery', 'stderr', message);
      broadcastToClients('backend_log', { backend: 'gallery', stream: 'stderr', message });
      clearGalleryProcessTelemetry();
      galleryBridgeProcess = null;
      galleryBridgeStartTime = null;
      scheduleGalleryBridgeSelfHeal('spawn_error', proc.pid ?? null);
    });

    proc.stdout?.on('data', (data) => {
      const lines = String(data || '').split('\n');
      for (const rawLine of lines) {
        const line = rawLine.trim();
        if (!line) continue;
        if (isBackendDiagnosticLoggingEnabled()) console.log(`\x1b[33m[GALLERY]\x1b[0m ${line}`);
        appendBackendStreamLog('gallery', 'stdout', line);
        broadcastToClients('backend_log', { backend: 'gallery', stream: 'stdout', message: line });
      }
    });

    proc.stderr?.on('data', (data) => {
      const lines = String(data || '').split('\n');
      for (const rawLine of lines) {
        const line = rawLine.trim();
        if (!line) continue;
        console.error(`\x1b[33m[GALLERY]\x1b[0m \x1b[31m${line}\x1b[0m`);
        appendBackendStreamLog('gallery', 'stderr', line);
        broadcastToClients('backend_log', { backend: 'gallery', stream: 'stderr', message: line });
      }
    });

    proc.on('exit', (code, signal) => {
      const exitingPid = proc.pid ?? null;
      const trackedPid = galleryBridgeProcess?.pid ?? null;
      const isTrackedExit = galleryBridgeProcess === proc || (exitingPid !== null && trackedPid === exitingPid);
      const uptimeMs = galleryBridgeStartTime ? Date.now() - galleryBridgeStartTime : null;
      const message = `Process exited with code ${code}${signal ? ` signal ${signal}` : ''}`;
      console.log(`\x1b[33m[GALLERY]\x1b[0m ${message}`);
      appendBackendLifecycleLog('gallery', 'exit', {
        pid: exitingPid,
        trackedPid,
        stale: !isTrackedExit,
        code,
        signal,
        uptimeMs,
      });
      appendBackendStreamLog('gallery', 'lifecycle', message);
      broadcastToClients('backend_log', { backend: 'gallery', stream: 'stderr', message });
      if (!isTrackedExit) {
        appendBackendLifecycleLog('gallery', 'stale_exit_ignored', {
          pid: exitingPid,
          trackedPid,
          code,
          signal,
        });
        return;
      }
      flushLogBuffer('gallery_stdout');
      flushLogBuffer('gallery_stderr');
      clearGalleryProcessTelemetry();
      galleryBridgeProcess = null;
      galleryBridgeStartTime = null;
      scheduleGalleryBridgeSelfHeal('exit', exitingPid);
    });

    const startedAt = Date.now();
    while (Date.now() - startedAt < GALLERY_BRIDGE_START_TIMEOUT_MS) {
      if (!isChildProcessAlive(galleryBridgeProcess)) break;
      if (await isGalleryBridgeHealthy()) {
        galleryBridgeWatchdogFailures = 0;
        startGalleryBridgeWatchdog();
        return {
          success: true,
          message: 'Gallery bridge started',
          running: true,
          healthy: true,
          pid: galleryBridgeProcess?.pid ?? null,
          host: getGalleryBridgeHostForClient(),
          port: GALLERY_BRIDGE_PORT,
          url: getGalleryWorkspaceUrl(),
          mode: 'split-process',
        };
      }
      await new Promise((resolve) => setTimeout(resolve, 250));
    }

    const healthy = await isGalleryBridgeHealthy();
    if (healthy) {
      galleryBridgeWatchdogFailures = 0;
      startGalleryBridgeWatchdog();
      return {
        success: true,
        message: 'Gallery bridge started',
        running: true,
        healthy: true,
        pid: galleryBridgeProcess?.pid ?? null,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
        url: getGalleryWorkspaceUrl(),
        mode: 'split-process',
      };
    }

    const exitCode = galleryBridgeProcess?.exitCode;
    const processRunning = isChildProcessAlive(galleryBridgeProcess);
    if (processRunning && !GALLERY_BRIDGE_AUTO_RECOVERY_ENABLED) {
      logGalleryRecoverySuppressed('start_timeout', 'start_request');
      return {
        success: true,
        message: 'Gallery bridge process started but did not become ready before the readiness check completed',
        running: true,
        healthy: false,
        pid: galleryBridgeProcess?.pid ?? null,
        host: getGalleryBridgeHostForClient(),
        port: GALLERY_BRIDGE_PORT,
        url: GALLERY_IN_PROCESS_WORKSPACE_URL,
        mode: 'split-process-unhealthy',
      };
    }
    return {
      success: false,
      error: exitCode == null
        ? 'Gallery bridge did not become ready in time'
        : `Gallery bridge exited with code ${exitCode}`,
      running: false,
      healthy: false,
      pid: galleryBridgeProcess?.pid ?? null,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: GALLERY_IN_PROCESS_WORKSPACE_URL,
      mode: 'split-process',
    };
  } catch (error: any) {
    galleryBridgeProcess = null;
    galleryBridgeStartTime = null;
    clearGalleryProcessTelemetry();
    appendBackendLifecycleLog('gallery', 'start_failed', {
      message: String(error?.message || 'Failed to start gallery bridge'),
      stack: error?.stack,
    });
    return {
      success: false,
      error: String(error?.message || 'Failed to start gallery bridge'),
      running: false,
      healthy: false,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: GALLERY_IN_PROCESS_WORKSPACE_URL,
      mode: 'split-process',
    };
  }
}

async function stopGalleryBridge() {
  galleryBridgeDesired = false;
  clearGalleryBridgeWatchdog();
  let hadRunning = await isGalleryBridgeHealthy();
  let stopped = true;
  const proc = galleryBridgeProcess;
  appendBackendLifecycleLog('gallery', 'stop_requested', {
    trackedPid: proc?.pid ?? null,
    port: GALLERY_BRIDGE_PORT,
    hadRunning,
    uptimeMs: galleryBridgeStartTime ? Date.now() - galleryBridgeStartTime : null,
  });
  logBackendProcessSnapshot('gallery', 'before_stop', [proc?.pid], { port: GALLERY_BRIDGE_PORT, hadRunning });

  if (isChildProcessAlive(proc)) {
    hadRunning = true;
    stopped = await stopProcessTree(proc, 'Gallery bridge');
  }

  const stoppedByPort = await stopByPort(GALLERY_BRIDGE_PORT, 'Gallery bridge');
  if (stoppedByPort) hadRunning = true;
  stopped = stopped || stoppedByPort;

  galleryBridgeProcess = null;
  galleryBridgeStartTime = null;
  clearGalleryProcessTelemetry();

  const stillHealthy = await isGalleryBridgeHealthy();
  appendBackendLifecycleLog('gallery', 'stop_completed', {
    trackedPid: proc?.pid ?? null,
    port: GALLERY_BRIDGE_PORT,
    hadRunning,
    stopped,
    stoppedByPort,
    stillHealthy,
  });
  if (stillHealthy) {
    return {
      success: false,
      error: 'Failed to fully stop Gallery bridge',
      running: true,
      healthy: true,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: getGalleryWorkspaceUrl(),
      mode: 'split-process',
    };
  }

  return {
    success: true,
    message: hadRunning ? 'Gallery bridge stopped' : 'Gallery bridge already stopped',
    running: false,
    healthy: false,
    host: getGalleryBridgeHostForClient(),
    port: GALLERY_BRIDGE_PORT,
    url: GALLERY_IN_PROCESS_WORKSPACE_URL,
    mode: 'split-process',
    stopped,
  };
}

async function restartGalleryBridgeForSelfHeal(reason: string, expectedPid: number | null = null) {
  if (isShuttingDown) return;
  const currentPid = galleryBridgeProcess?.pid ?? null;
  if (isChildProcessAlive(galleryBridgeProcess) && currentPid !== expectedPid) {
    appendBackendLifecycleLog('gallery', 'stale_self_heal_ignored', {
      reason,
      expectedPid,
      currentPid,
      port: GALLERY_BRIDGE_PORT,
    });
    return;
  }
  appendBackendLifecycleLog('gallery', 'self_heal_restart_started', {
    reason,
    trackedPid: currentPid,
    expectedPid,
    port: GALLERY_BRIDGE_PORT,
  });

  const wasDesired = galleryBridgeDesired;
  const proc = galleryBridgeProcess;
  const trackedPid = proc?.pid ?? null;
  let stoppedStalePortPids = false;
  if (isChildProcessAlive(proc)) {
    logBackendProcessSnapshot('gallery', 'before_self_heal_restart', [proc?.pid], { reason, port: GALLERY_BRIDGE_PORT });
    await stopProcessTree(proc, 'Gallery bridge');
  }
  const stalePortPids = listPidsByPort(GALLERY_BRIDGE_PORT)
    .filter((pid) => pid !== process.pid)
    .filter((pid) => pid !== trackedPid);
  if (stalePortPids.length > 0) {
    appendBackendLifecycleLog('gallery', 'self_heal_stale_port_cleanup_requested', {
      reason,
      port: GALLERY_BRIDGE_PORT,
      trackedPid,
      pids: stalePortPids,
    });
    stoppedStalePortPids = stopPids(stalePortPids, 'Gallery bridge stale port listener');
    await sleep(1200);
  }

  galleryBridgeProcess = null;
  galleryBridgeStartTime = null;
  clearGalleryProcessTelemetry();
  galleryBridgeProxyBackoffUntil = 0;
  galleryBridgeWatchdogFailures = 0;
  galleryBridgeDesired = wasDesired;

  const result = await startGalleryBridge();
  appendBackendLifecycleLog('gallery', result?.success ? 'self_heal_restart_completed' : 'self_heal_restart_failed', {
    reason,
    stoppedStalePortPids,
    success: result?.success === true,
    message: result?.message,
    error: result?.error,
    pid: result?.pid ?? null,
    healthy: result?.healthy === true,
  });
}

async function getGalleryStatusAsync() {
  const processRunning = isChildProcessAlive(galleryBridgeProcess);
  const healthy = await isGalleryBridgeHealthy();
  const startupGraceMs = 45000;
  const inStartupGrace = galleryBridgeDesired
    && !healthy
    && galleryBridgeStartTime !== null
    && (Date.now() - galleryBridgeStartTime) < startupGraceMs;
  if (galleryBridgeDesired && !healthy && !inStartupGrace && !processRunning) {
    scheduleGalleryBridgeSelfHeal(processRunning ? 'status_unhealthy' : 'status_process_missing');
  }
  const running = processRunning || healthy || inStartupGrace;
  const usingFallback = !healthy && !inStartupGrace;
  return {
    running,
    healthy,
    pid: processRunning ? (galleryBridgeProcess?.pid ?? null) : null,
    uptime: galleryBridgeStartTime && running
      ? Math.floor((Date.now() - galleryBridgeStartTime) / 1000)
      : (running ? 999 : 0),
    host: getGalleryBridgeHostForClient(),
    port: GALLERY_BRIDGE_PORT,
    url: healthy || inStartupGrace ? getGalleryWorkspaceUrl() : GALLERY_IN_PROCESS_WORKSPACE_URL,
    mode: healthy
      ? 'split-process'
      : (usingFallback ? (running ? 'split-process-unhealthy' : 'in-process-fallback') : 'split-process-starting'),
    bridgeEntry: GALLERY_BRIDGE_SERVER_ENTRY,
    fallbackUrl: GALLERY_IN_PROCESS_WORKSPACE_URL,
    publicDir: GALLERY_PUBLIC_DIR,
  };
}

async function proxyGalleryBridgeFsGet(
  req: Request,
  sourceUrl: URL,
  targetPath: string,
  fallback: () => Promise<Response> | Response,
  server?: RequestIpServer,
): Promise<Response> {
  const startedAt = performance.now();
  const traceProxy = (event: string, payload: Record<string, unknown>, thresholdMs = 250) => {
    if (!isBackendDiagnosticLoggingEnabled()) return;
    const durationMs = Math.round((performance.now() - startedAt) * 10) / 10;
    if (durationMs < thresholdMs && !payload.error && !payload.fallback) return;
    try {
      console.info(`[GalleryBridgeProxy] ${JSON.stringify({
        event,
        targetPath,
        sourcePath: sourceUrl.pathname,
        folderPath: sourceUrl.searchParams.get('path') || '',
        ...payload,
        durationMs,
        sampledAt: new Date().toISOString(),
      })}`);
    } catch {
      // Best-effort diagnostics only.
    }
  };
  if (!isChildProcessAlive(galleryBridgeProcess) && !(await isGalleryBridgeHealthy({ allowCached: false }))) {
    await startGalleryBridge().catch(() => undefined);
  }

  if (Date.now() < galleryBridgeProxyBackoffUntil) {
    const response = await fallback();
    response.headers.set('X-Gallery-Fallback', 'bridge-backoff');
    traceProxy('fallback_backoff', { status: response.status, fallback: true }, 0);
    return response;
  }

  const targetUrl = new URL(`${getGalleryBridgeBaseUrl()}${targetPath}`);
  targetUrl.search = sourceUrl.search;
  const remoteImageOptimized = applyRemoteGalleryBridgeFsOptimization(req, sourceUrl, targetPath, targetUrl, server);

  const headers = new Headers(req.headers);
  headers.delete('host');
  headers.delete('origin');
  headers.delete('referer');

  try {
    const proxyTimeoutMs = targetPath === '/api/fs/image'
      ? 20000
      : (targetPath === '/api/fs/thumbnail' ? 12000 : 6000);
    const upstream = await fetch(targetUrl.toString(), {
      method: 'GET',
      headers,
      signal: AbortSignal.timeout(proxyTimeoutMs),
    });
    galleryBridgeProxyBackoffUntil = 0;
    galleryBridgeProxyFailures = 0;
    const responseHeaders = new Headers(upstream.headers);
    responseHeaders.set('X-Gallery-Proxy-Ms', String(Math.round((performance.now() - startedAt) * 10) / 10));
    if (remoteImageOptimized) {
      responseHeaders.set('X-Umbra-Remote-Optimized', '1');
    }
    traceProxy('proxy_success', {
      status: upstream.status,
      core: responseHeaders.get('X-Gallery-Core') || '',
      bridgeMs: responseHeaders.get('X-Gallery-Bridge-Ms') || '',
    }, 500);
    return new Response(upstream.body, {
      status: upstream.status,
      headers: responseHeaders,
    });
  } catch (error: any) {
    galleryBridgeProxyFailures += 1;
    galleryBridgeProxyBackoffUntil = Date.now() + 2000;
    if (galleryBridgeProxyFailures >= 3 && !isChildProcessAlive(galleryBridgeProcess) && !(await isGalleryBridgeHealthy())) {
      scheduleGalleryBridgeSelfHeal('proxy_failure');
    }
    const response = await fallback();
    response.headers.set('X-Gallery-Fallback', 'bridge-error');
    traceProxy('proxy_error_fallback', {
      status: response.status,
      error: error?.message || String(error),
      failures: galleryBridgeProxyFailures,
      fallback: true,
    }, 0);
    return response;
  }
}

async function proxyGalleryBridgeFsPost(req: Request, targetPath: string): Promise<Response> {
  if (!isChildProcessAlive(galleryBridgeProcess) && !(await isGalleryBridgeHealthy({ allowCached: false }))) {
    await startGalleryBridge().catch(() => undefined);
  }

  const targetUrl = new URL(`${getGalleryBridgeBaseUrl()}${targetPath}`);
  const headers = new Headers(req.headers);
  headers.delete('host');
  headers.delete('origin');
  headers.delete('referer');

  try {
    const upstream = await fetch(targetUrl.toString(), {
      method: 'POST',
      headers,
      body: await req.arrayBuffer(),
      signal: AbortSignal.timeout(30000),
    });
    const responseHeaders = new Headers(upstream.headers);
    responseHeaders.set('X-Gallery-Proxy-Ms', '0');
    return new Response(upstream.body, {
      status: upstream.status,
      headers: responseHeaders,
    });
  } catch (error: any) {
    return json({
      error: error?.message || 'Gallery bridge request failed',
      target: targetUrl.toString(),
    }, 502);
  }
}

async function getBackendStatusAsync(backend: 'comfyui' | 'aitoolkit', portTimeoutMs = 3000) {
  let proc, startTime, port;

  if (backend === 'comfyui') {
    const config = getComfyProxyTarget();
    proc = comfyProcess;
    startTime = comfyStartTime;
    port = config.port;
  } else {
    const config = getBackendConfig().aitoolkit;
    proc = aitoolkitProcess;
    startTime = aitoolkitStartTime;
    port = config.port;
  }

  const trackedProc = (proc || null) as ChildProcess | null;
  const processRunning = isChildProcessAlive(trackedProc);

  if (backend === 'aitoolkit') {
    const portOpen = await isPortOpen(port, portTimeoutMs);
    return {
      running: processRunning || portOpen,
      healthy: portOpen,
      port,
      pid: trackedProc?.pid ?? null,
      uptime: startTime ? Math.floor((Date.now() - startTime) / 1000) : (portOpen ? 999 : 0),
      ownership: processRunning ? 'owned' : (portOpen ? 'external-compatible' : 'none'),
      ownerPid: processRunning ? trackedProc?.pid ?? null : null,
      trackedPid: trackedProc?.pid ?? null,
      signaturePids: [],
      portPids: [],
    };
  }

  const ownership = getComfyProcessOwnershipSnapshot();
  const portOpen = ownership.portOpen || await isPortOpen(port, portTimeoutMs);
  return {
    running: processRunning || portOpen,
    healthy: portOpen,
    port,
    pid: trackedProc?.pid ?? null,
    uptime: startTime ? Math.floor((Date.now() - startTime) / 1000) : (portOpen ? 999 : 0),
    ownership: ownership.kind,
    ownerPid: ownership.trackedAlive
      ? ownership.trackedPid
      : (ownership.signaturePids[0] ?? ownership.portPids[0] ?? null),
    trackedPid: ownership.trackedPid,
    signaturePids: ownership.signaturePids,
    portPids: ownership.portPids,
  };
}

const BACKEND_STATUS_REFRESH_MS = 15000;
const BACKEND_STATUS_STALE_MS = 30000;
const DEFAULT_BACKEND_STATUS = { running: false, healthy: false, pid: null, uptime: 0 };
let backendStatusSamplerTimer: NodeJS.Timeout | null = null;
let backendStatusRefreshInFlight: Promise<void> | null = null;
let cachedBackendControlPlane = {
  sampledAt: '',
  sampleAgeMs: 0,
  stale: true,
  refreshing: false,
  backends: {
    comfyui: DEFAULT_BACKEND_STATUS as any,
    aitoolkit: DEFAULT_BACKEND_STATUS as any,
    gallery: {
      running: false,
      healthy: false,
      pid: null,
      uptime: 0,
      host: getGalleryBridgeHostForClient(),
      port: GALLERY_BRIDGE_PORT,
      url: GALLERY_IN_PROCESS_WORKSPACE_URL,
      mode: 'in-process-fallback',
      bridgeEntry: GALLERY_BRIDGE_SERVER_ENTRY,
      fallbackUrl: GALLERY_IN_PROCESS_WORKSPACE_URL,
      publicDir: GALLERY_PUBLIC_DIR,
    } as any,
  },
};

function withBackendStatusFreshness() {
  const sampledAtMs = cachedBackendControlPlane.sampledAt
    ? Date.parse(cachedBackendControlPlane.sampledAt)
    : 0;
  const sampleAgeMs = Number.isFinite(sampledAtMs) && sampledAtMs > 0
    ? Math.max(0, Date.now() - sampledAtMs)
    : 0;
  return {
    ...cachedBackendControlPlane,
    sampleAgeMs,
    stale: !sampledAtMs || sampleAgeMs > BACKEND_STATUS_STALE_MS,
    refreshing: Boolean(backendStatusRefreshInFlight),
  };
}

function refreshBackendControlPlaneStatus(): Promise<void> {
  if (backendStatusRefreshInFlight) return backendStatusRefreshInFlight;
  backendStatusRefreshInFlight = (async () => {
    const safeStatus = async <T,>(promise: Promise<T>, fallback: T): Promise<T> => {
      try {
        return await promise;
      } catch {
        return fallback;
      }
    };
    const [comfyui, aitoolkit, gallery] = await Promise.all([
      safeStatus(getBackendStatusAsync('comfyui', 900), cachedBackendControlPlane.backends.comfyui || DEFAULT_BACKEND_STATUS),
      safeStatus(getBackendStatusAsync('aitoolkit', 900), cachedBackendControlPlane.backends.aitoolkit || DEFAULT_BACKEND_STATUS),
      safeStatus(getGalleryStatusAsync(), cachedBackendControlPlane.backends.gallery),
    ]);
    cachedBackendControlPlane = {
      sampledAt: new Date().toISOString(),
      sampleAgeMs: 0,
      stale: false,
      refreshing: false,
      backends: {
        comfyui,
        aitoolkit,
        gallery,
      },
    };
  })();
  backendStatusRefreshInFlight
    .catch((error) => {
      console.warn('[Status] Backend status sampler warning:', error);
    })
    .finally(() => {
      backendStatusRefreshInFlight = null;
    });
  return backendStatusRefreshInFlight;
}

async function forceRefreshBackendControlPlaneStatus(): Promise<void> {
  const activeRefresh = backendStatusRefreshInFlight;
  if (activeRefresh) {
    try {
      await activeRefresh;
    } catch {
      // A forced refresh below gets one clean attempt after a failed sampler pass.
    }
    if (backendStatusRefreshInFlight === activeRefresh) {
      backendStatusRefreshInFlight = null;
    }
  }
  await refreshBackendControlPlaneStatus();
}

function getCachedBackendControlPlaneStatus() {
  const status = withBackendStatusFreshness();
  if (status.stale || status.sampleAgeMs >= BACKEND_STATUS_REFRESH_MS) {
    void refreshBackendControlPlaneStatus();
  }
  return status;
}

function startBackendStatusSampler() {
  if (backendStatusSamplerTimer) return;
  void refreshBackendControlPlaneStatus();
  backendStatusSamplerTimer = setInterval(() => {
    void refreshBackendControlPlaneStatus();
  }, BACKEND_STATUS_REFRESH_MS);
  (backendStatusSamplerTimer as any).unref?.();
}

function stopBackendStatusSampler() {
  if (!backendStatusSamplerTimer) return;
  clearInterval(backendStatusSamplerTimer);
  backendStatusSamplerTimer = null;
}

