async function handleUmbraUiInpaintSubmit(req: Request): Promise<Response> {
  try {
    const form = await req.formData();
    const sourceFile = form.get('source') as any;
    const maskFile = form.get('mask') as any;
    const isUpload = (candidate: any) => candidate
      && typeof candidate === 'object'
      && typeof candidate.name === 'string'
      && typeof candidate.arrayBuffer === 'function'
      && Number(candidate.size) > 0;
    if (!isUpload(sourceFile)) return json({ success: false, error: 'Choose an image to inpaint.' }, 400);
    if (!isUpload(maskFile)) return json({ success: false, error: 'Paint or define an inpaint mask first.' }, 400);
    if (!UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(sourceFile.name).toLowerCase())) {
      return json({ success: false, error: 'The inpaint source is not a supported image.' }, 400);
    }
    if (!UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(maskFile.name).toLowerCase())) {
      return json({ success: false, error: 'The inpaint mask is not a supported image.' }, 400);
    }
    const fillModeRaw = String(form.get('fillMode') || 'navier-stokes').trim().toLowerCase();
    const fillMode = fillModeRaw === 'neutral' || fillModeRaw === 'telea' || fillModeRaw === 'color' || fillModeRaw === 'tile' || fillModeRaw === 'lama'
      ? fillModeRaw
      : 'navier-stokes';
    const infillColorRaw = String(form.get('infillColor') || '#7f7f7f').trim();
    const infillColor = /^#[0-9a-f]{6}$/i.test(infillColorRaw) ? infillColorRaw.toLowerCase() : '#7f7f7f';
    const modelFamily = String(form.get('modelFamily') || '').trim();
    const modelSource = normalizeUmbraUiPipelineModelSources(form.get('modelSource') || 'checkpoint')[0] || 'checkpoint';
    const resolvedPipeline = await resolveUmbraUiPipeline('inpainting', modelFamily, modelSource);
    const canvasCapabilities = resolvedPipeline.pipeline.inpaintCanvas;
    const declaredLayerLimit = (capability: { support?: string; maxLayers?: number } | undefined) => (
      capability?.support === 'unsupported'
        ? 0
        : Math.max(0, Math.floor(Number(capability?.maxLayers) || 0))
    );
    const assertLayerLimit = (kind: string, count: number, limit: number) => {
      if (count <= limit) return;
      if (limit <= 0) throw new Error(`The selected locked pipeline does not support ${kind}.`);
      throw new Error(`The selected locked pipeline supports at most ${limit} ${kind}.`);
    };
    let regionalPayload: any[] = [];
    try {
      const parsed = JSON.parse(String(form.get('regionalGuidance') || '[]'));
      regionalPayload = Array.isArray(parsed) ? parsed : [];
    } catch {
      return json({ success: false, error: 'Regional guidance is not valid JSON.' }, 400);
    }
    assertLayerLimit('regional guidance layers', regionalPayload.length, declaredLayerLimit(canvasCapabilities?.regionalGuidance));
    const regionalCapability = canvasCapabilities?.regionalGuidance;
    const regionalGuidance = regionalPayload.map((rawRegion, index) => {
      const id = String(rawRegion?.id || `region-${index + 1}`).trim().replace(/[^a-z0-9._-]+/gi, '-').slice(0, 120);
      const maskFile = form.get(`regionalMask:${id}`) as any;
      if (!id || !isUpload(maskFile)) throw new Error(`Regional guidance ${index + 1} is missing its mask.`);
      if (!UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(maskFile.name).toLowerCase())) {
        throw new Error(`Regional guidance ${index + 1} has an unsupported mask format.`);
      }
      const beginStepPercent = Math.max(0, Math.min(1, finiteNumberOrFallback(rawRegion?.beginStepPercent, 0)));
      const endStepPercent = Math.max(beginStepPercent, Math.min(1, finiteNumberOrFallback(rawRegion?.endStepPercent, 1)));
      const positivePrompt = String(rawRegion?.positivePrompt || '').trim().slice(0, 32000);
      const negativePrompt = String(rawRegion?.negativePrompt || '').trim().slice(0, 32000);
      const autoNegative = rawRegion?.autoNegative === true;
      if (positivePrompt && regionalCapability?.positivePrompt !== true) {
        throw new Error(`Regional guidance ${index + 1} uses a positive prompt that the selected locked pipeline does not support.`);
      }
      if (negativePrompt && regionalCapability?.negativePrompt !== true) {
        throw new Error(`Regional guidance ${index + 1} uses a negative prompt that the selected locked pipeline does not support.`);
      }
      if (autoNegative && regionalCapability?.autoNegative !== true) {
        throw new Error(`Regional guidance ${index + 1} uses automatic negative conditioning that the selected locked pipeline does not support.`);
      }
      return {
        id,
        name: String(rawRegion?.name || `Region ${index + 1}`).trim().slice(0, 160) || `Region ${index + 1}`,
        mask: {
          name: maskFile.name,
          read: () => maskFile.arrayBuffer(),
        },
        positivePrompt,
        negativePrompt,
        autoNegative,
        weight: Math.max(0, Math.min(10, finiteNumberOrFallback(rawRegion?.weight, 0))),
        beginStepPercent,
        endStepPercent,
      };
    });
    let controlPayload: any[] = [];
    try {
      const parsed = JSON.parse(String(form.get('controlLayers') || '[]'));
      controlPayload = Array.isArray(parsed) ? parsed : [];
    } catch {
      return json({ success: false, error: 'Control layers are not valid JSON.' }, 400);
    }
    assertLayerLimit('control layers', controlPayload.length, declaredLayerLimit(canvasCapabilities?.controlLayers));
    const controlTypes = new Set(['raw', 'canny', 'depth', 'pose', 'lineart', 'lineart_anime', 'softedge', 'scribble', 'face_mesh', 'mlsd', 'normal_map', 'pidi', 'content_shuffle']);
    const controlAdapterTypes = new Set(['controlnet', 't2i_adapter', 'control_lora', 'z_image_control', 'anima_lllite']);
    const controlModes = new Set(['balanced', 'more_prompt', 'more_control', 'unbalanced']);
    const declaredControlAdapterTypes = new Set<string>(canvasCapabilities?.controlLayers?.adapterTypes || []);
    const declaredControlModes = new Set<string>(canvasCapabilities?.controlLayers?.modes || []);
    const controlLayers = controlPayload.map((rawControl, index) => {
      const id = String(rawControl?.id || `control-${index + 1}`).trim().replace(/[^a-z0-9._-]+/gi, '-').slice(0, 120);
      const imageFile = form.get(`controlImage:${id}`) as any;
      if (!id || !isUpload(imageFile)) throw new Error(`Control layer ${index + 1} is missing its image.`);
      if (!UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(imageFile.name).toLowerCase())) {
        throw new Error(`Control layer ${index + 1} has an unsupported image format.`);
      }
      const controlTypeRaw = String(rawControl?.controlType || 'raw').trim().toLowerCase();
      const controlType = (controlTypes.has(controlTypeRaw) ? controlTypeRaw : 'raw') as UmbraUiInpaintControlLayer['controlType'];
      const adapterTypeRaw = String(rawControl?.adapterType || 'controlnet').trim().toLowerCase();
      if (!controlAdapterTypes.has(adapterTypeRaw)) {
        throw new Error(`Control layer ${index + 1} uses an unknown adapter type: ${adapterTypeRaw || '(empty)'}.`);
      }
      if (!declaredControlAdapterTypes.has(adapterTypeRaw)) {
        throw new Error(`Control layer ${index + 1} uses ${adapterTypeRaw}, which the selected locked pipeline does not support.`);
      }
      const controlModeRaw = String(rawControl?.controlMode || 'balanced').trim().toLowerCase();
      if (!controlModes.has(controlModeRaw)) {
        throw new Error(`Control layer ${index + 1} uses an unknown control mode: ${controlModeRaw || '(empty)'}.`);
      }
      if (!declaredControlModes.has(controlModeRaw)) {
        throw new Error(`Control layer ${index + 1} uses ${controlModeRaw}, which the selected locked pipeline does not support.`);
      }
      const beginStepPercent = Math.max(0, Math.min(1, finiteNumberOrFallback(rawControl?.beginStepPercent, 0)));
      const endStepPercent = Math.max(beginStepPercent, Math.min(1, finiteNumberOrFallback(rawControl?.endStepPercent, 1)));
      if (controlType === 'content_shuffle' && adapterTypeRaw !== 't2i_adapter') {
        throw new Error(`Control layer ${index + 1} uses Content Shuffle, which requires a T2I Adapter.`);
      }
      return {
        id,
        name: String(rawControl?.name || `Control ${index + 1}`).trim().slice(0, 160) || `Control ${index + 1}`,
        image: {
          name: imageFile.name,
          read: () => imageFile.arrayBuffer(),
        },
        adapterType: adapterTypeRaw as UmbraUiInpaintControlLayer['adapterType'],
        controlMode: controlModeRaw as UmbraUiInpaintControlLayer['controlMode'],
        controlType,
        modelName: String(rawControl?.modelName || '').trim().replace(/\\/g, '/').slice(0, 500),
        weight: Math.max(0, Math.min(10, finiteNumberOrFallback(rawControl?.weight, 0))),
        beginStepPercent,
        endStepPercent,
        processorResolution: Math.max(64, Math.min(4096, Math.round(finiteNumberOrFallback(rawControl?.processorResolution, 512)))),
        lowThreshold: Math.max(0, Math.min(255, Math.round(finiteNumberOrFallback(rawControl?.lowThreshold, 100)))),
        highThreshold: Math.max(0, Math.min(255, Math.round(finiteNumberOrFallback(rawControl?.highThreshold, 200)))),
        detectBody: rawControl?.detectBody !== false,
        detectFace: rawControl?.detectFace !== false,
        detectHands: rawControl?.detectHands !== false,
        maxFaces: Math.max(1, Math.min(50, Math.round(finiteNumberOrFallback(rawControl?.maxFaces, 10)))),
        minimumConfidence: Math.max(0.1, Math.min(1, finiteNumberOrFallback(rawControl?.minimumConfidence, 0.5))),
        scoreThreshold: Math.max(0.01, Math.min(2, finiteNumberOrFallback(rawControl?.scoreThreshold, 0.1))),
        distanceThreshold: Math.max(0.01, Math.min(20, finiteNumberOrFallback(rawControl?.distanceThreshold, 0.1))),
        normalStrength: Math.max(0, Math.min(Math.PI * 5, finiteNumberOrFallback(rawControl?.normalStrength, Math.PI * 2))),
        backgroundThreshold: Math.max(0, Math.min(1, finiteNumberOrFallback(rawControl?.backgroundThreshold, 0.1))),
        safeMode: rawControl?.safeMode !== false,
        processorSeed: Math.max(0, Math.min(Number.MAX_SAFE_INTEGER, Math.round(finiteNumberOrFallback(rawControl?.processorSeed, 0)))),
      };
    });
    let referencePayload: any[] = [];
    try {
      const parsed = JSON.parse(String(form.get('referenceLayers') || '[]'));
      referencePayload = Array.isArray(parsed) ? parsed : [];
    } catch {
      return json({ success: false, error: 'Reference layers are not valid JSON.' }, 400);
    }
    assertLayerLimit('reference layers', referencePayload.length, declaredLayerLimit(canvasCapabilities?.referenceLayers));
    const referenceMethods = new Set(['style_model', 'ip_adapter', 'flux_redux', 'flux_kontext', 'flux2_reference', 'qwen_image_reference', 'hidream_o1_reference']);
    const declaredReferenceMethods = new Set<string>(canvasCapabilities?.referenceLayers?.methods || []);
    const ipAdapterWeightTypes = new Set(['linear', 'ease in', 'ease out', 'ease in-out', 'reverse in-out', 'weak input', 'weak output', 'weak middle', 'strong middle', 'style transfer', 'composition', 'strong style transfer', 'style and composition', 'style transfer precise', 'composition precise']);
    const ipAdapterCombineModes = new Set(['concat', 'add', 'subtract', 'average', 'norm average']);
    const ipAdapterScalingModes = new Set(['V only', 'K+V', 'K+V w/ C penalty', 'K+mean(V) w/ C penalty']);
    const referenceLayers = referencePayload.map((rawReference, index): UmbraUiInpaintReferenceLayer => {
      const id = String(rawReference?.id || `reference-${index + 1}`).trim().replace(/[^a-z0-9._-]+/gi, '-').slice(0, 120);
      const imageFile = form.get(`referenceImage:${id}`) as any;
      const maskFile = rawReference?.hasMask === true ? form.get(`referenceMask:${id}`) as any : null;
      if (!id || !isUpload(imageFile)) throw new Error(`Reference layer ${index + 1} is missing its image.`);
      if (!UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(imageFile.name).toLowerCase())) {
        throw new Error(`Reference layer ${index + 1} has an unsupported image format.`);
      }
      if (maskFile && (!isUpload(maskFile) || !UMBRA_UI_INPAINT_IMAGE_EXTENSIONS.has(extname(maskFile.name).toLowerCase()))) {
        throw new Error(`Reference layer ${index + 1} has an unsupported or missing influence mask.`);
      }
      const methodRaw = String(rawReference?.method || 'style_model').trim().toLowerCase();
      if (!referenceMethods.has(methodRaw)) {
        throw new Error(`Reference layer ${index + 1} uses an unknown reference method: ${methodRaw || '(empty)'}.`);
      }
      if (!declaredReferenceMethods.has(methodRaw)) {
        throw new Error(`Reference layer ${index + 1} uses ${methodRaw}, which the selected locked pipeline does not support.`);
      }
      const beginStepPercent = Math.max(0, Math.min(1, finiteNumberOrFallback(rawReference?.beginStepPercent, 0)));
      const endStepPercent = Math.max(beginStepPercent, Math.min(1, finiteNumberOrFallback(rawReference?.endStepPercent, 1)));
      const ipAdapterWeightTypeRaw = String(rawReference?.ipAdapterWeightType || 'linear').trim();
      const ipAdapterCombineEmbedsRaw = String(rawReference?.ipAdapterCombineEmbeds || 'concat').trim();
      const ipAdapterEmbedsScalingRaw = String(rawReference?.ipAdapterEmbedsScaling || 'V only').trim();
      return {
        id,
        name: String(rawReference?.name || `Reference ${index + 1}`).trim().slice(0, 160) || `Reference ${index + 1}`,
        image: {
          name: imageFile.name,
          read: () => imageFile.arrayBuffer(),
        },
        ...(maskFile ? {
          mask: {
            name: maskFile.name,
            read: () => maskFile.arrayBuffer(),
          },
        } : {}),
        method: methodRaw as UmbraUiInpaintReferenceLayer['method'],
        modelName: String(rawReference?.modelName || '').trim().replace(/\\/g, '/').slice(0, 500),
        visionModelName: String(rawReference?.visionModelName || '').trim().replace(/\\/g, '/').slice(0, 500),
        crop: rawReference?.crop === 'none' ? 'none' : 'center',
        strengthType: rawReference?.strengthType === 'attn_bias' ? 'attn_bias' : 'multiply',
        weight: methodRaw === 'ip_adapter'
          ? Math.max(-1, Math.min(5, finiteNumberOrFallback(rawReference?.weight, 0)))
          : Math.max(0, Math.min(10, finiteNumberOrFallback(rawReference?.weight, 0))),
        beginStepPercent,
        endStepPercent,
        ipAdapterWeightType: (ipAdapterWeightTypes.has(ipAdapterWeightTypeRaw) ? ipAdapterWeightTypeRaw : 'linear') as UmbraUiInpaintReferenceLayer['ipAdapterWeightType'],
        ipAdapterCombineEmbeds: (ipAdapterCombineModes.has(ipAdapterCombineEmbedsRaw) ? ipAdapterCombineEmbedsRaw : 'concat') as UmbraUiInpaintReferenceLayer['ipAdapterCombineEmbeds'],
        ipAdapterEmbedsScaling: (ipAdapterScalingModes.has(ipAdapterEmbedsScalingRaw) ? ipAdapterEmbedsScalingRaw : 'V only') as UmbraUiInpaintReferenceLayer['ipAdapterEmbedsScaling'],
      };
    });
    const requestedWidth = Math.max(64, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('width'), 1024))));
    const requestedHeight = Math.max(64, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('height'), 1024))));
    const resolutionCapability = resolvedPipeline.pipeline.capabilities?.resolution;
    const resolutionStep = Math.max(1, Math.round(finiteNumberOrFallback(resolutionCapability?.step, 8)));
    const minimumWidth = Math.max(64, Math.round(finiteNumberOrFallback(resolutionCapability?.minimumWidth, 64)));
    const minimumHeight = Math.max(64, Math.round(finiteNumberOrFallback(resolutionCapability?.minimumHeight, 64)));
    const maximumWidth = Math.max(minimumWidth, Math.round(finiteNumberOrFallback(resolutionCapability?.maximumWidth, 16384)));
    const maximumHeight = Math.max(minimumHeight, Math.round(finiteNumberOrFallback(resolutionCapability?.maximumHeight, 16384)));
    if (requestedWidth < minimumWidth || requestedWidth > maximumWidth
      || requestedHeight < minimumHeight || requestedHeight > maximumHeight) {
      throw new Error(`The selected pipeline requires dimensions between ${minimumWidth}x${minimumHeight} and ${maximumWidth}x${maximumHeight}.`);
    }
    if (requestedWidth % resolutionStep !== 0 || requestedHeight % resolutionStep !== 0) {
      throw new Error(`The selected pipeline requires width and height aligned to ${resolutionStep} pixels.`);
    }
    const settings: UmbraUiInpaintSettings = {
      workflowId: resolvedPipeline.loaded.item.id,
      canvasProjectId: String(form.get('canvasProjectId') || '').trim().slice(0, 160),
      operationMode: String(form.get('operationMode') || '').trim() === 'outpaint' ? 'outpaint' : 'inpaint',
      generationRegionX: Math.max(0, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('generationRegionX'), 0)))),
      generationRegionY: Math.max(0, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('generationRegionY'), 0)))),
      generationRegionWidth: Math.max(1, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('generationRegionWidth'), requestedWidth)))),
      generationRegionHeight: Math.max(1, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('generationRegionHeight'), requestedHeight)))),
      submissionRegionX: Math.max(0, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('submissionRegionX'), 0)))),
      submissionRegionY: Math.max(0, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('submissionRegionY'), 0)))),
      submissionRegionWidth: Math.max(1, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('submissionRegionWidth'), requestedWidth)))),
      submissionRegionHeight: Math.max(1, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('submissionRegionHeight'), requestedHeight)))),
      modelFamily: resolvedPipeline.pipeline.modelFamily,
      modelSource,
      inpaintAdapter: resolvedPipeline.pipeline.inpaintAdapter
        || (modelSource === 'checkpoint' ? 'classic_conditioning' : 'native_edit'),
      adapterModelName: String(resolvedPipeline.pipeline.defaults?.adapterModelName || '').trim(),
      prompt: String(form.get('prompt') || '').trim(),
      negativePrompt: String(form.get('negativePrompt') || '').trim(),
      checkpointName: String(form.get('checkpointName') || '').trim(),
      clipSkip: Math.max(1, Math.min(12, Math.round(finiteNumberOrFallback(form.get('clipSkip'), 1)))),
      seed: Math.max(0, Math.min(Number.MAX_SAFE_INTEGER, Math.floor(finiteNumberOrFallback(form.get('seed'), 0)))),
      seedMode: normalizePPSeedControlMode(form.get('seedMode')),
      seedIncrement: normalizePPSeedIncrement(form.get('seedIncrement')),
      steps: Math.max(1, Math.min(10000, Math.round(finiteNumberOrFallback(form.get('steps'), 35)))),
      cfg: Math.max(0, Math.min(100, finiteNumberOrFallback(form.get('cfg'), 4))),
      samplerName: String(form.get('samplerName') || 'er_sde').trim() || 'er_sde',
      scheduler: String(form.get('scheduler') || 'simple').trim() || 'simple',
      denoise: Math.max(0.01, Math.min(1, finiteNumberOrFallback(form.get('denoise'), 0.8))),
      samples: Math.max(1, Math.min(8, Math.round(finiteNumberOrFallback(form.get('samples'), 1)))),
      width: requestedWidth,
      height: requestedHeight,
      maskGrow: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(form.get('maskGrow'), 0)))),
      maskFeather: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(form.get('maskFeather'), 0)))),
      canvasMaskGrow: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(
        form.get('canvasMaskGrow'),
        finiteNumberOrFallback(form.get('maskGrow'), 0),
      )))),
      canvasMaskFeather: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(
        form.get('canvasMaskFeather'),
        finiteNumberOrFallback(form.get('maskFeather'), 0),
      )))),
      contextPadding: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(form.get('contextPadding'), 0)))),
      processingScaleMode: String(form.get('processingScaleMode') || '').trim() === 'auto'
        ? 'auto'
        : String(form.get('processingScaleMode') || '').trim() === 'manual' ? 'manual' : 'none',
      processingWidth: Math.max(64, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('processingWidth'), requestedWidth)))),
      processingHeight: Math.max(64, Math.min(16384, Math.round(finiteNumberOrFallback(form.get('processingHeight'), requestedHeight)))),
      coherenceMode: String(form.get('coherenceMode') || '').trim() === 'gaussian'
        ? 'gaussian'
        : String(form.get('coherenceMode') || '').trim() === 'box'
          ? 'box'
          : String(form.get('coherenceMode') || '').trim() === 'staged' ? 'staged' : 'none',
      coherenceEdgeSize: Math.max(0, Math.min(2048, Math.round(finiteNumberOrFallback(form.get('coherenceEdgeSize'), 16)))),
      coherenceMinimumDenoise: Math.max(0, Math.min(1, finiteNumberOrFallback(form.get('coherenceMinimumDenoise'), 0))),
      fillMode,
      infillColor,
      infillTileSize: Math.max(8, Math.min(512, Math.round(finiteNumberOrFallback(form.get('infillTileSize'), 32)))),
      inpaintModelName: String(form.get('inpaintModelName') || '').trim().replace(/\\/g, '/').slice(0, 500),
      seamlessX: String(form.get('seamlessX') || '').trim().toLowerCase() === 'true',
      seamlessY: String(form.get('seamlessY') || '').trim().toLowerCase() === 'true',
      outputOnlyMaskedRegions: String(form.get('outputOnlyMaskedRegions') || '').trim().toLowerCase() === 'true',
      semanticCutout: String(form.get('semanticCutout') || '').trim().toLowerCase() === 'true',
      colorMatch: Math.max(0, Math.min(1, finiteNumberOrFallback(form.get('colorMatch'), 0))),
      differentialStrength: Math.max(0, Math.min(1, finiteNumberOrFallback(form.get('differentialStrength'), 1))),
      softInpaintEnabled: String(form.get('softInpaintEnabled') || '').trim().toLowerCase() === 'true',
      softInpaintPreservation: Math.max(0, Math.min(1, finiteNumberOrFallback(form.get('softInpaintPreservation'), 0.5))),
      softInpaintTransitionContrast: Math.max(0.25, Math.min(8, finiteNumberOrFallback(form.get('softInpaintTransitionContrast'), 2))),
      softInpaintMaskInfluence: Math.max(0, Math.min(1, finiteNumberOrFallback(form.get('softInpaintMaskInfluence'), 0))),
      regionalGuidance,
      controlLayers,
      referenceLayers,
    };
    if (!settings.checkpointName) return json({ success: false, error: 'Choose a primary model for inpainting.' }, 400);
    if (!settings.prompt) return json({ success: false, error: 'Enter an inpaint prompt.' }, 400);

    const source: UmbraUiInpaintSource = {
      name: sourceFile.name,
      read: () => sourceFile.arrayBuffer(),
    };
    const mask: UmbraUiInpaintSource = {
      name: maskFile.name,
      read: () => maskFile.arrayBuffer(),
    };
    const job = await umbraUiInpaintService.submit(source, mask, settings);
    return json({ success: true, job });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to queue inpaint job.') }, 400);
  }
}

function listUmbraUiInpaintModels(): string[] {
  const comfyRoot = getComfyToolRootFast();
  if (!comfyRoot) return [];
  const root = join(comfyRoot, 'models', 'inpaint');
  if (!existsSync(root)) return [];
  const supported = new Set(['.pt', '.pth', '.safetensors', '.patch']);
  const results: string[] = [];
  const pending = [root];
  while (pending.length > 0 && results.length < 2000) {
    const folder = pending.pop()!;
    let entries: Dirent[] = [];
    try {
      entries = readdirSync(folder, { withFileTypes: true });
    } catch {
      continue;
    }
    for (const entry of entries) {
      if (entry.isSymbolicLink()) continue;
      const fullPath = join(folder, entry.name);
      if (entry.isDirectory()) {
        pending.push(fullPath);
        continue;
      }
      if (!entry.isFile() || !supported.has(extname(entry.name).toLowerCase())) continue;
      const modelName = relative(root, fullPath).replace(/\\/g, '/');
      if (modelName && !modelName.startsWith('../')) results.push(modelName);
    }
  }
  return Array.from(new Set(results)).sort((left, right) => left.localeCompare(right));
}

function handleUmbraUiInpaintJob(path: string): Response {
  const jobId = decodeURIComponent(path.slice('/api/umbra-ui/inpaint/jobs/'.length)).trim();
  if (!jobId) return json({ success: false, error: 'Inpaint job id is required.' }, 400);
  const job = umbraUiInpaintService.getJob(jobId);
  if (!job) return json({ success: false, error: 'Inpaint job was not found.' }, 404);
  return json({ success: true, job });
}

async function handleUmbraUiInpaintJobCancel(path: string): Promise<Response> {
  const suffix = path.slice('/api/umbra-ui/inpaint/jobs/'.length);
  const jobId = decodeURIComponent(suffix.replace(/\/cancel$/, '')).trim();
  if (!jobId) return json({ success: false, error: 'Inpaint job id is required.' }, 400);
  const job = await umbraUiInpaintService.cancel(jobId);
  if (!job) return json({ success: false, error: 'Inpaint job was not found.' }, 404);
  return json({ success: true, job });
}

