async function handleUmbraUiInpaintProjectSave(req: Request, projectId: string): Promise<Response> {
  try {
    const form = await req.formData();
    const rawDocument = form.get('document');
    if (typeof rawDocument !== 'string' || !rawDocument.trim()) {
      return json({ success: false, error: 'The inpaint project document is missing.' }, 400);
    }
    const document = JSON.parse(rawDocument);
    const assets: Array<{ key: string; name: string; bytes: Uint8Array }> = [];
    for (const [field, value] of form.entries()) {
      if (!field.startsWith('asset:') || typeof value === 'string') continue;
      const key = decodeURIComponent(field.slice('asset:'.length)).trim();
      if (!key || typeof (value as any).arrayBuffer !== 'function') continue;
      assets.push({
        key,
        name: String((value as any).name || `${key}.png`),
        bytes: new Uint8Array(await (value as any).arrayBuffer()),
      });
      if (assets.length > 1024) throw new Error('An inpaint project cannot contain more than 1024 uploaded assets.');
    }
    const project = await umbraUiCanvasProjectService.save(projectId, document, assets);
    return json({ success: true, project });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to save the inpaint project.') }, 400);
  }
}

