async function handleUmbraUiInpaintProjectAsset(projectId: string, filename: string, thumbnailMode = false): Promise<Response> {
  try {
    const asset = await umbraUiCanvasProjectService.resolveAsset(projectId, filename);
    if (!asset) return new Response('Not found', { status: 404 });
    if (thumbnailMode) {
      const thumbnail = await thumbnailService.generateThumbnail(asset.path, {
        size: 'small',
        quality: 82,
        format: 'webp',
      });
      if (thumbnail) {
        return new Response(new Uint8Array(thumbnail), {
          headers: {
            'Cache-Control': 'private, max-age=86400',
            'Content-Length': String(thumbnail.byteLength),
            'Content-Type': 'image/webp',
          },
        });
      }
    }
    return new Response(Bun.file(asset.path), {
      headers: {
        'Cache-Control': 'private, max-age=0, must-revalidate',
        'Content-Length': String(asset.size),
      },
    });
  } catch {
    return new Response('Not found', { status: 404 });
  }
}

const UMBRA_UI_REPLACED_SOURCE_RECOVERY_ROOT = join(USER_DIR, 'Recovery', 'Replaced Sources');

function getUmbraUiReplaceableMediaRoots(): string[] {
  const roots = [
    resolvePathCandidate(getDefaultOutputRootPath()),
    resolvePathCandidate(LEGACY_OUTPUT_ROOT),
    resolve(USER_DIR, 'Outputs'),
    ...getConfiguredExternalRoots().map((root) => resolvePathCandidate(root)),
  ];
  return Array.from(new Set(roots.map((root) => resolve(root))));
}

async function handleUmbraUiReplaceImageSource(req: Request): Promise<Response> {
  try {
    const body = await req.json() as Record<string, unknown>;
    const original = resolvePath(String(body.originalPath || '').trim());
    const result = resolvePath(String(body.resultPath || '').trim());
    if (!original || !result) {
      return json({ success: false, error: 'The original or completed image path is not available to Umbra.' }, 403);
    }

    const replaced = await replaceUmbraUiImageSource({
      originalPath: original.fullPath,
      resultPath: result.fullPath,
      recoveryRoot: UMBRA_UI_REPLACED_SOURCE_RECOVERY_ROOT,
      allowedRoots: getUmbraUiReplaceableMediaRoots(),
    });
    const replacementStat = statSync(replaced.originalPath);
    const replacementCreatedMs = Number.isFinite(replacementStat.birthtimeMs) && replacementStat.birthtimeMs > 0
      ? replacementStat.birthtimeMs
      : (replacementStat.ctimeMs || replacementStat.mtimeMs);
    const replacementRevision = [
      Math.max(0, Math.trunc(replacementCreatedMs)),
      Math.max(0, Math.trunc(replacementStat.mtimeMs)),
      Math.max(0, Math.trunc(replacementStat.ctimeMs)),
      Math.max(0, Math.trunc(replacementStat.size)),
    ].join('-');
    await thumbnailService.clearCacheForPaths([replaced.originalPath]).catch(() => undefined);
    invalidateFsListCacheForPaths([
      toClientPath(replaced.originalPath),
      toClientPath(dirname(replaced.originalPath)),
    ], 'umbra-ui-source-replaced');

    return json({
      success: true,
      path: toClientPath(replaced.originalPath),
      backupPath: toClientPath(replaced.recoveryPath),
      converted: replaced.converted,
      createdMs: replacementCreatedMs,
      modifiedMs: replacementStat.mtimeMs,
      size: replacementStat.size,
      revision: replacementRevision,
    });
  } catch (error: any) {
    return json({
      success: false,
      error: String(error?.message || error || 'Failed to replace the original image.'),
    }, 400);
  }
}

async function handleUmbraUiCanvasSave(req: Request): Promise<Response> {
  try {
    const form = await req.formData();
    const image = form.get('image') as any;
    if (!image || typeof image.arrayBuffer !== 'function' || Number(image.size) <= 0) {
      return json({ success: false, error: 'A rendered canvas PNG is required.' }, 400);
    }
    if (Number(image.size) > 256 * 1024 * 1024) {
      return json({ success: false, error: 'The rendered canvas exceeds the 256 MB save limit.' }, 413);
    }
    let png = Buffer.from(await image.arrayBuffer());
    if (png.length < 8 || !png.subarray(0, 8).equals(Buffer.from([137, 80, 78, 71, 13, 10, 26, 10]))) {
      return json({ success: false, error: 'The rendered canvas is not a valid PNG.' }, 400);
    }

    const metadataText = String(form.get('metadata') || '').trim();
    if (Buffer.byteLength(metadataText, 'utf8') > 256 * 1024) {
      return json({ success: false, error: 'Canvas metadata exceeds the 256 KB limit.' }, 400);
    }
    let metadata: Record<string, unknown> = {};
    if (metadataText) {
      const parsed = JSON.parse(metadataText);
      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
        return json({ success: false, error: 'Canvas metadata must be a JSON object.' }, 400);
      }
      metadata = parsed as Record<string, unknown>;
    }
    const operationMode = String(metadata.operationMode || '').trim() === 'outpaint' ? 'outpaint' : 'inpaint';
    const prompt = String(metadata.prompt || '').trim().slice(0, 64_000);
    const negativePrompt = String(metadata.negativePrompt || '').trim().slice(0, 64_000);
    const checkpointName = String(metadata.checkpointName || '').trim().slice(0, 1000);
    const width = Math.max(1, Math.min(16384, Math.round(Number(metadata.width) || 1)));
    const height = Math.max(1, Math.min(16384, Math.round(Number(metadata.height) || 1)));
    const fillModeValue = String(metadata.fillMode || '').trim();
    const fillMode = ['neutral', 'telea', 'navier-stokes', 'color', 'tile', 'lama'].includes(fillModeValue)
      ? fillModeValue
      : 'neutral';
    const processingScaleModeValue = String(metadata.processingScaleMode || '').trim();
    const processingScaleMode = ['none', 'auto', 'manual'].includes(processingScaleModeValue)
      ? processingScaleModeValue
      : 'none';
    const coherenceModeValue = String(metadata.coherenceMode || '').trim();
    const coherenceMode = ['none', 'gaussian', 'box', 'staged'].includes(coherenceModeValue)
      ? coherenceModeValue
      : 'none';
    const loras = Array.isArray(metadata.loras)
      ? metadata.loras.map((candidate, index) => {
        const entry = candidate && typeof candidate === 'object' && !Array.isArray(candidate)
          ? candidate as Record<string, unknown>
          : {};
        const strengthModel = Math.max(-10, Math.min(10, finiteNumberOrFallback(entry.strengthModel, 1)));
        return {
          id: String(entry.id || `canvas-lora-${index + 1}`).trim().slice(0, 160),
          name: String(entry.name || '').trim().replace(/\\/g, '/').slice(0, 1000),
          enabled: entry.enabled !== false,
          strengthModel,
          strengthClip: Math.max(-10, Math.min(10, finiteNumberOrFallback(entry.strengthClip, strengthModel))),
        };
      }).filter((entry) => !!entry.name).slice(0, 256)
      : [];
    const inpaintMetadata = {
      version: 4,
      source: 'umbra_ui_canvas',
      canvasProjectId: String(metadata.canvasProjectId || '').trim().slice(0, 160),
      originalSourcePath: String(metadata.originalSourcePath || '').trim().replace(/\\/g, '/').slice(0, 2000),
      documentName: String(metadata.documentName || '').trim().slice(0, 240),
      operationMode,
      regionOnly: metadata.regionOnly === true,
      prompt,
      negativePrompt,
      checkpointName,
      modelFamily: String(metadata.modelFamily || '').trim().slice(0, 160),
      modelSource: String(metadata.modelSource || '').trim().slice(0, 80),
      loras,
      seed: Math.max(0, Math.min(Number.MAX_SAFE_INTEGER, Math.floor(Number(metadata.seed) || 0))),
      seedMode: normalizePPSeedControlMode(metadata.seedMode),
      seedIncrement: normalizePPSeedIncrement(metadata.seedIncrement),
      steps: Math.max(1, Math.min(10000, Math.round(Number(metadata.steps) || 1))),
      cfg: Math.max(0, Math.min(100, Number(metadata.cfg) || 0)),
      clipSkip: Math.max(1, Math.min(12, Math.round(Number(metadata.clipSkip) || 1))),
      samplerName: String(metadata.samplerName || '').trim().slice(0, 160),
      scheduler: String(metadata.scheduler || '').trim().slice(0, 160),
      samples: Math.max(1, Math.min(16, Math.round(Number(metadata.samples) || 1))),
      denoise: Math.max(0.01, Math.min(1, finiteNumberOrFallback(metadata.denoise, 0.8))),
      maskGrow: Math.max(0, Math.min(2048, Math.round(Number(metadata.maskGrow) || 0))),
      maskFeather: Math.max(0, Math.min(2048, Math.round(Number(metadata.maskFeather) || 0))),
      canvasMaskGrow: Math.max(0, Math.min(2048, Math.round(Number(metadata.maskGrow) || 0))),
      canvasMaskFeather: Math.max(0, Math.min(2048, Math.round(Number(metadata.maskFeather) || 0))),
      contextPadding: Math.max(0, Math.min(2048, Math.round(Number(metadata.contextPadding) || 0))),
      processingScaleMode,
      processingWidth: Math.max(64, Math.min(16384, Math.round(Number(metadata.processingWidth) || width))),
      processingHeight: Math.max(64, Math.min(16384, Math.round(Number(metadata.processingHeight) || height))),
      processing: {
        mode: processingScaleMode,
        requestedWidth: Math.max(64, Math.min(16384, Math.round(Number(metadata.processingWidth) || width))),
        requestedHeight: Math.max(64, Math.min(16384, Math.round(Number(metadata.processingHeight) || height))),
        width,
        height,
      },
      coherenceMode,
      coherenceEdgeSize: Math.max(0, Math.min(2048, Math.round(Number(metadata.coherenceEdgeSize) || 0))),
      coherenceMinimumDenoise: Math.max(0, Math.min(1, finiteNumberOrFallback(metadata.coherenceMinimumDenoise, 0))),
      seamlessX: metadata.seamlessX === true,
      seamlessY: metadata.seamlessY === true,
      outputOnlyMaskedRegions: metadata.outputOnlyMaskedRegions === true,
      semanticCutout: metadata.semanticCutout === true,
      fillMode,
      infillColor: /^#[0-9a-f]{6}$/i.test(String(metadata.infillColor || '')) ? String(metadata.infillColor).toLowerCase() : '#7f7f7f',
      infillTileSize: Math.max(8, Math.min(512, Math.round(Number(metadata.infillTileSize) || 32))),
      inpaintModelName: String(metadata.inpaintModelName || '').trim().replace(/\\/g, '/').slice(0, 500),
      colorMatch: Math.max(0, Math.min(1, finiteNumberOrFallback(metadata.colorMatch, 0))),
      differentialStrength: Math.max(0, Math.min(1, finiteNumberOrFallback(metadata.differentialStrength, 1))),
      regionalGuidanceCount: Math.max(0, Math.min(10_000, Math.round(Number(metadata.regionalGuidanceCount) || 0))),
      controlLayerCount: Math.max(0, Math.min(10_000, Math.round(Number(metadata.controlLayerCount) || 0))),
      referenceLayerCount: Math.max(0, Math.min(10_000, Math.round(Number(metadata.referenceLayerCount) || 0))),
      generationRegion: { x: 0, y: 0, width, height },
      savedAt: Date.now(),
    };
    png = injectPngInternationalTextChunk(png, 'umbra_inpaint', JSON.stringify(inpaintMetadata));
    const parameters = [
      prompt,
      negativePrompt ? `Negative prompt: ${negativePrompt}` : '',
      `Steps: ${inpaintMetadata.steps}, Sampler: ${inpaintMetadata.samplerName || 'unknown'}, Schedule type: ${inpaintMetadata.scheduler || 'unknown'}, CFG scale: ${inpaintMetadata.cfg}, Seed: ${inpaintMetadata.seed}, Size: ${width}x${height}${checkpointName ? `, Model: ${checkpointName}` : ''}`,
    ].filter(Boolean).join('\n');
    png = injectPngInternationalTextChunk(png, 'parameters', parameters);

    const configuredOutput = resolveConfiguredPath(String(settingsManager.getAppSettings()['comfyui.externalOutputPath'] || '').trim());
    const outputRoot = configuredOutput || resolvePathCandidate(getDefaultOutputRootPath());
    const dateFolder = new Date().toISOString().slice(0, 10);
    const outputFolder = join(outputRoot, 'Umbra UI', 'canvas', dateFolder);
    await fs.mkdir(outputFolder, { recursive: true });
    const requestedName = String(form.get('name') || inpaintMetadata.documentName || 'Umbra Canvas')
      .replace(/\.png$/i, '')
      .replace(/[^a-z0-9._-]+/gi, '_')
      .replace(/^[_-]+|[_-]+$/g, '')
      .slice(0, 120) || 'Umbra_Canvas';
    const filename = `${requestedName}_${Date.now()}_${randomBytes(3).toString('hex')}.png`;
    const fullPath = join(outputFolder, filename);
    const temporaryPath = `${fullPath}.tmp`;
    await fs.writeFile(temporaryPath, png);
    await fs.rename(temporaryPath, fullPath);
    return json({ success: true, path: toClientPath(fullPath), filename });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to save the canvas to Gallery.') }, 400);
  }
}

const UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS = new Set(['.avif', '.bmp', '.gif', '.jpeg', '.jpg', '.png', '.tif', '.tiff', '.webp']);
const UMBRA_UI_UPSCALE_UPLOAD_ROOT = join(USER_DIR, 'Temp', 'UmbraUiUpscale');
const UMBRA_UI_UPSCALE_MAX_ITEMS = 512;
const UMBRA_UI_UPSCALE_MAX_SOURCE_BYTES = 512 * 1024 * 1024;

function normalizeUmbraUiUpscaleBatchId(value: unknown): string {
  const batchId = String(value || '').trim();
  return /^[a-z0-9][a-z0-9-]{7,95}$/i.test(batchId) ? batchId : '';
}

function sanitizeUmbraUiUpscaleUploadName(value: unknown, fallback: string): string {
  const rawName = basename(String(value || '').trim().replace(/\\/g, '/')) || fallback;
  const extension = extname(rawName).toLowerCase();
  const safeExtension = UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS.has(extension) ? extension : '.png';
  const stem = rawName.slice(0, extension ? -extension.length : undefined)
    .replace(/[^a-z0-9._ -]+/gi, '_')
    .replace(/\s+/g, '_')
    .replace(/^\.+|\.+$/g, '')
    .slice(0, 120) || fallback;
  return `${stem}${safeExtension}`;
}

function resolveUmbraUiUpscaleBatchFolder(batchIdInput: unknown): string | null {
  const batchId = normalizeUmbraUiUpscaleBatchId(batchIdInput);
  if (!batchId) return null;
  const root = resolve(UMBRA_UI_UPSCALE_UPLOAD_ROOT);
  const target = resolve(join(root, batchId));
  const rel = relative(root, target);
  return rel && !rel.startsWith('..') && !isAbsolute(rel) ? target : null;
}

async function collectUmbraUiUpscaleFolderFiles(folderPath: string, maximum: number): Promise<string[]> {
  const results: string[] = [];
  const pending = [folderPath];
  while (pending.length > 0) {
    const current = pending.pop()!;
    const entries = await fs.readdir(current, { withFileTypes: true });
    entries.sort((left, right) => left.name.localeCompare(right.name, undefined, { sensitivity: 'base', numeric: true }));
    for (let index = entries.length - 1; index >= 0; index -= 1) {
      const entry = entries[index];
      if (entry.isSymbolicLink()) continue;
      const fullPath = join(current, entry.name);
      if (entry.isDirectory()) {
        pending.push(fullPath);
        continue;
      }
      if (!entry.isFile() || !UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS.has(extname(entry.name).toLowerCase())) continue;
      results.push(fullPath);
      if (results.length > maximum) {
        throw new Error(`Upscale folders are limited to ${maximum} images per job.`);
      }
    }
  }
  return results.sort((left, right) => left.localeCompare(right, undefined, { sensitivity: 'base', numeric: true }));
}

function quotePowerShellLiteral(value: string): string {
  return `'${String(value || '').replace(/'/g, "''")}'`;
}

async function runNativeFolderPicker(startDir: string, title: string): Promise<string | null> {
  let proc: ReturnType<typeof Bun.spawn> | null = null;
  if (process.platform === 'win32') {
    const script = [
      'Add-Type -AssemblyName System.Windows.Forms',
      '$dialog = New-Object System.Windows.Forms.FolderBrowserDialog',
      `$dialog.Description = ${quotePowerShellLiteral(title)}`,
      '$dialog.ShowNewFolderButton = $true',
      `$dialog.SelectedPath = ${quotePowerShellLiteral(startDir)}`,
      'if ($dialog.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {',
      '  [Console]::OutputEncoding = [System.Text.Encoding]::UTF8',
      '  Write-Output $dialog.SelectedPath',
      '}',
      '$dialog.Dispose()',
    ].join('; ');
    proc = Bun.spawn(['powershell.exe', '-NoProfile', '-STA', '-WindowStyle', 'Hidden', '-Command', script]);
  } else if (process.platform === 'darwin') {
    const prompt = title.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    const location = startDir.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    proc = Bun.spawn(['osascript', '-e', `POSIX path of (choose folder with prompt "${prompt}" default location POSIX file "${location}")`]);
  } else {
    try {
      proc = Bun.spawn(['kdialog', '--getexistingdirectory', startDir, '--title', title]);
      await proc.exited;
    } catch {
      proc = Bun.spawn(['zenity', '--file-selection', '--directory', `--title=${title}`, `--filename=${startDir}/`]);
    }
  }

  if (!proc) return null;
  if (proc.exitCode === null) await proc.exited;
  if (proc.exitCode !== 0) return null;
  const selectedPath = (await new Response(proc.stdout).text()).trim();
  if (!selectedPath) return null;
  const fullPath = resolve(selectedPath);
  if (!existsSync(fullPath) || !statSync(fullPath).isDirectory()) {
    throw new Error('The selected output folder is no longer available.');
  }
  return fullPath;
}

async function handleNativeFolderBrowse(req: Request, defaultTitle: string): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as Record<string, unknown>;
    const requestedStartDir = String(body.startDir || '').trim();
    const title = String(body.title || defaultTitle).trim().slice(0, 120) || defaultTitle;
    const defaultStartDir = resolvePath(getDefaultOutputRootPath(), { allowOutsideRoot: true })?.fullPath
      || join(ROOT_DIR, COMFY_OUTPUT_ROOT);
    const requestedResolved = requestedStartDir
      ? resolvePath(requestedStartDir, { allowOutsideRoot: true })?.fullPath
      : '';
    const startDir = requestedResolved && existsSync(requestedResolved) && statSync(requestedResolved).isDirectory()
      ? requestedResolved
      : defaultStartDir;
    return json({ path: await runNativeFolderPicker(startDir, title) });
  } catch (error: any) {
    console.error('[Native Folder Picker] Failed:', error);
    return json({ error: String(error?.message || error || 'Folder picker failed.') }, 500);
  }
}

async function handleUmbraUiUpscaleStage(req: Request): Promise<Response> {
  try {
    const form = await req.formData();
    const batchId = normalizeUmbraUiUpscaleBatchId(form.get('batchId'));
    const batchFolder = resolveUmbraUiUpscaleBatchFolder(batchId);
    const file = form.get('file') as any;
    if (!batchId || !batchFolder) return json({ success: false, error: 'Invalid upscale staging batch.' }, 400);
    if (!file || typeof file.name !== 'string' || typeof file.arrayBuffer !== 'function' || Number(file.size) <= 0) {
      return json({ success: false, error: 'Choose an image to stage.' }, 400);
    }
    if (Number(file.size) > UMBRA_UI_UPSCALE_MAX_SOURCE_BYTES) {
      return json({ success: false, error: 'The source image exceeds the 512 MB upscale limit.' }, 400);
    }
    if (!UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS.has(extname(file.name).toLowerCase())) {
      return json({ success: false, error: `Upscale source is not a supported image: ${file.name}` }, 400);
    }
    const index = Number(form.get('index'));
    if (!Number.isInteger(index) || index < 0 || index >= UMBRA_UI_UPSCALE_MAX_ITEMS) {
      return json({ success: false, error: `Upscale batches are limited to ${UMBRA_UI_UPSCALE_MAX_ITEMS} images per job.` }, 400);
    }
    const displayName = String(form.get('displayName') || file.name).trim().slice(0, 500) || file.name;
    const safeName = `${String(index + 1).padStart(4, '0')}_${sanitizeUmbraUiUpscaleUploadName(file.name, `image-${index + 1}`)}`;
    await fs.mkdir(batchFolder, { recursive: true });
    const targetPath = resolve(join(batchFolder, safeName));
    const rel = relative(batchFolder, targetPath);
    if (!rel || rel.startsWith('..') || isAbsolute(rel)) throw new Error('Invalid upscale staging path.');
    await fs.writeFile(targetPath, Buffer.from(await file.arrayBuffer()));
    return json({ success: true, batchId, staged: { path: toClientPath(targetPath), name: displayName } });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to stage upscale image.') }, 400);
  }
}

async function handleUmbraUiUpscaleStageCleanup(req: Request): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as Record<string, unknown>;
    const batchFolder = resolveUmbraUiUpscaleBatchFolder(body.batchId);
    if (!batchFolder) return json({ success: false, error: 'Invalid upscale staging batch.' }, 400);
    await fs.rm(batchFolder, { recursive: true, force: true });
    return json({ success: true });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to clean upscale staging files.') }, 400);
  }
}

async function handleUmbraUiUpscaleSubmit(req: Request, allowCustomOutputFolder: boolean): Promise<Response> {
  try {
    const form = await req.formData();
    const modelName = String(form.get('modelName') || '').trim().replace(/\\/g, '/');
    const maxDimension = Math.max(512, Math.min(16384, Math.round(Number(form.get('maxDimension')) || 3840)));
    const queuePlacement = normalizePowerPrompterQueuePlacement(form.get('queuePlacement'));
    const requestedOutputFolder = String(form.get('outputFolder') || '').trim();
    let outputFolder = '';
    if (requestedOutputFolder) {
      if (!allowCustomOutputFolder) {
        return json({ success: false, error: 'Custom upscale output folders can only be selected from the host PC.' }, 403);
      }
      if (!isAbsolutePathInput(requestedOutputFolder)) {
        throw new Error('The upscale output folder must be an absolute local path.');
      }
      outputFolder = resolve(requestedOutputFolder);
      if (!existsSync(outputFolder) || !statSync(outputFolder).isDirectory()) {
        throw new Error('The selected upscale output folder is unavailable.');
      }
    }
    const rawPaths = String(form.get('paths') || '').trim();
    let paths: string[] = [];
    if (rawPaths) {
      const parsed = JSON.parse(rawPaths);
      if (!Array.isArray(parsed)) throw new Error('Upscale paths must be a JSON array.');
      paths = parsed.map((entry) => String(entry || '').trim()).filter(Boolean);
    }
    const rawFolders = String(form.get('folders') || '').trim();
    let folders: string[] = [];
    if (rawFolders) {
      const parsed = JSON.parse(rawFolders);
      if (!Array.isArray(parsed)) throw new Error('Upscale folders must be a JSON array.');
      folders = parsed.map((entry) => String(entry || '').trim()).filter(Boolean);
    }
    const rawStaged = String(form.get('staged') || '').trim();
    let staged: Array<{ path: string; name: string }> = [];
    if (rawStaged) {
      const parsed = JSON.parse(rawStaged);
      if (!Array.isArray(parsed)) throw new Error('Staged upscale files must be a JSON array.');
      staged = parsed.map((entry) => ({
        path: String(entry?.path || '').trim(),
        name: String(entry?.name || '').trim(),
      })).filter((entry) => entry.path);
    }
    const files = form.getAll('files').filter((entry) => {
      const candidate = entry as any;
      return candidate
        && typeof candidate === 'object'
        && typeof candidate.name === 'string'
        && typeof candidate.arrayBuffer === 'function'
        && Number(candidate.size) > 0;
    }) as Array<{ name: string; size: number; arrayBuffer: () => Promise<ArrayBuffer> }>;
    if (paths.length + folders.length + staged.length + files.length <= 0) {
      return json({ success: false, error: 'Choose at least one image or folder to upscale.' }, 400);
    }

    const sources: UmbraUiUpscaleSource[] = [];
    const seenPaths = new Set<string>();
    const uploadRoot = resolve(UMBRA_UI_UPSCALE_UPLOAD_ROOT);
    const addPathSource = (fullPathInput: string, displayName = '', temporary = false) => {
      const fullPath = resolve(fullPathInput);
      const uploadRelative = relative(uploadRoot, fullPath);
      const isStagedUpload = !!uploadRelative && !uploadRelative.startsWith('..') && !isAbsolute(uploadRelative);
      if (temporary ? !isStagedUpload : !isPathInsideAllowedRoots(fullPath)) {
        throw new Error(`Upscale source is outside Umbra's allowed folders: ${fullPathInput}`);
      }
      if (!existsSync(fullPath) || !statSync(fullPath).isFile()) {
        throw new Error(`Upscale source was not found: ${fullPathInput}`);
      }
      if (!UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS.has(extname(fullPath).toLowerCase())) {
        throw new Error(`Upscale source is not a supported image: ${fullPathInput}`);
      }
      const key = fullPath.toLowerCase();
      if (seenPaths.has(key)) return;
      seenPaths.add(key);
      sources.push({
        name: displayName || basename(fullPath),
        sourcePath: temporary ? '' : toClientPath(fullPath),
        read: () => fs.readFile(fullPath),
        ...(temporary ? {
          cleanup: async () => {
            await fs.rm(fullPath, { force: true });
            await fs.rmdir(dirname(fullPath)).catch(() => undefined);
          },
        } : {}),
      });
      if (sources.length > UMBRA_UI_UPSCALE_MAX_ITEMS) {
        throw new Error(`Upscale batches are limited to ${UMBRA_UI_UPSCALE_MAX_ITEMS} images per job.`);
      }
    };
    for (const rawPath of paths) {
      const resolved = resolvePath(rawPath, { allowOutsideRoot: true });
      if (!resolved) {
        throw new Error(`Upscale source is outside Umbra's allowed folders: ${rawPath}`);
      }
      addPathSource(resolved.fullPath);
    }
    for (const rawFolder of folders) {
      const resolved = resolvePath(rawFolder, { allowOutsideRoot: true });
      if (!resolved || !isPathInsideAllowedRoots(resolved.fullPath)) {
        throw new Error(`Upscale folder is outside Umbra's allowed folders: ${rawFolder}`);
      }
      if (!existsSync(resolved.fullPath) || !statSync(resolved.fullPath).isDirectory()) {
        throw new Error(`Upscale folder was not found: ${rawFolder}`);
      }
      const folderFiles = await collectUmbraUiUpscaleFolderFiles(
        resolved.fullPath,
        Math.max(0, UMBRA_UI_UPSCALE_MAX_ITEMS - sources.length),
      );
      for (const folderFile of folderFiles) addPathSource(folderFile);
    }
    for (const entry of staged) {
      const stagedPath = isAbsolute(entry.path)
        ? entry.path
        : resolvePath(entry.path, { allowOutsideRoot: true })?.fullPath || '';
      if (!stagedPath) throw new Error(`Staged upscale source was not found: ${entry.path}`);
      addPathSource(stagedPath, entry.name, true);
    }
    for (const file of files) {
      if (!UMBRA_UI_UPSCALE_IMAGE_EXTENSIONS.has(extname(file.name).toLowerCase())) {
        throw new Error(`Upscale source is not a supported image: ${file.name}`);
      }
      sources.push({
        name: file.name,
        read: () => file.arrayBuffer(),
      });
      if (sources.length > UMBRA_UI_UPSCALE_MAX_ITEMS) {
        throw new Error(`Upscale batches are limited to ${UMBRA_UI_UPSCALE_MAX_ITEMS} images per job.`);
      }
    }

    if (sources.length <= 0) return json({ success: false, error: 'No supported images were found.' }, 400);

    const job = await umbraUiUpscaleService.submit(sources, {
      modelName,
      maxDimension,
      outputFolder,
      queuePlacement,
    });
    return json({ success: true, job });
  } catch (error: any) {
    return json({ success: false, error: String(error?.message || error || 'Failed to queue upscale job.') }, 400);
  }
}

function handleUmbraUiUpscaleJob(path: string): Response {
  const jobId = decodeURIComponent(path.slice('/api/umbra-ui/upscale/jobs/'.length)).trim();
  if (!jobId) return json({ success: false, error: 'Upscale job id is required.' }, 400);
  const job = umbraUiUpscaleService.getJob(jobId);
  if (!job) return json({ success: false, error: 'Upscale job was not found.' }, 404);
  return json({ success: true, job });
}

function toIsoString(value: unknown, fallback: string): string {
  const candidate = String(value || '').trim();
  if (!candidate) return fallback;
  const parsed = Date.parse(candidate);
  return Number.isFinite(parsed) ? new Date(parsed).toISOString() : fallback;
}

function createPPCardId(): string {
  try {
    return crypto.randomUUID();
  } catch {
    return `pp-card-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  }
}

function createPPSlotId(type: PowerPrompterCardType, label?: string): string {
  const normalizedLabel = String(label || type).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '') || String(type);
  try {
    return `pp-slot-${normalizedLabel}-${crypto.randomUUID()}`;
  } catch {
    return `pp-slot-${normalizedLabel}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  }
}

function normalizePPCardType(rawType: unknown): PowerPrompterCardType {
  const normalized = String(rawType || '').trim().toLowerCase();
  if (
    normalized === 'character' ||
    normalized === 'location' ||
    normalized === 'expression' ||
    normalized === 'action' ||
    normalized === 'style' ||
    normalized === 'custom'
  ) {
    return normalized;
  }
  return 'custom';
}

function normalizePPVariantName(rawName: unknown): string {
  return String(rawName || '')
    .trim()
    .replace(/\s+/g, ' ')
    .slice(0, 80);
}

function normalizePPVariantTag(rawTag: unknown): string {
  return String(rawTag || '')
    .trim()
    .replace(/\s+/g, ' ')
    .slice(0, 32);
}

function normalizePPVariantTags(rawTags: unknown): string[] {
  if (!Array.isArray(rawTags)) return [];
  const seen = new Set<string>();
  const normalized: string[] = [];
  for (const rawTag of rawTags) {
    const tag = normalizePPVariantTag(rawTag);
    if (!tag) continue;
    const key = tag.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    normalized.push(tag);
    if (normalized.length >= 16) break;
  }
  return normalized;
}

function normalizePPModelType(rawValue: unknown): string {
  return String(rawValue || '')
    .trim()
    .replace(/\s+/g, ' ')
    .slice(0, 80);
}

function normalizePPModelColor(rawValue: unknown): string {
  const value = String(rawValue || '').trim();
  if (!value) return '#38bdf8';
  const normalized = value.startsWith('#') ? value : `#${value}`;
  return /^#[0-9a-fA-F]{6}$/.test(normalized) ? normalized.toLowerCase() : '#38bdf8';
}

function sortPPCards(cards: PowerPrompterCardNode[]): PowerPrompterCardNode[] {
  return [...cards].sort((a, b) => {
    const orderDelta = Number(a.order) - Number(b.order);
    if (orderDelta !== 0) return orderDelta;
    return String(a.createdAt || '').localeCompare(String(b.createdAt || ''));
  });
}

function createPPCardNode(
  type: PowerPrompterCardType,
  label: string,
  text: string,
  order: number,
  nowIso = new Date().toISOString(),
  slotId?: string
): PowerPrompterCardNode {
  const resolvedLabel = String(label || '').trim() || (type === 'custom' ? 'Custom' : type[0].toUpperCase() + type.slice(1));
  return {
    id: createPPCardId(),
    slotId: String(slotId || '').trim() || createPPSlotId(type, resolvedLabel),
    type,
    label: resolvedLabel,
    variantName: '',
    variantTags: [],
    skipVariant: false,
    text: String(text || ''),
    randomEnabled: false,
    randomSetIds: [],
    queueEnabled: true,
    queueSetIds: [1],
    queueCycleWeights: {},
    chainLinks: [],
    blockLinks: [],
    order,
    createdAt: nowIso,
    updatedAt: nowIso,
  };
}

function createDefaultPPCardDocument(filePath: string | null): PowerPrompterCardDocument {
  const nowIso = new Date().toISOString();
  return {
    version: 1,
    file: filePath,
    createdAt: nowIso,
    updatedAt: nowIso,
    modelType: '',
    modelColor: '#38bdf8',
    pipeline: normalizeUmbraUiPipelineSelection(null),
    activeQueueSet: 1,
    styleSeedMode: 'same',
    generation: normalizePPGenerationControls(null),
    cards: [
      createPPCardNode('character', 'Character', '', 0, nowIso),
      createPPCardNode('location', 'Location', '', 1, nowIso),
      createPPCardNode('expression', 'Expression', '', 2, nowIso),
      createPPCardNode('action', 'Action', '', 3, nowIso),
      createPPCardNode('style', 'Style', '', 4, nowIso),
    ],
    deletedCardGroups: {},
  };
}

function composePPPromptFromCards(cards: PowerPrompterCardNode[]): string {
  const raw = sortPPCards(cards)
    .map((card) => String(card.text || '').trim())
    .filter((value) => value.length > 0)
    .join(', ');
  return raw
    .split(',')
    .map((segment) => segment.replace(/\s+/g, ' ').trim())
    .filter((segment) => segment.length > 0)
    .join(', ');
}

function splitLegacyPromptSegments(text: string): string[] {
  return String(text || '')
    .split(/\r?\n|,/g)
    .map((line) => line.replace(PP_LEGACY_SELECTION_PATTERN, '').trim())
    .filter((line) => line.length > 0);
}

function normalizePPCardDocument(rawDoc: unknown, filePath: string | null): PowerPrompterCardDocument {
  const nowIso = new Date().toISOString();
  const fallback = createDefaultPPCardDocument(filePath);
  if (!rawDoc || typeof rawDoc !== 'object') return fallback;

  const doc = rawDoc as Partial<PowerPrompterCardDocument>;
  const activeQueueSet = clampPPQueueSetId(doc.activeQueueSet);
  const rawCards = Array.isArray(doc.cards) ? doc.cards : [];
  const normalizedCards: PowerPrompterCardNode[] = rawCards.map((entry, idx) => {
    const card = (entry || {}) as Partial<PowerPrompterCardNode>;
    const type = normalizePPCardType(card.type);
    const queueSetIds = normalizePPCardQueueSetIds(card.queueSetIds, card.queueEnabled, activeQueueSet);
    const randomSetIds = normalizePPRandomSetIds(card.randomSetIds);
    const resolvedLabel = String(card.label || '').trim() || (type === 'custom' ? 'Custom' : type[0].toUpperCase() + type.slice(1));
    const id = String(card.id || createPPCardId()).trim() || createPPCardId();
    return {
      id,
      slotId: String(card.slotId || '').trim() || createPPSlotId(type, resolvedLabel),
      type,
      label: resolvedLabel,
      variantName: normalizePPVariantName((card as any).variantName),
      variantTags: normalizePPVariantTags((card as any).variantTags),
      skipVariant: (card as any).skipVariant === true,
      text: String(card.text || ''),
      randomEnabled: card.randomEnabled === true,
      randomSetIds,
      queueEnabled: queueSetIds.length > 0,
      queueSetIds,
      queueCycleWeights: normalizePPQueueCycleWeights((card as any).queueCycleWeights, queueSetIds),
      chainLinks: normalizePPChainLinks((card as any).chainLinks, id),
      blockLinks: normalizePPBlockLinks((card as any).blockLinks, id),
      order: Number.isFinite(Number(card.order)) ? Math.max(0, Math.floor(Number(card.order))) : idx,
      createdAt: toIsoString(card.createdAt, nowIso),
      updatedAt: toIsoString(card.updatedAt, nowIso),
    };
  });

  const dedupedCards = (() => {
    const seen = new Set<string>();
    return normalizedCards.map((card) => {
      let id = String(card.id || '').trim() || createPPCardId();
      while (seen.has(id)) {
        id = createPPCardId();
      }
      seen.add(id);
      return id === card.id ? card : { ...card, id };
    });
  })();

  const sorted = dedupedCards.length > 0 ? sortPPCards(dedupedCards).map((card, idx) => ({ ...card, order: idx })) : fallback.cards;

  const generation = normalizePPGenerationControls(doc.generation);
  const legacyModelFamily = normalizePPModelType((doc as any).modelType);
  const pipeline = normalizeUmbraUiPipelineSelection((doc as any).pipeline, {
    feature: 'txt2img',
    modelFamily: legacyModelFamily,
    modelSource: generation.modelType,
  });

  return {
    version: 1,
    file: filePath,
    createdAt: toIsoString(doc.createdAt, nowIso),
    updatedAt: toIsoString(doc.updatedAt, nowIso),
    modelType: pipeline.modelFamily,
    modelColor: normalizePPModelColor((doc as any).modelColor),
    pipeline,
    activeQueueSet,
    styleSeedMode: normalizePPStyleSeedMode((doc as any).styleSeedMode),
    generation,
    cards: sorted,
    deletedCardGroups: (doc as any).deletedCardGroups && typeof (doc as any).deletedCardGroups === 'object' && !Array.isArray((doc as any).deletedCardGroups)
      ? (doc as any).deletedCardGroups
      : {},
  };
}

function parsePPCardJson(raw: string): unknown {
  return JSON.parse(String(raw || '').replace(/^\uFEFF/, ''));
}

function isProbablyNullFilledPPCard(raw: string): boolean {
  if (!raw) return false;
  const sample = raw.slice(0, Math.min(raw.length, 4096));
  if (!sample) return false;
  const nulCount = sample.split('\u0000').length - 1;
  return nulCount > Math.max(16, Math.floor(sample.length * 0.25));
}

function importLegacyPromptToPPCardDocument(
  text: string,
  filePath: string | null,
  existingDoc?: PowerPrompterCardDocument | null
): PowerPrompterCardDocument {
  const baseDoc = existingDoc
    ? normalizePPCardDocument(existingDoc, filePath)
    : createDefaultPPCardDocument(filePath);
  const segments = splitLegacyPromptSegments(text);
  const nowIso = new Date().toISOString();
  const fallbackSetId = clampPPQueueSetId(baseDoc.activeQueueSet);
  const cards = sortPPCards(baseDoc.cards).map((card, idx) => {
    const queueSetIds = normalizePPCardQueueSetIds(card.queueSetIds, card.queueEnabled, fallbackSetId);
    return {
      ...card,
      skipVariant: (card as any).skipVariant === true,
      text: segments[idx] || '',
      randomEnabled: card.randomEnabled === true,
      randomSetIds: normalizePPRandomSetIds(card.randomSetIds),
      queueSetIds,
      queueEnabled: queueSetIds.length > 0,
      queueCycleWeights: normalizePPQueueCycleWeights((card as any).queueCycleWeights, queueSetIds),
      chainLinks: normalizePPChainLinks((card as any).chainLinks, String(card.id || '').trim()),
      blockLinks: normalizePPBlockLinks((card as any).blockLinks, String(card.id || '').trim()),
      order: idx,
      updatedAt: nowIso,
    };
  });

  if (segments.length > cards.length) {
    for (let idx = cards.length; idx < segments.length; idx += 1) {
      cards.push(createPPCardNode('custom', `Custom ${idx - cards.length + 1}`, segments[idx], idx, nowIso));
    }
  }

  return {
    ...baseDoc,
    file: filePath,
    updatedAt: nowIso,
    activeQueueSet: clampPPQueueSetId(baseDoc.activeQueueSet),
    styleSeedMode: normalizePPStyleSeedMode((baseDoc as any).styleSeedMode),
    generation: normalizePPGenerationControls(baseDoc.generation),
    cards,
    deletedCardGroups: (baseDoc as any).deletedCardGroups || {},
  };
}

function resolvePPPromptFile(filePath: string): { filePath: string; fullPath: string; sidecarPath: string } | null {
  const normalizedPath = String(filePath || '').replace(/\\/g, '/').trim();
  const isTxt = normalizedPath.toLowerCase().endsWith('.txt');
  const isJsonDoc = normalizedPath.toLowerCase().endsWith('.ppcards.json');
  if (!normalizedPath || (!isTxt && !isJsonDoc)) return null;

  const resolved = resolvePath(normalizedPath);
  if (!resolved) return null;

  const relativeFromPrompts = relative(PP_PROMPTS_ROOT_ABS, resolved.fullPath).replace(/\\/g, '/');
  if (!relativeFromPrompts || relativeFromPrompts.startsWith('..') || isAbsolute(relativeFromPrompts)) {
    return null;
  }

  return {
    filePath: resolved.relativePath.replace(/\\/g, '/'),
    fullPath: resolved.fullPath,
    sidecarPath: isJsonDoc ? resolved.fullPath : `${resolved.fullPath}${PP_CARD_DOC_EXT}`,
  };
}

async function loadPPCardDocumentForFile(filePath: string): Promise<{ document: PowerPrompterCardDocument; fromSidecar: boolean; healed: boolean; }> {
  const resolved = resolvePPPromptFile(filePath);
  if (!resolved) {
    throw new Error('Invalid Power Prompter file path');
  }
  const isJsonDoc = resolved.fullPath.toLowerCase().endsWith(PP_CARD_DOC_EXT);

  if (existsSync(resolved.sidecarPath)) {
    try {
      const raw = await fs.readFile(resolved.sidecarPath, 'utf-8');
      const parsed = parsePPCardJson(raw);
      const normalized = normalizePPCardDocument(parsed, resolved.filePath);
      return {
        document: normalized,
        fromSidecar: true,
        healed: false,
      };
    } catch (error) {
      console.warn('[PowerPrompter] Failed to read card document:', error);
      const healed = await healPPCardDocumentFromBackup(resolved.filePath, resolved.sidecarPath).catch((healError: any) => {
        console.warn('[PowerPrompter] Failed to heal card document from backups:', healError);
        return null;
      });
      if (healed) {
        return {
          document: healed,
          fromSidecar: true,
          healed: true,
        };
      }
      if (isJsonDoc) {
        await quarantineCorruptPPCardDocument(resolved.sidecarPath, 'load-parse-failed').catch(() => undefined);
        throw new Error('Power Prompter card file is corrupt and no valid backup was found.');
      }
      console.warn('[PowerPrompter] Falling back to legacy text import after sidecar read failure.');
    }
  }

  if (isJsonDoc) {
    return {
      document: createDefaultPPCardDocument(resolved.filePath),
      fromSidecar: false,
      healed: false,
    };
  }

  const text = existsSync(resolved.fullPath) ? await fs.readFile(resolved.fullPath, 'utf-8') : '';
  return {
    document: importLegacyPromptToPPCardDocument(text, resolved.filePath),
    fromSidecar: false,
    healed: false,
  };
}

interface PPCardDocumentSaveOptions {
  forceOverwrite?: boolean;
}

interface PPCardDocumentSafetySummary {
  cardCount: number;
  nonEmptyCardCount: number;
  serializedBytes: number;
}

function summarizePPCardDocumentForSafety(document: PowerPrompterCardDocument, serializedBytes?: number): PPCardDocumentSafetySummary {
  const cards = Array.isArray(document.cards) ? document.cards : [];
  return {
    cardCount: cards.length,
    nonEmptyCardCount: cards.filter((card) => String(card?.text || '').trim().length > 0).length,
    serializedBytes: Number.isFinite(Number(serializedBytes)) && Number(serializedBytes) >= 0
      ? Math.floor(Number(serializedBytes))
      : Buffer.byteLength(JSON.stringify(document), 'utf8'),
  };
}

function shouldBlockSuspiciousPPCardOverwrite(
  existing: PPCardDocumentSafetySummary | null,
  next: PPCardDocumentSafetySummary
): boolean {
  if (!existing) return false;
  const existingLooksSubstantial = existing.cardCount >= 10
    || existing.nonEmptyCardCount >= 8
    || existing.serializedBytes >= 10000;
  if (!existingLooksSubstantial) return false;

  if (existing.cardCount <= 0) {
    return next.cardCount <= 8 && next.serializedBytes < 25000 && next.serializedBytes <= Math.max(4096, Math.floor(existing.serializedBytes * 0.25));
  }

  const severeCardDrop = next.cardCount <= 8 && next.cardCount <= Math.max(1, Math.floor(existing.cardCount * 0.25));
  const severeContentDrop = next.nonEmptyCardCount <= 5 && next.nonEmptyCardCount <= Math.max(1, Math.floor(existing.nonEmptyCardCount * 0.25));
  const severeSizeDrop = next.serializedBytes < 25000 && next.serializedBytes <= Math.max(4096, Math.floor(existing.serializedBytes * 0.25));

  return severeCardDrop && (severeContentDrop || severeSizeDrop);
}

function getPPCardBackupBucket(filePath: string): string {
  const normalized = String(filePath || '').replace(/\\/g, '/').trim() || 'card';
  const base = basename(normalized).replace(/\.ppcards\.json$/i, '').replace(/\.txt$/i, '') || 'card';
  const safeBase = base
    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '_')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 72) || 'card';
  const hash = createHash('sha1').update(normalized).digest('hex').slice(0, 10);
  return `${safeBase}-${hash}`;
}

async function prunePPCardBackups(bucketDir: string): Promise<void> {
  try {
    const entries = await fs.readdir(bucketDir, { withFileTypes: true });
    const backups = await Promise.all(entries
      .filter((entry) => entry.isFile() && entry.name.toLowerCase().endsWith('.ppcards.json'))
      .map(async (entry) => {
        const fullPath = join(bucketDir, entry.name);
        const stat = await fs.stat(fullPath).catch(() => null);
        return stat ? { fullPath, mtimeMs: stat.mtimeMs } : null;
      }));
    const sorted = backups
      .filter((entry): entry is { fullPath: string; mtimeMs: number } => !!entry)
      .sort((left, right) => right.mtimeMs - left.mtimeMs);
    await Promise.all(sorted
      .slice(PP_CARD_BACKUP_KEEP_PER_FILE)
      .map((entry) => fs.rm(entry.fullPath, { force: true }).catch(() => undefined)));
  } catch {
    // Backups are protective only; failed pruning must not block saves.
  }
}

async function quarantineCorruptPPCardDocument(targetPath: string, reason: string): Promise<string | null> {
  if (!existsSync(targetPath)) return null;
  const quarantineDir = join(dirname(targetPath), '.corrupt-quarantine');
  await fs.mkdir(quarantineDir, { recursive: true });
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const safeReason = String(reason || 'corrupt')
    .replace(/[^a-z0-9_-]+/gi, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 48) || 'corrupt';
  const quarantinePath = join(quarantineDir, `${basename(targetPath)}.${safeReason}.${stamp}.corrupt`);
  await fs.rename(targetPath, quarantinePath);
  return quarantinePath;
}

async function findLatestValidPPCardBackup(filePath: string): Promise<{ raw: string; document: PowerPrompterCardDocument; backupPath: string } | null> {
  const bucketDir = join(PP_CARD_BACKUP_DIR, getPPCardBackupBucket(filePath));
  if (!existsSync(bucketDir)) return null;

  const entries = await fs.readdir(bucketDir, { withFileTypes: true }).catch(() => []);
  const candidates = await Promise.all(entries
    .filter((entry) => entry.isFile() && !entry.name.toLowerCase().endsWith('.tmp'))
    .map(async (entry) => {
      const backupPath = join(bucketDir, entry.name);
      const stat = await fs.stat(backupPath).catch(() => null);
      return stat ? { backupPath, mtimeMs: stat.mtimeMs } : null;
    }));

  const sorted = candidates
    .filter((entry): entry is { backupPath: string; mtimeMs: number } => !!entry)
    .sort((left, right) => right.mtimeMs - left.mtimeMs);

  for (const candidate of sorted) {
    try {
      const raw = await fs.readFile(candidate.backupPath, 'utf-8');
      if (isProbablyNullFilledPPCard(raw)) continue;
      const document = normalizePPCardDocument(parsePPCardJson(raw), filePath);
      if (!Array.isArray(document.cards) || document.cards.length <= 0) continue;
      return { raw, document, backupPath: candidate.backupPath };
    } catch {
      // Keep walking older backups; one bad backup should not block recovery.
    }
  }

  return null;
}

async function healPPCardDocumentFromBackup(filePath: string, targetPath: string): Promise<PowerPrompterCardDocument | null> {
  const backup = await findLatestValidPPCardBackup(filePath);
  if (!backup) return null;

  await quarantineCorruptPPCardDocument(targetPath, 'healed-from-backup').catch((error: any) => {
    console.warn('[PowerPrompter] Failed to quarantine corrupt ppcard before healing:', error);
  });
  const serialized = JSON.stringify(backup.document, null, 2);
  await writeTextFileAtomic(targetPath, serialized);
  console.warn('[PowerPrompter] Healed corrupt ppcard from backup', {
    file: filePath,
    backup: backup.backupPath,
  });
  return backup.document;
}

async function writeTextFileAtomic(targetPath: string, content: string): Promise<void> {
  const targetDir = dirname(targetPath);
  await fs.mkdir(targetDir, { recursive: true });
  const tempPath = join(targetDir, `.${basename(targetPath)}.${process.pid}.${Date.now()}.${randomBytes(4).toString('hex')}.tmp`);
  let handle: fs.FileHandle | null = null;
  try {
    handle = await fs.open(tempPath, 'w');
    await handle.writeFile(content, 'utf-8');
    await handle.sync();
    await handle.close();
    handle = null;
    await fs.rename(tempPath, targetPath);
  } catch (error) {
    if (handle) {
      await handle.close().catch(() => undefined);
    }
    await fs.rm(tempPath, { force: true }).catch(() => undefined);
    throw error;
  }
}

async function backupPPCardDocumentBeforeWrite(filePath: string, existingRaw: string, nextRaw: string): Promise<void> {
  if (!existingRaw || existingRaw === nextRaw) return;
  const bucketDir = join(PP_CARD_BACKUP_DIR, getPPCardBackupBucket(filePath));
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = join(bucketDir, `${stamp}.ppcards.json`);
  await fs.mkdir(bucketDir, { recursive: true });
  await writeTextFileAtomic(backupPath, existingRaw);
  await prunePPCardBackups(bucketDir);
}

async function savePPCardDocumentForFile(
  filePath: string,
  document: unknown,
  options: PPCardDocumentSaveOptions = {}
): Promise<PowerPrompterCardDocument> {
  const resolved = resolvePPPromptFile(filePath);
  if (!resolved) {
    throw new Error('Invalid Power Prompter file path');
  }

  const normalizedDoc = normalizePPCardDocument(document, resolved.filePath);
  const nextSerialized = JSON.stringify(normalizedDoc, null, 2);
  const nextSummary = summarizePPCardDocumentForSafety(normalizedDoc, Buffer.byteLength(nextSerialized, 'utf8'));
  let existingRawForBackup: string | null = null;

  if (existsSync(resolved.sidecarPath)) {
    let existingSummary: PPCardDocumentSafetySummary | null = null;
    try {
      const existingRaw = await fs.readFile(resolved.sidecarPath, 'utf-8');
      const existingDoc = normalizePPCardDocument(parsePPCardJson(existingRaw), resolved.filePath);
      existingRawForBackup = existingRaw;
      existingSummary = summarizePPCardDocumentForSafety(existingDoc, Buffer.byteLength(existingRaw, 'utf8'));
    } catch {
      try {
        const existingStat = await fs.stat(resolved.sidecarPath);
        existingSummary = {
          cardCount: 0,
          nonEmptyCardCount: 0,
          serializedBytes: existingStat.size,
        };
      } catch {
        existingSummary = null;
      }
    }

    if (!options.forceOverwrite && shouldBlockSuspiciousPPCardOverwrite(existingSummary, nextSummary)) {
      console.warn('[PowerPrompter] Blocked suspicious ppcard overwrite', {
        file: resolved.filePath,
        existing: existingSummary,
        next: nextSummary,
      });
      throw new Error('Refusing to overwrite a large Power Prompter card file with a tiny/default document. Reload the card before saving, or use an explicit replace action.');
    }
  }

  await fs.mkdir(dirname(resolved.sidecarPath), { recursive: true });
  if (existingRawForBackup !== null) {
    await backupPPCardDocumentBeforeWrite(resolved.filePath, existingRawForBackup, nextSerialized).catch((error: any) => {
      console.warn('[PowerPrompter] Failed to create ppcard backup before save:', error);
    });
  }
  await writeTextFileAtomic(resolved.sidecarPath, nextSerialized);
  return normalizedDoc;
}

interface PowerPrompterDocumentSession {
  version: 1;
  file: string | null;
  document: PowerPrompterCardDocument | null;
  composedPrompt: string;
  revision: number;
  dirty: boolean;
  lastSavedAt: number;
  updatedAt: number;
  sourceClientId: string;
}

interface PersistedPowerPrompterDocumentSession {
  version: 1;
  file: string | null;
  revision: number;
  lastSavedAt: number;
  updatedAt: number;
}

let powerPrompterDocumentSession: PowerPrompterDocumentSession = {
  version: 1,
  file: null,
  document: null,
  composedPrompt: '',
  revision: 0,
  dirty: false,
  lastSavedAt: 0,
  updatedAt: 0,
  sourceClientId: '',
};

function clonePowerPrompterDocumentSession(reason = 'snapshot') {
  return {
    type: 'document_state',
    reason,
    session: {
      ...powerPrompterDocumentSession,
      document: powerPrompterDocumentSession.document
        ? normalizePPCardDocument(powerPrompterDocumentSession.document, powerPrompterDocumentSession.file)
        : null,
    },
  };
}

async function readPersistedPowerPrompterDocumentSession(): Promise<PersistedPowerPrompterDocumentSession | null> {
  try {
    if (!existsSync(PP_SESSION_STATE_PATH)) return null;
    const raw = await fs.readFile(PP_SESSION_STATE_PATH, 'utf-8');
    const parsed = JSON.parse(raw) as Partial<PersistedPowerPrompterDocumentSession>;
    const file = String(parsed?.file || '').trim().replace(/\\/g, '/') || null;
    return {
      version: 1,
      file,
      revision: Math.max(0, Math.floor(Number(parsed?.revision) || 0)),
      lastSavedAt: Math.max(0, Math.floor(Number(parsed?.lastSavedAt) || 0)),
      updatedAt: Math.max(0, Math.floor(Number(parsed?.updatedAt) || 0)),
    };
  } catch {
    return null;
  }
}

async function persistPowerPrompterDocumentSessionSummary(): Promise<void> {
  const payload: PersistedPowerPrompterDocumentSession = {
    version: 1,
    file: powerPrompterDocumentSession.file,
    revision: powerPrompterDocumentSession.revision,
    lastSavedAt: powerPrompterDocumentSession.lastSavedAt,
    updatedAt: powerPrompterDocumentSession.updatedAt,
  };
  await fs.mkdir(dirname(PP_SESSION_STATE_PATH), { recursive: true });
  await writeTextFileAtomic(PP_SESSION_STATE_PATH, JSON.stringify(payload, null, 2));
}

function broadcastPowerPrompterDocumentSession(reason: string, preferredSourceWs?: ServerWebSocket<unknown> | null): void {
  sendPrompterEventToTargets(clonePowerPrompterDocumentSession(reason), preferredSourceWs);
}

async function openPowerPrompterDocumentSession(
  filePath: string,
  options: { sourceClientId?: string; preferredSourceWs?: ServerWebSocket<unknown> | null; reason?: string } = {}
): Promise<PowerPrompterDocumentSession> {
  const loaded = await loadPPCardDocumentForFile(filePath);
  const normalized = normalizePPCardDocument(loaded.document, loaded.document.file || filePath);
  const now = Date.now();
  powerPrompterDocumentSession = {
    version: 1,
    file: normalized.file,
    document: normalized,
    composedPrompt: composePPPromptFromCards(normalized.cards),
    revision: Math.max(powerPrompterDocumentSession.revision + 1, now),
    dirty: false,
    lastSavedAt: now,
    updatedAt: now,
    sourceClientId: String(options.sourceClientId || '').trim(),
  };
  await persistPowerPrompterDocumentSessionSummary().catch(() => undefined);
  broadcastPowerPrompterDocumentSession(options.reason || 'document_opened', options.preferredSourceWs);
  return powerPrompterDocumentSession;
}

async function ensurePowerPrompterDocumentSession(filePath?: string | null): Promise<PowerPrompterDocumentSession> {
  const requestedFile = String(filePath || '').trim().replace(/\\/g, '/');
  if (requestedFile) {
    if (powerPrompterDocumentSession.file !== requestedFile || !powerPrompterDocumentSession.document) {
      return openPowerPrompterDocumentSession(requestedFile, { reason: 'document_requested' });
    }
    return powerPrompterDocumentSession;
  }

  if (powerPrompterDocumentSession.file && powerPrompterDocumentSession.document) {
    return powerPrompterDocumentSession;
  }

  const persisted = await readPersistedPowerPrompterDocumentSession();
  if (persisted?.file) {
    return openPowerPrompterDocumentSession(persisted.file, { reason: 'document_restored' });
  }

  try {
    const preferences = await readUserConfigValue('powerprompter-ui') as Record<string, unknown> | null;
    const preferredFile = preferences && typeof preferences === 'object'
      ? String(preferences.currentFile || '').trim().replace(/\\/g, '/')
      : '';
    if (preferredFile) {
      return openPowerPrompterDocumentSession(preferredFile, { reason: 'document_restored_from_ui' });
    }
  } catch {
    // Ignore malformed legacy UI config; the session can still start empty.
  }

  return powerPrompterDocumentSession;
}

async function updatePowerPrompterDocumentSession(
  filePath: string,
  document: unknown,
  options: {
    save?: boolean;
    intent?: string;
    forceOverwrite?: boolean;
    sourceClientId?: string;
    preferredSourceWs?: ServerWebSocket<unknown> | null;
    reason?: string;
  } = {}
): Promise<PowerPrompterDocumentSession> {
  const resolved = resolvePPPromptFile(filePath);
  if (!resolved) throw new Error('Invalid Power Prompter file path');
  const normalized = normalizePPCardDocument(document, resolved.filePath);
  const now = Date.now();
  let savedDocument = normalized;
  let savedAt = powerPrompterDocumentSession.lastSavedAt || 0;

  if (options.save) {
    const intent = String(options.intent || '').trim();
    const allowed = new Set(['editor-save', 'editor-autosave', 'create-card', 'sidebar-card-operation', 'session-save', 'session-autosave']);
    if (!allowed.has(intent)) {
      throw new Error('Session saves require an explicit editor/session intent.');
    }
    savedDocument = await savePPCardDocumentForFile(resolved.filePath, normalized, {
      forceOverwrite: options.forceOverwrite === true,
    });
    savedAt = now;
  }

  powerPrompterDocumentSession = {
    version: 1,
    file: savedDocument.file || resolved.filePath,
    document: savedDocument,
    composedPrompt: composePPPromptFromCards(savedDocument.cards),
    revision: Math.max(powerPrompterDocumentSession.revision + 1, now),
    dirty: !options.save,
    lastSavedAt: savedAt,
    updatedAt: now,
    sourceClientId: String(options.sourceClientId || '').trim(),
  };
  await persistPowerPrompterDocumentSessionSummary().catch(() => undefined);
  broadcastPowerPrompterDocumentSession(options.reason || (options.save ? 'document_saved' : 'document_updated'), options.preferredSourceWs);
  return powerPrompterDocumentSession;
}

async function clearPowerPrompterDocumentSession(options: { sourceClientId?: string; preferredSourceWs?: ServerWebSocket<unknown> | null; reason?: string } = {}): Promise<PowerPrompterDocumentSession> {
  const now = Date.now();
  powerPrompterDocumentSession = {
    version: 1,
    file: null,
    document: null,
    composedPrompt: '',
    revision: Math.max(powerPrompterDocumentSession.revision + 1, now),
    dirty: false,
    lastSavedAt: 0,
    updatedAt: now,
    sourceClientId: String(options.sourceClientId || '').trim(),
  };
  await persistPowerPrompterDocumentSessionSummary().catch(() => undefined);
  broadcastPowerPrompterDocumentSession(options.reason || 'document_cleared', options.preferredSourceWs);
  return powerPrompterDocumentSession;
}

interface PPApiWorkflowListItem {
  id: string;
  fileName: string;
  name: string;
  compatible: boolean;
  missing: string[];
  runtimeNodes: UmbraUiPipelineReadiness['runtime']['nodes'];
  mediaType: PowerPrompterMediaType;
  modelFamily?: string;
  umbraUiPipelines?: UmbraUiPipelineDescriptor[];
  resources: PPApiWorkflowResourceSelector[];
  videoFamily?: PowerPrompterVideoFamily;
  videoMode?: PowerPrompterVideoMode;
  updatedAt: number;
  size: number;
}

type PPApiWorkflowResourceKind = UmbraUiPipelineResourceKind;

interface PPApiWorkflowResourceSelector {
  id: string;
  label: string;
  kind: PPApiWorkflowResourceKind;
  nodeId: string;
  inputName: string;
  required: boolean;
  defaultValue: string;
  options: string[];
  order: number;
}

function sanitizePPApiWorkflowBaseName(rawName: unknown): string {
  const source = String(rawName || '').trim();
  const withoutExt = source.replace(/\.json$/i, '');
  const cleaned = withoutExt
    .replace(/[<>:"/\\|?*\x00-\x1f]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 120);
  return cleaned || `api-workflow-${Date.now()}`;
}

function parsePPApiWorkflowId(rawId: unknown): string {
  const normalized = String(rawId || '').trim();
  if (!normalized) return '';
  if (normalized.startsWith(PP_API_WORKFLOW_TARGET_PREFIX)) {
    return normalized.slice(PP_API_WORKFLOW_TARGET_PREFIX.length).trim();
  }
  return normalized;
}

function ensurePPApiWorkflowDirSync() {
  if (!existsSync(PP_API_WORKFLOWS_DIR)) {
    mkdirSync(PP_API_WORKFLOWS_DIR, { recursive: true });
  }
  seedBundledWorkflowDirectory(PP_BUNDLED_API_WORKFLOWS_DIR, PP_API_WORKFLOWS_DIR);
}

function resolvePPApiWorkflowFilePath(rawId: unknown): string | null {
  return resolvePPApiWorkflowFilePathInDirectory(rawId, PP_API_WORKFLOWS_DIR);
}

function resolvePPApiWorkflowFilePathInDirectory(rawId: unknown, directory: string): string | null {
  const id = parsePPApiWorkflowId(rawId);
  if (!id) return null;
  const normalized = id.replace(/\\/g, '/').replace(/^\/+|\/+$/g, '');
  if (!normalized || normalized.includes('..') || normalized.includes('/')) return null;
  const fileName = normalized.toLowerCase().endsWith('.json') ? normalized : `${normalized}.json`;
  const fullPath = join(directory, fileName);
  const rel = relative(directory, fullPath).replace(/\\/g, '/');
  if (!rel || rel.startsWith('..') || rel.includes('/')) return null;
  return fullPath;
}

function resolveBundledUmbraUiWorkflowFilePath(rawId: unknown): string | null {
  const fullPath = resolvePPApiWorkflowFilePathInDirectory(rawId, PP_BUNDLED_API_WORKFLOWS_DIR);
  if (!fullPath || !/^\[Umbra UI\].+\.json$/i.test(basename(fullPath))) return null;
  return fullPath;
}

function extractPPApiPromptGraph(rawDoc: unknown): Record<string, unknown> | null {
  const isPromptGraph = (value: unknown): value is Record<string, unknown> => {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return false;
    const entries = Object.values(value as Record<string, unknown>);
    if (entries.length <= 0) return false;
    return entries.every((entry) => (
      !!entry
      && typeof entry === 'object'
      && !Array.isArray(entry)
      && String((entry as any).class_type || '').trim().length > 0
    ));
  };

  if (isPromptGraph(rawDoc)) return rawDoc;
  if (rawDoc && typeof rawDoc === 'object' && isPromptGraph((rawDoc as any).prompt)) {
    return (rawDoc as any).prompt;
  }
  if (rawDoc && typeof rawDoc === 'object' && isPromptGraph((rawDoc as any).output)) {
    return (rawDoc as any).output;
  }
  return null;
}

function normalizePPApiWorkflowResourceKind(value: unknown): PPApiWorkflowResourceKind | null {
  const normalized = String(value || '').trim().toLowerCase().replace(/[\s-]+/g, '_');
  const aliases: Record<string, PPApiWorkflowResourceKind> = {
    ckpt: 'checkpoint',
    checkpoints: 'checkpoint',
    diffuser: 'diffusers',
    diffusion_models: 'diffusion_model',
    model_only: 'diffusion_model',
    unets: 'unet',
    vaes: 'vae',
    clip: 'text_encoder',
    text_encoders: 'text_encoder',
    encoder: 'text_encoder',
    vision_encoder: 'clip_vision',
    clipvision: 'clip_vision',
    control_net: 'controlnet',
    upscale: 'upscale_model',
  };
  const candidate = aliases[normalized] || normalized;
  return [
    'checkpoint', 'diffusers', 'diffusion_model', 'unet', 'gguf', 'vae',
    'text_encoder', 'clip_vision', 'controlnet', 'upscale_model', 'model',
  ].includes(candidate) ? candidate as PPApiWorkflowResourceKind : null;
}

function sanitizePPApiWorkflowResourceId(value: unknown, fallback: string): string {
  const normalized = String(value || '').trim().toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 160);
  return normalized || fallback;
}

function titlePPApiWorkflowResourceInput(inputName: string): string {
  return inputName
    .replace(/clip_name/gi, 'Text Encoder ')
    .replace(/ckpt_name/gi, 'Checkpoint')
    .replace(/unet_name/gi, 'Diffusion Model')
    .replace(/vae_name/gi, 'VAE')
    .replace(/control_net_name/gi, 'ControlNet')
    .replace(/model_name/gi, 'Model')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (character) => character.toUpperCase());
}

function inferPPApiWorkflowResourceInputs(classType: string): Array<{
  inputName: string;
  kind: PPApiWorkflowResourceKind;
  label?: string;
}> {
  if (classType === 'CheckpointLoaderSimple' || classType === 'unCLIPCheckpointLoader') {
    return [{ inputName: 'ckpt_name', kind: 'checkpoint', label: 'Checkpoint' }];
  }
  if (classType === 'DiffusersLoader') {
    return [{ inputName: 'model_path', kind: 'diffusers', label: 'Diffusers Model' }];
  }
  if (classType === 'UNETLoader' || classType === 'DiffusionModelLoader') {
    return [{ inputName: 'unet_name', kind: 'diffusion_model', label: 'Diffusion Model' }];
  }
  if (classType === 'VAELoader') {
    return [{ inputName: 'vae_name', kind: 'vae', label: 'VAE' }];
  }
  if (classType === 'CLIPLoader') {
    return [{ inputName: 'clip_name', kind: 'text_encoder', label: 'Text Encoder' }];
  }
  if (classType === 'DualCLIPLoader') {
    return [1, 2].map((index) => ({ inputName: `clip_name${index}`, kind: 'text_encoder', label: `Text Encoder ${index}` }));
  }
  if (classType === 'TripleCLIPLoader') {
    return [1, 2, 3].map((index) => ({ inputName: `clip_name${index}`, kind: 'text_encoder', label: `Text Encoder ${index}` }));
  }
  if (classType === 'QuadrupleCLIPLoader') {
    return [1, 2, 3, 4].map((index) => ({ inputName: `clip_name${index}`, kind: 'text_encoder', label: `Text Encoder ${index}` }));
  }
  if (classType === 'CLIPVisionLoader') {
    return [{ inputName: 'clip_name', kind: 'clip_vision', label: 'Vision Encoder' }];
  }
  if (classType === 'ControlNetLoader' || classType === 'DiffControlNetLoader') {
    return [{ inputName: 'control_net_name', kind: 'controlnet', label: 'ControlNet' }];
  }
  if (classType === 'UpscaleModelLoader') {
    return [{ inputName: 'model_name', kind: 'upscale_model', label: 'Upscale Model' }];
  }
  return [];
}

function describePPApiWorkflowResources(promptGraph: Record<string, unknown>): PPApiWorkflowResourceSelector[] {
  const resources: PPApiWorkflowResourceSelector[] = [];
  const seenInputs = new Set<string>();
  const seenIds = new Set<string>();
  const append = (
    nodeId: string,
    node: any,
    inputName: string,
    kind: PPApiWorkflowResourceKind,
    raw: Record<string, unknown> = {},
    fallbackLabel = '',
  ) => {
    const inputKey = `${nodeId}:${inputName}`;
    if (!inputName || seenInputs.has(inputKey)) return;
    const fallbackId = sanitizePPApiWorkflowResourceId(`${kind}.${nodeId}.${inputName}`, `resource-${resources.length + 1}`);
    let id = sanitizePPApiWorkflowResourceId(raw.id, fallbackId);
    if (seenIds.has(id)) id = `${id}-${resources.length + 1}`;
    seenInputs.add(inputKey);
    seenIds.add(id);
    const rawOptions = Array.isArray(raw.options) ? raw.options : [];
    resources.push({
      id,
      label: String(raw.label || fallbackLabel || titlePPApiWorkflowResourceInput(inputName)).trim().slice(0, 120),
      kind,
      nodeId,
      inputName,
      required: raw.required !== false,
      defaultValue: typeof node?.inputs?.[inputName] === 'string' ? String(node.inputs[inputName]).trim().replace(/\\/g, '/') : '',
      options: Array.from(new Set(rawOptions.map((entry) => String(entry || '').trim().replace(/\\/g, '/')).filter(Boolean))).slice(0, 500),
      order: Number.isFinite(Number(raw.order)) ? Math.floor(Number(raw.order)) : resources.length,
    });
  };

  for (const [nodeId, node] of Object.entries(promptGraph) as Array<[string, any]>) {
    const classType = String(node?.class_type || '').trim();
    const meta = node?._meta && typeof node._meta === 'object' ? node._meta as Record<string, unknown> : {};
    const rawResources = [
      ...(Array.isArray(meta.umbra_resources) ? meta.umbra_resources : []),
      ...(meta.umbra_resource && typeof meta.umbra_resource === 'object' ? [meta.umbra_resource] : []),
    ];
    for (const rawEntry of rawResources) {
      const raw = rawEntry && typeof rawEntry === 'object' ? rawEntry as Record<string, unknown> : {};
      const inputName = String(raw.inputName || raw.input || '').trim();
      const kind = normalizePPApiWorkflowResourceKind(raw.kind || raw.type);
      if (!inputName || !kind) continue;
      append(nodeId, node, inputName, kind, raw);
    }
    for (const inferred of inferPPApiWorkflowResourceInputs(classType)) {
      if (!Object.prototype.hasOwnProperty.call(node?.inputs || {}, inferred.inputName)) continue;
      append(nodeId, node, inferred.inputName, inferred.kind, {}, inferred.label);
    }
  }
  return resources
    .sort((left, right) => left.order - right.order || left.nodeId.localeCompare(right.nodeId, undefined, { numeric: true }))
    .map((resource, order) => ({ ...resource, order }));
}

function describeUmbraUiPipelines(
  promptGraph: Record<string, unknown>,
  fallbackModelFamily: string,
): UmbraUiPipelineDescriptor[] {
  const rawPipelines = Object.values(promptGraph).flatMap((node: any) => {
    const meta = node?._meta && typeof node._meta === 'object' ? node._meta : {};
    return [
      ...(Array.isArray(meta.umbra_ui_pipelines) ? meta.umbra_ui_pipelines : []),
      ...(meta.umbra_ui_pipeline && typeof meta.umbra_ui_pipeline === 'object' && !Array.isArray(meta.umbra_ui_pipeline)
        ? [meta.umbra_ui_pipeline]
        : []),
    ];
  });
  const descriptors = rawPipelines.map((entry) => {
    const rawPipeline = entry && typeof entry === 'object' && !Array.isArray(entry)
      ? entry as Record<string, unknown>
      : {};
    const feature = normalizeUmbraUiPipelineFeature(rawPipeline.feature || rawPipeline.mode);
    const modelFamily = String(
      rawPipeline.modelFamily
      || rawPipeline.model_family
      || rawPipeline.family
      || fallbackModelFamily
      || '',
    ).trim().slice(0, 120);
    const modelFamilyKey = normalizeUmbraUiModelFamilyKey(modelFamily);
    const modelSources = normalizeUmbraUiPipelineModelSources(
      rawPipeline.modelSources ?? rawPipeline.model_sources ?? rawPipeline.modelTypes ?? rawPipeline.model_types,
    );
    if (!feature || !modelFamily || !modelFamilyKey || modelSources.length <= 0) return null;
    const rawInpaintAdapter = String(rawPipeline.inpaintAdapter || rawPipeline.inpaint_adapter || '').trim().toLowerCase();
    const inpaintAdapter: UmbraUiInpaintAdapter | undefined = feature !== 'inpainting'
      ? undefined
      : rawInpaintAdapter === 'qwen_image_controlnet'
        ? 'qwen_image_controlnet'
        : rawInpaintAdapter === 'flux_fill'
          ? 'flux_fill'
          : rawInpaintAdapter === 'native_edit'
            ? 'native_edit'
            : rawInpaintAdapter === 'classic_conditioning'
              ? 'classic_conditioning'
              : undefined;
    if (feature === 'inpainting' && !inpaintAdapter) return null;
    const rawDefaults = rawPipeline.defaults && typeof rawPipeline.defaults === 'object' && !Array.isArray(rawPipeline.defaults)
      ? rawPipeline.defaults as Record<string, unknown>
      : {};
    const rawModelNamesBySource = rawDefaults.modelNamesBySource ?? rawDefaults.model_names_by_source;
    const modelNamesBySource: Partial<Record<UmbraUiPipelineModelSource, string>> = {};
    if (rawModelNamesBySource && typeof rawModelNamesBySource === 'object' && !Array.isArray(rawModelNamesBySource)) {
      for (const [rawSource, rawModelName] of Object.entries(rawModelNamesBySource as Record<string, unknown>)) {
        const source = normalizeUmbraUiPipelineModelSources([rawSource])[0];
        const modelName = String(rawModelName || '').trim().replace(/\\/g, '/').slice(0, 500);
        if (source && modelName) modelNamesBySource[source] = modelName;
      }
    }
    const readFiniteDefault = (key: string, fallbackKey = '') => {
      const value = rawDefaults[key] ?? (fallbackKey ? rawDefaults[fallbackKey] : undefined);
      const numeric = Number(value);
      return Number.isFinite(numeric) ? numeric : undefined;
    };
    const defaults = {
      modelName: String(rawDefaults.modelName || rawDefaults.model_name || '').trim().replace(/\\/g, '/').slice(0, 500) || undefined,
      modelNamesBySource: Object.keys(modelNamesBySource).length > 0 ? modelNamesBySource : undefined,
      adapterModelName: String(rawDefaults.adapterModelName || rawDefaults.adapter_model_name || '').trim().replace(/\\/g, '/').slice(0, 500) || undefined,
      steps: readFiniteDefault('steps'),
      cfg: readFiniteDefault('cfg'),
      denoise: readFiniteDefault('denoise'),
      samplerName: String(rawDefaults.samplerName || rawDefaults.sampler_name || '').trim().slice(0, 120) || undefined,
      scheduler: String(rawDefaults.scheduler || '').trim().slice(0, 120) || undefined,
      width: readFiniteDefault('width'),
      height: readFiniteDefault('height'),
      clipSkip: readFiniteDefault('clipSkip', 'clip_skip'),
    };
    const hasDefaults = Object.values(defaults).some((value) => value !== undefined);
    const descriptor: UmbraUiPipelineDescriptor = {
      feature,
      modelFamily,
      modelFamilyKey,
      modelSources,
      priority: Number.isFinite(Number(rawPipeline.priority)) ? Math.floor(Number(rawPipeline.priority)) : 0,
      locked: true,
      ...(inpaintAdapter ? { inpaintAdapter } : {}),
      ...(hasDefaults ? { defaults } : {}),
    };
    if (feature === 'txt2img' || feature === 'img2img' || feature === 'inpainting') {
      descriptor.capabilities = deriveUmbraUiTxt2ImgCapabilities(promptGraph, descriptor);
    }
    if (feature === 'inpainting') {
      descriptor.inpaintCanvas = deriveUmbraUiInpaintCanvasCapabilities(promptGraph, descriptor);
    }
    return descriptor;
  }).filter((entry): entry is UmbraUiPipelineDescriptor => !!entry);
  const seen = new Set<string>();
  return descriptors.filter((entry) => {
    const key = `${entry.feature}:${entry.modelFamilyKey}:${entry.modelSources.join(',')}:${entry.inpaintAdapter || ''}:${entry.priority}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function describePPApiWorkflow(rawDoc: unknown): {
  mediaType: PowerPrompterMediaType;
  modelFamily?: string;
  umbraUiPipelines?: UmbraUiPipelineDescriptor[];
  resources: PPApiWorkflowResourceSelector[];
  videoFamily?: PowerPrompterVideoFamily;
  videoMode?: PowerPrompterVideoMode;
} {
  const promptGraph = extractPPApiPromptGraph(rawDoc);
  if (!promptGraph) return { mediaType: 'image', resources: [] };
  const resources = describePPApiWorkflowResources(promptGraph);
  const modelFamily = Object.values(promptGraph)
    .map((node: any) => String(node?._meta?.umbra_model_family || '').trim())
    .find(Boolean) || '';
  const umbraUiPipelines = describeUmbraUiPipelines(promptGraph, modelFamily);
  const effectiveModelFamily = modelFamily || umbraUiPipelines[0]?.modelFamily || '';
  for (const node of Object.values(promptGraph) as any[]) {
    const mediaType = String(node?._meta?.umbra_media_type || '').trim().toLowerCase();
    if (mediaType !== 'video') continue;
    const familyRaw = String(node?._meta?.umbra_video_family || '').trim().toLowerCase();
    const modeRaw = String(node?._meta?.umbra_video_mode || '').trim().toLowerCase();
    return {
      mediaType: 'video',
      ...(effectiveModelFamily ? { modelFamily: effectiveModelFamily } : {}),
      ...(umbraUiPipelines.length > 0 ? { umbraUiPipelines } : {}),
      resources,
      videoFamily: familyRaw === 'ltx23' ? 'ltx23' : 'wan22',
      videoMode: modeRaw === 'video_to_video'
        ? 'video_to_video'
        : modeRaw === 'image_to_video' ? 'image_to_video' : 'text_to_video',
    };
  }
  return {
    mediaType: 'image',
    ...(effectiveModelFamily ? { modelFamily: effectiveModelFamily } : {}),
    ...(umbraUiPipelines.length > 0 ? { umbraUiPipelines } : {}),
    resources,
  };
}

let ppComfyObjectInfoCache: { expiresAt: number; objectInfo: Record<string, unknown> | null } = {
  expiresAt: 0,
  objectInfo: null,
};

async function getPPComfyObjectInfoForValidation(): Promise<Record<string, unknown> | null> {
  const now = Date.now();
  if (ppComfyObjectInfoCache.expiresAt > now) return ppComfyObjectInfoCache.objectInfo;
  try {
    const response = await fetch(`${getComfyProxyBaseUrl()}/object_info`, {
      cache: 'no-store',
      signal: AbortSignal.timeout(5000),
    });
    if (!response.ok) throw new Error(`ComfyUI object_info returned ${response.status}`);
    const payload = await response.json().catch(() => null);
    const objectInfo = payload && typeof payload === 'object' && !Array.isArray(payload)
      ? payload as Record<string, unknown>
      : null;
    ppComfyObjectInfoCache = {
      expiresAt: now + 15000,
      objectInfo,
    };
    return objectInfo;
  } catch {
    ppComfyObjectInfoCache = {
      expiresAt: now + 3000,
      objectInfo: null,
    };
    return null;
  }
}

interface PPApiWorkflowValidation {
  ok: boolean;
  missing: string[];
  graph: UmbraUiPipelineReadiness['graph'];
  runtimeNodes: UmbraUiPipelineReadiness['runtime']['nodes'];
  pipelineGraphIssues: Record<string, string[]>;
}

function getUmbraUiPipelineValidationKey(pipeline: UmbraUiPipelineDescriptor): string {
  return [
    pipeline.feature,
    pipeline.modelFamilyKey,
    pipeline.modelSources.join(','),
    pipeline.inpaintAdapter || '',
    pipeline.priority,
  ].join(':');
}

function validatePPApiWorkflowDocument(
  rawDoc: unknown,
  availableComfyClassTypes: Set<string> | null = null,
): PPApiWorkflowValidation {
  const promptGraph = extractPPApiPromptGraph(rawDoc);
  if (!promptGraph) {
    return {
      ok: false,
      missing: ['prompt graph'],
      graph: { status: 'invalid', issues: ['prompt graph'] },
      runtimeNodes: { status: availableComfyClassTypes ? 'ready' : 'unverified', missing: [] },
      pipelineGraphIssues: {},
    };
  }
  const classTypes = new Set(
    Object.values(promptGraph)
      .map((entry) => String((entry as any)?.class_type || '').trim())
      .filter((entry) => entry.length > 0)
  );
  const graphIssues: string[] = [];
  const descriptor = describePPApiWorkflow(rawDoc);
  if (descriptor.mediaType === 'video') {
    const roles = new Set(
      Object.values(promptGraph)
        .map((entry) => getPPApiNodeRole(entry))
        .filter(Boolean)
    );
    if (!roles.has('positive_prompt')) graphIssues.push('Umbra video role: positive_prompt');
    if (!roles.has('video_output')) graphIssues.push('Umbra video role: video_output');
    if (!classTypes.has('SaveVideo') && !classTypes.has('VHS_VideoCombine')) {
      graphIssues.push('SaveVideo/VHS_VideoCombine');
    }
  } else {
    const hasUnifiedPowerPrompter = classTypes.has('UmbraPowerPrompter');
    if (!hasUnifiedPowerPrompter) {
      if (!classTypes.has('UmbraPowerPrompterReader')) graphIssues.push('UmbraPowerPrompterReader');
      const imageSamplerTypes = [
        'UmbraKSampler',
        'UmbraKSamplerNormal',
        'UmbraKSamplerHiResFix',
        'KSampler',
        'KSamplerAdvanced',
        'SamplerCustom',
        'SamplerCustomAdvanced',
      ];
      if (!imageSamplerTypes.some((classType) => classTypes.has(classType))) {
        graphIssues.push('image sampler');
      }
    }
    if (!classTypes.has('UmbraLabSaveImage')) {
      graphIssues.push('UmbraLabSaveImage');
    }
  }
  const pipelineGraphIssues: Record<string, string[]> = {};
  for (const pipeline of descriptor.umbraUiPipelines || []) {
    const issues = pipeline.feature === 'inpainting'
      ? listUmbraUiInpaintPipelineGraphIssues(promptGraph, pipeline)
      : pipeline.feature === 'img2img'
        ? listUmbraUiImg2ImgPipelineGraphIssues(promptGraph)
        : pipeline.feature === 'vid2vid'
          ? listUmbraUiVid2VidPipelineGraphIssues(promptGraph)
        : [];
    if (issues.length > 0) pipelineGraphIssues[getUmbraUiPipelineValidationKey(pipeline)] = issues;
  }
  const missingNodeTypes: string[] = [];
  if (availableComfyClassTypes) {
    for (const classType of classTypes) {
      if (!availableComfyClassTypes.has(classType)) {
        missingNodeTypes.push(classType);
      }
    }
  }
  const runtimeNodes: UmbraUiPipelineReadiness['runtime']['nodes'] = availableComfyClassTypes
    ? {
      status: missingNodeTypes.length > 0 ? 'missing' : 'ready',
      missing: missingNodeTypes,
    }
    : { status: 'unverified', missing: [] };
  const missing = [...graphIssues];
  return {
    ok: graphIssues.length <= 0,
    missing,
    graph: {
      status: graphIssues.length > 0 ? 'invalid' : 'valid',
      issues: graphIssues,
    },
    runtimeNodes,
    pipelineGraphIssues,
  };
}

function getPPComfyResourceKinds(nodeType: string, inputName: string): PPApiWorkflowResourceKind[] {
  if (nodeType === 'ModelPatchLoader' && inputName === 'name') return ['model'];
  if (inputName === 'checkpoint_name' || inputName === 'ckpt_name') return ['checkpoint'];
  if (inputName === 'diffusers_model' || inputName === 'model_path') return ['diffusers'];
  if (inputName === 'diffusion_model_name') return ['diffusion_model'];
  if (inputName === 'unet_name') return ['diffusion_model', 'unet'];
  if (inputName === 'gguf_name') return ['gguf'];
  if (/^clip_name\d*$/.test(inputName)) {
    return /vision/i.test(nodeType) ? ['clip_vision'] : ['text_encoder'];
  }
  if (inputName === 'vae_name') return ['vae'];
  if (inputName === 'control_net_name') return ['controlnet'];
  if (inputName === 'upscale_model' || (inputName === 'model_name' && /upscale/i.test(nodeType))) {
    return ['upscale_model'];
  }
  if (inputName === 'model_name') return ['model'];
  return [];
}

function buildPPComfyResourceCatalog(
  objectInfo: Record<string, unknown> | null,
): Map<PPApiWorkflowResourceKind, Set<string>> {
  const catalog = new Map<PPApiWorkflowResourceKind, Set<string>>();
  if (!objectInfo) return catalog;
  for (const [nodeType, rawNode] of Object.entries(objectInfo)) {
    const input = toRecord(toRecord(rawNode).input);
    for (const rawSection of [input.required, input.optional]) {
      const section = toRecord(rawSection);
      for (const [inputName, rawDescriptor] of Object.entries(section)) {
        const descriptor = Array.isArray(rawDescriptor) ? rawDescriptor : [];
        const options = Array.isArray(descriptor[0]) ? descriptor[0] : [];
        if (options.length <= 0) continue;
        for (const kind of getPPComfyResourceKinds(nodeType, inputName)) {
          const values = catalog.get(kind) || new Set<string>();
          for (const rawOption of options) {
            const option = normalizeUmbraUiCatalogName(rawOption);
            if (option && !['none', '[none]'].includes(option.toLowerCase())) values.add(option);
          }
          catalog.set(kind, values);
        }
      }
    }
  }
  return catalog;
}

function formatUmbraUiQueueResourceIssue(issue: UmbraUiQueueResourceIssue): string {
  if (issue.type === 'selection_required') {
    return `${issue.label} selection is required before this pipeline can run.`;
  }
  if (issue.type === 'ambiguous') {
    return `${issue.label} "${issue.value}" is ambiguous. Choose an exact relative path${issue.matches.length > 0 ? ` (${issue.matches.join(', ')})` : ''}.`;
  }
  if (issue.type === 'missing') {
    return `${issue.label} "${issue.value}" is not installed in ComfyUI.`;
  }
  return `${issue.label} "${issue.value}" could not be verified against the live ComfyUI resource catalog.`;
}

async function assertPPApiWorkflowExecutionReady(
  loaded: LoadedPPApiWorkflow,
  generationInput: unknown,
): Promise<void> {
  const objectInfo = await getPPComfyObjectInfoForValidation();
  const availableClassTypes = objectInfo ? new Set(Object.keys(objectInfo)) : null;
  const validation = validatePPApiWorkflowDocument(loaded.document, availableClassTypes);
  if (!validation.ok) {
    throw new Error(`Selected generation pipeline has an invalid graph: ${validation.graph.issues.join(', ') || 'unknown graph issue'}.`);
  }
  const nodeError = getUmbraUiRuntimeNodeExecutionError(validation.runtimeNodes);
  if (nodeError) throw new Error(nodeError);

  const catalog = buildPPComfyResourceCatalog(objectInfo);
  const generation = normalizePPGenerationControls(generationInput);
  const requiredIssues = listUmbraUiRequiredResourceIssues(
    loaded.item.resources,
    generation.workflowResources,
    catalog,
  );
  if (requiredIssues[0]) throw new Error(formatUmbraUiQueueResourceIssue(requiredIssues[0]));

  if (loaded.item.mediaType === 'image' && loaded.selectedPipeline) {
    const modelSource = loaded.selectedModelSource || generation.modelType;
    const primaryModelIssue = getUmbraUiResourceSelectionIssue(
      'primary-model',
      'Primary model',
      modelSource,
      generation.checkpointName,
      catalog,
    );
    if (primaryModelIssue) throw new Error(formatUmbraUiQueueResourceIssue(primaryModelIssue));
  }

  const capabilities = loaded.selectedPipeline?.capabilities;
  if (!capabilities) return;
  const optionalPolicy = resolveUmbraUiOptionalStagePolicy(
    capabilities,
    generation.hiresFix || {},
    Array.isArray(generation.detailerPipeline) ? generation.detailerPipeline : [],
    generation.outputUpscale || {},
  );
  if (!optionalPolicy.outputUpscale.enabled) return;
  const selectedUpscaleModel = optionalPolicy.outputUpscale.modelSelection
    ? generation.outputUpscale?.modelName
    : capabilities.finalModelUpscale.value;
  if (!optionalPolicy.outputUpscale.modelSelection
    && (typeof selectedUpscaleModel !== 'string' || !selectedUpscaleModel.trim())) return;
  const upscaleIssue = getUmbraUiResourceSelectionIssue(
    'final-upscale-model',
    'Output upscale model',
    'upscale_model',
    selectedUpscaleModel,
    catalog,
  );
  if (upscaleIssue) throw new Error(formatUmbraUiQueueResourceIssue(upscaleIssue));
}

function listPPQueueGenerationInputs(stateInput: unknown): unknown[] {
  const state = stateInput && typeof stateInput === 'object' ? stateInput as Record<string, unknown> : {};
  const generations = Array.isArray(state.generationByPrompt) ? state.generationByPrompt : [];
  return generations.length > 0 ? generations : [state.generation];
}

function describeUmbraUiPipelineResourceReadiness(
  pipeline: UmbraUiPipelineDescriptor,
  resources: PPApiWorkflowResourceSelector[],
  objectInfo: Record<string, unknown> | null,
): UmbraUiPipelineReadiness['runtime']['resources'] {
  const references: Omit<UmbraUiPipelineResourceReadinessItem, 'status'>[] = resources
    .filter((resource) => resource.required || resource.defaultValue.length > 0)
    .map((resource) => ({
      id: resource.id,
      label: resource.label,
      kind: resource.kind,
      value: resource.defaultValue,
      required: resource.required,
      source: 'graph' as const,
    }));
  const defaultsBySource = pipeline.defaults?.modelNamesBySource || {};
  for (const source of pipeline.modelSources) {
    const value = String(
      defaultsBySource[source]
      || (source === pipeline.modelSources[0] ? pipeline.defaults?.modelName : '')
      || '',
    ).trim().replace(/\\/g, '/');
    if (!value) continue;
    references.push({
      id: `default-model.${source}`,
      label: `Default ${source.replace(/_/g, ' ')} model`,
      kind: source,
      value,
      required: false,
      source: 'descriptor_default',
    });
  }
  const upscaleModel = pipeline.capabilities?.finalModelUpscale.value;
  if (typeof upscaleModel === 'string' && upscaleModel.trim()) {
    references.push({
      id: 'final-upscale.default-model',
      label: 'Default final upscale model',
      kind: 'upscale_model',
      value: upscaleModel.trim().replace(/\\/g, '/'),
      required: false,
      source: 'graph',
    });
  }

  const seen = new Set<string>();
  const catalog = buildPPComfyResourceCatalog(objectInfo);
  const items = references
    .filter((reference) => {
      const key = `${reference.kind}:${reference.value.toLowerCase() || reference.id}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .map((reference): UmbraUiPipelineResourceReadinessItem => {
      const availableValues = catalog.get(reference.kind);
      const status: UmbraUiPipelineResourceReadinessItem['status'] = reference.required && !reference.value
        ? 'selection_required'
        : !objectInfo || !availableValues || availableValues.size <= 0
          ? 'unverified'
          : matchUmbraUiResourceCatalog(reference.value, availableValues).status;
      return { ...reference, status };
    });
  const missing = items.filter((item) => item.status === 'missing').map((item) => item.value);
  const requiredMissing = items
    .filter((item) => item.required && item.status === 'missing')
    .map((item) => item.value);
  const selectionRequired = items
    .filter((item) => item.required && item.status === 'selection_required')
    .map((item) => item.label);
  const ambiguous = items
    .filter((item) => item.status === 'ambiguous')
    .map((item) => item.value);
  return {
    status: resolveUmbraUiPipelineResourceReadinessStatus(items, Boolean(objectInfo)),
    missing,
    requiredMissing,
    selectionRequired,
    ambiguous,
    items,
  };
}

function attachUmbraUiPipelineReadiness(
  descriptor: ReturnType<typeof describePPApiWorkflow>,
  validation: PPApiWorkflowValidation,
  objectInfo: Record<string, unknown> | null,
): ReturnType<typeof describePPApiWorkflow> {
  if (!descriptor.umbraUiPipelines) return descriptor;
  return {
    ...descriptor,
    umbraUiPipelines: descriptor.umbraUiPipelines.map((pipeline) => {
      const capabilities = pipeline.capabilities
        || (pipeline.feature === 'txt2img' || pipeline.feature === 'img2img'
          ? deriveUmbraUiTxt2ImgCapabilities({}, pipeline)
          : undefined);
      if (!capabilities) return pipeline;
      const pipelineIssues = validation.pipelineGraphIssues[getUmbraUiPipelineValidationKey(pipeline)] || [];
      const graphIssues = Array.from(new Set([
        ...validation.graph.issues,
        ...pipelineIssues,
      ]));
      return {
        ...pipeline,
        capabilities,
        readiness: {
          graph: {
            status: graphIssues.length > 0 ? 'invalid' : validation.graph.status,
            issues: graphIssues,
          },
          capabilitySupport: summarizeUmbraUiPipelineCapabilitySupport(capabilities, pipeline.modelSources),
          runtime: {
            comfyUi: objectInfo ? 'online' : 'offline',
            nodes: validation.runtimeNodes,
            resources: describeUmbraUiPipelineResourceReadiness(
              { ...pipeline, capabilities },
              descriptor.resources,
              objectInfo,
            ),
          },
        },
      } satisfies UmbraUiResolvedPipelineDescriptor;
    }),
  };
}

async function loadPPApiWorkflowFromFilePath(fullPath: string | null): Promise<LoadedPPApiWorkflow | null> {
  if (!fullPath || !existsSync(fullPath)) return null;
  const stat = statSync(fullPath);
  if (!stat.isFile()) return null;
  const raw = readFileSync(fullPath, 'utf-8');
  const parsed = JSON.parse(raw);
  const objectInfo = await getPPComfyObjectInfoForValidation();
  const comfyClassTypes = objectInfo ? new Set(Object.keys(objectInfo)) : null;
  const validation = validatePPApiWorkflowDocument(parsed, comfyClassTypes);
  const descriptor = attachUmbraUiPipelineReadiness(describePPApiWorkflow(parsed), validation, objectInfo);
  const fileName = basename(fullPath);
  const id = fileName.replace(/\.json$/i, '');
  return {
    item: {
      id,
      fileName,
      name: sanitizePPApiWorkflowBaseName(id),
      compatible: validation.ok,
      missing: validation.missing,
      runtimeNodes: validation.runtimeNodes,
      ...descriptor,
      updatedAt: stat.mtimeMs,
      size: stat.size,
    },
    document: parsed,
  };
}

async function loadPPApiWorkflowById(rawId: unknown): Promise<LoadedPPApiWorkflow | null> {
  return loadPPApiWorkflowFromFilePath(resolvePPApiWorkflowFilePath(rawId));
}

async function loadBundledUmbraUiWorkflowById(rawId: unknown): Promise<LoadedPPApiWorkflow | null> {
  return loadPPApiWorkflowFromFilePath(resolveBundledUmbraUiWorkflowFilePath(rawId));
}

async function listPPApiWorkflowsFromDirectory(
  directory: string,
  include: (fileName: string) => boolean = () => true,
): Promise<PPApiWorkflowListItem[]> {
  if (!existsSync(directory)) return [];
  const objectInfo = await getPPComfyObjectInfoForValidation();
  const comfyClassTypes = objectInfo ? new Set(Object.keys(objectInfo)) : null;
  const entries = readdirSync(directory, { withFileTypes: true })
    .filter((entry) => entry.isFile() && entry.name.toLowerCase().endsWith('.json') && include(entry.name));
  const items: PPApiWorkflowListItem[] = [];
  for (const entry of entries) {
    const fullPath = join(directory, entry.name);
    try {
      const stat = statSync(fullPath);
      const content = readFileSync(fullPath, 'utf-8');
      const parsed = JSON.parse(content);
      const validation = validatePPApiWorkflowDocument(parsed, comfyClassTypes);
      const descriptor = attachUmbraUiPipelineReadiness(describePPApiWorkflow(parsed), validation, objectInfo);
      const id = entry.name.replace(/\.json$/i, '');
      items.push({
        id,
        fileName: entry.name,
        name: sanitizePPApiWorkflowBaseName(id),
        compatible: validation.ok,
        missing: validation.missing,
        runtimeNodes: validation.runtimeNodes,
        ...descriptor,
        updatedAt: stat.mtimeMs,
        size: stat.size,
      });
    } catch {
      // ignore invalid workflow file
    }
  }
  items.sort((a, b) => b.updatedAt - a.updatedAt || a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }));
  return items;
}

async function listPPApiWorkflows(): Promise<PPApiWorkflowListItem[]> {
  ensurePPApiWorkflowDirSync();
  return listPPApiWorkflowsFromDirectory(PP_API_WORKFLOWS_DIR);
}

async function listBundledUmbraUiWorkflows(): Promise<PPApiWorkflowListItem[]> {
  return listPPApiWorkflowsFromDirectory(
    PP_BUNDLED_API_WORKFLOWS_DIR,
    (fileName) => /^\[Umbra UI\].+\.json$/i.test(fileName),
  );
}

interface UmbraUiPipelineRegistryEntry extends UmbraUiPipelineDescriptor {
  workflowId: string;
  workflowName: string;
  compatible: boolean;
  missing: string[];
  updatedAt: number;
}

function buildUmbraUiPipelineRegistry(items: PPApiWorkflowListItem[]): UmbraUiPipelineRegistryEntry[] {
  return items
    .flatMap((item) => (item.umbraUiPipelines || []).map((pipeline) => ({
      ...pipeline,
      workflowId: item.id,
      workflowName: item.name,
      compatible: pipeline.readiness?.graph.status === 'valid'
        || (pipeline.readiness?.graph.status == null && item.compatible),
      missing: pipeline.readiness?.graph.issues
        ? [...pipeline.readiness.graph.issues]
        : [...item.missing],
      updatedAt: item.updatedAt,
    })))
    .sort((left, right) => (
      left.feature.localeCompare(right.feature)
      || left.modelFamily.localeCompare(right.modelFamily, undefined, { sensitivity: 'base' })
      || right.priority - left.priority
      || right.updatedAt - left.updatedAt
    ));
}

async function listUmbraUiPipelines(): Promise<UmbraUiPipelineRegistryEntry[]> {
  return buildUmbraUiPipelineRegistry(await listBundledUmbraUiWorkflows());
}

async function resolveUmbraUiPipeline(
  featureInput: unknown,
  modelFamilyInput: unknown,
  modelSourceInput: unknown,
): Promise<{
  pipeline: UmbraUiPipelineRegistryEntry;
  loaded: LoadedPPApiWorkflow;
}> {
  const feature = normalizeUmbraUiPipelineFeature(featureInput);
  if (!feature) throw new Error('Umbra UI pipeline feature is missing or invalid.');
  const modelFamily = String(modelFamilyInput || '').trim();
  const modelFamilyKey = normalizeUmbraUiModelFamilyKey(modelFamily);
  if (!modelFamilyKey) {
    throw new Error('Model family is missing. Tag the PPCard file with Anima, SDXL, Flux, ERNIE, HiDream, Krea 2, or another installed Umbra UI family.');
  }
  const modelSource = normalizeUmbraUiPipelineModelSources(modelSourceInput)[0] || null;
  if (!modelSource) throw new Error('Primary model source is missing or invalid.');

  const registry = await listUmbraUiPipelines();
  const familyMatches = registry.filter((entry) => (
    entry.feature === feature
    && entry.modelFamilyKey === modelFamilyKey
  ));
  if (familyMatches.length <= 0) {
    const available = Array.from(new Set(registry
      .filter((entry) => entry.feature === feature)
      .map((entry) => entry.modelFamily)))
      .sort((left, right) => left.localeCompare(right, undefined, { sensitivity: 'base' }));
    throw new Error(`No locked Umbra UI ${feature} pipeline is installed for ${modelFamily}.${available.length > 0 ? ` Available families: ${available.join(', ')}.` : ''}`);
  }
  const sourceMatches = familyMatches.filter((entry) => entry.modelSources.includes(modelSource));
  if (sourceMatches.length <= 0) {
    const acceptedSources = Array.from(new Set(familyMatches.flatMap((entry) => entry.modelSources)));
    throw new Error(`The ${familyMatches[0].modelFamily} ${feature} pipeline does not accept ${modelSource} models. Accepted sources: ${acceptedSources.join(', ')}.`);
  }
  const compatibleMatches = sourceMatches.filter((entry) => entry.compatible);
  if (compatibleMatches.length <= 0) {
    const missing = Array.from(new Set(sourceMatches.flatMap((entry) => entry.missing)));
    throw new Error(`The locked ${familyMatches[0].modelFamily} ${feature} pipeline is unavailable.${missing.length > 0 ? ` Missing: ${missing.join(', ')}.` : ''}`);
  }
  const sorted = [...compatibleMatches].sort((left, right) => right.priority - left.priority || right.updatedAt - left.updatedAt);
  if (sorted.length > 1 && sorted[0].priority === sorted[1].priority) {
    throw new Error(`Multiple locked ${familyMatches[0].modelFamily} ${feature} pipelines have priority ${sorted[0].priority}. Assign one pipeline a higher priority.`);
  }
  const pipeline = sorted[0];
  const loaded = await loadBundledUmbraUiWorkflowById(pipeline.workflowId);
  if (!loaded) throw new Error(`Locked Umbra UI pipeline file was not found (${pipeline.workflowId}).`);
  return {
    pipeline,
    loaded: {
      ...loaded,
      selectedPipeline: pipeline,
      selectedModelSource: modelSource,
    },
  };
}

function getUmbraUiPipelineRequestFromQueueState(stateInput: unknown): {
  feature: UmbraUiPipelineFeature | null;
  modelFamily: string;
  modelSource: PowerPrompterModelType;
} {
  const state = stateInput && typeof stateInput === 'object' ? stateInput as Record<string, unknown> : {};
  const generation = Array.isArray(state.generationByPrompt) && state.generationByPrompt[0] && typeof state.generationByPrompt[0] === 'object'
    ? state.generationByPrompt[0] as Record<string, unknown>
    : state.generation && typeof state.generation === 'object'
      ? state.generation as Record<string, unknown>
      : {};
  const pipeline = normalizeUmbraUiPipelineSelection(state.pipeline, {
    feature: normalizeUmbraUiPipelineFeature(state.umbraUiFeature || state.pipelineFeature) || 'txt2img',
    modelFamily: String(state.modelFamily || state.ppcardModelType || state.documentModelType || ''),
    modelSource: normalizePPGenerationModelType(generation.modelType ?? generation.model_type),
  });
  return {
    feature: normalizeUmbraUiPipelineFeature(
      pipeline.feature
      || state.umbraUiFeature
      || state.pipelineFeature
      || generation.outputMode
      || (String(generation.mediaType || '').trim().toLowerCase() === 'video' ? (generation as any)?.video?.mode : 'txt2img'),
    ),
    modelFamily: String(
      pipeline.modelFamily
      || state.modelFamily
      || state.ppcardModelType
      || state.documentModelType
      || (generation as any).modelFamily
      || '',
    ).trim(),
    modelSource: normalizePPGenerationModelType(pipeline.modelSource || (generation.modelType ?? generation.model_type)),
  };
}

function getPowerPrompterPipelineSelection(
  stateInput: unknown,
  loaded?: LoadedPPApiWorkflow | null,
): UmbraUiPipelineSelection {
  const request = getUmbraUiPipelineRequestFromQueueState(stateInput);
  return normalizeUmbraUiPipelineSelection({
    feature: loaded?.selectedPipeline?.feature || request.feature || 'txt2img',
    modelFamily: loaded?.selectedPipeline?.modelFamily || request.modelFamily,
    modelFamilyKey: loaded?.selectedPipeline?.modelFamilyKey,
    modelSource: loaded?.selectedModelSource || request.modelSource,
  });
}

async function loadRequestedPowerPrompterPipeline(state: unknown): Promise<LoadedPPApiWorkflow> {
  const request = getUmbraUiPipelineRequestFromQueueState(state);
  const resolved = await resolveUmbraUiPipeline(request.feature, request.modelFamily, request.modelSource);
  return resolved.loaded;
}

async function loadRequestedPPApiWorkflow(
  apiWorkflowId: string,
  state: unknown,
): Promise<LoadedPPApiWorkflow> {
  if (apiWorkflowId !== UMBRA_UI_AUTO_PIPELINE_ID) {
    const loaded = await loadPPApiWorkflowById(apiWorkflowId);
    if (!loaded) throw new Error('Selected API workflow was not found.');
    const request = getUmbraUiPipelineRequestFromQueueState(state);
    const descriptors = loaded.item.umbraUiPipelines || [];
    const modelFamily = request.modelFamily || loaded.item.modelFamily || descriptors[0]?.modelFamily || '';
    const matches = matchUmbraUiPipelineDescriptors(
      descriptors,
      request.feature,
      modelFamily,
      request.modelSource,
    ).sort((left, right) => right.priority - left.priority);
    if (matches.length > 1 && matches[0].priority === matches[1].priority) {
      throw new Error(`Multiple ${modelFamily} ${request.feature || 'generation'} descriptors in the selected workflow share priority ${matches[0].priority}.`);
    }
    if (matches.length <= 0 && descriptors.some((descriptor) => !!descriptor.capabilities)) {
      throw new Error(`The selected workflow has no descriptor matching ${modelFamily}, ${request.feature || 'generation'}, and ${request.modelSource}.`);
    }
    return {
      ...loaded,
      ...(matches[0] ? { selectedPipeline: matches[0], selectedModelSource: request.modelSource } : {}),
    };
  }
  const request = getUmbraUiPipelineRequestFromQueueState(state);
  const resolved = await resolveUmbraUiPipeline(request.feature, request.modelFamily, request.modelSource);
  return resolved.loaded;
}

async function loadPPFavorites(): Promise<PPFavorite[]> {
  try {
    if (existsSync(PP_FAVORITES_PATH)) {
      const content = await fs.readFile(PP_FAVORITES_PATH, 'utf-8');
      return JSON.parse(content);
    }
  } catch { }
  return [];
}

async function savePPFavorites(favorites: PPFavorite[]) {
  const configDir = join(USER_DIR, 'Config');
  if (!existsSync(configDir)) await fs.mkdir(configDir, { recursive: true });
  await fs.writeFile(PP_FAVORITES_PATH, JSON.stringify(favorites, null, 2));
}

async function loadPPSelections(): Promise<PPSelectionsMap> {
  try {
    if (existsSync(PP_SELECTIONS_PATH)) {
      const content = await fs.readFile(PP_SELECTIONS_PATH, 'utf-8');
      const parsed = JSON.parse(content);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        const next: PPSelectionsMap = {};
        for (const [key, value] of Object.entries(parsed)) {
          const normalizedKey = normalizePPSelectionFileKey(key);
          if (!normalizedKey) continue;
          next[normalizedKey] = sanitizePPSelectionIndices(value);
        }
        return next;
      }
    }
  } catch { }
  return {};
}

async function savePPSelections(selections: PPSelectionsMap) {
  const configDir = join(USER_DIR, 'Config');
  if (!existsSync(configDir)) await fs.mkdir(configDir, { recursive: true });
  await fs.writeFile(PP_SELECTIONS_PATH, JSON.stringify(selections, null, 2));
}

interface PPItem {
  tag: string;
  category: number;
  extra?: string; // trigger tags for characters
  source: string;
  sourceId: string;
  type: 'tag' | 'character';
}

type PowerPrompterCardType = 'character' | 'location' | 'expression' | 'action' | 'style' | 'custom';
type PowerPrompterSearchScope = 'scoped' | 'all';

interface PowerPrompterCardNode {
  id: string;
  slotId: string;
  type: PowerPrompterCardType;
  label: string;
  variantName: string;
  variantTags: string[];
  skipVariant?: boolean;
  text: string;
  randomEnabled: boolean;
  randomSetIds: number[];
  queueEnabled: boolean;
  queueSetIds: number[];
  queueCycleWeights?: Record<string, number>;
  chainLinks?: string[];
  blockLinks?: string[];
  order: number;
  createdAt: string;
  updatedAt: string;
}

interface PowerPrompterCardDocument {
  version: number;
  file: string | null;
  createdAt: string;
  updatedAt: string;
  modelType?: string;
  modelColor?: string;
  pipeline?: UmbraUiPipelineSelection;
  activeQueueSet: number;
  styleSeedMode?: 'same' | 'different';
  generation: PowerPrompterGenerationControls;
  cards: PowerPrompterCardNode[];
  deletedCardGroups?: Record<string, unknown>;
}

type PowerPrompterQueueMode = 'prompt' | 'selected' | 'variants';
type PowerPrompterQueueTargetType = 'pipeline';

interface PowerPrompterQueueSnapshot {
  version: 1;
  snapshotSchemaVersion?: number;
  savedAt: number;
  file: string | null;
  mode: PowerPrompterQueueMode;
  activeSetId: number;
  queueTargetType: PowerPrompterQueueTargetType;
  targetBridgeId: string;
  requestIds: string[];
  prompts: string[];
  promptEntries?: unknown[];
  promptSetIds: number[];
  promptOutputSubfolders: string[];
  promptStyleNames: string[];
  promptSeedGroupIds: string[];
  generation: PowerPrompterGenerationControls;
  generationByPrompt: PowerPrompterGenerationControls[];
  randomApplied: boolean;
  paused: boolean;
  dispatchDelayMs: number;
  groupSnapshots?: PowerPrompterQueueGroupSnapshot[];
}

interface PowerPrompterQueueGroupSnapshot {
  id: string;
  requestId: string;
  label?: string;
  mode?: PowerPrompterQueueMode;
  activeSetId?: number;
  promptStartIndex: number;
  promptCount: number;
  promptIndices?: number[];
  editorSnapshot?: unknown;
}

interface PowerPrompterSavedQueueDocument {
  version: 1;
  id: string;
  name: string;
  savedAt: number;
  snapshot: PowerPrompterQueueSnapshot;
}

type PowerPrompterQueueHistoryStatus = 'queued' | 'running' | 'completed' | 'canceled' | 'failed' | 'interrupted';

interface PowerPrompterQueueHistoryPreviewImage {
  id: string;
  path: string;
  name: string;
  type: 'image' | 'video' | 'gif';
  mediaKind?: string;
  promptIndex?: number;
  promptId?: string;
  setId?: number;
  modified?: number;
}

interface PowerPrompterQueueHistoryDocument {
  version: 1;
  id: string;
  name: string;
  createdAt: number;
  updatedAt: number;
  file: string | null;
  mode: PowerPrompterQueueMode;
  activeSetId: number;
  promptCount: number;
  completed: number;
  failed: number;
  canceled: number;
  status: PowerPrompterQueueHistoryStatus;
  outputFolders: string[];
  previewImages: PowerPrompterQueueHistoryPreviewImage[];
  hasEditorSnapshot: boolean;
  snapshot: PowerPrompterQueueSnapshot;
}

let ppIndex: PPItem[] = [];
let ppTagIndex: PPItem[] = [];
let ppCharacterIndex: PPItem[] = [];
let ppIndexingPromise: Promise<void> | null = null;

function normalizePPQueueMode(rawMode: unknown): PowerPrompterQueueMode {
  const normalized = String(rawMode || '').trim().toLowerCase();
  if (normalized === 'selected' || normalized === 'variants') return normalized;
  return 'prompt';
}

function normalizePPQueueTargetType(rawType: unknown): PowerPrompterQueueTargetType {
  return 'pipeline';
}

const PP_QUEUE_HISTORY_PREVIEW_IMAGE_LIMIT = 20;

function normalizePPQueueHistoryPreviewPath(rawValue: unknown): string {
  const value = String(rawValue || '').trim();
  if (!value) return '';
  const lower = value.toLowerCase();
  if (lower.startsWith('http://') || lower.startsWith('https://') || lower.startsWith('data:') || lower.startsWith('blob:')) {
    return '';
  }
  return value.replace(/\\/g, '/');
}

function derivePPQueueHistoryPreviewName(path: string, rawValue: unknown): string {
  const explicit = String(rawValue || '').trim();
  if (explicit) return explicit;
  return path.split(/[\\/]/).pop() || 'Output preview';
}

function normalizePPQueueHistoryPreviewType(rawValue: unknown, path: string): PowerPrompterQueueHistoryPreviewImage['type'] {
  const value = String(rawValue || '').trim().toLowerCase();
  if (value === 'video' || value === 'gif') return value;
  if (/\.gif(?:[?#].*)?$/i.test(path)) return 'gif';
  if (/\.(mp4|webm|mov|avi|mkv|m4v)(?:[?#].*)?$/i.test(path)) return 'video';
  return 'image';
}

function normalizePPOptionalFiniteInteger(rawValue: unknown): number | undefined {
  const numeric = Math.floor(Number(rawValue));
  return Number.isFinite(numeric) ? numeric : undefined;
}

function normalizePPQueueHistoryPreviewImages(rawValue: unknown, limit = PP_QUEUE_HISTORY_PREVIEW_IMAGE_LIMIT): PowerPrompterQueueHistoryPreviewImage[] {
  if (!Array.isArray(rawValue)) return [];
  const normalized: PowerPrompterQueueHistoryPreviewImage[] = [];
  const seenPaths = new Set<string>();
  const maxCount = Math.max(0, Math.floor(Number(limit) || 0));
  for (const entry of rawValue) {
    if (normalized.length >= maxCount) break;
    if (!entry || typeof entry !== 'object') continue;
    const value = entry as Record<string, unknown>;
    const path = normalizePPQueueHistoryPreviewPath(value.path || value.fullpath || value.fullPath);
    if (!path) continue;
    const pathKey = path.toLowerCase();
    if (seenPaths.has(pathKey)) continue;
    seenPaths.add(pathKey);
    const promptIndex = normalizePPOptionalFiniteInteger(value.promptIndex);
    const setId = normalizePPOptionalFiniteInteger(value.setId ?? value.promptSetId);
    const modified = Number(value.modified ?? value.mtime ?? value.updatedAt);
    const promptId = String(value.promptId || '').trim();
    const mediaKind = String(value.mediaKind || value.type || '').trim();
    normalized.push({
      id: String(value.id || promptId || path).trim() || path,
      path,
      name: derivePPQueueHistoryPreviewName(path, value.name || value.filename),
      type: normalizePPQueueHistoryPreviewType(value.type || value.mediaKind, path),
      ...(mediaKind ? { mediaKind } : {}),
      ...(promptIndex !== undefined && promptIndex >= 0 ? { promptIndex } : {}),
      ...(promptId ? { promptId } : {}),
      ...(setId !== undefined && setId >= 1 ? { setId } : {}),
      ...(Number.isFinite(modified) && modified > 0 ? { modified } : {}),
    });
  }
  return normalized;
}

function hasPPQueueEditorSnapshot(rawSnapshot: unknown): boolean {
  if (!rawSnapshot || typeof rawSnapshot !== 'object') return false;
  const groupSnapshots = (rawSnapshot as any).groupSnapshots;
  return Array.isArray(groupSnapshots)
    && groupSnapshots.some((entry: any) => !!entry?.editorSnapshot && typeof entry.editorSnapshot === 'object');
}

function normalizePPQueueSnapshot(rawSnapshot: unknown): PowerPrompterQueueSnapshot | null {
  if (!rawSnapshot || typeof rawSnapshot !== 'object') return null;
  const snapshot = rawSnapshot as Partial<PowerPrompterQueueSnapshot>;
  const prompts = Array.isArray(snapshot.prompts)
    ? snapshot.prompts.map((entry) => String(entry || '').trim()).filter((entry) => entry.length > 0)
    : [];
  if (prompts.length <= 0) return null;
  const activeSetId = clampPPQueueSetId((snapshot as any).activeSetId ?? 1);
  const promptSetIds = prompts.map((_, index) => clampPPQueueSetId((snapshot.promptSetIds || [])[index] ?? activeSetId));
  const promptEntries = Array.isArray((snapshot as any).promptEntries)
    ? prompts.map((prompt, index) => {
      const entry = (snapshot as any).promptEntries[index];
      if (!entry || typeof entry !== 'object') {
        return { prompt, tokens: [] };
      }
      return {
        ...entry,
        prompt: String((entry as any).prompt || prompt || '').trim(),
        tokens: Array.isArray((entry as any).tokens) ? (entry as any).tokens : [],
      };
    })
    : undefined;
  const promptOutputSubfolders = prompts.map((_, index) => String((snapshot as any).promptOutputSubfolders?.[index] || '').trim());
  const promptStyleNames = prompts.map((_, index) => String((snapshot as any).promptStyleNames?.[index] || '').trim());
  const promptSeedGroupIds = prompts.map((_, index) => String((snapshot as any).promptSeedGroupIds?.[index] || `${promptSetIds[index]}:${index}`).trim());
  const generation = normalizePPGenerationControls(
    (snapshot as any).generation ?? (snapshot.generationByPrompt || [])[0]
  );
  const generationByPrompt = prompts.map((_, index) =>
    normalizePPGenerationControls((snapshot.generationByPrompt || [])[index] ?? generation)
  );
  const requestIds = Array.isArray(snapshot.requestIds)
    ? snapshot.requestIds.map((entry) => String(entry || '').trim()).filter((entry) => entry.length > 0)
    : [];
  const groupSnapshots = Array.isArray((snapshot as any).groupSnapshots)
    ? (snapshot as any).groupSnapshots
      .map((entry: any): PowerPrompterQueueGroupSnapshot | null => {
        if (!entry || typeof entry !== 'object') return null;
        const requestId = String(entry.requestId || '').trim();
        if (!requestId) return null;
        const rawPromptIndices = Array.isArray(entry.promptIndices)
          ? entry.promptIndices
            .map((value: unknown) => Math.floor(Number(value)))
            .filter((value: number) => Number.isFinite(value) && value >= 0 && value < prompts.length)
          : [];
        const fallbackIndices = requestIds
          .map((candidate, index) => (candidate === requestId ? index : -1))
          .filter((index) => index >= 0);
        const promptIndices = Array.from(new Set(rawPromptIndices.length > 0 ? rawPromptIndices : fallbackIndices));
        const promptStartIndex = Math.max(
          0,
          Math.min(
            Math.max(0, prompts.length - 1),
            Math.floor(Number(entry.promptStartIndex) || promptIndices[0] || 0)
          )
        );
        const promptCount = Math.max(
          0,
          Math.floor(Number(entry.promptCount) || promptIndices.length || fallbackIndices.length)
        );
        return {
          id: String(entry.id || requestId).trim() || requestId,
          requestId,
          ...(String(entry.label || '').trim() ? { label: String(entry.label || '').trim() } : {}),
          ...(entry.mode ? { mode: normalizePPQueueMode(entry.mode) } : {}),
          ...(entry.activeSetId !== undefined ? { activeSetId: clampPPQueueSetId(entry.activeSetId) } : {}),
          promptStartIndex,
          promptCount,
          ...(promptIndices.length > 0 ? { promptIndices } : {}),
          ...(entry.editorSnapshot && typeof entry.editorSnapshot === 'object' ? { editorSnapshot: entry.editorSnapshot } : {}),
        };
      })
      .filter((entry: PowerPrompterQueueGroupSnapshot | null): entry is PowerPrompterQueueGroupSnapshot => !!entry)
    : [];
  return {
    version: 1,
    ...(groupSnapshots.length > 0 ? { snapshotSchemaVersion: 2 } : {}),
    savedAt: Number(snapshot.savedAt) || Date.now(),
    file: typeof snapshot.file === 'string' ? String(snapshot.file).trim() || null : null,
    mode: normalizePPQueueMode(snapshot.mode),
    activeSetId,
    queueTargetType: normalizePPQueueTargetType(snapshot.queueTargetType),
    targetBridgeId: String(snapshot.targetBridgeId || '').trim(),
    requestIds,
    prompts,
    ...(promptEntries ? { promptEntries } : {}),
    promptSetIds,
    promptOutputSubfolders,
    promptStyleNames,
    promptSeedGroupIds,
    generation,
    generationByPrompt,
    randomApplied: snapshot.randomApplied === true,
    paused: snapshot.paused === true,
    dispatchDelayMs: Math.max(0, Math.floor(Number(snapshot.dispatchDelayMs) || 0)),
    ...(groupSnapshots.length > 0 ? { groupSnapshots } : {}),
  };
}

async function loadPPQueueSnapshot(): Promise<PowerPrompterQueueSnapshot | null> {
  if (!POWER_PROMPTER_QUEUE_STATE_SNAPSHOT_ENABLED) {
    return null;
  }
  try {
    if (!existsSync(PP_QUEUE_STATE_PATH)) {
      return null;
    }
    const content = await fs.readFile(PP_QUEUE_STATE_PATH, 'utf-8');
    return normalizePPQueueSnapshot(JSON.parse(content));
  } catch {
    return null;
  }
}

async function savePPQueueSnapshot(snapshot: unknown): Promise<PowerPrompterQueueSnapshot | null> {
  void snapshot;
  if (!POWER_PROMPTER_QUEUE_STATE_SNAPSHOT_ENABLED) {
    if (existsSync(PP_QUEUE_STATE_PATH)) {
      await fs.rm(PP_QUEUE_STATE_PATH, { force: true });
    }
    lastPPQueueSnapshotClearedAt = Date.now();
    return null;
  }
  const normalized = normalizePPQueueSnapshot(snapshot);
  if (!normalized) {
    if (existsSync(PP_QUEUE_STATE_PATH)) {
      await fs.rm(PP_QUEUE_STATE_PATH, { force: true });
    }
    lastPPQueueSnapshotClearedAt = Date.now();
    broadcastPowerPrompterQueueStateUpdate(null, 'queue_state_saved_empty');
    return null;
  }
  if (lastPPQueueSnapshotClearedAt > 0 && normalized.savedAt < lastPPQueueSnapshotClearedAt) {
    return loadPPQueueSnapshot();
  }
  const existing = await loadPPQueueSnapshot();
  if (existing && normalized.savedAt < existing.savedAt) {
    appendPowerPrompterQueueLog('queue_state_stale_write_ignored', {
      incomingSavedAt: normalized.savedAt,
      existingSavedAt: existing.savedAt,
      incomingPrompts: normalized.prompts.length,
      existingPrompts: existing.prompts.length,
    });
    return existing;
  }
  if (!existsSync(PP_QUEUE_DIR)) {
    await fs.mkdir(PP_QUEUE_DIR, { recursive: true });
  }
  await fs.writeFile(PP_QUEUE_STATE_PATH, JSON.stringify(normalized, null, 2), 'utf-8');
  lastPPQueueSnapshotClearedAt = 0;
  broadcastPowerPrompterQueueStateUpdate(normalized, 'queue_state_saved');
  return normalized;
}

async function clearPPQueueSnapshot() {
  lastPPQueueSnapshotClearedAt = Date.now();
  if (existsSync(PP_QUEUE_STATE_PATH)) {
    await fs.rm(PP_QUEUE_STATE_PATH, { force: true });
  }
}

function sanitizePPSavedQueueName(rawName: unknown): string {
  const normalized = String(rawName || '')
    .replace(/\.(?:ppqueue\.)?json$/i, '')
    .replace(/[<>:"/\\|?*\x00-\x1F]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 120);
  return normalized || 'Saved Queue';
}

function createPPSavedQueueId(rawName: unknown): string {
  const normalized = sanitizePPSavedQueueName(rawName)
    .toLowerCase()
    .replace(/[^a-z0-9._ -]+/g, ' ')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 96);
  return normalized || 'saved-queue';
}

function normalizePPSavedQueueId(rawId: unknown): string {
  return String(rawId || '')
    .replace(/\.(?:ppqueue\.)?json$/i, '')
    .toLowerCase()
    .replace(/[^a-z0-9._ -]+/g, ' ')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 96);
}

function getPPSavedQueuePath(id: string): string | null {
  const normalizedId = normalizePPSavedQueueId(id);
  if (!normalizedId) return null;
  return join(PP_QUEUE_SNAPSHOTS_DIR, `${normalizedId}.ppqueue.json`);
}

function normalizePPSavedQueueDocument(rawDocument: unknown, fallbackId?: string): PowerPrompterSavedQueueDocument | null {
  if (!rawDocument || typeof rawDocument !== 'object') return null;
  const document = rawDocument as Partial<PowerPrompterSavedQueueDocument> & { snapshot?: unknown };
  const snapshot = normalizePPQueueSnapshot(document.snapshot ?? rawDocument);
  if (!snapshot) return null;
  const name = sanitizePPSavedQueueName(document.name || fallbackId || 'Saved Queue');
  const id = normalizePPSavedQueueId(document.id || fallbackId || createPPSavedQueueId(name));
  if (!id) return null;
  return {
    version: 1,
    id,
    name,
    savedAt: Number(document.savedAt) || Date.now(),
    snapshot: {
      ...snapshot,
      paused: true,
    },
  };
}

async function collectPPSavedQueueFiles(): Promise<Array<{ path: string; fallbackId: string }>> {
  const files: Array<{ path: string; fallbackId: string }> = [];
  const seenIds = new Set<string>();

  const addFile = (filePath: string, fallbackId: string) => {
    const normalizedId = normalizePPSavedQueueId(fallbackId);
    if (!normalizedId || normalizedId === 'queue-state') return;
    if (seenIds.has(normalizedId)) return;
    seenIds.add(normalizedId);
    files.push({ path: filePath, fallbackId: normalizedId });
  };

  if (existsSync(PP_QUEUE_SNAPSHOTS_DIR)) {
    const entries = await fs.readdir(PP_QUEUE_SNAPSHOTS_DIR, { withFileTypes: true });
    for (const entry of entries) {
      if (!entry.isFile() || !entry.name.toLowerCase().endsWith('.ppqueue.json')) continue;
      addFile(join(PP_QUEUE_SNAPSHOTS_DIR, entry.name), entry.name.replace(/\.ppqueue\.json$/i, ''));
    }
  }

  if (existsSync(PP_QUEUE_DIR)) {
    const entries = await fs.readdir(PP_QUEUE_DIR, { withFileTypes: true });
    for (const entry of entries) {
      if (!entry.isFile() || !entry.name.toLowerCase().endsWith('.json')) continue;
      if (entry.name.toLowerCase() === 'queue-state.json') continue;
      addFile(join(PP_QUEUE_DIR, entry.name), entry.name.replace(/\.json$/i, ''));
    }
  }

  return files;
}

async function listPPSavedQueues(): Promise<Array<{
  id: string;
  name: string;
  savedAt: number;
  file: string | null;
  promptCount: number;
  activeSetId: number;
  mode: PowerPrompterQueueMode;
}>> {
  const items: Array<{
    id: string;
    name: string;
    savedAt: number;
    file: string | null;
    promptCount: number;
    activeSetId: number;
    mode: PowerPrompterQueueMode;
  }> = [];
  const files = await collectPPSavedQueueFiles();
  for (const entry of files) {
    try {
      const parsed = JSON.parse(await fs.readFile(entry.path, 'utf-8'));
      const document = normalizePPSavedQueueDocument(parsed, entry.fallbackId);
      if (!document) continue;
      items.push({
        id: document.id,
        name: document.name,
        savedAt: document.savedAt,
        file: document.snapshot.file,
        promptCount: document.snapshot.prompts.length,
        activeSetId: document.snapshot.activeSetId,
        mode: document.snapshot.mode,
      });
    } catch {
      // Ignore malformed user snapshots; deleting them should remain manual.
    }
  }
  return items.sort((a, b) => b.savedAt - a.savedAt || a.name.localeCompare(b.name));
}

async function loadPPSavedQueue(id: unknown): Promise<PowerPrompterSavedQueueDocument | null> {
  const normalizedId = normalizePPSavedQueueId(id);
  const snapshotPath = getPPSavedQueuePath(normalizedId);
  const legacyPath = normalizedId ? join(PP_QUEUE_DIR, `${normalizedId}.json`) : null;
  const filePath = snapshotPath && existsSync(snapshotPath)
    ? snapshotPath
    : legacyPath && existsSync(legacyPath)
      ? legacyPath
      : null;
  if (!filePath) return null;
  try {
    const parsed = JSON.parse(await fs.readFile(filePath, 'utf-8'));
    return normalizePPSavedQueueDocument(parsed, normalizedId);
  } catch {
    return null;
  }
}

async function savePPSavedQueue(name: unknown, snapshot: unknown): Promise<PowerPrompterSavedQueueDocument | null> {
  const normalizedSnapshot = normalizePPQueueSnapshot(snapshot);
  if (!normalizedSnapshot) return null;
  const safeName = sanitizePPSavedQueueName(name);
  const id = createPPSavedQueueId(safeName);
  const filePath = getPPSavedQueuePath(id);
  if (!filePath) return null;
  const document: PowerPrompterSavedQueueDocument = {
    version: 1,
    id,
    name: safeName,
    savedAt: Date.now(),
    snapshot: {
      ...normalizedSnapshot,
      savedAt: Date.now(),
      paused: true,
    },
  };
  await fs.mkdir(PP_QUEUE_SNAPSHOTS_DIR, { recursive: true });
  await fs.writeFile(filePath, JSON.stringify(document, null, 2), 'utf-8');
  return document;
}

async function deletePPSavedQueue(id: unknown): Promise<boolean> {
  const normalizedId = normalizePPSavedQueueId(id);
  if (!normalizedId) return false;
  const candidatePaths = [
    getPPSavedQueuePath(normalizedId),
    join(PP_QUEUE_DIR, `${normalizedId}.json`),
  ].filter((entry): entry is string => !!entry);
  let deleted = false;
  for (const filePath of candidatePaths) {
    if (!existsSync(filePath)) continue;
    await fs.rm(filePath, { force: true });
    deleted = true;
  }
  return deleted;
}

function normalizePPQueueHistoryStatus(rawStatus: unknown): PowerPrompterQueueHistoryStatus {
  const normalized = String(rawStatus || '').trim().toLowerCase();
  if (
    normalized === 'queued'
    || normalized === 'running'
    || normalized === 'completed'
    || normalized === 'canceled'
    || normalized === 'failed'
    || normalized === 'interrupted'
  ) {
    return normalized;
  }
  return 'queued';
}

function normalizePPQueueHistoryId(rawId: unknown): string {
  return String(rawId || '')
    .replace(/\.pphistory\.json$/i, '')
    .toLowerCase()
    .replace(/[^a-z0-9._ -]+/g, ' ')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 140);
}

function createPPQueueHistoryId(rawName: unknown): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, '').slice(0, 14);
  const base = createPPSavedQueueId(rawName).slice(0, 72) || 'queue';
  const suffix = typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function'
    ? crypto.randomUUID().slice(0, 8)
    : Math.random().toString(36).slice(2, 10);
  return normalizePPQueueHistoryId(`${stamp}-${base}-${suffix}`);
}

function getPPQueueHistoryPath(id: unknown): string | null {
  const normalizedId = normalizePPQueueHistoryId(id);
  if (!normalizedId) return null;
  return join(PP_QUEUE_HISTORY_DIR, `${normalizedId}.pphistory.json`);
}

function summarizePPQueueHistoryDocument(document: PowerPrompterQueueHistoryDocument) {
  return {
    id: document.id,
    name: document.name,
    createdAt: document.createdAt,
    updatedAt: document.updatedAt,
    file: document.file,
    mode: document.mode,
    activeSetId: document.activeSetId,
    promptCount: document.promptCount,
    completed: document.completed,
    failed: document.failed,
    canceled: document.canceled,
    status: document.status,
    outputFolders: document.outputFolders,
    previewImages: document.previewImages,
    hasEditorSnapshot: document.hasEditorSnapshot,
  };
}

function normalizePPQueueHistoryDocument(rawDocument: unknown, fallbackId?: string): PowerPrompterQueueHistoryDocument | null {
  if (!rawDocument || typeof rawDocument !== 'object') return null;
  const document = rawDocument as Partial<PowerPrompterQueueHistoryDocument> & { snapshot?: unknown };
  const snapshot = normalizePPQueueSnapshot(document.snapshot ?? rawDocument);
  if (!snapshot) return null;
  const id = normalizePPQueueHistoryId(document.id || fallbackId || createPPQueueHistoryId(document.name || snapshot.file || 'Queue History'));
  if (!id) return null;
  const name = sanitizePPSavedQueueName(document.name || snapshot.file || 'Queue History');
  const promptCount = snapshot.prompts.length;
  const outputFolders = Array.isArray(document.outputFolders)
    ? Array.from(new Set(document.outputFolders.map((entry) => String(entry || '').trim()).filter(Boolean))).slice(0, 200)
    : Array.from(new Set(snapshot.promptOutputSubfolders.map((entry) => String(entry || '').trim()).filter(Boolean))).slice(0, 200);
  const previewImages = normalizePPQueueHistoryPreviewImages((document as any).previewImages);
  return {
    version: 1,
    id,
    name,
    createdAt: Number(document.createdAt) || snapshot.savedAt || Date.now(),
    updatedAt: Number(document.updatedAt) || Number(document.createdAt) || snapshot.savedAt || Date.now(),
    file: typeof document.file === 'string' ? String(document.file).trim() || null : snapshot.file,
    mode: normalizePPQueueMode(document.mode || snapshot.mode),
    activeSetId: clampPPQueueSetId(document.activeSetId ?? snapshot.activeSetId),
    promptCount,
    completed: Math.max(0, Math.min(promptCount, Math.floor(Number(document.completed) || 0))),
    failed: Math.max(0, Math.min(promptCount, Math.floor(Number(document.failed) || 0))),
    canceled: Math.max(0, Math.min(promptCount, Math.floor(Number(document.canceled) || 0))),
    status: normalizePPQueueHistoryStatus(document.status),
    outputFolders,
    previewImages,
    hasEditorSnapshot: document.hasEditorSnapshot === true || hasPPQueueEditorSnapshot(snapshot),
    snapshot: {
      ...snapshot,
      paused: true,
    },
  };
}

async function listPPQueueHistory() {
  if (!existsSync(PP_QUEUE_HISTORY_DIR)) return [];
  const entries = await fs.readdir(PP_QUEUE_HISTORY_DIR, { withFileTypes: true });
  const items = [];
  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.toLowerCase().endsWith('.pphistory.json')) continue;
    try {
      const parsed = JSON.parse(await fs.readFile(join(PP_QUEUE_HISTORY_DIR, entry.name), 'utf-8'));
      const document = normalizePPQueueHistoryDocument(parsed, entry.name.replace(/\.pphistory\.json$/i, ''));
      if (document) items.push(summarizePPQueueHistoryDocument(document));
    } catch {
      // Keep malformed history files user-recoverable by leaving them in place.
    }
  }
  return items.sort((a, b) => b.updatedAt - a.updatedAt || b.createdAt - a.createdAt);
}

async function loadPPQueueHistory(id: unknown): Promise<PowerPrompterQueueHistoryDocument | null> {
  const filePath = getPPQueueHistoryPath(id);
  if (!filePath || !existsSync(filePath)) return null;
  try {
    const parsed = JSON.parse(await fs.readFile(filePath, 'utf-8'));
    return normalizePPQueueHistoryDocument(parsed, normalizePPQueueHistoryId(id));
  } catch {
    return null;
  }
}

async function savePPQueueHistory(name: unknown, snapshot: unknown, status?: unknown, previewImages?: unknown): Promise<PowerPrompterQueueHistoryDocument | null> {
  const normalizedSnapshot = normalizePPQueueSnapshot(snapshot);
  if (!normalizedSnapshot) return null;
  const now = Date.now();
  const safeName = sanitizePPSavedQueueName(name || normalizedSnapshot.file || 'Queue History');
  const id = createPPQueueHistoryId(safeName);
  const document = normalizePPQueueHistoryDocument({
    version: 1,
    id,
    name: safeName,
    createdAt: now,
    updatedAt: now,
    status: normalizePPQueueHistoryStatus(status),
    previewImages,
    snapshot: {
      ...normalizedSnapshot,
      savedAt: now,
      paused: true,
    },
  }, id);
  if (!document) return null;
  const filePath = getPPQueueHistoryPath(document.id);
  if (!filePath) return null;
  await fs.mkdir(PP_QUEUE_HISTORY_DIR, { recursive: true });
  await fs.writeFile(filePath, JSON.stringify(document, null, 2), 'utf-8');
  return document;
}

async function updatePPQueueHistory(id: unknown, patch: unknown): Promise<PowerPrompterQueueHistoryDocument | null> {
  const existing = await loadPPQueueHistory(id);
  if (!existing || !patch || typeof patch !== 'object') return existing;
  const payload = patch as Partial<PowerPrompterQueueHistoryDocument> & { snapshot?: unknown };
  const nextSnapshot = payload.snapshot ? normalizePPQueueSnapshot(payload.snapshot) : existing.snapshot;
  if (!nextSnapshot) return existing;
  const nextPromptCount = nextSnapshot.prompts.length;
  const nextPreviewImages = payload.previewImages !== undefined
    ? normalizePPQueueHistoryPreviewImages(payload.previewImages)
    : existing.previewImages;
  const next = normalizePPQueueHistoryDocument({
    ...existing,
    ...payload,
    id: existing.id,
    name: payload.name !== undefined ? sanitizePPSavedQueueName(payload.name) : existing.name,
    updatedAt: Date.now(),
    file: typeof payload.file === 'string' ? payload.file : existing.file,
    completed: payload.completed !== undefined ? Math.max(0, Math.min(nextPromptCount, Math.floor(Number(payload.completed) || 0))) : existing.completed,
    failed: payload.failed !== undefined ? Math.max(0, Math.min(nextPromptCount, Math.floor(Number(payload.failed) || 0))) : existing.failed,
    canceled: payload.canceled !== undefined ? Math.max(0, Math.min(nextPromptCount, Math.floor(Number(payload.canceled) || 0))) : existing.canceled,
    status: payload.status !== undefined ? normalizePPQueueHistoryStatus(payload.status) : existing.status,
    outputFolders: Array.isArray(payload.outputFolders) ? payload.outputFolders : existing.outputFolders,
    previewImages: nextPreviewImages,
    snapshot: {
      ...nextSnapshot,
      paused: true,
    },
  }, existing.id);
  if (!next) return existing;
  const filePath = getPPQueueHistoryPath(next.id);
  if (!filePath) return next;
  await fs.mkdir(PP_QUEUE_HISTORY_DIR, { recursive: true });
  await fs.writeFile(filePath, JSON.stringify(next, null, 2), 'utf-8');
  return next;
}

async function deletePPQueueHistory(id: unknown): Promise<boolean> {
  const filePath = getPPQueueHistoryPath(id);
  if (!filePath || !existsSync(filePath)) return false;
  await fs.rm(filePath, { force: true });
  return true;
}

async function loadPPSettings(): Promise<PowerPrompterSettings> {
  try {
    if (existsSync(PP_SETTINGS_PATH)) {
      const content = await fs.readFile(PP_SETTINGS_PATH, 'utf-8');
      const parsed = JSON.parse(content);
      return normalizePPSettingsPayload(parsed);
    }
  } catch { }
  return DEFAULT_PP_SETTINGS;
}

async function savePPSettings(settings: PowerPrompterSettings) {
  const configDir = join(USER_DIR, 'Config');
  if (!existsSync(configDir)) await fs.mkdir(configDir, { recursive: true });
  const normalized = normalizePPSettingsPayload(settings);
  await fs.writeFile(PP_SETTINGS_PATH, JSON.stringify(normalized, null, 2));
}

function cleanCSVValue(val: string): string {
  return val.replace(/^["']|["']$/g, '').trim();
}

function getPPCsvSourceId(type: 'tag' | 'character', fileName: string): string {
  return `${type}:${String(fileName || '').trim()}`;
}

function createPPCsvFilter(enabledCSVs: string[]): Set<string> {
  const filter = new Set<string>();
  for (const rawValue of enabledCSVs) {
    const value = String(rawValue || '').trim();
    if (!value) continue;
    filter.add(value);
    const separatorIndex = value.indexOf(':');
    if (separatorIndex > 0) {
      const fileName = value.slice(separatorIndex + 1).trim();
      if (fileName) filter.add(fileName);
    }
  }
  return filter;
}

function matchesPPCsvFilter(item: PPItem, filter: Set<string>): boolean {
  const sourceId = item.sourceId || getPPCsvSourceId(item.type, item.source);
  return filter.has(sourceId) || filter.has(item.source);
}

async function indexPowerPrompterCSVs() {
  if (ppIndexingPromise) {
    await ppIndexingPromise;
    return;
  }

  ppIndexingPromise = (async () => {
    console.log('[PowerPrompter] Indexing CSVs...');
    const newIndex: PPItem[] = [];

    const processDir = async (dir: string, type: 'tag' | 'character') => {
      if (!existsSync(dir)) return;
      const files = readdirSync(dir).filter(f => f.endsWith('.csv'));

      for (const file of files) {
        const filePath = join(dir, file);
        const content = await fs.readFile(filePath, 'utf-8');
        const lines = content.split('\n');
        let processedLines = 0;

        for (const line of lines) {
          if (!line.trim()) continue;
          const parts = line.split(',').map(cleanCSVValue);

          if (type === 'tag' && parts.length >= 2) {
            newIndex.push({
              tag: parts[0],
              category: parseInt(parts[1]) || 0,
              source: file,
              sourceId: getPPCsvSourceId(type, file),
              type: 'tag'
            });
          } else if (type === 'character' && parts.length >= 2) {
            newIndex.push({
              tag: parts[0],
              category: 4, // Character
              extra: parts.slice(1).join(', '),
              source: file,
              sourceId: getPPCsvSourceId(type, file),
              type: 'character'
            });
          }

          processedLines += 1;
          if (processedLines % 2000 === 0) {
            // Keep request handling responsive while indexing large CSV corpora.
            await new Promise<void>((resolve) => setTimeout(resolve, 0));
          }
        }

        await new Promise<void>((resolve) => setTimeout(resolve, 0));
      }
    };

    await processDir(PP_CSV_TAGS_DIR, 'tag');
    await processDir(PP_CSV_CHARS_DIR, 'character');

    ppIndex = newIndex;
    ppCharacterIndex = newIndex.filter((entry) => entry.type === 'character' || entry.category === 4);
    ppTagIndex = newIndex.filter((entry) => !(entry.type === 'character' || entry.category === 4));
    console.log(`[PowerPrompter] Indexed ${ppIndex.length} items`);
  })().finally(() => {
    ppIndexingPromise = null;
  });

  await ppIndexingPromise;
}

// Simple fuzzy search
function normalizePPCardSearchType(rawType: unknown): PowerPrompterCardType | null {
  const normalized = String(rawType || '').trim().toLowerCase();
  if (
    normalized === 'character' ||
    normalized === 'location' ||
    normalized === 'expression' ||
    normalized === 'action' ||
    normalized === 'style' ||
    normalized === 'custom'
  ) {
    return normalized;
  }
  return null;
}

function normalizePPSearchScope(rawScope: unknown): PowerPrompterSearchScope {
  return String(rawScope || '').trim().toLowerCase() === 'all' ? 'all' : 'scoped';
}

function normalizePPSearchText(rawValue: unknown): string {
  return String(rawValue || '')
    .toLowerCase()
    .replace(/_/g, ' ')
    .replace(/^["']|["']$/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function matchesPPSearchQuery(item: PPItem, rawQuery: string): boolean {
  const normalizedQuery = normalizePPSearchText(rawQuery);
  if (!normalizedQuery) return false;
  const queryTokens = normalizedQuery.split(' ').filter(Boolean);
  const tag = normalizePPSearchText(item.tag);
  const extra = normalizePPSearchText(item.extra || '');

  if (tag.includes(normalizedQuery) || extra.includes(normalizedQuery)) {
    return true;
  }

  if (queryTokens.length === 0) return false;

  const tokenMatch = (value: string) => (
    value.length > 0
    && queryTokens.every((token) => value.includes(token))
  );

  return tokenMatch(tag) || tokenMatch(extra);
}

function matchesPPSearchCardScope(item: PPItem, cardType: PowerPrompterCardType | null, scope: PowerPrompterSearchScope): boolean {
  if (scope !== 'scoped' || !cardType || cardType === 'custom') return true;

  if (cardType === 'character') {
    return item.type === 'character' || item.category === 4;
  }

  if (cardType === 'style') {
    return item.type === 'tag' && (item.category === 1 || item.category === 3 || item.category === 5);
  }

  // location / expression / action -> prefer general tag tokens, avoid character rows
  return item.type === 'tag' && item.category !== 4;
}

function searchPP(
  query: string,
  page: number = 0,
  limit: number = 100,
  enabledCSVs: string[] = [],
  options?: { scope?: unknown; cardType?: unknown; fast?: unknown; }
) {
  const q = normalizePPSearchText(query);
  const safePage = Number.isFinite(page) ? Math.max(0, Math.floor(page)) : 0;
  const safeLimit = Number.isFinite(limit) ? Math.min(200, Math.max(1, Math.floor(limit))) : 100;
  const scope = normalizePPSearchScope(options?.scope);
  const cardType = normalizePPCardSearchType(options?.cardType);
  const fast = String(options?.fast || '').trim().toLowerCase() === '1' || options?.fast === true;
  const start = safePage * safeLimit;
  const results: PPItem[] = [];
  let total = 0;
  const csvFilter = createPPCsvFilter(enabledCSVs);

  if (q.length < 2 || csvFilter.size === 0) {
    return { results: [], total: 0, hasMore: false };
  }

  if (fast) {
    const byKey = new Map<string, PPItem>();
    const seenOrder: string[] = [];
    const considerItem = (item: PPItem) => {
      if (!matchesPPCsvFilter(item, csvFilter)) return;
      if (!matchesPPSearchCardScope(item, cardType, scope)) return;
      if (!matchesPPSearchQuery(item, q)) return;
      const key = normalizePPSearchText(item.tag) || `${item.type}:${String(item.tag || '')}`;
      const existing = byKey.get(key);
      if (!existing) {
        byKey.set(key, item);
        seenOrder.push(key);
        return;
      }
      const existingHasExtra = Boolean(String(existing.extra || '').trim());
      const itemHasExtra = Boolean(String(item.extra || '').trim());
      const shouldReplace =
        (item.type === 'character' && itemHasExtra && (!existingHasExtra || existing.type !== 'character'))
        || (itemHasExtra && !existingHasExtra);
      if (shouldReplace) {
        byKey.set(key, item);
      }
    };

    for (const item of ppCharacterIndex) {
      considerItem(item);
      if (seenOrder.length >= start + safeLimit) break;
    }
    if (seenOrder.length < start + safeLimit) {
      for (const item of ppTagIndex) {
        considerItem(item);
        if (seenOrder.length >= start + safeLimit) break;
      }
    }

    const ordered = seenOrder
      .map((key) => byKey.get(key))
      .filter(Boolean) as PPItem[];
    total = ordered.length;
    results.push(...ordered.slice(start, start + safeLimit));
  } else {
    // Avoid expensive array allocations on huge indexes by streaming matches.
    for (const item of ppIndex) {
      if (!matchesPPCsvFilter(item, csvFilter)) continue;
      if (!matchesPPSearchCardScope(item, cardType, scope)) continue;
      if (!matchesPPSearchQuery(item, q)) continue;

      if (total >= start && results.length < safeLimit) {
        results.push(item);
      }
      total += 1;
    }
  }

  return {
    results,
    total,
    hasMore: start + safeLimit < total
  };
}

