const FS_LIST_CACHE_TTL_MS = 1800;
const FS_LIST_CACHE_MAX_ENTRIES = 24;
const FS_LIST_SINGLE_FLIGHT_WARN_MS = 220;
const FS_LIST_DEBUG = String(process.env.UMBRA_FS_LIST_DEBUG || '').trim() === '1';
const FS_LIST_PROGRESSIVE_SLOW_LOG_MS = Math.max(80, Math.floor(Number(process.env.UMBRA_FS_LIST_PROGRESSIVE_SLOW_MS) || 250));
const FS_LIST_PROGRESSIVE_SAMPLE_RATE = Math.max(0, Math.min(1, Number(process.env.UMBRA_FS_LIST_PROGRESSIVE_SAMPLE_RATE) || 0.08));
const fsListCache = new Map<string, {
  expiresAt: number;
  value: {
    path: string;
    folders: any[];
    files: any[];
    total: number;
    counts?: Record<string, number>;
  };
}>();
const fsListInFlight = new Map<string, Promise<void>>();
let fsListCacheMutationVersion = 0;
const FS_FOLDER_SUMMARY_CACHE_TTL_MS = 30_000;
const FS_FOLDER_SUMMARY_CACHE_MAX_ENTRIES = 384;
const fsFolderSummaryCache = new Map<string, {
  expiresAt: number;
  value: {
    path: string;
    subfolderCount: number;
    imageCount: number;
    videoCount: number;
    totalMediaCount: number;
  };
}>();
const fsFolderSummaryInFlight = new Map<string, Promise<{
  path: string;
  subfolderCount: number;
  imageCount: number;
  videoCount: number;
  totalMediaCount: number;
}>>();

type GalleryProgressiveRefreshFile = {
  name?: unknown;
  path?: unknown;
  relativePath?: unknown;
  type?: unknown;
};

const GALLERY_PROGRESSIVE_REFRESH_DELAY_MS = 900;
const galleryProgressiveRefreshQueue: Array<{
  folderPath: string;
  files: GalleryProgressiveRefreshFile[];
}> = [];
const galleryProgressiveRefreshQueuedPaths = new Set<string>();
let galleryProgressiveRefreshActive = false;
let galleryProgressiveRefreshTimer: ReturnType<typeof setTimeout> | null = null;

function scheduleGalleryProgressiveMetadataRefresh(folderPathInput: string, filesInput: GalleryProgressiveRefreshFile[]) {
  const folderPath = normalizeOutputPathInput(folderPathInput);
  if (!folderPath || !Array.isArray(filesInput) || filesInput.length === 0) return;

  const files: GalleryProgressiveRefreshFile[] = [];
  for (const file of filesInput) {
    const normalizedPath = normalizeOutputPathInput(String(file?.path || file?.relativePath || '').trim());
    if (!normalizedPath || galleryProgressiveRefreshQueuedPaths.has(normalizedPath)) continue;
    galleryProgressiveRefreshQueuedPaths.add(normalizedPath);
    files.push(file);
  }
  if (files.length === 0) return;

  galleryProgressiveRefreshQueue.push({ folderPath, files });
  if (galleryProgressiveRefreshTimer) return;
  galleryProgressiveRefreshTimer = setTimeout(() => {
    galleryProgressiveRefreshTimer = null;
    void pumpGalleryProgressiveRefreshQueue();
  }, GALLERY_PROGRESSIVE_REFRESH_DELAY_MS);
  (galleryProgressiveRefreshTimer as any).unref?.();
}

async function pumpGalleryProgressiveRefreshQueue() {
  if (galleryProgressiveRefreshActive) return;
  galleryProgressiveRefreshActive = true;
  try {
    while (galleryProgressiveRefreshQueue.length > 0) {
      const job = galleryProgressiveRefreshQueue.shift();
      if (!job) continue;
      await runGalleryProgressiveMetadataRefresh(job.folderPath, job.files);
    }
  } finally {
    galleryProgressiveRefreshActive = false;
  }
}

async function runGalleryProgressiveMetadataRefresh(folderPath: string, files: GalleryProgressiveRefreshFile[]) {
  const startedAt = Date.now();
  let statMs = 0;
  let dbMs = 0;
  try {
    const statStartedAt = Date.now();
    const statItems = files.map((file) => {
      const normalizedPath = normalizeOutputPathInput(String(file?.path || file?.relativePath || '').trim());
      if (!normalizedPath) return null;
      const resolvedFile = resolvePath(normalizedPath);
      if (!resolvedFile || !isPathInsideAllowedRoots(resolvedFile.fullPath)) return null;
      return {
        path: normalizedPath,
        fullPath: resolvedFile.fullPath,
        folderPath,
        name: String(file?.name || basename(normalizedPath)).trim() || basename(normalizedPath),
        type: inferGalleryMediaType(normalizedPath, file?.type),
      };
    }).filter((entry): entry is {
      path: string;
      fullPath: string;
      folderPath: string;
      name: string;
      type: GalleryMediaType;
    } => Boolean(entry));
    const statResult = statItems.length > 0
      ? await galleryRefreshWorkerService.statFiles({ items: statItems })
      : { files: [] };
    const fileInputs = (Array.isArray((statResult as any)?.files) ? (statResult as any).files : [])
      .filter((entry: any): entry is {
      path: string;
      folderPath: string;
      name: string;
      type: GalleryMediaType;
      size: number;
      createdMs: number;
      modifiedMs: number;
    } => Boolean(entry?.path && entry?.folderPath));
    statMs = Date.now() - statStartedAt;

    if (fileInputs.length > 0) {
      const dbStartedAt = Date.now();
      galleryDb.upsertFolderFiles(folderPath, fileInputs);
      dbMs = Date.now() - dbStartedAt;
    }
  } catch (error) {
    appendGalleryProgressiveListLog({
      event: 'gallery_list_progressive_refresh_error',
      path: folderPath,
      elapsedMs: Date.now() - startedAt,
      error: String((error as Error)?.message || error || 'Unknown error'),
    });
  } finally {
    for (const file of files) {
      const normalizedPath = normalizeOutputPathInput(String(file?.path || file?.relativePath || '').trim());
      if (normalizedPath) galleryProgressiveRefreshQueuedPaths.delete(normalizedPath);
    }
    const elapsedMs = Date.now() - startedAt;
    if (elapsedMs >= FS_LIST_PROGRESSIVE_SLOW_LOG_MS || FS_LIST_DEBUG) {
      appendGalleryProgressiveListLog({
        event: 'gallery_list_progressive_refresh',
        path: folderPath,
        elapsedMs,
        statMs,
        dbMs,
        fileCount: files.length,
      });
    }
  }
}

function normalizeFsListPathKey(inputPath: string): string {
  let normalized = String(inputPath || '').replace(/\\/g, '/').replace(/\/+/g, '/').trim();
  if (!normalized) return '';
  if (normalized.length > 1 && /\/+$/.test(normalized) && !/^[a-zA-Z]:\/$/.test(normalized)) {
    normalized = normalized.replace(/\/+$/, '');
  }
  return normalized;
}

function parseFsListCacheKeyPath(cacheKey: string): string {
  return normalizeFsListPathKey(String(cacheKey || '').split('|', 1)[0] || '');
}

function buildFsListCacheKey(targetPath: string, filter: string | null, isTrashPath: boolean, isTrashRoot: boolean, recursive = false): string {
  const normalizedPath = normalizeFsListPathKey(targetPath);
  return [
    normalizedPath,
    String(filter || ''),
    isTrashPath ? 'trash:1' : 'trash:0',
    isTrashRoot ? 'trashroot:1' : 'trashroot:0',
    recursive ? 'recursive:1' : 'recursive:0',
  ].join('|');
}

function pruneFsListCache() {
  const now = Date.now();
  for (const [key, entry] of fsListCache.entries()) {
    if (entry.expiresAt <= now) fsListCache.delete(key);
  }
  while (fsListCache.size > FS_LIST_CACHE_MAX_ENTRIES) {
    const oldestKey = fsListCache.keys().next().value as string | undefined;
    if (!oldestKey) break;
    fsListCache.delete(oldestKey);
  }
}

function pruneFsFolderSummaryCache() {
  const now = Date.now();
  for (const [key, entry] of fsFolderSummaryCache.entries()) {
    if (entry.expiresAt <= now) fsFolderSummaryCache.delete(key);
  }
  while (fsFolderSummaryCache.size > FS_FOLDER_SUMMARY_CACHE_MAX_ENTRIES) {
    const oldestKey = fsFolderSummaryCache.keys().next().value as string | undefined;
    if (!oldestKey) break;
    fsFolderSummaryCache.delete(oldestKey);
  }
}

function getFsFolderSummaryCache(pathKey: string) {
  pruneFsFolderSummaryCache();
  const cached = fsFolderSummaryCache.get(pathKey);
  if (!cached) return null;
  return cached.value;
}

function setFsFolderSummaryCache(pathKey: string, value: {
  path: string;
  subfolderCount: number;
  imageCount: number;
  videoCount: number;
  totalMediaCount: number;
}) {
  fsFolderSummaryCache.set(pathKey, {
    expiresAt: Date.now() + FS_FOLDER_SUMMARY_CACHE_TTL_MS,
    value,
  });
  pruneFsFolderSummaryCache();
}

function invalidateFsFolderSummaryForPaths(paths: Array<string | null | undefined>) {
  const targets = new Set<string>();
  for (const rawPath of paths) {
    const normalized = normalizeFsListPathKey(String(rawPath || ''));
    if (!normalized) continue;
    for (const ancestor of collectFsListPathAncestors(normalized)) {
      targets.add(ancestor);
    }
  }
  if (targets.size === 0) return;
  for (const key of Array.from(fsFolderSummaryCache.keys())) {
    const shouldDrop = Array.from(targets).some((target) => (
      key === target ||
      key.startsWith(`${target}/`) ||
      target.startsWith(`${key}/`)
    ));
    if (shouldDrop) fsFolderSummaryCache.delete(key);
  }
}

function getFsListCache(cacheKey: string) {
  pruneFsListCache();
  const cached = fsListCache.get(cacheKey);
  if (!cached) return null;
  return cached.value;
}

function setFsListCache(cacheKey: string, value: {
  path: string;
  folders: any[];
  files: any[];
  total: number;
  counts?: Record<string, number>;
}) {
  const now = Date.now();
  fsListCache.set(cacheKey, {
    expiresAt: now + FS_LIST_CACHE_TTL_MS,
    value,
  });
  pruneFsListCache();
}

function collectFsListPathAncestors(pathValue: string): string[] {
  const normalized = normalizeFsListPathKey(pathValue);
  if (!normalized) return [];
  const ancestors = new Set<string>();
  ancestors.add(normalized);
  const parts = normalized.split('/').filter(Boolean);
  for (let idx = parts.length - 1; idx > 0; idx -= 1) {
    const parent = parts.slice(0, idx).join('/');
    if (!parent) continue;
    ancestors.add(parent);
    if (/^[a-zA-Z]:$/.test(parent)) break;
  }
  return Array.from(ancestors);
}

function invalidateFsListCacheForPaths(
  paths: Array<string | null | undefined>,
  reason = 'invalidate',
) {
  const targets = new Set<string>();
  for (const rawPath of paths) {
    const normalized = normalizeFsListPathKey(String(rawPath || ''));
    if (!normalized) continue;
    for (const ancestor of collectFsListPathAncestors(normalized)) {
      targets.add(ancestor);
    }
  }
  if (targets.size === 0) return;
  invalidateFsFolderSummaryForPaths(Array.from(targets));
  const invalidateFullPaths = Array.from(targets)
    .map((target) => resolvePath(target)?.fullPath || '')
    .filter(Boolean);
  if (invalidateFullPaths.length > 0) {
    void galleryFsWorkerService.invalidatePaths({ paths: invalidateFullPaths });
  }

  for (const cacheKey of Array.from(fsListCache.keys())) {
    const keyPath = parseFsListCacheKeyPath(cacheKey);
    if (!keyPath) continue;
    const shouldDrop = Array.from(targets).some((target) => (
      keyPath === target ||
      keyPath.startsWith(`${target}/`) ||
      target.startsWith(`${keyPath}/`)
    ));
    if (shouldDrop) fsListCache.delete(cacheKey);
  }
  fsListCacheMutationVersion += 1;
  queueOutputPathsChanged(Array.from(targets), reason);
}

function collectPathLikeStringsFromUnknown(input: unknown, out: Set<string>, depth = 0) {
  if (depth > 5 || input == null) return;
  if (typeof input === 'string') {
    const value = normalizeFsListPathKey(input);
    if (value && (value.includes('/') || value.includes('\\') || /^[a-zA-Z]:/.test(value))) {
      out.add(value);
    }
    return;
  }
  if (Array.isArray(input)) {
    for (const entry of input) collectPathLikeStringsFromUnknown(entry, out, depth + 1);
    return;
  }
  if (typeof input === 'object') {
    for (const value of Object.values(input as Record<string, unknown>)) {
      collectPathLikeStringsFromUnknown(value, out, depth + 1);
    }
  }
}

async function tryReadJsonBody(req: Request): Promise<unknown> {
  try {
    return await req.clone().json();
  } catch {
    return null;
  }
}

async function tryReadJsonResponseBody(res: Response): Promise<unknown> {
  try {
    return await res.clone().json();
  } catch {
    return null;
  }
}

async function handleTrashMutationWithCacheInvalidation(
  req: Request,
  url: URL,
  handler: (request: Request, parsedUrl: URL, context: any) => Promise<Response>,
): Promise<Response> {
  const body = await tryReadJsonBody(req);
  const hintedPaths = new Set<string>();
  collectPathLikeStringsFromUnknown(body, hintedPaths);

  const response = await handler(req, url, routeContext);
  if (!response.ok) return response;

  const responseBody = await tryReadJsonResponseBody(response);
  collectPathLikeStringsFromUnknown(responseBody, hintedPaths);

  try {
    if (url.pathname === '/api/trash/delete' || url.pathname === '/api/fs/trash/move') {
      const items = Array.isArray((responseBody as any)?.items) ? (responseBody as any).items : [];
      galleryDb.moveRecordsForPaths(items.map((item: any) => ({
        sourcePath: String(item?.originalPath || ''),
        targetPath: String(item?.trashPath || ''),
      })));
    } else if (url.pathname === '/api/trash/restore') {
      const restored = Array.isArray((responseBody as any)?.restored) ? (responseBody as any).restored : [];
      galleryDb.moveRecordsForPaths(restored.map((item: any) => ({
        sourcePath: String(item?.trashPath || ''),
        targetPath: String(item?.restoredPath || item?.originalPath || ''),
      })));
    } else if (
      url.pathname === '/api/trash/permanent-delete'
      || url.pathname === '/api/trash/delete-direct'
      || url.pathname === '/api/trash/system'
    ) {
      const paths = Array.isArray((body as any)?.paths) ? (body as any).paths : [];
      galleryDb.removeRecordsForPaths(paths.map((entry: unknown) => String(entry || '')));
    } else if (url.pathname === '/api/trash/empty') {
      galleryDb.removeRecordsForPaths([TRASH_ROOT]);
    }
  } catch (error) {
    console.warn('[GalleryDb] Failed to sync trash metadata:', error);
  }

  invalidateFsListCacheForPaths([
    TRASH_ROOT,
    getDefaultOutputRootPath(),
    ...Array.from(hintedPaths),
  ], 'trash-mutation');
  return response;
}

function paginateFsListResult(
  base: {
    path: string;
    folders: any[];
    files: any[];
    total: number;
    counts?: Record<string, number>;
  },
  limit: number,
  offset: number,
) {
  const safeLimit = Number.isFinite(limit) ? Math.max(0, Math.floor(limit)) : 0;
  const safeOffset = Number.isFinite(offset) ? Math.max(0, Math.floor(offset)) : 0;
  const paginatedFiles = safeLimit > 0
    ? base.files.slice(safeOffset, safeOffset + safeLimit)
    : base.files;

  return {
    path: base.path,
    folders: base.folders,
    files: paginatedFiles,
    total: base.total,
    hasMore: safeLimit > 0 ? (safeOffset + safeLimit < base.total) : false,
    ...(base.counts ? { counts: base.counts } : {}),
  };
}

async function handleFsList(url: URL): Promise<Response> {
  const requestStartedAt = Date.now();
  const path = url.searchParams.get('path');
  const limit = parseInt(url.searchParams.get('limit') || '0', 10);
  const offset = parseInt(url.searchParams.get('offset') || '0', 10);
  const filter = url.searchParams.get('filter'); // 'text' for text files, 'font' for fonts, 'all' for any file, null/undefined for media
  const recursive = String(url.searchParams.get('recursive') || '').toLowerCase() === 'true';
  let cacheKey = '';
  let cacheHit = false;
  let singleFlightWaitMs = 0;
  let scanMs = 0;
  let singleFlightResolve: (() => void) | null = null;
  let singleFlightReject: ((reason?: unknown) => void) | null = null;
  let singleFlightOwned = false;
  let singleFlightError: unknown = null;
  let cacheMutationVersionAtScanStart = fsListCacheMutationVersion;

  // Default to configured output root if no path provided, with legacy compatibility.
    const normalizedInputPath = String(path || '').trim();
    const defaultOutputRoot = getDefaultOutputRootPath();
    const targetPath = !normalizedInputPath
      ? defaultOutputRoot
      : normalizeOutputPathInput(normalizedInputPath);
  const normalizedTargetPath = targetPath.replace(/\\/g, '/');
  const isTrashPath = normalizedTargetPath.startsWith(TRASH_ROOT);
  const isTrashRoot = normalizedTargetPath === TRASH_ROOT;

  try {
    const resolved = resolvePath(targetPath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;

    // Security check: ensure we are within allowed roots
    if (!isPathInsideAllowedRoots(fullPath)) {
      return json({ error: 'Access denied' }, 403);
    }

    if (isTrashPath) {
      try {
        await trashRoutes.runTrashCleanup(routeContext);
      } catch (cleanupErr) {
        console.warn('[FS List] Trash cleanup warning:', cleanupErr);
      }
    }

    if (!existsSync(fullPath)) {
      // Auto-create known user folders when missing
      if (
        targetPath === defaultOutputRoot ||
        targetPath === COMFY_OUTPUT_ROOT ||
        targetPath === LEGACY_OUTPUT_ROOT ||
        targetPath === TRASH_ROOT ||
        targetPath === 'User/FontforWatermark' ||
        targetPath.startsWith('User/PowerPrompter/')
      ) {
        await fs.mkdir(fullPath, { recursive: true });
      } else {
        return json({ error: 'Path does not exist' }, 404);
      }
    }

    const stat = statSync(fullPath);
    if (!stat.isDirectory()) return json({ error: 'Path is not a directory' }, 400);
    const shouldCacheResult = !isTrashPath;
    cacheKey = shouldCacheResult
      ? buildFsListCacheKey(targetPath, filter, isTrashPath, isTrashRoot, recursive)
      : '';
    if (cacheKey) {
      const cached = getFsListCache(cacheKey);
      if (cached) {
        cacheHit = true;
        const payload = paginateFsListResult(cached, limit, offset);
        if (FS_LIST_DEBUG) {
          console.debug(`[FS List] cache hit path="${targetPath}" total=${cached.total} elapsedMs=${Date.now() - requestStartedAt}`);
          return json({ ...payload, debug: { cacheHit: true, scanMs: 0, singleFlightWaitMs: 0 } });
        }
        return json(payload);
      }

      const inFlight = fsListInFlight.get(cacheKey);
      if (inFlight) {
        const waitStartedAt = Date.now();
        try {
          await inFlight;
        } catch {
          // If the leading request failed, we continue and perform a fresh scan.
        }
        singleFlightWaitMs = Date.now() - waitStartedAt;
        if (singleFlightWaitMs > FS_LIST_SINGLE_FLIGHT_WARN_MS) {
          console.warn(`[FS List] single-flight wait ${singleFlightWaitMs}ms path="${targetPath}"`);
        }
        const cachedAfterWait = getFsListCache(cacheKey);
        if (cachedAfterWait) {
          cacheHit = true;
          const payload = paginateFsListResult(cachedAfterWait, limit, offset);
          if (FS_LIST_DEBUG) {
            console.debug(`[FS List] cache hit (post-wait) path="${targetPath}" total=${cachedAfterWait.total} waitMs=${singleFlightWaitMs} elapsedMs=${Date.now() - requestStartedAt}`);
            return json({ ...payload, debug: { cacheHit: true, scanMs: 0, singleFlightWaitMs } });
          }
          return json(payload);
        }
      }

      let resolveInFlight!: () => void;
      let rejectInFlight!: (reason?: unknown) => void;
      const runPromise = new Promise<void>((resolve, reject) => {
        resolveInFlight = resolve;
        rejectInFlight = reject;
      });
      fsListInFlight.set(cacheKey, runPromise);
      singleFlightResolve = resolveInFlight;
      singleFlightReject = rejectInFlight;
      singleFlightOwned = true;
      cacheMutationVersionAtScanStart = fsListCacheMutationVersion;
    }

    const scanStartedAt = Date.now();
    const fullResult = await fsWorkerService.list({
      fullPath,
      targetPath,
      filter,
      isTrashPath,
      isTrashRoot,
      recursive,
      trashMetadataPath: isTrashPath ? join(ROOT_DIR, 'User', 'Config', 'trash-metadata.json') : undefined,
    });
    scanMs = Date.now() - scanStartedAt;
    if (cacheKey) {
      if (cacheMutationVersionAtScanStart === fsListCacheMutationVersion) {
        setFsListCache(cacheKey, fullResult as any);
      }
    }

    const payload = paginateFsListResult(fullResult as any, limit, offset);
    if (FS_LIST_DEBUG) {
      console.debug(`[FS List] scan path="${targetPath}" cacheHit=${cacheHit ? 1 : 0} total=${fullResult.total} scanMs=${scanMs} waitMs=${singleFlightWaitMs} elapsedMs=${Date.now() - requestStartedAt}`);
      return json({
        ...payload,
        debug: {
          cacheHit,
          scanMs,
          singleFlightWaitMs,
          totalFiles: fullResult.total,
        },
      });
    }
    return json(payload);

  } catch (error: any) {
    singleFlightError = error;
    console.error('[FS List] Error:', error);
    return json({ error: error.message }, 500);
  } finally {
    if (cacheKey && singleFlightOwned) {
      if (singleFlightError) {
        singleFlightReject?.(singleFlightError);
      } else {
        singleFlightResolve?.();
      }
      const active = fsListInFlight.get(cacheKey);
      if (active) fsListInFlight.delete(cacheKey);
    }
  }
}

async function handleFsListProgressive(url: URL): Promise<Response> {
  const requestStartedAt = Date.now();
  const path = url.searchParams.get('path');
  const limit = Math.min(240, Math.max(20, parseInt(url.searchParams.get('limit') || '120', 10) || 120));
  const cursor = Math.max(0, parseInt(url.searchParams.get('cursor') || '0', 10) || 0);
  const filter = url.searchParams.get('filter');
  const sortBy = String(url.searchParams.get('sortBy') || '').trim();
  const sortOrder = String(url.searchParams.get('sortOrder') || '').trim();
  const recursive = String(url.searchParams.get('recursive') || '').toLowerCase() === 'true';
  const force = ['1', 'true', 'yes'].includes(String(url.searchParams.get('force') || url.searchParams.get('refresh') || '').trim().toLowerCase());

      // Keep the legacy/full path as the fallback for non-library variants.
  if (recursive || filter === 'text' || filter === 'font' || filter === 'all') {
    return handleFsList(url);
  }

  const normalizedInputPath = String(path || '').trim();
  const defaultOutputRoot = getDefaultOutputRootPath();
  const targetPath = !normalizedInputPath
    ? defaultOutputRoot
    : normalizeOutputPathInput(normalizedInputPath);
  const normalizedTargetPath = targetPath.replace(/\\/g, '/');
  const isTrashPath = normalizedTargetPath.startsWith(TRASH_ROOT);

  if (isTrashPath) {
    return handleFsList(url);
  }

  try {
    const resolved = resolvePath(targetPath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (!isPathInsideAllowedRoots(fullPath)) {
      return json({ error: 'Access denied' }, 403);
    }

    if (!existsSync(fullPath)) {
      if (
        targetPath === defaultOutputRoot ||
        targetPath === COMFY_OUTPUT_ROOT ||
        targetPath === LEGACY_OUTPUT_ROOT
      ) {
        await fs.mkdir(fullPath, { recursive: true });
      } else {
        const normalizedFolderPath = normalizeOutputPathInput(targetPath);
        invalidateFsFolderSummaryForPaths([normalizedFolderPath]);
        return json({
          path: normalizedFolderPath,
          folders: [],
          files: [],
          done: true,
          nextCursor: null,
          total: 0,
          missing: true,
          sortBy,
          sortOrder,
        });
      }
    }

    const stat = statSync(fullPath);
    if (!stat.isDirectory()) return json({ error: 'Path is not a directory' }, 400);
    if (force) {
      invalidateFsFolderSummaryForPaths([targetPath]);
    }

    const workerStartedAt = Date.now();
    const result = await galleryFsWorkerService.listProgressive({
      fullPath,
      targetPath,
      limit,
      cursor,
      force,
    });
    const workerMs = Date.now() - workerStartedAt;
    const files = Array.isArray((result as any)?.files) ? (result as any).files : [];
    const folders = Array.isArray((result as any)?.folders) ? (result as any).folders : [];
    const normalizedFolderPath = normalizeOutputPathInput(targetPath);

    const dbStartedAt = Date.now();
    const orderedPaths = files
      .map((file: any) => normalizeOutputPathInput(String(file?.path || file?.relativePath || '').trim()))
      .filter(Boolean);
    const indexedFiles = orderedPaths.length > 0
      ? galleryDb.getFolderFilesByPaths(normalizedFolderPath, orderedPaths)
      : [];
    const dbMs = Date.now() - dbStartedAt;
    const indexedByPath = new Map<string, (typeof indexedFiles)[number]>();
    for (const entry of indexedFiles) {
      const normalized = normalizeOutputPathInput(String(entry?.path || '').trim());
      if (!normalized || indexedByPath.has(normalized)) continue;
      indexedByPath.set(normalized, entry);
    }

    const augmentStartedAt = Date.now();
    const augmentedFiles = files.map((file: any, index: number) => {
      const normalizedPath = normalizeOutputPathInput(String(file?.path || file?.relativePath || '').trim());
      const indexed = indexedByPath.get(normalizedPath);
      if (indexed) {
        return {
          ...file,
          uid: indexed.uid,
          path: indexed.path,
          createdMs: indexed.createdMs,
          modifiedMs: indexed.modifiedMs,
          customOrder: indexed.customOrder,
          type: indexed.type,
          metadataReady: indexed.metadataReady,
          metadataFormat: indexed.metadataFormat,
          tags: Array.isArray(indexed.tags) ? indexed.tags : [],
          width: Number.isFinite(indexed.width) ? Math.max(0, Math.trunc(indexed.width)) : 0,
          height: Number.isFinite(indexed.height) ? Math.max(0, Math.trunc(indexed.height)) : 0,
        };
      }

      const createdRaw = Number(file?.createdMs ?? file?.created ?? 0);
      const modifiedRaw = Number(file?.modifiedMs ?? file?.modified ?? 0);
      const createdMs = Number.isFinite(createdRaw) && createdRaw > 0 ? Math.floor(createdRaw) : 0;
      const modifiedMs = Number.isFinite(modifiedRaw) && modifiedRaw > 0 ? Math.floor(modifiedRaw) : createdMs;
      const fallbackId = String(file?.uid || file?.id || normalizedPath || '').trim();
      return {
        ...file,
        uid: fallbackId,
        id: fallbackId,
        path: normalizedPath || String(file?.path || file?.relativePath || '').trim(),
        createdMs,
        modifiedMs,
        customOrder: cursor + index,
        type: inferGalleryMediaType(normalizedPath, file?.type),
        tags: [],
        width: 0,
        height: 0,
      };
    });
    const augmentMs = Date.now() - augmentStartedAt;
    scheduleGalleryProgressiveMetadataRefresh(normalizedFolderPath, files);
    const elapsedMs = Date.now() - requestStartedAt;
    const workerDebug = ((result as any)?.debug && typeof (result as any).debug === 'object')
      ? (result as any).debug
      : {};
    const serviceDebug = ((result as any)?.__serviceDebug && typeof (result as any).__serviceDebug === 'object')
      ? (result as any).__serviceDebug
      : {};
    const shouldLog = FS_LIST_DEBUG
      || elapsedMs >= FS_LIST_PROGRESSIVE_SLOW_LOG_MS
      || workerMs >= FS_LIST_PROGRESSIVE_SLOW_LOG_MS
      || dbMs >= FS_LIST_PROGRESSIVE_SLOW_LOG_MS
      || Math.random() < FS_LIST_PROGRESSIVE_SAMPLE_RATE;

    if (shouldLog) {
      appendGalleryProgressiveListLog({
        path: normalizedFolderPath,
        cursor,
        limit,
        sortBy: sortBy || undefined,
        sortOrder: sortOrder || undefined,
        status: 200,
        elapsedMs,
        workerMs,
        statMs: 0,
        dbMs,
        augmentMs,
        fileCount: files.length,
        folderCount: folders.length,
        indexedCount: indexedFiles.length,
        nextCursor: (result as any)?.nextCursor ?? null,
        done: (result as any)?.done === true,
        total: Number((result as any)?.total ?? 0),
        worker: {
          seedSource: workerDebug.seedSource,
          seedMs: workerDebug.seedMs,
          seedBuildMs: workerDebug.seedBuildMs,
          seedWaitMs: workerDebug.seedWaitMs,
          totalEntries: workerDebug.totalEntries,
          totalMedia: workerDebug.totalMedia,
          chunkEntries: workerDebug.chunkEntries,
          elapsedMs: workerDebug.elapsedMs,
        },
        workerService: {
          elapsedMs: serviceDebug.elapsedMs,
          ensureMs: serviceDebug.ensureMs,
          writeMs: serviceDebug.writeMs,
          responseWaitMs: serviceDebug.responseWaitMs,
          spawned: serviceDebug.spawned,
        },
      });
    }

    const { __serviceDebug: _serviceDebug, ...publicResult } = (result as any) || {};
    return json({
      ...publicResult,
      path: normalizedFolderPath,
      files: augmentedFiles,
    });
  } catch (error: any) {
    const code = String(error?.code || '').trim().toUpperCase();
    if (code === 'ENOENT' || code === 'ENOTDIR') {
      const normalizedFolderPath = normalizeOutputPathInput(String(path || '').trim() || getDefaultOutputRootPath());
      invalidateFsFolderSummaryForPaths([normalizedFolderPath]);
      return json({
        path: normalizedFolderPath,
        folders: [],
        files: [],
        done: true,
        nextCursor: null,
        total: 0,
        missing: true,
        sortBy,
        sortOrder,
      });
    }
    appendGalleryProgressiveListLog({
      path: normalizeOutputPathInput(String(path || '').trim() || getDefaultOutputRootPath()),
      cursor,
      limit,
      sortBy: sortBy || undefined,
      sortOrder: sortOrder || undefined,
      status: 500,
      elapsedMs: Date.now() - requestStartedAt,
      error: String(error?.message || error || 'Unknown error'),
    });
    console.error('[FS List Progressive] Error:', error);
    return json({ error: error.message }, 500);
  }
}

function normalizeFsTag(value: unknown): string {
  const normalized = String(value || '').replace(/\s+/g, ' ').trim().toLowerCase();
  if (!normalized) return '';
  return normalized.slice(0, 48);
}

function normalizeFsSearchQuery(value: unknown): string {
  return String(value || '').replace(/\s+/g, ' ').trim().toLowerCase();
}

function fsTextMatchesSearch(value: unknown, query: string): boolean {
  const text = String(value || '').toLowerCase();
  if (!text || !query) return false;
  return text.includes(query);
}

function fsTagSearchPriority(file: any, query: string): number {
  const tags = Array.isArray(file?.tags) ? file.tags : [];
  for (const tag of tags) {
    const normalized = String(tag || '').toLowerCase().trim();
    if (!normalized) continue;
    if (normalized === query) return 3;
    if (normalized.startsWith(query)) return 2;
    if (normalized.includes(query)) return 1;
  }
  return 0;
}

function fsFileMatchesSearch(file: any, query: string): boolean {
  return fsTextMatchesSearch(file?.name, query)
    || fsTextMatchesSearch(file?.path, query)
    || fsTagSearchPriority(file, query) > 0;
}

function compareFsSearchFiles(left: any, right: any, query: string, sortBy: string, sortOrder: string): number {
  const tagDelta = fsTagSearchPriority(right, query) - fsTagSearchPriority(left, query);
  if (tagDelta !== 0) return tagDelta;
  let value = 0;
  if (sortBy === 'name') {
    value = String(left?.name || basename(String(left?.path || ''))).localeCompare(String(right?.name || basename(String(right?.path || ''))), undefined, { numeric: true, sensitivity: 'base' });
  } else if (sortBy === 'custom') {
    value = Number(left?.customOrder || 0) - Number(right?.customOrder || 0);
  } else if (sortBy === 'created') {
    value = Number(left?.createdMs || 0) - Number(right?.createdMs || 0);
  } else {
    value = Number(left?.modifiedMs || 0) - Number(right?.modifiedMs || 0);
  }
  if (value === 0) {
    value = String(left?.name || basename(String(left?.path || ''))).localeCompare(String(right?.name || basename(String(right?.path || ''))), undefined, { numeric: true, sensitivity: 'base' });
  }
  return sortOrder === 'desc' ? -value : value;
}

function mapAbsolutePathToGalleryPath(clientRootPath: string, absoluteRootPath: string, absolutePath: string): string {
  const relativePath = normalizeOutputPathInput(relative(absoluteRootPath, absolutePath));
  const root = normalizeOutputPathInput(clientRootPath);
  return relativePath && relativePath !== '.'
    ? normalizeOutputPathInput(`${root}/${relativePath}`)
    : root;
}

const GALLERY_VIDEO_EXTENSIONS = new Set(['.mp4', '.webm', '.mov', '.avi', '.mkv', '.m4v']);

function inferGalleryMediaType(pathLike: string, fallbackType: unknown): GalleryMediaType {
  const normalizedFallback = String(fallbackType || '').trim().toLowerCase();
  if (normalizedFallback === 'video') return 'video';
  if (normalizedFallback === 'gif') return 'gif';
  if (normalizedFallback === 'image') return 'image';
  const ext = extname(pathLike).toLowerCase();
  if (ext === '.gif') return 'gif';
  if (GALLERY_VIDEO_EXTENSIONS.has(ext)) return 'video';
  return 'image';
}

async function handleFsReorder(req: Request): Promise<Response> {
  try {
    const payload = await req.json().catch(() => ({} as Record<string, unknown>));
    const folderPathRaw = String((payload as any).path || '').trim();
    if (!folderPathRaw) return json({ error: 'Missing folder path' }, 400);

    const normalizedFolderPath = normalizeOutputPathInput(folderPathRaw);
    const resolved = resolvePath(normalizedFolderPath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (!isPathInsideAllowedRoots(fullPath)) return json({ error: 'Access denied' }, 403);
    if (!existsSync(fullPath) || !statSync(fullPath).isDirectory()) {
      return json({ error: 'Path is not a directory' }, 400);
    }

    const rawOrderedPaths = Array.isArray((payload as any).orderedPaths) ? (payload as any).orderedPaths : [];
    const orderedPaths = Array.from(new Set(
      rawOrderedPaths
        .map((entry: unknown) => normalizeOutputPathInput(String(entry || '').trim()))
        .filter(Boolean),
    ));
    const rawOrdered = Array.isArray((payload as any).orderedUids) ? (payload as any).orderedUids : [];
    const fallbackOrderedUids = Array.from(new Set(
      rawOrdered
        .map((entry: unknown) => String(entry || '').trim())
        .filter(Boolean),
    ));
    const orderedUidsFromPaths = orderedPaths.length > 0
      ? galleryDb.resolveUidsForFolderPaths(normalizedFolderPath, orderedPaths)
      : [];
    const orderedUids = orderedUidsFromPaths.length > 0 ? orderedUidsFromPaths : fallbackOrderedUids;
    if (orderedUids.length === 0) {
      return json({ error: 'No valid ordered items resolved for reorder' }, 400);
    }
    const merged = galleryDb.reorderFolder(normalizedFolderPath, orderedUids);
    return json({
      success: true,
      path: normalizedFolderPath,
      count: merged.length,
    });
  } catch (error: any) {
    console.error('[FS Reorder] Error:', error);
    return json({ error: error?.message || 'Failed to persist custom order' }, 500);
  }
}

async function handleFsTagsAdd(req: Request): Promise<Response> {
  try {
    const payload = await req.json().catch(() => ({} as Record<string, unknown>));
    const rawUids = Array.isArray((payload as any).uids) ? (payload as any).uids : [];
    const rawTags = Array.isArray((payload as any).tags) ? (payload as any).tags : [];

    const uids = Array.from(new Set(
      rawUids
        .map((entry: unknown) => String(entry || '').trim())
        .filter(Boolean),
    ));
    const tags = Array.from(new Set(
      rawTags
        .map((entry: unknown) => normalizeFsTag(entry))
        .filter(Boolean),
    ));

    if (uids.length === 0) return json({ error: 'Missing uids' }, 400);
    if (tags.length === 0) return json({ error: 'Missing tags' }, 400);

    const tagsByUidMap = galleryDb.addTagsToFiles(uids, tags);
    const tagsByUid: Record<string, string[]> = {};
    for (const [uid, uidTags] of tagsByUidMap.entries()) {
      const normalizedUid = String(uid || '').trim();
      if (!normalizedUid) continue;
      tagsByUid[normalizedUid] = Array.from(new Set(
        (Array.isArray(uidTags) ? uidTags : [])
          .map((entry) => normalizeFsTag(entry))
          .filter(Boolean),
      ));
    }

    return json({
      success: true,
      updated: Object.keys(tagsByUid).length,
      tagsByUid,
    });
  } catch (error: any) {
    console.error('[FS Tags Add] Error:', error);
    return json({ error: error?.message || 'Failed to add tags' }, 500);
  }
}

async function handleFsTagsSet(req: Request): Promise<Response> {
  try {
    const payload = await req.json().catch(() => ({} as Record<string, unknown>));
    const rawUids = Array.isArray((payload as any).uids) ? (payload as any).uids : [];
    const rawPaths = Array.isArray((payload as any).paths) ? (payload as any).paths : [];
    const rawTags = Array.isArray((payload as any).tags) ? (payload as any).tags : [];

    const directUids = Array.from(new Set(
      rawUids
        .map((entry: unknown) => String(entry || '').trim())
        .filter(Boolean),
    ));
    const paths = Array.from(new Set(
      rawPaths
        .map((entry: unknown) => normalizeOutputPathInput(String(entry || '').trim()))
        .filter(Boolean),
    ));
    const pathResolvedUids = paths.length > 0
      ? galleryDb.resolveUidsForPaths(paths)
      : [];
    const uids = Array.from(new Set([...directUids, ...pathResolvedUids]));
    const tags = Array.from(new Set(
      rawTags
        .map((entry: unknown) => normalizeFsTag(entry))
        .filter(Boolean),
    ));

    if (uids.length === 0) return json({ error: 'Missing uids or paths' }, 400);

    const tagsByUidMap = galleryDb.setTagsForFiles(uids, tags);
    const tagsByUid: Record<string, string[]> = {};
    for (const [uid, uidTags] of tagsByUidMap.entries()) {
      const normalizedUid = String(uid || '').trim();
      if (!normalizedUid) continue;
      tagsByUid[normalizedUid] = Array.from(new Set(
        (Array.isArray(uidTags) ? uidTags : [])
          .map((entry) => normalizeFsTag(entry))
          .filter(Boolean),
      ));
    }

    return json({
      success: true,
      updated: Object.keys(tagsByUid).length,
      tagsByUid,
    });
  } catch (error: any) {
    console.error('[FS Tags Set] Error:', error);
    return json({ error: error?.message || 'Failed to set tags' }, 500);
  }
}

async function handleFsSearch(url: URL): Promise<Response> {
  const startedAt = Date.now();
  const query = normalizeFsSearchQuery(url.searchParams.get('q') || url.searchParams.get('query') || '');
  const sortBy = String(url.searchParams.get('sortBy') || 'modified').trim().toLowerCase();
  const sortOrder = String(url.searchParams.get('sortOrder') || 'desc').trim().toLowerCase() === 'asc' ? 'asc' : 'desc';
  const fileLimit = Math.max(1, Math.min(1200, Math.trunc(Number(url.searchParams.get('limit') || 360) || 360)));
  const folderLimit = Math.max(1, Math.min(600, Math.trunc(Number(url.searchParams.get('folderLimit') || 120) || 120)));
  const maxFolders = Math.max(1, Math.min(6000, Math.trunc(Number(url.searchParams.get('maxFolders') || 1800) || 1800)));
  const maxDurationMs = Math.max(300, Math.min(5000, Math.trunc(Number(url.searchParams.get('maxMs') || 1800) || 1800)));
  const roots = url.searchParams.getAll('root')
    .concat(url.searchParams.getAll('roots'))
    .flatMap((entry) => String(entry || '').split('|'))
    .map((entry) => normalizeOutputPathInput(String(entry || '').trim()))
    .filter(Boolean);
  const rootInputs = roots.length > 0 ? roots : [getDefaultOutputRootPath()];

  if (query.length < 2) {
    return json({ query, files: [], folders: [], scannedFolders: 0, done: true, sortBy, sortOrder });
  }

  try {
    const resolvedRoots: Array<{ clientRootPath: string; fullPath: string }> = [];
    const seenRoots = new Set<string>();
    for (const root of rootInputs) {
      const resolved = resolvePath(root);
      if (!resolved) continue;
      const { fullPath } = resolved;
      const key = normalizeOutputPathInput(fullPath).toLowerCase();
      if (!key || seenRoots.has(key)) continue;
      if (!isPathInsideAllowedRoots(fullPath)) continue;
      if (!existsSync(fullPath) || !statSync(fullPath).isDirectory()) continue;
      seenRoots.add(key);
      resolvedRoots.push({ clientRootPath: normalizeOutputPathInput(root), fullPath });
    }

    if (resolvedRoots.length === 0) {
      return json({ query, files: [], folders: [], scannedFolders: 0, done: true, sortBy, sortOrder });
    }

    const filesByPath = new Map<string, any>();
    const indexedFiles = galleryDb.searchFiles(
      resolvedRoots.map((root) => root.clientRootPath),
      query,
      fileLimit * 3,
    );
    for (const file of indexedFiles) {
      if (!fsFileMatchesSearch(file, query)) continue;
      const key = normalizeOutputPathInput(String(file?.path || '')).toLowerCase();
      if (!key || filesByPath.has(key)) continue;
      filesByPath.set(key, file);
      if (filesByPath.size >= fileLimit) break;
    }

    const foldersByPath = new Map<string, { name: string; path: string; rootPath: string }>();
    let scannedFolders = 0;
    let capped = false;
    const queue = resolvedRoots.map((root) => ({
      absolutePath: root.fullPath,
      clientPath: root.clientRootPath,
      rootPath: root.clientRootPath,
      absoluteRootPath: root.fullPath,
    }));
    const seenDirs = new Set(queue.map((entry) => normalizeOutputPathInput(entry.absolutePath).toLowerCase()));

    for (const root of queue) {
      const label = basename(root.clientPath) || root.clientPath;
      if (fsTextMatchesSearch(label, query) || fsTextMatchesSearch(root.clientPath, query)) {
        foldersByPath.set(root.clientPath.toLowerCase(), { name: label, path: root.clientPath, rootPath: root.rootPath });
      }
    }

    while (queue.length > 0 && scannedFolders < maxFolders && Date.now() - startedAt < maxDurationMs) {
      const current = queue.shift();
      if (!current) continue;
      scannedFolders += 1;
      let entries: Dirent[] = [];
      try {
        entries = await fs.readdir(current.absolutePath, { withFileTypes: true });
      } catch {
        continue;
      }

      for (const entry of entries) {
        if (!entry.isDirectory()) continue;
        const absolutePath = join(current.absolutePath, entry.name);
        const absoluteKey = normalizeOutputPathInput(absolutePath).toLowerCase();
        if (!absoluteKey || seenDirs.has(absoluteKey)) continue;
        seenDirs.add(absoluteKey);
        const clientPath = mapAbsolutePathToGalleryPath(current.rootPath, current.absoluteRootPath, absolutePath);
        if (foldersByPath.size < folderLimit && (fsTextMatchesSearch(entry.name, query) || fsTextMatchesSearch(clientPath, query))) {
          foldersByPath.set(clientPath.toLowerCase(), { name: entry.name, path: clientPath, rootPath: current.rootPath });
        }
        queue.push({
          absolutePath,
          clientPath,
          rootPath: current.rootPath,
          absoluteRootPath: current.absoluteRootPath,
        });
      }
    }
    if (queue.length > 0) capped = true;

    const files = Array.from(filesByPath.values())
      .filter((file) => fsFileMatchesSearch(file, query))
      .sort((left, right) => compareFsSearchFiles(left, right, query, sortBy, sortOrder))
      .slice(0, fileLimit);
    const folders = Array.from(foldersByPath.values())
      .sort((left, right) => left.path.localeCompare(right.path, undefined, { numeric: true, sensitivity: 'base' }))
      .slice(0, folderLimit);

    return json({
      query,
      files,
      folders,
      scannedFolders,
      done: !capped,
      sortBy,
      sortOrder,
    });
  } catch (error: any) {
    console.error('[FS Search] Error:', error);
    return json({ error: error?.message || 'Gallery search failed' }, 500);
  }
}

async function handleFsSearchSuggestions(url: URL): Promise<Response> {
  const query = normalizeFsSearchQuery(url.searchParams.get('q') || url.searchParams.get('query') || '');
  const limit = Math.max(1, Math.min(40, Math.trunc(Number(url.searchParams.get('limit') || 18) || 18)));
  const roots = url.searchParams.getAll('root')
    .concat(url.searchParams.getAll('roots'))
    .flatMap((entry) => String(entry || '').split('|'))
    .map((entry) => normalizeOutputPathInput(String(entry || '').trim()))
    .filter(Boolean);
  const rootInputs = roots.length > 0 ? roots : [getDefaultOutputRootPath()];

  if (query.length < 1) {
    return json({ query, suggestions: [] });
  }

  try {
    const resolvedRoots: string[] = [];
    const seenRoots = new Set<string>();
    for (const root of rootInputs) {
      const resolved = resolvePath(root);
      if (!resolved) continue;
      const key = normalizeOutputPathInput(resolved.fullPath).toLowerCase();
      if (!key || seenRoots.has(key)) continue;
      if (!isPathInsideAllowedRoots(resolved.fullPath)) continue;
      if (!existsSync(resolved.fullPath) || !statSync(resolved.fullPath).isDirectory()) continue;
      seenRoots.add(key);
      resolvedRoots.push(normalizeOutputPathInput(root));
    }

    const suggestions = galleryDb.searchSuggestions(resolvedRoots, query, limit);
    return json({ query, suggestions });
  } catch (error: any) {
    console.error('[FS Search Suggestions] Error:', error);
    return json({ error: error?.message || 'Gallery search suggestions failed' }, 500);
  }
}

async function handleFsTagsSummary(url: URL): Promise<Response> {
  const folders = url.searchParams.getAll('folder')
    .concat(url.searchParams.getAll('path'))
    .flatMap((entry) => String(entry || '').split('|'))
    .map((entry) => normalizeOutputPathInput(String(entry || '').trim()))
    .filter(Boolean);
  const limit = Math.max(1, Math.min(600, Math.trunc(Number(url.searchParams.get('limit') || 300) || 300)));

  try {
    const validFolders: string[] = [];
    const seenFolders = new Set<string>();
    for (const folder of folders) {
      const resolved = resolvePath(folder);
      if (!resolved) continue;
      const key = normalizeOutputPathInput(folder).toLowerCase();
      if (!key || seenFolders.has(key)) continue;
      if (!isPathInsideAllowedRoots(resolved.fullPath)) continue;
      seenFolders.add(key);
      validFolders.push(normalizeOutputPathInput(folder));
      if (validFolders.length >= 240) break;
    }
    const tags = galleryDb.tagSummaryForFolders(validFolders, limit);
    return json({ folders: validFolders, tags });
  } catch (error: any) {
    console.error('[FS Tags Summary] Error:', error);
    return json({ error: error?.message || 'Failed to load gallery tags' }, 500);
  }
}

const THUMBNAIL_PENDING_PLACEHOLDER = `<svg xmlns="http://www.w3.org/2000/svg" width="2" height="2" viewBox="0 0 2 2"><rect width="2" height="2" fill="#18181b"/></svg>`;

function thumbnailResponse(
  thumbnail: Buffer,
  headers: Record<string, string>,
): Response {
  return new Response(new Uint8Array(thumbnail), { headers });
}

function pendingThumbnailResponse(): Response {
  return new Response(THUMBNAIL_PENDING_PLACEHOLDER, {
    status: 200,
    headers: {
      'Content-Type': 'image/svg+xml; charset=utf-8',
      'Cache-Control': 'no-store',
      'Retry-After': '1',
      'X-Thumbnail-Pending': '1',
    },
  });
}

const REMOTE_GALLERY_IMAGE_MAX_LONG_SIDE = 1536;
const REMOTE_GALLERY_IMAGE_QUALITY = 78;
const REMOTE_GALLERY_THUMBNAIL_QUALITY = 64;
const REMOTE_GALLERY_OPTIMIZABLE_IMAGE_EXTENSIONS = new Set([
  '.bmp',
  '.jpg',
  '.jpeg',
  '.png',
  '.webp',
]);

function hasRemoteGalleryImageOptimizationHint(url: URL): boolean {
  const previewMode = String(url.searchParams.get('preview') || '').trim().toLowerCase();
  return previewMode === 'viewer-webp' || previewMode === 'original-webp';
}

function isRemoteGalleryImageOptimizationEnabled(req: Request, url: URL, server?: RequestIpServer): boolean {
  return (isRemoteRequest(req, url, server) || hasRemoteGalleryImageOptimizationHint(url))
    && getAppSettings()['remote.galleryViewerOriginals'] !== true;
}

function isRemoteOptimizableStillImagePath(pathValue: string): boolean {
  return REMOTE_GALLERY_OPTIMIZABLE_IMAGE_EXTENSIONS.has(extname(pathValue).toLowerCase());
}

function clampRemoteGalleryQuality(value: string | null, fallback: number, remoteMax: number): number {
  const parsed = Number.parseInt(String(value || ''), 10);
  const quality = Number.isFinite(parsed)
    ? Math.max(1, Math.min(100, parsed))
    : fallback;
  return Math.min(quality, remoteMax);
}

function clampRemoteGalleryMaxLongSide(value: string | null): number {
  const parsed = Number(value);
  const maxLongSide = Number.isFinite(parsed)
    ? Math.max(128, Math.min(2048, Math.round(parsed)))
    : REMOTE_GALLERY_IMAGE_MAX_LONG_SIDE;
  return Math.min(maxLongSide, REMOTE_GALLERY_IMAGE_MAX_LONG_SIDE);
}

function applyRemoteGalleryBridgeFsOptimization(
  req: Request,
  sourceUrl: URL,
  targetPath: string,
  targetUrl: URL,
  server?: RequestIpServer,
): boolean {
  if (!isRemoteGalleryImageOptimizationEnabled(req, sourceUrl, server)) return false;

  if (targetPath === '/api/fs/thumbnail') {
    targetUrl.searchParams.set('size', 'small');
    targetUrl.searchParams.set('q', String(clampRemoteGalleryQuality(targetUrl.searchParams.get('q'), REMOTE_GALLERY_THUMBNAIL_QUALITY, REMOTE_GALLERY_THUMBNAIL_QUALITY)));
    return true;
  }

  if (targetPath !== '/api/fs/image') return false;
  if (String(targetUrl.searchParams.get('download') || '').trim() === '1') return false;
  const pathValue = String(targetUrl.searchParams.get('path') || '').trim();
  if (!pathValue || !isRemoteOptimizableStillImagePath(pathValue)) return false;

  const previewMode = String(targetUrl.searchParams.get('preview') || '').trim().toLowerCase();
  if (!previewMode || previewMode === 'viewer-webp' || previewMode === 'original-webp') {
    targetUrl.searchParams.set('preview', 'grid');
  }
  targetUrl.searchParams.set('gpr', '1');
  targetUrl.searchParams.set('gpm', String(clampRemoteGalleryMaxLongSide(targetUrl.searchParams.get('gpm'))));
  targetUrl.searchParams.set('gpq', String(clampRemoteGalleryQuality(targetUrl.searchParams.get('gpq'), REMOTE_GALLERY_IMAGE_QUALITY, REMOTE_GALLERY_IMAGE_QUALITY)));
  return true;
}

async function handleFsThumbnail(req: Request, url: URL, server?: RequestIpServer): Promise<Response> {
  const path = url.searchParams.get('path');
  const sizeParam = url.searchParams.get('size') as 'small' | 'medium' | 'large' || 'medium';
  const qualityParam = Number.parseInt(url.searchParams.get('q') ?? '', 10);
  const deferGeneration = String(url.searchParams.get('defer') || '').trim() === '1';
  if (!path) return new Response('Path parameter required', { status: 400 });

  try {
    const resolved = resolvePath(path);
    if (!resolved) return new Response('Invalid path', { status: 403 });

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) {
      return new Response('File not found', { status: 404 });
    }
    const fileStat = statSync(fullPath);

    // Validate size parameter
    const size = ['small', 'medium', 'large'].includes(sizeParam) ? sizeParam : 'medium';
    const remoteOptimized = isRemoteGalleryImageOptimizationEnabled(req, url, server);
    const quality = Math.min(Number.isFinite(qualityParam)
      ? Math.max(1, Math.min(100, qualityParam))
      : 100, remoteOptimized ? REMOTE_GALLERY_THUMBNAIL_QUALITY : 100);

    const requestedRevision = String(url.searchParams.get('rev') || '').trim();
    const fallbackRevision = `m${Math.max(0, Math.floor(fileStat.mtimeMs))}-s${Math.max(0, Math.floor(fileStat.size))}`;
    const sidecarRevision = 'plain';
    const effectiveRevision = requestedRevision || `${fallbackRevision}-${sidecarRevision}`;
    const etag = `W/"thumb-${createHash('md5').update(`${path}|${size}|${quality}|${effectiveRevision}`).digest('hex').slice(0, 16)}"`;
    const ifNoneMatch = String(req.headers.get('if-none-match') || '').trim();
    if (ifNoneMatch && ifNoneMatch === etag) {
      return new Response(null, {
        status: 304,
        headers: {
          'ETag': etag,
          'Cache-Control': requestedRevision
            ? 'public, max-age=31536000, immutable'
            : 'public, max-age=120, stale-while-revalidate=600',
        },
      });
    }

    const thumbnailOptions = {
      size: size as 'small' | 'medium' | 'large',
      quality,
      format: 'webp' as const,
    };

    if (deferGeneration) {
      const cachedThumbnail = await thumbnailService.readCachedThumbnail(fullPath, thumbnailOptions);
      if (cachedThumbnail) {
        return thumbnailResponse(cachedThumbnail, {
          'Content-Type': 'image/webp',
          'Cache-Control': requestedRevision
            ? 'public, max-age=31536000, immutable'
            : 'public, max-age=120, stale-while-revalidate=600',
          'ETag': etag,
          'X-Thumbnail-Size': size,
          'X-Thumbnail-Quality': String(quality),
          'X-Thumbnail-Edited': '0',
          'X-Thumbnail-Deferred': 'hit',
          ...(remoteOptimized ? { 'X-Umbra-Remote-Optimized': '1' } : {}),
        });
      }

      thumbnailService.enqueueThumbnailGeneration(fullPath, thumbnailOptions);
      return pendingThumbnailResponse();
    }

    const thumbnail = await thumbnailService.generateThumbnail(fullPath, {
      ...thumbnailOptions,
    });

    if (!thumbnail) {
      // Fallback: Redirect to raw image since we can't generate thumbnails
      // This only happens if Sharp isn't available
      return new Response(null, {
        status: 302,
        headers: { 'Location': `/api/fs/image?path=${encodeURIComponent(path)}` }
      });
    }

    return thumbnailResponse(thumbnail, {
        'Content-Type': 'image/webp',
        'Cache-Control': requestedRevision
          ? 'public, max-age=31536000, immutable'
          : 'public, max-age=120, stale-while-revalidate=600',
        'ETag': etag,
        'X-Thumbnail-Size': size,
        'X-Thumbnail-Quality': String(quality),
        'X-Thumbnail-Edited': '0',
        ...(remoteOptimized ? { 'X-Umbra-Remote-Optimized': '1' } : {}),
    });
  } catch (error: any) {
    console.error('[Thumbnail] Error:', error);
    return new Response('Failed to generate thumbnail', { status: 500 });
  }
}


async function handleFsPreview(url: URL): Promise<Response> {
  const path = url.searchParams.get('path');
  const sizeParam = url.searchParams.get('size') as 'small' | 'medium' | 'large' || 'medium';
  if (!path) return new Response('Path parameter required', { status: 400 });

  try {
    const resolved = resolvePath(path);
    if (!resolved) return new Response('Invalid path', { status: 403 });

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) {
      return new Response('File not found', { status: 404 });
    }
    const fileStat = statSync(fullPath);

    // Check if it's a video file
    const ext = fullPath.split('.').pop()?.toLowerCase();
    const videoExts = ['mp4', 'webm', 'mov', 'avi', 'mkv', 'm4v', 'flv', 'wmv'];
    if (!ext || !videoExts.includes(ext)) {
      return new Response('Preview only available for video files', { status: 400 });
    }

    const size = ['small', 'medium', 'large'].includes(sizeParam) ? sizeParam : 'medium';
    const requestedRevision = String(url.searchParams.get('rev') || '').trim();
    const fallbackRevision = `m${Math.max(0, Math.floor(fileStat.mtimeMs))}-s${Math.max(0, Math.floor(fileStat.size))}`;
    const effectiveRevision = requestedRevision || `${fallbackRevision}-preview`;
    const etag = `W/"preview-${createHash('md5').update(`${path}|${size}|${effectiveRevision}`).digest('hex').slice(0, 16)}"`;
    const ifNoneMatch = String(url.headers?.get?.('if-none-match') || '').trim();
    if (ifNoneMatch && ifNoneMatch === etag) {
      return new Response(null, {
        status: 304,
        headers: {
          'ETag': etag,
          'Cache-Control': requestedRevision
            ? 'public, max-age=31536000, immutable'
            : 'public, max-age=60, stale-while-revalidate=300',
        },
      });
    }

    const preview = await thumbnailService.generateVideoPreview(fullPath, {
      size: size as 'small' | 'medium' | 'large',
      duration: 4,
      fps: 8
    });

    if (!preview) {
      // Fallback: Return static thumbnail
      return new Response(null, {
        status: 302,
        headers: { 'Location': `/api/fs/thumbnail?path=${encodeURIComponent(path)}&size=${size}&q=100&rev=v3` }
      });
    }

    return new Response(new Uint8Array(preview), {
      headers: {
        'Content-Type': 'video/webm',
        'Cache-Control': requestedRevision
          ? 'public, max-age=31536000, immutable'
          : 'public, max-age=60, stale-while-revalidate=300',
        'ETag': etag,
        'X-Preview-Size': size
      }
    });
  } catch (error: any) {
    console.error('[Preview] Error:', error);
    return new Response('Failed to generate preview', { status: 500 });
  }
}

async function handleFsImage(req: Request, url: URL, server?: RequestIpServer): Promise<Response> {
  const path = url.searchParams.get('path');
  if (!path) return new Response('Path parameter required', { status: 400 });

  try {
    const resolved = resolvePath(path);
    if (!resolved) return new Response('Invalid path', { status: 403 });

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) {
      // try { db.exec(`DELETE FROM images WHERE path = '${fullPath.replace(/'/g, "''")}'`); } catch { }
      return new Response('File not found', { status: 404 });
    }

    const file = Bun.file(fullPath);
    const fileStat = statSync(fullPath);
    const etag = `W/"${fileStat.size}-${Math.floor(fileStat.mtimeMs)}"`;
    const hasRevision = String(url.searchParams.get('rev') || '').trim().length > 0;
    const downloadMode = String(url.searchParams.get('download') || '').trim() === '1';
    const range = String(req.headers.get('range') || '').trim();
    let previewMode = String(url.searchParams.get('preview') || '').trim().toLowerCase();
    let resizeEnabled = String(url.searchParams.get('gpr') || '1').trim() !== '0';
    let maxLongSide = Number.isFinite(Number(url.searchParams.get('gpm')))
      ? Math.max(128, Math.min(2048, Math.round(Number(url.searchParams.get('gpm')))))
      : 512;
    let quality = Number.isFinite(Number(url.searchParams.get('gpq')))
      ? Math.max(40, Math.min(100, Math.round(Number(url.searchParams.get('gpq')))))
      : 90;
    const remoteOptimized = isRemoteGalleryImageOptimizationEnabled(req, url, server)
      && !downloadMode
      && !range
      && isRemoteOptimizableStillImagePath(fullPath);
    if (remoteOptimized) {
      if (!previewMode || previewMode === 'viewer-webp' || previewMode === 'original-webp') {
        previewMode = 'grid';
      }
      resizeEnabled = true;
      maxLongSide = url.searchParams.has('gpm')
        ? Math.min(maxLongSide, REMOTE_GALLERY_IMAGE_MAX_LONG_SIDE)
        : REMOTE_GALLERY_IMAGE_MAX_LONG_SIDE;
      quality = Math.min(quality, REMOTE_GALLERY_IMAGE_QUALITY);
    }

    if (!downloadMode && previewMode === 'grid' && resizeEnabled) {
      const preview = await thumbnailService.generateGridPreview(fullPath, {
        maxLongSide,
        quality,
        format: 'webp',
      });
      if (preview) {
        return new Response(new Uint8Array(preview), {
          headers: {
            'Content-Type': 'image/webp',
            'Content-Length': String(preview.length),
            'Cache-Control': hasRevision
              ? 'public, max-age=31536000, immutable'
              : 'public, max-age=120, stale-while-revalidate=600',
            'ETag': `${etag}-grid-${maxLongSide}-${quality}`,
            'X-Grid-Preview': '1',
            'X-Grid-Preview-Max': String(maxLongSide),
            'X-Grid-Preview-Quality': String(quality),
            ...(remoteOptimized ? { 'X-Umbra-Remote-Optimized': '1' } : {}),
          }
        });
      }
    }

    if (!downloadMode && (previewMode === 'viewer-webp' || previewMode === 'original-webp')) {
      const preview = await thumbnailService.generateOriginalWebpPreview(fullPath, {
        quality,
      });
      if (preview) {
        return new Response(new Uint8Array(preview), {
          headers: {
            'Content-Type': 'image/webp',
            'Content-Length': String(preview.length),
            'Cache-Control': hasRevision
              ? 'public, max-age=31536000, immutable'
              : 'public, max-age=120, stale-while-revalidate=600',
            'ETag': `${etag}-viewer-webp-${quality}`,
            'X-Viewer-Preview': 'original-webp',
            'X-Viewer-Preview-Quality': String(quality),
            ...(remoteOptimized ? { 'X-Umbra-Remote-Optimized': '1' } : {}),
          }
        });
      }
    }

    const cacheControl = hasRevision
      ? 'public, max-age=31536000, immutable'
      : 'public, max-age=10, stale-while-revalidate=30';
    const contentType = file.type || 'application/octet-stream';
    const lastModified = new Date(fileStat.mtimeMs).toUTCString();
    const baseHeaders: Record<string, string> = {
      'Content-Type': contentType,
      'Cache-Control': cacheControl,
      'ETag': etag,
      'Last-Modified': lastModified,
      'Accept-Ranges': 'bytes',
    };
    if (downloadMode) {
      const rawName = basename(fullPath) || 'umbra-media';
      const asciiName = rawName.replace(/[^\x20-\x7E]+/g, '_').replace(/["\\\r\n]/g, '_') || 'umbra-media';
      baseHeaders['Content-Disposition'] = `attachment; filename="${asciiName}"; filename*=UTF-8''${encodeURIComponent(rawName)}`;
    }

    if (range) {
      const match = /^bytes=(\d*)-(\d*)$/i.exec(range);
      if (match) {
        const size = fileStat.size;
        let start = match[1] ? Number.parseInt(match[1], 10) : Number.NaN;
        let end = match[2] ? Number.parseInt(match[2], 10) : Number.NaN;
        if (!Number.isFinite(start) && Number.isFinite(end)) {
          start = Math.max(0, size - end);
          end = size - 1;
        } else {
          if (!Number.isFinite(start)) start = 0;
          if (!Number.isFinite(end)) end = size - 1;
        }
        start = Math.max(0, Math.min(size - 1, Math.floor(start)));
        end = Math.max(start, Math.min(size - 1, Math.floor(end)));
        if (size > 0 && start <= end) {
          return new Response(file.slice(start, end + 1), {
            status: 206,
            headers: {
              ...baseHeaders,
              'Content-Length': String(end - start + 1),
              'Content-Range': `bytes ${start}-${end}/${size}`,
            },
          });
        }
      }
      return new Response(null, {
        status: 416,
        headers: {
          ...baseHeaders,
          'Content-Range': `bytes */${fileStat.size}`,
        },
      });
    }

    return new Response(file, {
      headers: {
        ...baseHeaders,
        'Content-Length': String(fileStat.size),
      }
    });
  } catch (error: any) {
    console.error('[Image] Error:', error);
    return new Response('Failed to serve image', { status: 500 });
  }
}

const ZIP_CRC32_TABLE = (() => {
  const table = new Uint32Array(256);
  for (let index = 0; index < 256; index++) {
    let value = index;
    for (let bit = 0; bit < 8; bit++) {
      value = (value & 1) ? (0xedb88320 ^ (value >>> 1)) : (value >>> 1);
    }
    table[index] = value >>> 0;
  }
  return table;
})();

function updateZipCrc32(crc: number, chunk: Uint8Array): number {
  let next = crc >>> 0;
  for (const byte of chunk) {
    next = ZIP_CRC32_TABLE[(next ^ byte) & 0xff] ^ (next >>> 8);
  }
  return next >>> 0;
}

function zipDosDateTime(dateValue: Date): { date: number; time: number } {
  const year = Math.max(1980, Math.min(2107, dateValue.getFullYear()));
  const month = Math.max(1, Math.min(12, dateValue.getMonth() + 1));
  const day = Math.max(1, Math.min(31, dateValue.getDate()));
  const hours = Math.max(0, Math.min(23, dateValue.getHours()));
  const minutes = Math.max(0, Math.min(59, dateValue.getMinutes()));
  const seconds = Math.max(0, Math.min(59, Math.floor(dateValue.getSeconds() / 2)));
  return {
    date: ((year - 1980) << 9) | (month << 5) | day,
    time: (hours << 11) | (minutes << 5) | seconds,
  };
}

function zipU16(value: number): Buffer {
  const buffer = Buffer.allocUnsafe(2);
  buffer.writeUInt16LE(value & 0xffff, 0);
  return buffer;
}

function zipU32(value: number): Buffer {
  const buffer = Buffer.allocUnsafe(4);
  buffer.writeUInt32LE(value >>> 0, 0);
  return buffer;
}

function zipSafeEntryName(name: string): string {
  const leaf = basename(String(name || '').replace(/\\/g, '/')).replace(/[\u0000-\u001f<>:"\\|?*]+/g, '_').trim();
  return leaf || 'umbra-media';
}

function uniqueZipEntryName(name: string, usedNames: Set<string>): string {
  const safe = zipSafeEntryName(name);
  let candidate = safe;
  let index = 2;
  const parsed = { ext: extname(safe), base: safe.slice(0, safe.length - extname(safe).length) };
  while (usedNames.has(candidate.toLowerCase())) {
    candidate = `${parsed.base || 'umbra-media'} (${index})${parsed.ext}`;
    index += 1;
  }
  usedNames.add(candidate.toLowerCase());
  return candidate;
}

function writeZipChunk(stream: ReturnType<typeof createWriteStream>, chunk: Uint8Array | Buffer): Promise<void> {
  return new Promise((resolve, reject) => {
    stream.write(chunk, (error) => {
      if (error) reject(error);
      else resolve();
    });
  });
}

async function finishZipStream(stream: ReturnType<typeof createWriteStream>): Promise<void> {
  return new Promise((resolve, reject) => {
    stream.once('error', reject);
    stream.end(() => resolve());
  });
}

async function buildOriginalsZip(items: Array<{ fullPath: string; name: string; mtime: Date; size: number }>): Promise<{ zipPath: string; size: number }> {
  const tempRoot = join(USER_DIR, 'Temp', 'Downloads');
  await fs.mkdir(tempRoot, { recursive: true });
  const zipPath = join(tempRoot, `umbra-originals-${Date.now()}-${randomBytes(4).toString('hex')}.zip`);
  const stream = createWriteStream(zipPath);
  const centralDirectory: Buffer[] = [];
  const usedNames = new Set<string>();
  let offset = 0;

  try {
    for (const item of items) {
      if (item.size > 0xffffffff) {
        throw new Error(`File is too large for portable zip download: ${item.name}`);
      }
      const entryName = uniqueZipEntryName(item.name, usedNames);
      const nameBuffer = Buffer.from(entryName, 'utf8');
      const { date, time } = zipDosDateTime(item.mtime);
      const entryOffset = offset;
      const flags = 0x0808; // UTF-8 names + trailing data descriptor.
      const localHeader = Buffer.concat([
        zipU32(0x04034b50),
        zipU16(20),
        zipU16(flags),
        zipU16(0),
        zipU16(time),
        zipU16(date),
        zipU32(0),
        zipU32(0),
        zipU32(0),
        zipU16(nameBuffer.length),
        zipU16(0),
        nameBuffer,
      ]);
      await writeZipChunk(stream, localHeader);
      offset += localHeader.length;

      let crc = 0xffffffff;
      let size = 0;
      for await (const chunk of createReadStream(item.fullPath)) {
        const buffer = Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk);
        crc = updateZipCrc32(crc, buffer);
        size += buffer.length;
        if (size > 0xffffffff) {
          throw new Error(`File is too large for portable zip download: ${item.name}`);
        }
        await writeZipChunk(stream, buffer);
        offset += buffer.length;
      }
      crc = (crc ^ 0xffffffff) >>> 0;

      const descriptor = Buffer.concat([
        zipU32(0x08074b50),
        zipU32(crc),
        zipU32(size),
        zipU32(size),
      ]);
      await writeZipChunk(stream, descriptor);
      offset += descriptor.length;

      centralDirectory.push(Buffer.concat([
        zipU32(0x02014b50),
        zipU16(20),
        zipU16(20),
        zipU16(flags),
        zipU16(0),
        zipU16(time),
        zipU16(date),
        zipU32(crc),
        zipU32(size),
        zipU32(size),
        zipU16(nameBuffer.length),
        zipU16(0),
        zipU16(0),
        zipU16(0),
        zipU16(0),
        zipU32(0),
        zipU32(entryOffset),
        nameBuffer,
      ]));
    }

    const centralOffset = offset;
    for (const entry of centralDirectory) {
      await writeZipChunk(stream, entry);
      offset += entry.length;
    }
    const centralSize = offset - centralOffset;
    const endRecord = Buffer.concat([
      zipU32(0x06054b50),
      zipU16(0),
      zipU16(0),
      zipU16(centralDirectory.length),
      zipU16(centralDirectory.length),
      zipU32(centralSize),
      zipU32(centralOffset),
      zipU16(0),
    ]);
    await writeZipChunk(stream, endRecord);
    offset += endRecord.length;
    await finishZipStream(stream);
    return { zipPath, size: offset };
  } catch (error) {
    stream.destroy();
    await fs.rm(zipPath, { force: true }).catch(() => {});
    throw error;
  }
}

async function buildBufferZip(
  label: string,
  items: Array<{ name: string; mtime: Date; data: Buffer }>,
): Promise<{ zipPath: string; size: number }> {
  const tempRoot = join(USER_DIR, 'Temp', 'Downloads');
  await fs.mkdir(tempRoot, { recursive: true });
  const zipPath = join(tempRoot, `umbra-${label}-${Date.now()}-${randomBytes(4).toString('hex')}.zip`);
  const stream = createWriteStream(zipPath);
  const centralDirectory: Buffer[] = [];
  const usedNames = new Set<string>();
  let offset = 0;

  try {
    for (const item of items) {
      const data = Buffer.isBuffer(item.data) ? item.data : Buffer.from(item.data);
      if (data.length > 0xffffffff) {
        throw new Error(`File is too large for portable zip download: ${item.name}`);
      }
      const entryName = uniqueZipEntryName(item.name, usedNames);
      const nameBuffer = Buffer.from(entryName, 'utf8');
      const { date, time } = zipDosDateTime(item.mtime);
      const entryOffset = offset;
      const flags = 0x0800;
      let crc = 0xffffffff;
      crc = updateZipCrc32(crc, data);
      crc = (crc ^ 0xffffffff) >>> 0;
      const size = data.length;

      const localHeader = Buffer.concat([
        zipU32(0x04034b50),
        zipU16(20),
        zipU16(flags),
        zipU16(0),
        zipU16(time),
        zipU16(date),
        zipU32(crc),
        zipU32(size),
        zipU32(size),
        zipU16(nameBuffer.length),
        zipU16(0),
        nameBuffer,
      ]);
      await writeZipChunk(stream, localHeader);
      await writeZipChunk(stream, data);
      offset += localHeader.length + data.length;

      centralDirectory.push(Buffer.concat([
        zipU32(0x02014b50),
        zipU16(20),
        zipU16(20),
        zipU16(flags),
        zipU16(0),
        zipU16(time),
        zipU16(date),
        zipU32(crc),
        zipU32(size),
        zipU32(size),
        zipU16(nameBuffer.length),
        zipU16(0),
        zipU16(0),
        zipU16(0),
        zipU16(0),
        zipU32(0),
        zipU32(entryOffset),
        nameBuffer,
      ]));
    }

    const centralOffset = offset;
    for (const entry of centralDirectory) {
      await writeZipChunk(stream, entry);
      offset += entry.length;
    }
    const centralSize = offset - centralOffset;
    const endRecord = Buffer.concat([
      zipU32(0x06054b50),
      zipU16(0),
      zipU16(0),
      zipU16(centralDirectory.length),
      zipU16(centralDirectory.length),
      zipU32(centralSize),
      zipU32(centralOffset),
      zipU16(0),
    ]);
    await writeZipChunk(stream, endRecord);
    offset += endRecord.length;
    await finishZipStream(stream);
    return { zipPath, size: offset };
  } catch (error) {
    stream.destroy();
    await fs.rm(zipPath, { force: true }).catch(() => {});
    throw error;
  }
}

async function handleFsDownloadZip(req: Request): Promise<Response> {
  try {
    const contentType = String(req.headers.get('content-type') || '').toLowerCase();
    let paths: unknown[] = [];
    if (contentType.includes('multipart/form-data') || contentType.includes('application/x-www-form-urlencoded')) {
      const formData = await req.formData();
      const rawPaths = formData.get('paths');
      paths = typeof rawPaths === 'string' ? JSON.parse(rawPaths) : [];
    } else {
      const body = await req.json().catch(() => ({}));
      paths = Array.isArray(body?.paths) ? body.paths : [];
    }

    const normalizedPaths = Array.from(new Set(paths.map((entry) => String(entry || '').trim()).filter(Boolean)));
    if (normalizedPaths.length < 2) return json({ error: 'At least two files are required for a zip download' }, 400);
    if (normalizedPaths.length > 1000) return json({ error: 'Too many files selected for one zip download' }, 400);

    const items: Array<{ fullPath: string; name: string; mtime: Date; size: number }> = [];
    for (const path of normalizedPaths) {
      const resolved = resolvePath(path);
      if (!resolved) return json({ error: `Invalid path: ${path}` }, 403);
      const stats = statSync(resolved.fullPath);
      if (!stats.isFile()) continue;
      items.push({
        fullPath: resolved.fullPath,
        name: basename(resolved.fullPath),
        mtime: stats.mtime,
        size: stats.size,
      });
    }
    if (items.length < 2) return json({ error: 'Select at least two files to download a zip' }, 400);

    const { zipPath, size } = await buildOriginalsZip(items);
    const cleanupTimer = setTimeout(() => {
      fs.rm(zipPath, { force: true }).catch(() => {});
    }, 15 * 60 * 1000);
    (cleanupTimer as any).unref?.();

    return new Response(Bun.file(zipPath), {
      headers: {
        'Content-Type': 'application/zip',
        'Content-Disposition': `attachment; filename="umbra-originals-${new Date().toISOString().slice(0, 10)}.zip"`,
        'Content-Length': String(size),
        'Cache-Control': 'no-store',
      },
    });
  } catch (error: any) {
    console.error('[ImageZip] Error:', error);
    return json({ error: error?.message || 'Failed to create zip download' }, 500);
  }
}

async function handleFsDownloadJpegZip(req: Request): Promise<Response> {
  try {
    const contentType = String(req.headers.get('content-type') || '').toLowerCase();
    let paths: unknown[] = [];
    let keepMetadata = true;
    if (contentType.includes('multipart/form-data') || contentType.includes('application/x-www-form-urlencoded')) {
      const formData = await req.formData();
      const rawPaths = formData.get('paths');
      paths = typeof rawPaths === 'string' ? JSON.parse(rawPaths) : [];
      keepMetadata = String(formData.get('metadata') || 'keep').toLowerCase() !== 'strip';
    } else {
      const body = await req.json().catch(() => ({}));
      paths = Array.isArray(body?.paths) ? body.paths : [];
      keepMetadata = String(body?.metadata || 'keep').toLowerCase() !== 'strip';
    }

    const normalizedPaths = Array.from(new Set(paths.map((entry) => String(entry || '').trim()).filter(Boolean)));
    if (normalizedPaths.length === 0) return json({ error: 'Select at least one image to download' }, 400);
    if (normalizedPaths.length > 1000) return json({ error: 'Too many images selected for one zip download' }, 400);

    const sharp = (await import('sharp')).default;
    const imageExts = new Set(['.png', '.jpg', '.jpeg', '.webp', '.bmp', '.gif', '.avif', '.tif', '.tiff']);
    const items: Array<{ name: string; mtime: Date; data: Buffer }> = [];

    for (const path of normalizedPaths) {
      const resolved = resolvePath(path);
      if (!resolved) return json({ error: `Invalid path: ${path}` }, 403);
      const stats = statSync(resolved.fullPath);
      if (!stats.isFile()) continue;
      if (!imageExts.has(extname(resolved.fullPath).toLowerCase())) continue;

      let pipeline = sharp(resolved.fullPath, { animated: false }).rotate();
      pipeline = keepMetadata ? pipeline.withMetadata() : pipeline;
      const data = await pipeline
        .jpeg({
          quality: 94,
          mozjpeg: true,
          chromaSubsampling: '4:4:4',
        })
        .toBuffer();
      const sourceName = basename(resolved.fullPath).replace(/\.[^.]+$/, '');
      items.push({
        name: `${sourceName || 'umbra-media'}.jpg`,
        mtime: stats.mtime,
        data,
      });
    }

    if (items.length === 0) return json({ error: 'No supported images were selected' }, 400);

    const label = keepMetadata ? 'jpeg-metadata' : 'jpeg-clean';
    const { zipPath, size } = await buildBufferZip(label, items);
    const cleanupTimer = setTimeout(() => {
      fs.rm(zipPath, { force: true }).catch(() => {});
    }, 15 * 60 * 1000);
    (cleanupTimer as any).unref?.();

    return new Response(Bun.file(zipPath), {
      headers: {
        'Content-Type': 'application/zip',
        'Content-Disposition': `attachment; filename="umbra-${label}-${new Date().toISOString().slice(0, 10)}.zip"`,
        'Content-Length': String(size),
        'Cache-Control': 'no-store',
      },
    });
  } catch (error: any) {
    console.error('[ImageJpegZip] Error:', error);
    return json({ error: error?.message || 'Failed to create JPEG zip download' }, 500);
  }
}

async function handleFsMetadata(url: URL): Promise<Response> {
  const path = url.searchParams.get('path');
  if (!path) return json({ error: 'Path parameter required' }, 400);

  try {
    const resolved = resolvePath(path);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) return json({ error: 'File not found' }, 404);

    const stat = statSync(fullPath);
    const parsed = (await MetadataParser.parse(fullPath)) || {};
    let imageMetadata: any = {};
    try {
      const sharp = (await import('sharp')).default;
      imageMetadata = await sharp(fullPath).metadata();
    } catch {
      imageMetadata = {};
    }

    return json({
      type: /\.(mp4|webm|mov|avi|mkv|m4v|flv|wmv|gif)$/i.test(fullPath) ? 'video' : 'image',
      name: basename(fullPath),
      size: stat.size,
      modified: stat.mtime.toISOString(),
      width: imageMetadata.width ?? (parsed as any).width,
      height: imageMetadata.height ?? (parsed as any).height,
      format: (parsed as any).format ?? imageMetadata.format,
      exif: imageMetadata.exif,
      ...parsed,
    });
  } catch (error: any) {
    console.error('[Metadata] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsRead(url: URL): Promise<Response> {
  const path = url.searchParams.get('path');
  if (!path) return new Response('Path parameter required', { status: 400 });

  try {
    const resolved = resolvePath(path);
    if (!resolved) return new Response('Invalid path', { status: 403 });

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) return new Response('File not found', { status: 404 });
    if (!statSync(fullPath).isFile()) return new Response('Not a file', { status: 400 });

    const result = await fsWorkerService.read({ fullPath });
    const buffer = Buffer.from(String((result as any).contentBase64 || ''), 'base64');
    return new Response(buffer);
  } catch (error: any) {
    console.error('[Read] Error:', error);
    return new Response('Failed to read file', { status: 500 });
  }
}

async function handleFsWrite(req: Request): Promise<Response> {
  try {
    const { path: filePath, content, encoding } = await req.json() as {
      path: string;
      content?: string;
      encoding?: 'utf8' | 'base64';
    };
    if (!filePath) return json({ error: 'Path required' }, 400);

    const resolved = resolvePath(filePath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (resolved.relativePath.toLowerCase().endsWith(PP_CARD_DOC_EXT)) {
      if (encoding === 'base64') {
        return json({ error: 'Power Prompter card writes must use JSON text.' }, 400);
      }
      try {
        const parsed = JSON.parse(String(content ?? ''));
        const saved = await savePPCardDocumentForFile(resolved.relativePath, parsed, { forceOverwrite: false });
        return json({ success: true, path: saved.file || resolved.relativePath, guarded: true });
      } catch (error: any) {
        return json({ error: error?.message || 'Failed to save Power Prompter card document' }, 400);
      }
    }

    await fsWorkerService.write({
      fullPath,
      content: content ?? '',
      encoding: encoding === 'base64' ? 'base64' : 'utf8',
    });
    return json({ success: true, path: filePath });
  } catch (error: any) {
    console.error('[FS Write] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsReveal(req: Request, server?: RequestIpServer): Promise<Response> {
  try {
    const requestUrl = new URL(req.url);
    if (isRemoteRequest(req, requestUrl, server)) {
      return json({ error: 'Opening File Explorer is only available from the host PC.' }, 403);
    }
    const body = await req.json() as { path?: string };
    const targetPath = body.path;
    if (!targetPath) return json({ error: 'Path required' }, 400);

    const resolved = resolvePath(targetPath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (!isPathInsideAllowedRoots(fullPath)) return json({ error: 'Access denied' }, 403);
    if (!existsSync(fullPath)) return json({ error: 'File not found' }, 404);

    const targetStat = statSync(fullPath);
    const opened = await openPathInHostFileExplorer(fullPath, targetStat);
    if (!opened.opened) return json({ error: 'Failed to open file explorer' }, 500);
    return json({ success: true, highlighted: opened.highlighted, fullPath });
  } catch (error: any) {
    console.error('[FS Reveal] Error:', error);
    return json({ error: error.message || 'Failed to reveal path' }, 500);
  }
}

async function openPathInHostFileExplorer(
  revealPath: string,
  targetStat = statSync(revealPath)
): Promise<{ opened: boolean; highlighted: boolean }> {
  const parentPath = targetStat.isDirectory() ? revealPath : dirname(revealPath);
  const runCommand = async (args: string[], options?: { acceptAnyExitCode?: boolean }) => {
    try {
      const proc = Bun.spawn(args, { stdout: 'ignore', stderr: 'ignore' });
      const code = await proc.exited;
      if (options?.acceptAnyExitCode === true) return code >= 0;
      return code === 0;
    } catch {
      return false;
    }
  };

  let opened = false;
  let highlighted = false;

  if (process.platform === 'win32') {
    const revealPathWin = revealPath.replace(/\//g, '\\');
    const parentPathWin = parentPath.replace(/\//g, '\\');

    if (targetStat.isDirectory()) {
      opened = await runCommand(['explorer.exe', revealPathWin], { acceptAnyExitCode: true });
    } else {
      opened = await runCommand(['explorer.exe', '/select,', revealPathWin], { acceptAnyExitCode: true });
      highlighted = opened;
      if (!opened) {
        opened = await runCommand(['explorer.exe', parentPathWin], { acceptAnyExitCode: true });
        highlighted = false;
      }
    }
  } else if (process.platform === 'darwin') {
    if (targetStat.isDirectory()) {
      opened = await runCommand(['open', revealPath]);
    } else {
      opened = await runCommand(['open', '-R', revealPath]);
      highlighted = opened;
    }
  } else {
    if (!targetStat.isDirectory()) {
      const fileUri = pathToFileURL(revealPath).toString();
      opened = await runCommand([
        'dbus-send',
        '--session',
        '--dest=org.freedesktop.FileManager1',
        '--type=method_call',
        '--print-reply',
        '/org/freedesktop/FileManager1',
        'org.freedesktop.FileManager1.ShowItems',
        `array:string:${fileUri}`,
        'string:'
      ]);
      highlighted = opened;
    }

    if (!opened) {
      opened = await runCommand(['xdg-open', parentPath]);
    }
  }

  return { opened, highlighted };
}

async function handleLocalServerOpenFolder(req: Request, server?: RequestIpServer): Promise<Response> {
  try {
    const requestUrl = new URL(req.url);
    if (isRemoteRequest(req, requestUrl, server)) {
      return json({ error: 'Opening local server app folders is only available from the host PC.' }, 403);
    }
    const body = await req.json().catch(() => ({})) as { path?: string };
    const rawPath = String(body.path || '').trim();
    if (!rawPath) return json({ error: 'Path required' }, 400);
    if (!isAbsolute(rawPath)) return json({ error: 'Use an absolute folder path.' }, 400);
    const fullPath = resolve(rawPath);
    if (!existsSync(fullPath)) return json({ error: 'Folder not found' }, 404);
    const targetStat = statSync(fullPath);
    if (!targetStat.isDirectory()) return json({ error: 'Local server app path must be a folder.' }, 400);
    const opened = await openPathInHostFileExplorer(fullPath, targetStat);
    if (!opened.opened) return json({ error: 'Failed to open app folder' }, 500);
    return json({ success: true, fullPath });
  } catch (error: any) {
    console.error('[Local Servers] Open folder error:', error);
    return json({ error: error.message || 'Failed to open app folder' }, 500);
  }
}

const modelManagerDownloadInvalidationSet = new Set<string>();

function normalizeModelManagerTypeFolder(rawType: unknown): string {
  const value = String(rawType || '').trim().toLowerCase();
  if (value.includes('checkpoint')) return 'Checkpoints';
  if (value.includes('lora')) return 'Lora';
  if (value.includes('lycoris')) return 'Lycoris';
  if (value.includes('textual') || value.includes('embedding')) return 'TextualInversion';
  if (value.includes('vae')) return 'VAE';
  if (value.includes('control')) return 'ControlNet';
  if (value.includes('upscaler')) return 'Upscaler';
  if (value.includes('hypernetwork')) return 'Hypernetwork';
  return 'Other';
}

async function ensureModelManagerRootsExist() {
  const roots = getModelManagerRootsResolved();
  for (const root of roots) {
    if (!root.fullPath) continue;
    try {
      await fs.mkdir(root.fullPath, { recursive: true });
    } catch {
      // best effort
    }
  }
}

async function handleModelManagerRoots(): Promise<Response> {
  try {
    await ensureModelManagerRootsExist();
    const roots = getModelManagerRootsResolved();
    const result = await modelIndexWorkerService.getRoots(roots);
    return json(result);
  } catch (error: any) {
    console.error('[ModelManager] roots error:', error);
    return json({ error: error?.message || 'Failed to load model roots' }, 500);
  }
}

async function handleModelManagerTree(url: URL): Promise<Response> {
  try {
    await ensureModelManagerRootsExist();
    const rawPath = String(url.searchParams.get('path') || MODEL_MANAGER_ROOTS[0].path).trim();
    const resolved = resolveModelManagerPath(rawPath);
    if (!resolved) return json({ error: 'Invalid model path' }, 400);
    if (!existsSync(resolved.fullPath)) await fs.mkdir(resolved.fullPath, { recursive: true });
    const payload = await modelIndexWorkerService.tree({
      path: resolved.clientPath,
      fullPath: resolved.fullPath,
    });
    return json(payload);
  } catch (error: any) {
    console.error('[ModelManager] tree error:', error);
    return json({ error: error?.message || 'Failed to load model tree' }, 500);
  }
}

async function handleModelManagerList(url: URL): Promise<Response> {
  try {
    await ensureModelManagerRootsExist();
    const rawPath = String(url.searchParams.get('path') || MODEL_MANAGER_ROOTS[0].path).trim();
    const resolved = resolveModelManagerPath(rawPath);
    if (!resolved) return json({ error: 'Invalid model path' }, 400);
    if (!existsSync(resolved.fullPath)) await fs.mkdir(resolved.fullPath, { recursive: true });
    if (url.searchParams.get('recursive') === '1') {
      const payload = await listModelManagerSnapshotFilesRecursive(resolved.fullPath);
      return json(payload);
    }
    const payload = await modelIndexWorkerService.list({
      path: resolved.clientPath,
      fullPath: resolved.fullPath,
      includeMetadata: url.searchParams.get('fast') !== '1',
    });
    return json(payload);
  } catch (error: any) {
    console.error('[ModelManager] list error:', error);
    return json({ error: error?.message || 'Failed to load model list' }, 500);
  }
}

async function handleModelManagerReconcile(req: Request): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as { path?: string; recoverFromCivitai?: boolean; recursive?: boolean };
    const rawPath = String(body.path || MODEL_MANAGER_ROOTS[0].path).trim();
    const resolved = resolveModelManagerPath(rawPath);
    if (!resolved) return json({ error: 'Invalid model path' }, 400);
    const options = {
      recoverFromCivitai: body.recoverFromCivitai === true,
    };
    const result = body.recursive === true
      ? await reconcileModelManagerFolderRecursive(resolved.fullPath, options)
      : await reconcileModelManagerFolder(resolved.fullPath, options);
    return json(result);
  } catch (error: any) {
    console.error('[ModelManager] reconcile error:', error);
    return json({ error: error?.message || 'Failed to reconcile model metadata' }, 500);
  }
}

async function handleModelManagerInspect(req: Request): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as { path?: string };
    const rawPath = String(body.path || '').trim();
    const resolved = resolveModelManagerPath(rawPath);
    if (!resolved) return json({ error: 'Invalid model path' }, 400);
    const stat = await fs.stat(resolved.fullPath).catch(() => null);
    if (!stat?.isFile()) return json({ error: 'Select a model file to inspect' }, 400);
    const result = await inspectModelManagerModelFile(resolved.fullPath);
    return json(result);
  } catch (error: any) {
    console.error('[ModelManager] inspect error:', error);
    return json({ error: error?.message || 'Failed to inspect model metadata' }, 500);
  }
}

type ModelInspectionSummary = ReturnType<typeof summarizeModelMetadata>;

async function runModelManagerFsTransferJob(job: ModelManagerFsTransferJob) {
  console.log(`[ModelManager] ${job.mode === 'copy' ? 'Copy' : 'Move'} started paths=${job.items.length} destination="${job.destination}" job=${job.id}`);
  try {
    const validItems = job.items;
    if (validItems.length <= 0) {
      job.status = 'failed';
      job.error = 'No valid source paths';
      job.finishedAt = Date.now();
      console.warn(`[ModelManager] ${job.mode === 'copy' ? 'Copy' : 'Move'} failed paths=0 destination="${job.destination}" job=${job.id}`);
      return;
    }

    const progressOptions = {
      onProgress: (progress: any) => {
        const totalUnits = Number(progress?.totalUnits || 0);
        const completedUnits = Number(progress?.completedUnits || 0);
        if (totalUnits > 0) job.totalUnits = totalUnits;
        job.completedUnits = Math.min(job.totalUnits || completedUnits, completedUnits);
        job.currentPath = String(progress?.currentPath || '');
      },
    };

    const execution = job.mode === 'move'
      ? await fsWorkerService.move(
        {
          items: validItems,
          destination: job.destination,
          destinationFullPath: job.destinationFullPath,
          transferMode: 'default',
        },
        progressOptions,
      )
      : await fsWorkerService.copy(
        {
          items: validItems,
          destination: job.destination,
          destinationFullPath: job.destinationFullPath,
        },
        progressOptions,
      );

    if (job.totalUnits <= 0) job.totalUnits = Number((execution as any)?.totalUnits || validItems.length || 1);
    job.completedUnits = Math.min(job.totalUnits, Math.max(job.completedUnits, job.totalUnits));
    job.results = ((execution as any)?.results || []) as Array<FsMoveResult | FsCopyResult>;
    job.status = 'completed';
    job.finishedAt = Date.now();
    const successCount = job.results.filter((entry) => entry.success).length;
    console.log(`[ModelManager] ${job.mode === 'copy' ? 'Copy' : 'Move'} completed paths=${validItems.length} success=${successCount} destination="${job.destination}" ms=${job.finishedAt - job.startedAt} job=${job.id}`);

    await modelIndexWorkerService.invalidatePaths([
      job.destinationFullPath,
      ...job.sourceFullPaths,
      ...job.results
        .map((entry: any) => String(entry?.newPath || '').trim())
        .filter((entry: string) => entry.length > 0),
    ]);
  } catch (error: any) {
    job.status = 'failed';
    job.error = error?.message || `${job.mode === 'copy' ? 'Copy' : 'Move'} failed`;
    job.finishedAt = Date.now();
    console.error(`[ModelManager] ${job.mode === 'copy' ? 'Copy' : 'Move'} failed paths=${job.items.length} destination="${job.destination}" ms=${job.finishedAt - job.startedAt} job=${job.id}:`, error);
  } finally {
    scheduleModelManagerFsTransferJobCleanup(job.id);
  }
}

function handleModelManagerFsTransferStatus(url: URL): Response {
  pruneModelManagerFsTransferJobs();
  const jobId = String(url.searchParams.get('jobId') || '').trim();
  if (!jobId) return json({ error: 'jobId required' }, 400);

  const job = modelManagerFsTransferJobs.get(jobId);
  if (!job) return json({ error: 'Transfer job not found' }, 404);

  const percent = job.totalUnits > 0
    ? Math.min(100, Math.round((job.completedUnits / job.totalUnits) * 100))
    : 0;
  const successCount = job.results.filter((entry) => entry.success).length;

  return json({
    success: true,
    job: {
      id: job.id,
      jobId: job.id,
      mode: job.mode,
      status: job.status,
      destination: job.destination,
      totalPaths: job.paths.length,
      totalUnits: job.totalUnits,
      completedUnits: job.completedUnits,
      percent,
      currentPath: job.currentPath,
      error: job.error,
      moved: job.mode === 'move' ? successCount : undefined,
      copied: job.mode === 'copy' ? successCount : undefined,
      results: job.results,
      startedAt: job.startedAt,
      finishedAt: job.finishedAt,
    },
  });
}

async function handleModelManagerFsMove(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { paths?: string[]; destination?: string; trackProgress?: boolean };
    const paths = Array.isArray(body.paths) ? body.paths : [];
    const destinationRaw = String(body.destination || '').trim();
    if (paths.length <= 0 || !destinationRaw) return json({ error: 'Missing parameters' }, 400);

    const destination = resolveModelManagerPath(destinationRaw);
    if (!destination) return json({ error: 'Invalid destination path' }, 400);

    const resolvedSources = paths
      .map((rawPath) => resolveModelManagerPath(String(rawPath || '').trim()))
      .filter((entry): entry is NonNullable<typeof entry> => Boolean(entry));
    const validItems = await buildModelManagerTransferItems(
      resolvedSources.map((entry) => entry.fullPath),
      destination.fullPath,
    );
    if (validItems.length <= 0) return json({ error: 'No valid source paths' }, 400);

    if (body.trackProgress) {
      const job = createModelManagerFsTransferJob(
        'move',
        paths,
        destination.clientPath,
        destination.fullPath,
        validItems,
      );
      void runModelManagerFsTransferJob(job);
      return json({ success: true, jobId: job.id, job: {
        id: job.id,
        jobId: job.id,
        mode: job.mode,
        status: job.status,
        destination: job.destination,
        totalPaths: job.paths.length,
        totalUnits: job.totalUnits,
        completedUnits: job.completedUnits,
        percent: 0,
        currentPath: job.currentPath,
        startedAt: job.startedAt,
      } });
    }

    const startedAt = Date.now();
    console.log(`[ModelManager] Move started paths=${validItems.length} destination="${destination.clientPath}"`);
    const execution = await fsWorkerService.move({
      items: validItems,
      destination: destination.clientPath,
      destinationFullPath: destination.fullPath,
      transferMode: 'default',
    });

    await modelIndexWorkerService.invalidatePaths([
      destination.fullPath,
      ...validItems.map((item) => item.sourceFullPath),
      ...(((execution as any)?.results || []) as any[])
        .map((entry: any) => String(entry?.newPath || '').trim())
        .filter((entry: string) => entry.length > 0),
    ]);
    const successCount = Number((execution as any)?.moved || (((execution as any)?.results || []) as any[]).filter((entry: any) => entry?.success).length || 0);
    console.log(`[ModelManager] Move completed paths=${validItems.length} success=${successCount} destination="${destination.clientPath}" ms=${Date.now() - startedAt}`);

    return json({
      success: true,
      ...(execution as any),
    });
  } catch (error: any) {
    console.error('[ModelManager] move error:', error);
    return json({ error: error?.message || 'Move failed' }, 500);
  }
}

