async function handleModelManagerFsRename(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { path?: string; oldPath?: string; newName?: string; name?: string };
    const sourceRaw = String(body.path || body.oldPath || '').trim();
    const newName = String(body.newName || body.name || '').trim();
    if (!sourceRaw || !newName) return json({ error: 'Missing parameters' }, 400);
    if (newName.includes('/') || newName.includes('\\') || newName === '.' || newName === '..') {
      return json({ error: 'Invalid file/folder name' }, 400);
    }

    const source = resolveModelManagerPath(sourceRaw);
    if (!source) return json({ error: 'Invalid source path' }, 400);

    const targetFullPath = resolve(dirname(source.fullPath), newName);
    if (!isPathInsideModelManagerRoots(targetFullPath)) return json({ error: 'Access denied' }, 403);
    const targetPath = toClientPath(targetFullPath);
    const oldThumbArtifacts = await listModelThumbArtifactsForFile(source.fullPath);
    const oldBaseName = basename(source.fullPath);
    const nextBaseName = basename(targetFullPath);
    const startedAt = Date.now();

    await fsWorkerService.rename({
      oldFullPath: source.fullPath,
      newFullPath: targetFullPath,
    });

    const snapshotRenames = [
      {
        oldPath: getPreferredModelSnapshotFullPath(source.fullPath),
        nextPath: getPreferredModelSnapshotFullPath(targetFullPath),
      },
      {
        oldPath: getLegacyModelSnapshotFullPath(source.fullPath),
        nextPath: getLegacyModelSnapshotFullPath(targetFullPath),
      },
      {
        oldPath: getPreferredModelInspectionReportFullPath(source.fullPath),
        nextPath: getPreferredModelInspectionReportFullPath(targetFullPath),
      },
    ];
    for (const snapshotRename of snapshotRenames) {
      if (!existsSync(snapshotRename.oldPath) || !isPathInsideModelManagerRoots(snapshotRename.nextPath)) continue;
      await fs.mkdir(dirname(snapshotRename.nextPath), { recursive: true }).catch(() => undefined);
      await fsWorkerService.rename({
        oldFullPath: snapshotRename.oldPath,
        newFullPath: snapshotRename.nextPath,
      }).catch(() => undefined);
    }

    for (const oldThumbPath of oldThumbArtifacts) {
      const parentDir = dirname(oldThumbPath);
      const oldFileName = basename(oldThumbPath);
      const nextFileName = oldFileName.replace(`${oldBaseName}${MODEL_THUMB_PREFIX}`, `${nextBaseName}${MODEL_THUMB_PREFIX}`);
      const nextThumbPath = join(parentDir, nextFileName);
      if (!isPathInsideModelManagerRoots(nextThumbPath)) continue;
      await fsWorkerService.rename({
        oldFullPath: oldThumbPath,
        newFullPath: nextThumbPath,
      }).catch(() => undefined);
    }

    await modelIndexWorkerService.invalidatePaths([source.fullPath, targetFullPath, dirname(source.fullPath)]);
    console.log(`[ModelManager] Rename completed from="${source.clientPath}" to="${targetPath}" ms=${Date.now() - startedAt}`);
    return json({
      success: true,
      path: source.clientPath,
      newPath: targetPath,
    });
  } catch (error: any) {
    console.error('[ModelManager] rename error:', error);
    return json({ error: error?.message || 'Rename failed' }, 500);
  }
}

async function handleModelManagerFsDelete(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { paths?: string[] };
    const paths = Array.isArray(body.paths) ? body.paths : [];
    if (paths.length <= 0) return json({ error: 'Missing parameters' }, 400);

    const resolvedItems = paths
      .map((rawPath) => resolveModelManagerPath(String(rawPath || '').trim()))
      .filter((entry): entry is NonNullable<typeof entry> => Boolean(entry));
    const artifactPaths = await expandModelArtifactPaths(resolvedItems.map((entry) => entry.fullPath));
    const items = artifactPaths.map((fullPath) => ({
      path: toClientPath(fullPath),
      fullPath,
    }));
    if (items.length <= 0) return json({ error: 'No valid paths' }, 400);

    const execution = await fsWorkerService.delete({
      items,
      force: true,
    });
    await modelIndexWorkerService.invalidatePaths([
      ...items.map((item) => item.fullPath),
      ...items.map((item) => dirname(item.fullPath)),
    ]);
    const successCount = Number((execution as any)?.deleted || (((execution as any)?.results || []) as any[]).filter((entry: any) => entry?.success).length || 0);
    console.log(`[ModelManager] Delete completed paths=${items.length} success=${successCount}`);
    return json({
      success: true,
      ...(execution as any),
    });
  } catch (error: any) {
    console.error('[ModelManager] delete error:', error);
    return json({ error: error?.message || 'Delete failed' }, 500);
  }
}

async function handleModelManagerFsMkdir(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { path?: string };
    const pathRaw = String(body.path || '').trim();
    if (!pathRaw) return json({ error: 'Missing path' }, 400);
    const destination = resolveModelManagerPath(pathRaw);
    if (!destination) return json({ error: 'Invalid path' }, 400);
    await fsWorkerService.mkdir({ fullPath: destination.fullPath });
    await modelIndexWorkerService.invalidatePaths([destination.fullPath, dirname(destination.fullPath)]);
    console.log(`[ModelManager] Folder created path="${destination.clientPath}"`);
    return json({ success: true, path: destination.clientPath });
  } catch (error: any) {
    console.error('[ModelManager] mkdir error:', error);
    return json({ error: error?.message || 'Mkdir failed' }, 500);
  }
}

async function handleModelManagerFsReveal(req: Request, server?: RequestIpServer): Promise<Response> {
  try {
    const requestUrl = new URL(req.url);
    if (isRemoteRequest(req, requestUrl, server)) {
      return json({ error: 'Opening File Explorer is only available from the host PC.' }, 403);
    }
    const body = await req.json() as { path?: string };
    const pathRaw = String(body.path || '').trim();
    if (!pathRaw) return json({ error: 'Missing path' }, 400);
    const resolved = resolveModelManagerPath(pathRaw);
    if (!resolved) return json({ error: 'Invalid path' }, 400);
    const proxyReq = new Request('http://127.0.0.1/api/fs/reveal', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ path: resolved.clientPath }),
    });
    return await handleFsReveal(proxyReq, server);
  } catch (error: any) {
    console.error('[ModelManager] reveal error:', error);
    return json({ error: error?.message || 'Reveal failed' }, 500);
  }
}

const MODEL_MANAGER_MEDIA_MAX_BYTES = 80 * 1024 * 1024;
const MODEL_MANAGER_MEDIA_ALLOWED_HOST = /(^|\.)civitai\.com$/i;

function getModelManagerMediaExtension(rawUrl: string, mimeTypeInput: string): string {
  const mimeType = String(mimeTypeInput || '').toLowerCase();
  if (mimeType.includes('image/jpeg')) return 'jpg';
  if (mimeType.includes('image/png')) return 'png';
  if (mimeType.includes('image/webp')) return 'webp';
  if (mimeType.includes('image/gif')) return 'gif';
  if (mimeType.includes('image/avif')) return 'avif';
  if (mimeType.includes('video/mp4')) return 'mp4';
  if (mimeType.includes('video/webm')) return 'webm';
  if (mimeType.includes('video/quicktime')) return 'mov';

  try {
    const parsed = new URL(rawUrl);
    const match = parsed.pathname.match(/\.([a-z0-9]{2,8})$/i);
    if (match && match[1]) return String(match[1]).toLowerCase();
  } catch {
    // ignore
  }
  return 'bin';
}

function validateModelManagerMediaUrl(rawUrl: string): URL {
  const parsed = new URL(String(rawUrl || '').trim());
  const protocol = String(parsed.protocol || '').toLowerCase();
  if (protocol !== 'http:' && protocol !== 'https:') {
    throw new Error('Unsupported media URL protocol');
  }
  if (!MODEL_MANAGER_MEDIA_ALLOWED_HOST.test(parsed.hostname)) {
    throw new Error('Unsupported media host');
  }
  return parsed;
}

function maskCivitaiToken(token: string): string {
  const normalized = String(token || '').trim();
  if (!normalized) return '';
  if (normalized.length <= 8) return '*'.repeat(normalized.length);
  return `${normalized.slice(0, 4)}...${normalized.slice(-4)}`;
}

async function getModelManagerCivitaiToken(): Promise<string> {
  const config = await loadStoredApiKeys();
  return String(config.civitai?.apiToken || config.civitai?.apiKey || '').trim();
}

async function buildModelManagerCivitaiHeaders(accept = 'application/json'): Promise<Headers> {
  const headers = new Headers();
  headers.set('User-Agent', 'UmbraStudio/0.8');
  headers.set('Accept', accept);
  const token = await getModelManagerCivitaiToken();
  if (token) headers.set('Authorization', `Bearer ${token}`);
  return headers;
}

async function handleModelManagerCivitaiAuthGet(): Promise<Response> {
  try {
    const token = await getModelManagerCivitaiToken();
    return json({
      success: true,
      hasToken: Boolean(token),
      maskedToken: maskCivitaiToken(token),
    });
  } catch (error: any) {
    return json({ error: error?.message || 'Failed to read CivitAI account token' }, 500);
  }
}

async function handleModelManagerCivitaiAuthPost(req: Request): Promise<Response> {
  try {
    const body = await req.json().catch(() => ({})) as { apiToken?: unknown; token?: unknown; apiKey?: unknown };
    const token = String(body.apiToken || body.token || body.apiKey || '').trim();
    if (!token) return json({ error: 'Missing CivitAI API token' }, 400);
    const config = await loadStoredApiKeys();
    config.civitai = { apiToken: token };
    await saveStoredApiKeys(config);
    return json({
      success: true,
      hasToken: true,
      maskedToken: maskCivitaiToken(token),
    });
  } catch (error: any) {
    return json({ error: error?.message || 'Failed to save CivitAI account token' }, 500);
  }
}

async function handleModelManagerCivitaiAuthDelete(): Promise<Response> {
  try {
    const config = await loadStoredApiKeys();
    delete config.civitai;
    await saveStoredApiKeys(config);
    return json({ success: true, hasToken: false, maskedToken: '' });
  } catch (error: any) {
    return json({ error: error?.message || 'Failed to remove CivitAI account token' }, 500);
  }
}

async function resolveModelManagerMediaCache(rawUrl: string): Promise<{ localPath: string; mimeType: string }> {
  const normalizedUrl = String(rawUrl || '').trim();
  const cached = modelManagerStateDb.getMediaCache(normalizedUrl);
  if (cached && cached.localPath && existsSync(cached.localPath)) {
    return {
      localPath: cached.localPath,
      mimeType: String(cached.mimeType || '').trim() || 'application/octet-stream',
    };
  }

  const mediaUrl = validateModelManagerMediaUrl(normalizedUrl);
  const headers = await buildModelManagerCivitaiHeaders('image/*,video/*;q=0.9,*/*;q=0.5');
  const response = await fetch(mediaUrl, { headers });
  if (!response.ok) {
    throw new Error(`Media fetch failed (${response.status})`);
  }

  const contentLength = Number(response.headers.get('content-length') || 0);
  if (Number.isFinite(contentLength) && contentLength > MODEL_MANAGER_MEDIA_MAX_BYTES) {
    throw new Error('Media exceeds cache size limit');
  }

  const buffer = Buffer.from(await response.arrayBuffer());
  if (buffer.length > MODEL_MANAGER_MEDIA_MAX_BYTES) {
    throw new Error('Media exceeds cache size limit');
  }

  const mimeType = String(response.headers.get('content-type') || '').split(';')[0].trim().toLowerCase() || 'application/octet-stream';
  const ext = getModelManagerMediaExtension(normalizedUrl, mimeType);
  const fileName = `${createHash('sha1').update(normalizedUrl).digest('hex')}.${ext}`;
  if (!existsSync(MODEL_MANAGER_MEDIA_CACHE_DIR)) {
    await fs.mkdir(MODEL_MANAGER_MEDIA_CACHE_DIR, { recursive: true });
  }
  const localPath = join(MODEL_MANAGER_MEDIA_CACHE_DIR, fileName);
  await fs.writeFile(localPath, buffer);
  modelManagerStateDb.upsertMediaCache({
    mediaUrl: normalizedUrl,
    localPath,
    mimeType,
    sizeBytes: buffer.length,
    fetchedAt: Date.now(),
  });

  return { localPath, mimeType };
}

function extractModelManagerSnapshotMediaUrls(modelRaw: Record<string, unknown>): string[] {
  const urls: string[] = [];
  const seen = new Set<string>();
  const pushUrl = (value: unknown) => {
    const url = String(value || '').trim();
    if (!url || seen.has(url)) return;
    seen.add(url);
    urls.push(url);
  };

  const model = modelRaw && typeof modelRaw === 'object' && !Array.isArray(modelRaw)
    ? modelRaw
    : {};
  const modelVersions = Array.isArray(model.modelVersions) ? model.modelVersions : [];
  for (const versionRaw of modelVersions) {
    if (!versionRaw || typeof versionRaw !== 'object' || Array.isArray(versionRaw)) continue;
    const version = versionRaw as Record<string, unknown>;
    const images = Array.isArray(version.images) ? version.images : [];
    for (const imageRaw of images) {
      if (!imageRaw || typeof imageRaw !== 'object' || Array.isArray(imageRaw)) continue;
      pushUrl((imageRaw as Record<string, unknown>).url);
      if (urls.length >= 24) return urls;
    }
  }

  const communityMedia = Array.isArray(model.communityMedia) ? model.communityMedia : [];
  for (const mediaRaw of communityMedia) {
    if (!mediaRaw || typeof mediaRaw !== 'object' || Array.isArray(mediaRaw)) continue;
    pushUrl((mediaRaw as Record<string, unknown>).url);
    if (urls.length >= 40) break;
  }

  return urls;
}

async function prewarmModelManagerSnapshotMedia(modelRaw: Record<string, unknown>): Promise<void> {
  const mediaUrls = extractModelManagerSnapshotMediaUrls(modelRaw);
  for (const mediaUrl of mediaUrls) {
    await resolveModelManagerMediaCache(mediaUrl).catch(() => undefined);
  }
}

async function handleModelManagerMedia(url: URL): Promise<Response> {
  try {
    const rawUrl = String(url.searchParams.get('url') || '').trim();
    if (!rawUrl) return json({ error: 'Missing media URL' }, 400);
    const resolved = await resolveModelManagerMediaCache(rawUrl);
    if (!existsSync(resolved.localPath)) return json({ error: 'Cached media unavailable' }, 404);
    const thumbnailMode = url.searchParams.get('thumb') === '1';
    if (thumbnailMode) {
      const maxLongSideRaw = Number(url.searchParams.get('size') || 320);
      const maxLongSide = Number.isFinite(maxLongSideRaw)
        ? Math.max(128, Math.min(640, Math.round(maxLongSideRaw)))
        : 320;
      const thumbnail = await thumbnailService.generateGridPreview(resolved.localPath, {
        maxLongSide,
        quality: 88,
        format: 'webp',
      });
      if (thumbnail) {
        return new Response(new Uint8Array(thumbnail), {
          headers: {
            'Content-Type': 'image/webp',
            'Cache-Control': 'public, max-age=31536000, immutable',
          },
        });
      }
    }
    return new Response(Bun.file(resolved.localPath), {
      headers: {
        'Content-Type': resolved.mimeType || 'application/octet-stream',
        'Cache-Control': 'public, max-age=31536000, immutable',
      },
    });
  } catch (error: any) {
    const message = String(error?.message || 'Failed to load media');
    const badRequest = message.includes('Unsupported media URL') || message.includes('Unsupported media host') || message.includes('Missing media URL');
    return json({ error: message }, badRequest ? 400 : 500);
  }
}

async function handleModelManagerCivitaiSearch(url: URL): Promise<Response> {
  try {
    const allowedSort = new Set(['Highest Rated', 'Most Downloaded', 'Newest', 'Most Comments']);
    const allowedPeriod = new Set(['AllTime', 'Year', 'Month', 'Week', 'Day']);
    const allowedTypes = new Set([
      'Checkpoint',
      'TextualInversion',
      'Hypernetwork',
      'AestheticGradient',
      'LORA',
      'LoCon',
      'DoRA',
      'Controlnet',
      'Poses',
      'VAE',
      'Upscaler',
      'MotionModule',
      'Wildcards',
      'Workflows',
      'Other',
    ]);

    const target = new URL('https://civitai.com/api/v1/models');
    const passthroughParams = [
      'query',
      'baseModels',
      'favorites',
      'hidden',
      'limit',
      'page',
      'nsfw',
      'username',
      'tag',
    ];
    for (const key of passthroughParams) {
      const value = url.searchParams.get(key);
      if (value == null || value === '') continue;
      target.searchParams.set(key, value);
    }

    const incomingTypes = String(url.searchParams.get('types') || '')
      .split(',')
      .map((value) => String(value || '').trim())
      .filter((value) => value.length > 0 && allowedTypes.has(value));
    if (incomingTypes.length > 0) {
      target.searchParams.set('types', incomingTypes.join(','));
    }

    const incomingSort = String(url.searchParams.get('sort') || '').trim();
    if (incomingSort && allowedSort.has(incomingSort)) {
      target.searchParams.set('sort', incomingSort);
    } else if (!incomingSort) {
      target.searchParams.set('sort', 'Highest Rated');
    }

    const incomingPeriod = String(url.searchParams.get('period') || '').trim();
    if (incomingPeriod && allowedPeriod.has(incomingPeriod) && incomingPeriod !== 'AllTime') {
      target.searchParams.set('period', incomingPeriod);
    }

    if (!target.searchParams.get('limit')) target.searchParams.set('limit', '50');
    if (!target.searchParams.get('page')) target.searchParams.set('page', '1');

    const query = String(target.searchParams.get('query') || '').trim();
    const limit = String(target.searchParams.get('limit') || '50').trim() || '50';
    const page = String(target.searchParams.get('page') || '1').trim() || '1';
    const sort = String(target.searchParams.get('sort') || '').trim();
    const period = String(target.searchParams.get('period') || '').trim();
    const type = String(target.searchParams.get('types') || '').trim();
    const baseModels = String(target.searchParams.get('baseModels') || '').trim();

    const makeAttempt = (input: {
      includeQuery?: boolean;
      includeSort?: boolean;
      includePeriod?: boolean;
      includeType?: boolean;
      includeBaseModels?: boolean;
    }): URL => {
      const candidate = new URL('https://civitai.com/api/v1/models');
      candidate.searchParams.set('limit', limit);
      candidate.searchParams.set('page', page);
      if (input.includeQuery !== false && query) candidate.searchParams.set('query', query);
      if (input.includeSort !== false && sort) candidate.searchParams.set('sort', sort);
      if (input.includePeriod !== false && period) candidate.searchParams.set('period', period);
      if (input.includeType !== false && type) candidate.searchParams.set('types', type);
      if (input.includeBaseModels !== false && baseModels) candidate.searchParams.set('baseModels', baseModels);
      return candidate;
    };

    const attempts: URL[] = [
      target,
      makeAttempt({ includePeriod: false }),
      makeAttempt({ includeSort: false }),
      makeAttempt({ includeSort: false, includePeriod: false }),
      makeAttempt({ includeQuery: false, includeSort: false, includePeriod: false }),
      makeAttempt({ includeQuery: false, includeSort: false, includePeriod: false, includeBaseModels: false }),
      makeAttempt({ includeQuery: false, includeSort: false, includePeriod: false, includeBaseModels: false, includeType: false }),
    ];

    const headers = await buildModelManagerCivitaiHeaders('application/json');
    headers.set('Content-Type', 'application/json');

    const attemptedUrls = new Set<string>();
    let lastStatus = 500;
    let lastErrorText = '';
    for (const attempt of attempts) {
      const requestUrl = new URL(attempt.toString());
      const key = requestUrl.toString();
      if (attemptedUrls.has(key)) continue;
      attemptedUrls.add(key);

      const response = await fetch(requestUrl, {
        headers,
        signal: AbortSignal.timeout(MODEL_MANAGER_CIVITAI_TIMEOUT_MS),
      });
      if (response.ok) {
        const payload = await response.json();
        return json(payload);
      }

      lastStatus = response.status;
      lastErrorText = await response.text().catch(() => '');

      if (response.status === 400) continue;
      if (response.status === 429 || response.status >= 500) continue;
      break;
    }

    return json({
      items: [],
      metadata: { nextPage: null },
      warning: `CivitAI search unavailable (${lastStatus || 500}).`,
      details: lastErrorText.slice(0, 320),
    });
  } catch (error: any) {
    console.error('[ModelManager] CivitAI search error:', error);
    return json({
      items: [],
      metadata: { nextPage: null },
      warning: error?.message || 'CivitAI search failed',
    });
  }
}

async function handleModelManagerCivitaiModel(url: URL): Promise<Response> {
  try {
    const id = String(url.searchParams.get('id') || '').trim();
    if (!id) return json({ error: 'Missing model id' }, 400);
    const slim = url.searchParams.get('slim') === '1';
    const targetBase = new URL(`https://civitai.com/api/v1/models/${encodeURIComponent(id)}`);

    const headers = await buildModelManagerCivitaiHeaders('application/json');
    headers.set('Content-Type', 'application/json');

    const response = await fetch(targetBase, {
      headers,
      signal: AbortSignal.timeout(MODEL_MANAGER_CIVITAI_TIMEOUT_MS),
    });
    if (!response.ok) {
      const detail = await response.text().catch(() => '');
      return json({ error: `CivitAI model request failed (${response.status})`, details: detail.slice(0, 240) }, response.status || 500);
    }
    const payload = await response.json() as Record<string, unknown>;
    if (slim) {
      payload.communityMedia = [];
      return json(payload);
    }

    const normalizeImageUrl = (value: unknown): string => {
      const raw = String(value || '').trim();
      if (!raw) return '';
      const idx = raw.indexOf('?');
      return idx >= 0 ? raw.slice(0, idx) : raw;
    };

    const modelVersions = Array.isArray(payload?.modelVersions)
      ? payload.modelVersions as Array<Record<string, unknown>>
      : [];
    const enrichedVersions: Array<Record<string, unknown>> = [];

    for (const version of modelVersions) {
      const versionId = Number(version?.id || 0);
      const existingImages = Array.isArray(version?.images) ? version.images as Array<Record<string, unknown>> : [];
      const needsMetaEnrichment = existingImages.length > 0 && existingImages.some((image) => {
        const imageRecord = (image && typeof image === 'object') ? image as Record<string, unknown> : {};
        return !(Object.prototype.hasOwnProperty.call(imageRecord, 'meta')) || imageRecord.meta == null;
      });
      if (!needsMetaEnrichment || !Number.isFinite(versionId) || versionId <= 0) {
        enrichedVersions.push(version);
        continue;
      }

      let apiItems: Array<Record<string, unknown>> = [];
      try {
        const imagesTarget = new URL('https://civitai.com/api/v1/images');
        imagesTarget.searchParams.set('modelVersionId', String(versionId));
        imagesTarget.searchParams.set('limit', '200');
        const imagesResponse = await fetch(imagesTarget, {
          headers,
          signal: AbortSignal.timeout(MODEL_MANAGER_CIVITAI_TIMEOUT_MS),
        });
        if (imagesResponse.ok) {
          const imagesPayload = await imagesResponse.json().catch(() => ({})) as { items?: Array<Record<string, unknown>> };
          apiItems = Array.isArray(imagesPayload.items) ? imagesPayload.items : [];
        }
      } catch {
        apiItems = [];
      }

      if (apiItems.length <= 0) {
        enrichedVersions.push(version);
        continue;
      }

      const byId = new Map<string, Record<string, unknown>>();
      const byUrl = new Map<string, Record<string, unknown>>();
      for (const item of apiItems) {
        const idValue = String(item?.id ?? '').trim();
        if (idValue) byId.set(idValue, item);
        const urlValue = normalizeImageUrl(item?.url);
        if (urlValue) byUrl.set(urlValue, item);
      }

      const mergedImages = existingImages.map((image) => {
        const imageRecord = (image && typeof image === 'object') ? image as Record<string, unknown> : {};
        const imageId = String(imageRecord?.id ?? '').trim();
        const imageUrl = normalizeImageUrl(imageRecord?.url);
        const matched = (imageId && byId.get(imageId))
          || (imageUrl && byUrl.get(imageUrl))
          || null;
        if (!matched) return imageRecord;
        const mergedMeta = imageRecord?.meta ?? matched?.meta ?? null;
        return {
          ...matched,
          ...imageRecord,
          meta: mergedMeta,
        };
      });

      enrichedVersions.push({
        ...version,
        images: mergedImages,
      });
    }

    let remainingImages = MODEL_MANAGER_CLIPBOARD_IMAGE_LIMIT;
    const cappedVersions = enrichedVersions.map((version) => {
      const versionRecord = { ...version };
      const versionImages = Array.isArray(versionRecord.images) ? versionRecord.images as Array<Record<string, unknown>> : [];
      const keep = Math.max(0, remainingImages);
      const trimmedImages = versionImages.slice(0, keep);
      remainingImages -= trimmedImages.length;
      versionRecord.images = trimmedImages;
      return versionRecord;
    });

    payload.modelVersions = cappedVersions;
    payload.communityMedia = [];
    return json(payload);
  } catch (error: any) {
    console.error('[ModelManager] CivitAI model error:', error);
    return json({ error: error?.message || 'CivitAI model request failed' }, 500);
  }
}

async function handleModelManagerCivitaiVersion(url: URL): Promise<Response> {
  try {
    const id = String(url.searchParams.get('id') || '').trim();
    if (!id) return json({ error: 'Missing version id' }, 400);
    const versionId = Number(id);
    if (!Number.isFinite(versionId) || versionId <= 0) {
      return json({ error: 'Invalid version id' }, 400);
    }

    const headers = await buildModelManagerCivitaiHeaders('application/json');
    headers.set('Content-Type', 'application/json');
    const targetBase = new URL(`https://civitai.com/api/v1/model-versions/${encodeURIComponent(String(versionId))}`);
    const response = await fetch(targetBase, {
      headers,
      signal: AbortSignal.timeout(MODEL_MANAGER_CIVITAI_TIMEOUT_MS),
    });
    if (!response.ok) {
      const detail = await response.text().catch(() => '');
      return json({ error: `CivitAI model version request failed (${response.status})`, details: detail.slice(0, 240) }, response.status || 500);
    }
    const payload = await response.json().catch(() => ({})) as Record<string, unknown>;
    const modelId = Number(payload?.modelId || 0);
    if (!Number.isFinite(modelId) || modelId <= 0) {
      return json({ error: 'Model id not found for version' }, 404);
    }
    return json({
      modelId,
      versionId,
      name: String(payload?.name || '').trim(),
    });
  } catch (error: any) {
    console.error('[ModelManager] CivitAI version error:', error);
    return json({ error: error?.message || 'CivitAI model version request failed' }, 500);
  }
}

async function handleModelManagerCivitaiDownload(req: Request): Promise<Response> {
  try {
    const body = await req.json() as {
      downloadUrl?: string;
      fileName?: string;
      modelType?: string;
      destinationFolder?: string;
      jobId?: string;
      snapshot?: unknown;
    };
    const downloadUrl = String(body.downloadUrl || '').trim();
    const fileName = String(body.fileName || '').trim();
    const modelType = String(body.modelType || '').trim();
    if (!downloadUrl) return json({ error: 'Missing download URL' }, 400);

    const userRoot = getModelManagerRootsResolved().find((root) => root.key === 'user');
    if (!userRoot) return json({ error: 'User models root unavailable' }, 500);
    await fs.mkdir(userRoot.fullPath, { recursive: true });
    const requestedDestination = String(body.destinationFolder || '').trim();
    const exactDestination = requestedDestination ? resolveModelManagerPath(requestedDestination) : null;
    if (requestedDestination && !exactDestination) {
      return json({ error: 'Invalid download destination folder' }, 400);
    }
    if (exactDestination) {
      const destinationStat = await fs.stat(exactDestination.fullPath).catch(() => null);
      if (!destinationStat?.isDirectory()) {
        return json({ error: 'Download destination must be a folder' }, 400);
      }
    }

    const jobId = String(body.jobId || '').trim() || `model-download-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
    const resolvedFileName = fileName || `model-${Date.now()}.safetensors`;
    console.log(`[ModelManager] CivitAI download queued file="${resolvedFileName}" type="${modelType || 'Other'}"`);
    const workerResult = await modelDownloadWorkerService.startDownload({
      jobId,
      downloadUrl,
      fileName: resolvedFileName,
      modelType: modelType || 'Other',
      destinationRoot: exactDestination?.fullPath || userRoot.fullPath,
      useExactDestination: Boolean(exactDestination),
      civitaiToken: await getModelManagerCivitaiToken(),
      snapshot: body.snapshot,
    }) as { job?: unknown };
    const folder = normalizeModelManagerTypeFolder(modelType || 'Other');
    modelManagerDownloadInvalidationSet.delete(jobId);
    return json({
      success: true,
      jobId,
      destinationFolder: exactDestination?.clientPath || `User/Models/${folder}`,
      ...(workerResult || {}),
    });
  } catch (error: any) {
    console.error('[ModelManager] CivitAI download error:', error);
    return json({ error: error?.message || 'Failed to start download' }, 500);
  }
}

async function handleModelManagerDownloadStatus(jobId: string): Promise<Response> {
  try {
    const result = await modelDownloadWorkerService.getStatus(jobId) as {
      job?: {
        status?: string;
        destinationPath?: string;
        destinationRoot?: string;
      } | null;
    };
    const job = result?.job;
    if (!job) return json({ success: true, job: null }, 404);
    const status = String(job.status || '').trim();
    if ((status === 'completed' || status === 'failed' || status === 'cancelled') && !modelManagerDownloadInvalidationSet.has(jobId)) {
      modelManagerDownloadInvalidationSet.add(jobId);
      const fileName = String((job as any).fileName || basename(String(job.destinationPath || jobId)));
      console.log(`[ModelManager] Download ${status} file="${fileName}"`);
      const invalidatePaths: string[] = [];
      const destinationPath = String(job.destinationPath || '').trim();
      if (destinationPath) {
        invalidatePaths.push(destinationPath, dirname(destinationPath));
      }
      const destinationRoot = String(job.destinationRoot || '').trim();
      if (destinationRoot) invalidatePaths.push(destinationRoot);
      if (invalidatePaths.length > 0) {
        await modelIndexWorkerService.invalidatePaths(invalidatePaths);
      }
    }
    return json({ success: true, ...(result || {}) });
  } catch (error: any) {
    console.error('[ModelManager] download status error:', error);
    return json({ error: error?.message || 'Failed to read download status' }, 500);
  }
}

async function handleModelManagerDownloadCancel(jobId: string): Promise<Response> {
  try {
    const result = await modelDownloadWorkerService.cancel(jobId);
    return json({ success: true, ...(result as any) });
  } catch (error: any) {
    console.error('[ModelManager] download cancel error:', error);
    return json({ error: error?.message || 'Failed to cancel download job' }, 500);
  }
}

async function handleModelManagerOpenedModelsGet(): Promise<Response> {
  const state = await loadModelManagerState();
  return json({
    success: true,
    openedModelIds: state.openedModelIds,
    civitaiClipboard: state.civitaiClipboard.map((entry) => entry.model),
  });
}

async function handleModelManagerOpenedModelsPost(req: Request): Promise<Response> {
  try {
    const body = await req.json() as {
      openedModelIds?: unknown;
      modelSnapshot?: unknown;
    };
    const currentState = await loadModelManagerState();
    let nextClipboard = currentState.civitaiClipboard;
    let snapshotToPrewarm: Record<string, unknown> | null = null;
    if (Object.prototype.hasOwnProperty.call(body, 'modelSnapshot')) {
      const entry = normalizeModelManagerClipboardEntry({
        model: body.modelSnapshot,
      });
      if (entry) {
        snapshotToPrewarm = entry.model;
        nextClipboard = [
          entry,
          ...currentState.civitaiClipboard.filter((item) => item.id !== entry.id),
        ];
      }
    }
    const nextState = await saveModelManagerState({
      openedModelIds: Object.prototype.hasOwnProperty.call(body, 'openedModelIds')
        ? body.openedModelIds
        : currentState.openedModelIds,
      civitaiClipboard: nextClipboard,
    });
    if (snapshotToPrewarm) {
      void prewarmModelManagerSnapshotMedia(snapshotToPrewarm);
    }
    return json({
      success: true,
      openedModelIds: nextState.openedModelIds,
      civitaiClipboard: nextState.civitaiClipboard.map((entry) => entry.model),
    });
  } catch (error: any) {
    console.error('[ModelManager] opened model ids update error:', error);
    return json({ error: error?.message || 'Failed to update opened model ids' }, 500);
  }
}

async function deleteModelManagerCachedMediaForModel(modelRaw: Record<string, unknown>): Promise<void> {
  const mediaUrls = extractModelManagerSnapshotMediaUrls(modelRaw);
  if (mediaUrls.length <= 0) return;
  for (const mediaUrl of mediaUrls) {
    const removed = modelManagerStateDb.deleteMediaCache(mediaUrl);
    if (!removed?.localPath) continue;
    if (!isPathInsideDirectory(MODEL_MANAGER_MEDIA_CACHE_DIR, removed.localPath)) continue;
    await fs.unlink(removed.localPath).catch(() => {});
  }
}

async function handleModelManagerOpenedModelsRefresh(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { modelId?: unknown };
    const modelId = Math.floor(Number(body.modelId || 0));
    if (!Number.isFinite(modelId) || modelId <= 0) {
      return json({ error: 'Missing modelId' }, 400);
    }

    const modelUrl = new URL('http://127.0.0.1/api/model-manager/civitai/model');
    modelUrl.searchParams.set('id', String(modelId));
    const modelResponse = await handleModelManagerCivitaiModel(modelUrl);
    const modelPayload = await modelResponse.json().catch(() => ({})) as Record<string, unknown>;
    if (!modelResponse.ok) {
      return json({
        error: String(modelPayload?.error || `Failed to refresh model (${modelResponse.status})`),
      }, modelResponse.status || 500);
    }

    const entry = normalizeModelManagerClipboardEntry({
      id: modelId,
      capturedAt: Date.now(),
      model: modelPayload,
    });
    if (!entry) {
      return json({ error: 'Invalid model response from CivitAI' }, 502);
    }

    const currentState = await loadModelManagerState();
    const nextState = await saveModelManagerState({
      openedModelIds: [entry.id, ...currentState.openedModelIds.filter((value) => value !== entry.id)],
      civitaiClipboard: [
        entry,
        ...currentState.civitaiClipboard.filter((item) => item.id !== entry.id),
      ],
    });
    void prewarmModelManagerSnapshotMedia(entry.model);
    return json({
      success: true,
      model: entry.model,
      openedModelIds: nextState.openedModelIds,
      civitaiClipboard: nextState.civitaiClipboard.map((item) => item.model),
    });
  } catch (error: any) {
    console.error('[ModelManager] opened model refresh error:', error);
    return json({ error: error?.message || 'Failed to refresh saved model' }, 500);
  }
}

async function handleModelManagerOpenedModelsDelete(req: Request): Promise<Response> {
  try {
    const body = await req.json() as { modelId?: unknown };
    const modelId = Math.floor(Number(body.modelId || 0));
    if (!Number.isFinite(modelId) || modelId <= 0) {
      return json({ error: 'Missing modelId' }, 400);
    }

    const currentState = await loadModelManagerState();
    const removedEntry = currentState.civitaiClipboard.find((item) => item.id === modelId) || null;
    const nextState = await saveModelManagerState({
      openedModelIds: currentState.openedModelIds.filter((value) => value !== modelId),
      civitaiClipboard: currentState.civitaiClipboard.filter((item) => item.id !== modelId),
    });

    if (removedEntry?.model) {
      await deleteModelManagerCachedMediaForModel(removedEntry.model);
    }

    return json({
      success: true,
      removedModelId: modelId,
      openedModelIds: nextState.openedModelIds,
      civitaiClipboard: nextState.civitaiClipboard.map((item) => item.model),
    });
  } catch (error: any) {
    console.error('[ModelManager] opened model delete error:', error);
    return json({ error: error?.message || 'Failed to delete saved model' }, 500);
  }
}

async function handleEditorSearch(url: URL): Promise<Response> {
  const rawQuery = (url.searchParams.get('q') || '').trim();
  const requestedRoot = (url.searchParams.get('root') || getDefaultOutputRootPath()).trim();
  const rootPath = normalizeOutputPathInput(requestedRoot);
  const limit = Math.min(Math.max(parseInt(url.searchParams.get('limit') || '40', 10), 1), 200);

  if (!rawQuery) return json({ error: 'Search query required' }, 400);

  const query = rawQuery.toLowerCase();
  const resolvedRoot = resolvePath(rootPath);
  if (!resolvedRoot) return json({ error: 'Invalid root path' }, 400);

  const normalizePath = (p: string) => p.replace(/\\/g, '/');
  const normalizedRoot = normalizePath(resolvedRoot.relativePath === '.' ? '' : resolvedRoot.relativePath);

  const albums: Array<{ path: string; name: string; match: 'album' }> = [];
  const seenAlbumPaths = new Set<string>();
  const stack: Array<{ fullPath: string; relPath: string }> = [
    { fullPath: resolvedRoot.fullPath, relPath: normalizedRoot },
  ];

  // Search album/folder names recursively
  while (stack.length > 0 && albums.length < limit * 3) {
    const current = stack.pop()!;
    let entries: Dirent[] = [];

    try {
      entries = await fs.readdir(current.fullPath, { withFileTypes: true });
    } catch {
      continue;
    }

    for (const entry of entries) {
      if (!entry.isDirectory() || entry.name.startsWith('.')) continue;

      const childFullPath = join(current.fullPath, entry.name);
      const childRelPath = normalizePath(join(current.relPath, entry.name));
      const nameMatch = entry.name.toLowerCase().includes(query) || childRelPath.toLowerCase().includes(query);

      if (nameMatch && !seenAlbumPaths.has(childRelPath)) {
        seenAlbumPaths.add(childRelPath);
        albums.push({ path: childRelPath, name: entry.name, match: 'album' });
      }

      stack.push({ fullPath: childFullPath, relPath: childRelPath });
    }
  }

  // Search images by tags
  const taggedImagePaths = EditorDb.searchImagePathsByTag(query, limit * 4);
  const images: Array<{
    path: string;
    name: string;
    albumPath: string;
    tags: string[];
    match: 'tag';
  }> = [];

  for (const rawImagePath of taggedImagePaths) {
    const imagePath = normalizePath(rawImagePath);
    if (normalizedRoot && !imagePath.startsWith(`${normalizedRoot}/`) && imagePath !== normalizedRoot) continue;

    const resolvedImage = resolvePath(imagePath);
    if (!resolvedImage || !existsSync(resolvedImage.fullPath)) continue;

    const albumPath = normalizePath(dirname(imagePath));
    const tags = EditorDb.getImageTags(imagePath).map((t) => t.name);
    images.push({
      path: imagePath,
      name: basename(imagePath),
      albumPath,
      tags,
      match: 'tag',
    });

    if (!seenAlbumPaths.has(albumPath)) {
      seenAlbumPaths.add(albumPath);
      albums.push({ path: albumPath, name: basename(albumPath), match: 'album' });
    }
  }

  albums.sort((a, b) => a.path.localeCompare(b.path, undefined, { numeric: true, sensitivity: 'base' }));
  images.sort((a, b) => a.path.localeCompare(b.path, undefined, { numeric: true, sensitivity: 'base' }));

  return json({
    query: rawQuery,
    root: normalizedRoot,
    albums: albums.slice(0, limit),
    images: images.slice(0, limit),
  });
}

async function handleFsTree(url: URL): Promise<Response> {
  const rawPath = (url.searchParams.get('path') || '').trim();
  const requestedMaxDepth = Number.parseInt(url.searchParams.get('maxDepth') || '0', 10);
  const maxDepth = Number.isFinite(requestedMaxDepth)
    ? Math.max(0, Math.min(8, requestedMaxDepth))
    : 0;
  const path = !rawPath
    ? getDefaultOutputRootPath()
    : normalizeOutputPathInput(rawPath);
  const normalizedPath = path.replace(/\\/g, '/');

  // Trash is rendered as a virtual flat collection in the grid, so hide nested
  // filesystem folders in the sidebar tree.
  if (normalizedPath === TRASH_ROOT || normalizedPath.startsWith(`${TRASH_ROOT}/`)) {
    return json({ folders: [] });
  }

  try {
    const resolved = resolvePath(path);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    const { fullPath } = resolved;
    if (!existsSync(fullPath)) return json({ folders: [] });

    const result = await fsWorkerService.tree({
      fullPath,
      targetPath: path,
      // Sidebar tree is lazy by default, while specific browsers can opt into
      // bounded nested traversal with maxDepth.
      maxDepth,
    });
    return json(result);
  } catch (error: any) {
    const code = String(error?.code || '').trim().toUpperCase();
    if (code === 'ENOENT' || code === 'ENOTDIR') {
      return json({
        folders: [],
        missing: true,
        path: normalizedPath,
      });
    }
    console.error('[FS Tree] Error:', error);
    return json({ error: error.message, folders: [] }, 500);
  }
}

async function handleFsFolderSummary(url: URL): Promise<Response> {
  const rawPath = (url.searchParams.get('path') || '').trim();
  if (!rawPath) return json({ error: 'Missing path' }, 400);
  const path = normalizeOutputPathInput(rawPath);
  const normalizedPath = normalizeFsListPathKey(path);
  const force = ['1', 'true', 'yes'].includes(String(url.searchParams.get('force') || url.searchParams.get('refresh') || '').trim().toLowerCase());
  let ownsInFlight = false;

  if (normalizedPath === TRASH_ROOT || normalizedPath.startsWith(`${TRASH_ROOT}/`)) {
    return json({
      path: normalizedPath,
      subfolderCount: 0,
      imageCount: 0,
      videoCount: 0,
      totalMediaCount: 0,
    });
  }

  try {
    if (force) {
      invalidateFsFolderSummaryForPaths([normalizedPath]);
    }
    const cached = force ? null : getFsFolderSummaryCache(normalizedPath);
    if (cached) {
      return json(cached);
    }
    const inFlight = force ? null : fsFolderSummaryInFlight.get(normalizedPath);
    if (inFlight) {
      const pendingSummary = await inFlight;
      return json(pendingSummary);
    }

    const resolved = resolvePath(path);
    if (!resolved) return json({ error: 'Invalid path' }, 400);
    const { fullPath } = resolved;
    if (!isPathInsideAllowedRoots(fullPath)) return json({ error: 'Access denied' }, 403);
    if (!existsSync(fullPath)) {
      const empty = {
        path: normalizedPath,
        subfolderCount: 0,
        imageCount: 0,
        videoCount: 0,
        totalMediaCount: 0,
      };
      setFsFolderSummaryCache(normalizedPath, empty);
      return json(empty);
    }
    const stat = statSync(fullPath);
    if (!stat.isDirectory()) return json({ error: 'Path is not a directory' }, 400);

    const pending = (async () => {
      const summary = await fsWorkerService.folderSummary({
        fullPath,
        targetPath: path,
        force,
      }) as {
        path?: string;
        subfolderCount?: number;
        imageCount?: number;
        videoCount?: number;
        totalMediaCount?: number;
      };
      const normalizedSummary = {
        path: normalizeOutputPathInput(String(summary?.path || normalizedPath)),
        subfolderCount: Math.max(0, Number(summary?.subfolderCount || 0) || 0),
        imageCount: Math.max(0, Number(summary?.imageCount || 0) || 0),
        videoCount: Math.max(0, Number(summary?.videoCount || 0) || 0),
        totalMediaCount: Math.max(0, Number(summary?.totalMediaCount || 0) || 0),
      };
      setFsFolderSummaryCache(normalizedPath, normalizedSummary);
      return normalizedSummary;
    })();
    fsFolderSummaryInFlight.set(normalizedPath, pending);
    ownsInFlight = true;
    const resolvedSummary = await pending;
    return json(resolvedSummary);
  } catch (error: any) {
    console.error('[FS Folder Summary] Error:', error);
    return json({ error: error.message }, 500);
  } finally {
    if (ownsInFlight) {
      const active = fsFolderSummaryInFlight.get(normalizedPath);
      if (active) fsFolderSummaryInFlight.delete(normalizedPath);
    }
  }
}

async function handleFsMkdir(req: Request): Promise<Response> {
  try {
    const { path } = await req.json() as { path: string };
    if (!path) return json({ error: 'Path required' }, 400);

    const resolved = resolvePath(path);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    await fsWorkerService.mkdir({ fullPath: resolved.fullPath });
    invalidateFsListCacheForPaths([path, dirname(path)], 'mkdir');
    return json({ success: true, path });
  } catch (error: any) {
    console.error('[Mkdir] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsRename(req: Request): Promise<Response> {
  try {
    const body = await req.json() as {
      oldPath?: string;
      name?: string;
      path?: string;
      newName?: string;
    };
    const oldPath = (body.oldPath || body.path || '').trim();
    const name = (body.name || body.newName || '').trim();
    if (!oldPath || !name) return json({ error: 'Missing parameters' }, 400);

    const resolved = resolvePath(oldPath);
    if (!resolved) return json({ error: 'Invalid path' }, 400);

    if (name.includes('/') || name.includes('\\') || name === '.' || name === '..') {
      return json({ error: 'Invalid folder or file name' }, 400);
    }

    const newPath = resolve(dirname(resolved.fullPath), name);
    if (!isPathInsideAllowedRoots(newPath)) return json({ error: 'Access denied' }, 403);

    if (resolve(resolved.fullPath) !== resolve(newPath)) {
      try {
        await fs.lstat(newPath);
        return json({ error: 'A file or folder with that name already exists' }, 409);
      } catch (error: any) {
        if (error?.code !== 'ENOENT') throw error;
      }
    }

    await fsWorkerService.rename({
      oldFullPath: resolved.fullPath,
      newFullPath: newPath,
    });
    invalidateFsListCacheForPaths([
      oldPath,
      toClientPath(newPath),
      dirname(oldPath),
      toClientPath(dirname(newPath)),
    ], 'rename');
    return json({ success: true, path: oldPath, newPath: toClientPath(newPath) });
  } catch (error: any) {
    console.error('[Rename] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsRenameBatch(req: Request): Promise<Response> {
  try {
    const body = await req.json() as {
      items?: Array<{
        oldPath?: string;
        path?: string;
        name?: string;
        newName?: string;
      }>;
    };
    const rawItems = Array.isArray(body?.items) ? body.items : [];
    if (rawItems.length === 0) return json({ error: 'Missing items' }, 400);

    const results: Array<{
      path: string;
      newPath?: string;
      success: boolean;
      error?: string;
    }> = [];
    const invalidatePaths = new Set<string>();
    const seenOldPaths = new Set<string>();
    const normalizedSourcePaths = new Set<string>();
    const RESERVED_RENAME_SUFFIX_WIDTH = 4;

    const splitRenameTargetName = (name: string) => {
      const extension = extname(name);
      if (!extension) return { base: name, extension: '' };
      return {
        base: name.slice(0, -extension.length),
        extension,
      };
    };

    const buildSequencedRenameTarget = (fullPath: string, index: number) => {
      const leaf = basename(fullPath);
      const parent = dirname(fullPath);
      const { base, extension } = splitRenameTargetName(leaf);
      const suffix = String(index).padStart(RESERVED_RENAME_SUFFIX_WIDTH, '0');
      return resolve(parent, `${base}_${suffix}${extension}`);
    };

    for (const rawItem of rawItems) {
      const oldPath = String(rawItem?.oldPath || rawItem?.path || '').trim();
      const dedupeKey = normalizeOutputPathInput(oldPath);
      if (dedupeKey) normalizedSourcePaths.add(dedupeKey);
    }

    const reservedTargetPaths = new Set<string>();
    const desiredTargetCounts = new Map<string, number>();

    for (const rawItem of rawItems) {
      const oldPath = String(rawItem?.oldPath || rawItem?.path || '').trim();
      const name = String(rawItem?.name || rawItem?.newName || '').trim();
      if (!oldPath || !name) continue;
      if (name.includes('/') || name.includes('\\') || name === '.' || name === '..') continue;
      const resolved = resolvePath(oldPath);
      if (!resolved) continue;
      const desiredPath = resolve(dirname(resolved.fullPath), name);
      if (!isPathInsideAllowedRoots(desiredPath)) continue;
      const normalizedDesired = normalizeOutputPathInput(desiredPath);
      if (!normalizedDesired) continue;
      desiredTargetCounts.set(normalizedDesired, Number(desiredTargetCounts.get(normalizedDesired) || 0) + 1);
    }

    const resolveUniqueRenameTarget = async (resolvedSourcePath: string, desiredPath: string, forceSequence = false) => {
      const normalizedSourcePath = normalizeOutputPathInput(resolvedSourcePath);
      let candidate = desiredPath;
      let sequenceIndex = 1;

      if (forceSequence) {
        candidate = buildSequencedRenameTarget(desiredPath, sequenceIndex);
        sequenceIndex += 1;
      }

      while (true) {
        const normalizedCandidate = normalizeOutputPathInput(candidate);
        if (!normalizedCandidate) {
          throw new Error('Invalid rename target');
        }
        if (normalizedCandidate === normalizedSourcePath) {
          return candidate;
        }
        if (reservedTargetPaths.has(normalizedCandidate)) {
          candidate = buildSequencedRenameTarget(desiredPath, sequenceIndex);
          sequenceIndex += 1;
          continue;
        }
        if (normalizedSourcePaths.has(normalizedCandidate)) {
          candidate = buildSequencedRenameTarget(desiredPath, sequenceIndex);
          sequenceIndex += 1;
          continue;
        }

        try {
          await fs.lstat(candidate);
          candidate = buildSequencedRenameTarget(desiredPath, sequenceIndex);
          sequenceIndex += 1;
          continue;
        } catch (error: any) {
          if (error?.code !== 'ENOENT') {
            throw new Error(String(error?.message || 'Failed to validate rename target'));
          }
        }

        reservedTargetPaths.add(normalizedCandidate);
        return candidate;
      }
    };

    for (const rawItem of rawItems) {
      const oldPath = String(rawItem?.oldPath || rawItem?.path || '').trim();
      const name = String(rawItem?.name || rawItem?.newName || '').trim();
      if (!oldPath || !name) {
        results.push({
          path: oldPath,
          success: false,
          error: 'Missing parameters',
        });
        continue;
      }
      const dedupeKey = normalizeOutputPathInput(oldPath);
      if (!dedupeKey || seenOldPaths.has(dedupeKey)) {
        results.push({
          path: oldPath,
          success: false,
          error: 'Duplicate source path in batch',
        });
        continue;
      }
      seenOldPaths.add(dedupeKey);

      if (name.includes('/') || name.includes('\\') || name === '.' || name === '..') {
        results.push({
          path: oldPath,
          success: false,
          error: 'Invalid folder or file name',
        });
        continue;
      }

      const resolved = resolvePath(oldPath);
      if (!resolved) {
        results.push({
          path: oldPath,
          success: false,
          error: 'Invalid path',
        });
        continue;
      }

      const desiredPath = resolve(dirname(resolved.fullPath), name);
      let newPath = desiredPath;
      if (!isPathInsideAllowedRoots(newPath)) {
        results.push({
          path: oldPath,
          success: false,
          error: 'Access denied',
        });
        continue;
      }

      try {
        const normalizedDesiredPath = normalizeOutputPathInput(desiredPath);
        const forceSequence = normalizedDesiredPath
          ? Number(desiredTargetCounts.get(normalizedDesiredPath) || 0) > 1
          : false;
        newPath = await resolveUniqueRenameTarget(resolved.fullPath, desiredPath, forceSequence);
      } catch (error: any) {
        results.push({
          path: oldPath,
          success: false,
          error: String(error?.message || 'Failed to validate rename target'),
        });
        continue;
      }

      try {
        await fsWorkerService.rename({
          oldFullPath: resolved.fullPath,
          newFullPath: newPath,
        });
        const clientNewPath = toClientPath(newPath);
        results.push({
          path: oldPath,
          newPath: clientNewPath,
          success: true,
        });
        invalidatePaths.add(oldPath);
        invalidatePaths.add(clientNewPath);
        invalidatePaths.add(dirname(oldPath));
        invalidatePaths.add(toClientPath(dirname(newPath)));
      } catch (error: any) {
        results.push({
          path: oldPath,
          success: false,
          error: String(error?.message || 'Rename failed'),
        });
      }
    }

    if (invalidatePaths.size > 0) {
      invalidateFsListCacheForPaths(Array.from(invalidatePaths), 'rename-batch');
    }

    const renamed = results.filter((entry) => entry.success).length;
    return json({
      success: renamed > 0,
      renamed,
      failed: results.length - renamed,
      total: results.length,
      results,
    });
  } catch (error: any) {
    console.error('[Rename Batch] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function copyPathRecursive(sourcePath: string, targetPath: string): Promise<void> {
  const sourceStat = await fs.lstat(sourcePath);

  if (sourceStat.isSymbolicLink()) {
    const linkTarget = await fs.readlink(sourcePath);
    await withMoveRetry('symlink', () => fs.symlink(linkTarget, targetPath));
    return;
  }

  if (sourceStat.isDirectory()) {
    await withMoveRetry('mkdir', () => fs.mkdir(targetPath, { recursive: true }));
    const entries = await fs.readdir(sourcePath, { withFileTypes: true });
    for (const entry of entries) {
      const childSource = join(sourcePath, entry.name);
      const childTarget = join(targetPath, entry.name);
      await copyPathRecursive(childSource, childTarget);
    }
    return;
  }

  await withMoveRetry('copy-file', () => fs.copyFile(sourcePath, targetPath));
}

function isTransientMoveError(err: any): boolean {
  const code = String(err?.code || '');
  return code === 'EBUSY'
    || code === 'EPERM'
    || code === 'ETIMEDOUT'
    || code === 'EIO'
    || code === 'ENOTEMPTY'
    || code === 'EMFILE'
    || code === 'ENFILE'
    || code === 'EBADF'
    || code === 'ESTALE'
    || code === 'EAGAIN';
}

async function withMoveRetry<T>(label: string, fn: () => Promise<T>, attempts = 5): Promise<T> {
  let delayMs = 350;
  for (let attempt = 1; attempt <= attempts; attempt += 1) {
    try {
      return await fn();
    } catch (err: any) {
      if (!isTransientMoveError(err) || attempt >= attempts) {
        throw err;
      }
      console.warn(`[Move] ${label} retry ${attempt}/${attempts} after ${err?.code || 'error'}`);
      await sleep(delayMs);
      delayMs = Math.min(delayMs * 2, 2500);
    }
  }
  throw new Error(`[Move] ${label} failed`);
}

async function movePathWithFallback(sourcePath: string, targetPath: string): Promise<void> {
  try {
    await withMoveRetry('rename', () => fs.rename(sourcePath, targetPath));
    return;
  } catch (err: any) {
    if (err?.code !== 'EXDEV') throw err;
  }

  await copyPathRecursive(sourcePath, targetPath);
  await removePathRecursiveSafe(sourcePath, false);
}

function resolveUniqueMoveTargetPath(baseTargetPath: string, sourceIsDirectory: boolean): string {
  if (!existsSync(baseTargetPath)) return baseTargetPath;

  const targetDir = dirname(baseTargetPath);
  const baseName = basename(baseTargetPath);
  const ext = sourceIsDirectory ? '' : extname(baseName);
  const nameWithoutExt = sourceIsDirectory
    ? baseName
    : baseName.slice(0, -(ext.length || 0));

  let counter = 1;
  let candidate = baseTargetPath;
  while (existsSync(candidate)) {
    const nextName = ext
      ? `${nameWithoutExt} (${counter})${ext}`
      : `${nameWithoutExt} (${counter})`;
    candidate = join(targetDir, nextName);
    counter += 1;
  }
  return candidate;
}

type MoveTransferMode = 'default' | 'cloud';
type FsMoveResult = { path: string; success: boolean; error?: string; newPath?: string };
type FsMoveJobStatus = 'running' | 'completed' | 'failed';
type FsCopyResult = { path: string; success: boolean; error?: string; newPath?: string };
type FsCopyJobStatus = 'running' | 'completed' | 'failed';

interface FsMoveJob {
  id: string;
  status: FsMoveJobStatus;
  transferMode: MoveTransferMode;
  destination: string;
  paths: string[];
  totalUnits: number;
  completedUnits: number;
  currentPath: string;
  startedAt: number;
  finishedAt?: number;
  error?: string;
  results: FsMoveResult[];
}

interface FsCopyJob {
  id: string;
  status: FsCopyJobStatus;
  destination: string;
  paths: string[];
  totalUnits: number;
  completedUnits: number;
  currentPath: string;
  startedAt: number;
  finishedAt?: number;
  error?: string;
  results: FsCopyResult[];
}

type ModelManagerFsTransferMode = 'copy' | 'move';
type ModelManagerFsTransferStatus = 'running' | 'completed' | 'failed';

interface ModelManagerFsTransferJob {
  id: string;
  mode: ModelManagerFsTransferMode;
  status: ModelManagerFsTransferStatus;
  destination: string;
  destinationFullPath: string;
  paths: string[];
  items: ModelManagerTransferItem[];
  sourceFullPaths: string[];
  totalUnits: number;
  completedUnits: number;
  currentPath: string;
  startedAt: number;
  finishedAt?: number;
  error?: string;
  results: Array<FsMoveResult | FsCopyResult>;
}

const fsMoveJobs = new Map<string, FsMoveJob>();
const fsCopyJobs = new Map<string, FsCopyJob>();
const modelManagerFsTransferJobs = new Map<string, ModelManagerFsTransferJob>();
const FS_MOVE_JOB_TTL_MS = 10 * 60 * 1000;
const CLOUD_TRANSFER_DELAY_MS = 180;
const CLOUD_FILE_STABLE_CHECK_INTERVAL_MS = 300;
const CLOUD_FILE_STABLE_MAX_ATTEMPTS = 40;

function assertSafeRemovalPath(targetPath: string): void {
  const resolvedPath = resolve(targetPath);
  if (!resolvedPath || resolvedPath === '/') {
    throw new Error(`Refusing to remove unsafe path: ${targetPath}`);
  }
  if (process.platform === 'win32' && /^[a-zA-Z]:[\\/]?$/.test(resolvedPath)) {
    throw new Error(`Refusing to remove drive root: ${targetPath}`);
  }
}

async function removePathRecursiveSafe(targetPath: string, force = false): Promise<void> {
  try {
    await withMoveRetry('remove-recursive', () => fs.rm(targetPath, { recursive: true, force }));
    return;
  } catch (error: any) {
    const code = String(error?.code || '');
    if (force && code === 'ENOENT') return;
    if (code !== 'EFAULT') throw error;
  }

  assertSafeRemovalPath(targetPath);

  if (process.platform !== 'win32') {
    const args = force ? ['rm', '-rf', targetPath] : ['rm', '-r', targetPath];
    const proc = Bun.spawn(args, { stdout: 'ignore', stderr: 'pipe' });
    const exitCode = await proc.exited;
    if (exitCode === 0) return;
    const stderrText = (await new Response(proc.stderr).text()).trim();
    throw new Error(stderrText || `Failed to remove path: ${targetPath}`);
  }

  await fs.rm(targetPath, { recursive: true, force });
}

async function removePathNonRecursiveSafe(
  targetPath: string,
  kind: 'file' | 'directory' | 'symlink',
  force = false,
): Promise<void> {
  try {
    if (kind === 'directory') {
      await withMoveRetry('remove-dir', () => fs.rmdir(targetPath));
    } else {
      await withMoveRetry('remove-file', () => fs.unlink(targetPath));
    }
    return;
  } catch (error: any) {
    const code = String(error?.code || '');
    if (force && (code === 'ENOENT' || code === 'ENOTDIR')) return;
    if (code !== 'EFAULT') throw error;
  }

  assertSafeRemovalPath(targetPath);

  if (process.platform !== 'win32') {
    const args = kind === 'directory' ? ['rmdir', targetPath] : ['rm', '-f', targetPath];
    const proc = Bun.spawn(args, { stdout: 'ignore', stderr: 'pipe' });
    const exitCode = await proc.exited;
    if (exitCode === 0) return;
    const stderrText = (await new Response(proc.stderr).text()).trim();
    if (force && /No such file|cannot remove|not found/i.test(stderrText)) return;
    throw new Error(stderrText || `Failed to remove path: ${targetPath}`);
  }

  await fs.rm(targetPath, { recursive: false, force });
}

function sanitizeMoveTransferMode(input: unknown): MoveTransferMode {
  return 'default';
}

function createFsMoveJob(paths: string[], destination: string, transferMode: MoveTransferMode): FsMoveJob {
  const id = `fsmove-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
  const job: FsMoveJob = {
    id,
    status: 'running',
    transferMode,
    destination,
    paths: [...paths],
    totalUnits: 0,
    completedUnits: 0,
    currentPath: '',
    startedAt: Date.now(),
    results: [],
  };
  fsMoveJobs.set(id, job);
  return job;
}

function createFsCopyJob(paths: string[], destination: string): FsCopyJob {
  const id = `fscopy-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
  const job: FsCopyJob = {
    id,
    status: 'running',
    destination,
    paths: [...paths],
    totalUnits: 0,
    completedUnits: 0,
    currentPath: '',
    startedAt: Date.now(),
    results: [],
  };
  fsCopyJobs.set(id, job);
  return job;
}

function createModelManagerFsTransferJob(
  mode: ModelManagerFsTransferMode,
  paths: string[],
  destination: string,
  destinationFullPath: string,
  items: ModelManagerTransferItem[],
): ModelManagerFsTransferJob {
  const id = `mmfs-${mode}-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
  const job: ModelManagerFsTransferJob = {
    id,
    mode,
    status: 'running',
    destination,
    destinationFullPath,
    paths: [...paths],
    items: items.map((item) => ({ ...item })),
    sourceFullPaths: items.map((item) => item.sourceFullPath),
    totalUnits: 0,
    completedUnits: 0,
    currentPath: '',
    startedAt: Date.now(),
    results: [],
  };
  modelManagerFsTransferJobs.set(id, job);
  return job;
}

function scheduleFsMoveJobCleanup(jobId: string) {
  setTimeout(() => {
    fsMoveJobs.delete(jobId);
  }, FS_MOVE_JOB_TTL_MS);
}

function scheduleFsCopyJobCleanup(jobId: string) {
  setTimeout(() => {
    fsCopyJobs.delete(jobId);
  }, FS_MOVE_JOB_TTL_MS);
}

function scheduleModelManagerFsTransferJobCleanup(jobId: string) {
  setTimeout(() => {
    modelManagerFsTransferJobs.delete(jobId);
  }, FS_MOVE_JOB_TTL_MS);
}

function pruneFsMoveJobs() {
  const now = Date.now();
  for (const [jobId, job] of fsMoveJobs.entries()) {
    if (job.status === 'running') continue;
    if (!job.finishedAt) continue;
    if (now - job.finishedAt > FS_MOVE_JOB_TTL_MS) {
      fsMoveJobs.delete(jobId);
    }
  }
}

function pruneModelManagerFsTransferJobs() {
  const now = Date.now();
  for (const [jobId, job] of modelManagerFsTransferJobs.entries()) {
    if (job.status === 'running') continue;
    if (!job.finishedAt) continue;
    if (now - job.finishedAt > FS_MOVE_JOB_TTL_MS) {
      modelManagerFsTransferJobs.delete(jobId);
    }
  }
}

function pruneFsCopyJobs() {
  const now = Date.now();
  for (const [jobId, job] of fsCopyJobs.entries()) {
    if (job.status === 'running') continue;
    if (!job.finishedAt) continue;
    if (now - job.finishedAt > FS_MOVE_JOB_TTL_MS) {
      fsCopyJobs.delete(jobId);
    }
  }
}

async function countTransferUnits(sourcePath: string): Promise<number> {
  const sourceStat = await fs.lstat(sourcePath);
  if (sourceStat.isSymbolicLink()) return 1;
  if (sourceStat.isFile()) return 1;
  if (!sourceStat.isDirectory()) return 1;

  const entries = await fs.readdir(sourcePath, { withFileTypes: true });
  if (entries.length === 0) return 1;

  let total = 0;
  for (const entry of entries) {
    const childSource = join(sourcePath, entry.name);
    total += await countTransferUnits(childSource);
  }
  return Math.max(total, 1);
}

async function waitForStableFile(
  sourcePath: string,
  attempts = CLOUD_FILE_STABLE_MAX_ATTEMPTS,
  intervalMs = CLOUD_FILE_STABLE_CHECK_INTERVAL_MS,
): Promise<fs.Stats> {
  let lastSize = -1;
  let lastMtime = -1;

  for (let attempt = 0; attempt < attempts; attempt += 1) {
    const stat = await fs.stat(sourcePath);
    if (!stat.isFile()) return stat;

    if (attempt > 0 && stat.size === lastSize && stat.mtimeMs === lastMtime) {
      return stat;
    }

    lastSize = stat.size;
    lastMtime = stat.mtimeMs;
    await sleep(intervalMs);
  }

  const finalStat = await fs.stat(sourcePath);
  if (finalStat.size === lastSize && finalStat.mtimeMs === lastMtime) {
    return finalStat;
  }

  throw new Error(`File is still being written: ${sourcePath}`);
}

async function copyCloudFileSafely(sourcePath: string, targetPath: string): Promise<void> {
  const sourceStat = await waitForStableFile(sourcePath);
  const tempTargetPath = `${targetPath}.umbra-transfer-${Date.now()}-${Math.random().toString(36).slice(2, 10)}.tmp`;
  let promotedToTarget = false;

  try {
    await withMoveRetry('cloud-copy-file-temp', () => fs.copyFile(sourcePath, tempTargetPath));

    const copiedTempStat = await withMoveRetry('cloud-stat-temp', () => fs.stat(tempTargetPath));
    if (copiedTempStat.size !== sourceStat.size) {
      throw new Error(`Copied file size mismatch: ${basename(sourcePath)} (${copiedTempStat.size}/${sourceStat.size})`);
    }

    await withMoveRetry('cloud-rename-temp', () => fs.rename(tempTargetPath, targetPath));
    promotedToTarget = true;

    const copiedTargetStat = await withMoveRetry('cloud-stat-target', () => fs.stat(targetPath));
    if (copiedTargetStat.size !== sourceStat.size) {
      throw new Error(`Final file size mismatch: ${basename(sourcePath)} (${copiedTargetStat.size}/${sourceStat.size})`);
    }

    const sourceAfterCopy = await withMoveRetry('cloud-stat-source-after-copy', () => fs.stat(sourcePath));
    if (sourceAfterCopy.size !== sourceStat.size || sourceAfterCopy.mtimeMs !== sourceStat.mtimeMs) {
      throw new Error(`Source changed during transfer: ${basename(sourcePath)}`);
    }
  } catch (error) {
    await removePathNonRecursiveSafe(tempTargetPath, 'file', true).catch(() => { });
    if (promotedToTarget) {
      await removePathNonRecursiveSafe(targetPath, 'file', true).catch(() => { });
    }
    throw error;
  }
}

async function movePathCloudSafe(
  sourcePath: string,
  targetPath: string,
  onUnitDone: (movedPath: string) => Promise<void> | void
): Promise<void> {
  const sourceStat = await fs.lstat(sourcePath);

  if (sourceStat.isSymbolicLink()) {
    const linkTarget = await fs.readlink(sourcePath);
    await withMoveRetry('cloud-symlink', () => fs.symlink(linkTarget, targetPath));
    await removePathNonRecursiveSafe(sourcePath, 'symlink', true);
    await onUnitDone(sourcePath);
    await sleep(CLOUD_TRANSFER_DELAY_MS);
    return;
  }

  if (sourceStat.isDirectory()) {
    await withMoveRetry('cloud-mkdir', () => fs.mkdir(targetPath, { recursive: true }));
    const entries = await fs.readdir(sourcePath, { withFileTypes: true });
    if (entries.length === 0) {
      await removePathNonRecursiveSafe(sourcePath, 'directory', false);
      await onUnitDone(sourcePath);
      await sleep(CLOUD_TRANSFER_DELAY_MS);
      return;
    }

    for (const entry of entries) {
      const childSource = join(sourcePath, entry.name);
      const childTarget = join(targetPath, entry.name);
      await movePathCloudSafe(childSource, childTarget, onUnitDone);
    }

    await removePathNonRecursiveSafe(sourcePath, 'directory', false);
    return;
  }

  await copyCloudFileSafely(sourcePath, targetPath);
  await removePathNonRecursiveSafe(sourcePath, 'file', false);
  await onUnitDone(sourcePath);
  await sleep(CLOUD_TRANSFER_DELAY_MS);
}

async function estimateMoveUnits(paths: string[], transferMode: MoveTransferMode): Promise<number> {
  if (transferMode !== 'cloud') return Math.max(paths.length, 1);

  let total = 0;
  for (const sourcePath of paths) {
    const sourceResolved = resolvePath(sourcePath);
    if (!sourceResolved) {
      total += 1;
      continue;
    }
    try {
      total += await countTransferUnits(sourceResolved.fullPath);
    } catch {
      total += 1;
    }
  }

  return Math.max(total, 1);
}

async function executeFsMove(
  paths: string[],
  destination: string,
  transferMode: MoveTransferMode,
  onProgress?: (deltaUnits: number, currentPath: string) => Promise<void> | void
): Promise<{ results: FsMoveResult[]; moved: number; total: number; totalUnits: number }> {
  const destinationResolved = resolvePath(destination);
  if (!destinationResolved) throw new Error('Invalid destination path');

  await fs.mkdir(destinationResolved.fullPath, { recursive: true });

  const pathUnits = new Map<string, number>();
  if (transferMode === 'cloud') {
    for (const sourcePath of paths) {
      const sourceResolved = resolvePath(sourcePath);
      if (!sourceResolved) {
        pathUnits.set(sourcePath, 1);
        continue;
      }
      try {
        pathUnits.set(sourcePath, await countTransferUnits(sourceResolved.fullPath));
      } catch {
        pathUnits.set(sourcePath, 1);
      }
    }
  } else {
    for (const sourcePath of paths) pathUnits.set(sourcePath, 1);
  }

  const totalUnits = Array.from(pathUnits.values()).reduce((sum, units) => sum + Math.max(units, 1), 0) || Math.max(paths.length, 1);
  const markProgress = async (deltaUnits: number, currentPath: string) => {
    if (!onProgress) return;
    await onProgress(Math.max(deltaUnits, 1), currentPath);
  };

  const results: FsMoveResult[] = [];
  for (const sourcePath of paths) {
    const sourceUnits = Math.max(pathUnits.get(sourcePath) || 1, 1);
    try {
      const sourceResolved = resolvePath(sourcePath);
      if (!sourceResolved) {
        results.push({ path: sourcePath, success: false, error: 'Invalid source path' });
        await markProgress(sourceUnits, sourcePath);
        continue;
      }

      const sourceStat = await fs.lstat(sourceResolved.fullPath);
      const filename = basename(sourceResolved.fullPath);
      const sourceParentNormalized = normalizePathForCompare(dirname(sourceResolved.fullPath));
      const destinationNormalized = normalizePathForCompare(destinationResolved.fullPath);
      if (destinationNormalized === sourceParentNormalized) {
        results.push({ path: sourcePath, success: false, error: 'Source and destination are the same folder' });
        await markProgress(sourceUnits, toClientPath(sourceResolved.fullPath));
        continue;
      }

      const rawTargetPath = join(destinationResolved.fullPath, filename);
      const targetPath = resolveUniqueMoveTargetPath(rawTargetPath, sourceStat.isDirectory() && !sourceStat.isSymbolicLink());
      const sourceNormalized = normalizePathForCompare(sourceResolved.fullPath);
      const targetNormalized = normalizePathForCompare(targetPath);
      if (
        targetNormalized === sourceNormalized ||
        targetNormalized.startsWith(`${sourceNormalized}/`)
      ) {
        results.push({ path: sourcePath, success: false, error: 'Cannot move a folder into itself' });
        await markProgress(sourceUnits, toClientPath(sourceResolved.fullPath));
        continue;
      }

      if (transferMode === 'cloud') {
        await movePathCloudSafe(sourceResolved.fullPath, targetPath, async (movedPath) => {
          await markProgress(1, toClientPath(movedPath));
        });
      } else {
        await movePathWithFallback(sourceResolved.fullPath, targetPath);
        await markProgress(sourceUnits, toClientPath(sourceResolved.fullPath));
      }
      results.push({ path: sourcePath, success: true, newPath: toClientPath(targetPath) });
    } catch (error: any) {
      results.push({ path: sourcePath, success: false, error: error.message });
      await markProgress(sourceUnits, sourcePath);
    }
  }

  return {
    results,
    moved: results.filter((r) => r.success).length,
    total: paths.length,
    totalUnits,
  };
}

function normalizeFsTransferResultPath(value: unknown): string {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    return normalizeOutputPathInput(isAbsolute(raw) ? toClientPath(raw) : raw);
  } catch {
    return normalizeOutputPathInput(raw);
  }
}

function syncGalleryDbAfterTransfer(results: Array<Record<string, unknown>>, mode: 'move' | 'copy') {
  const pairs = (results || [])
    .filter((entry) => entry?.success === true)
    .map((entry) => ({
      sourcePath: normalizeFsTransferResultPath(entry.path),
      targetPath: normalizeFsTransferResultPath(entry.newPath),
    }))
    .filter((pair) => pair.sourcePath && pair.targetPath && pair.sourcePath !== pair.targetPath);
  if (pairs.length === 0) return;
  try {
    const changed = mode === 'move'
      ? galleryDb.moveRecordsForPaths(pairs)
      : galleryDb.copyRecordsForPaths(pairs);
    if (changed > 0 && FS_LIST_DEBUG) {
      console.debug(`[GalleryDb] Synced ${changed} ${mode} record${changed === 1 ? '' : 's'}`);
    }
  } catch (error) {
    console.warn(`[GalleryDb] Failed to sync ${mode} metadata:`, error);
  }
}

const GALLERY_MEDIA_SIDECAR_EXTENSIONS = ['.txt', '.json', '.caption', '.yaml', '.yml'];

async function syncGallerySidecarsAfterTransfer(results: Array<Record<string, unknown>>, mode: 'move' | 'copy') {
  const pairs = (results || [])
    .filter((entry) => entry?.success === true)
    .map((entry) => ({
      sourcePath: normalizeFsTransferResultPath(entry.path),
      targetPath: normalizeFsTransferResultPath(entry.newPath),
    }))
    .filter((pair) => pair.sourcePath && pair.targetPath && pair.sourcePath !== pair.targetPath);
  for (const pair of pairs) {
    try {
      const sourceResolved = resolvePath(pair.sourcePath);
      const targetResolved = resolvePath(pair.targetPath);
      if (!sourceResolved || !targetResolved) continue;
      const targetStat = await fs.stat(targetResolved.fullPath).catch(() => null);
      if (!targetStat || !targetStat.isFile()) continue;

      const sourceDir = dirname(sourceResolved.fullPath);
      const targetDir = dirname(targetResolved.fullPath);
      const sourceName = basename(sourceResolved.fullPath);
      const targetName = basename(targetResolved.fullPath);
      const sourceExt = extname(sourceName);
      const sourceBase = sourceExt ? sourceName.slice(0, -sourceExt.length) : sourceName;
      const targetExt = extname(targetName);
      const targetBase = targetExt ? targetName.slice(0, -targetExt.length) : targetName;
      for (const sidecarExt of GALLERY_MEDIA_SIDECAR_EXTENSIONS) {
        for (const variant of [
          { source: join(sourceDir, `${sourceBase}${sidecarExt}`), target: join(targetDir, `${targetBase}${sidecarExt}`) },
          { source: join(sourceDir, `${sourceName}${sidecarExt}`), target: join(targetDir, `${targetName}${sidecarExt}`) },
        ]) {
          const sidecarStat = await fs.stat(variant.source).catch(() => null);
          if (!sidecarStat || !sidecarStat.isFile()) continue;
          await fs.mkdir(dirname(variant.target), { recursive: true });
          if (mode === 'move') {
            await fs.rename(variant.source, variant.target).catch(async () => {
              await fs.copyFile(variant.source, variant.target);
              await fs.rm(variant.source, { force: true });
            });
          } else {
            await fs.copyFile(variant.source, variant.target);
          }
        }
      }
    } catch (error) {
      console.warn(`[Gallery] Failed to ${mode} sidecar for ${pair.sourcePath}:`, error);
    }
  }
}

async function runFsMoveJob(job: FsMoveJob) {
  try {
    const destinationResolved = resolvePath(job.destination);
    if (!destinationResolved) throw new Error('Invalid destination path');
    const items = job.paths.map((sourcePath) => {
      const sourceResolved = resolvePath(sourcePath);
      if (!sourceResolved) {
        return null;
      }
      return {
        sourcePath,
        sourceFullPath: sourceResolved.fullPath,
      };
    });

    const invalidPaths = items.filter((item) => !item).map((_, index) => job.paths[index]);
    for (const invalidPath of invalidPaths) {
      job.results.push({ path: invalidPath, success: false, error: 'Invalid source path' });
    }

    const validItems = items.filter((item): item is NonNullable<typeof item> => !!item);
    if (validItems.length === 0) {
      job.status = 'failed';
      job.error = 'No valid source paths';
      job.finishedAt = Date.now();
      return;
    }

    const execution = await fsWorkerService.move(
      {
        items: validItems,
        destination: job.destination,
        destinationFullPath: destinationResolved.fullPath,
        transferMode: job.transferMode,
      },
      {
        onProgress: (progress) => {
          const totalUnits = Number(progress?.totalUnits || 0);
          const completedUnits = Number(progress?.completedUnits || 0);
          if (totalUnits > 0) job.totalUnits = totalUnits;
          job.completedUnits = Math.min(job.totalUnits || completedUnits, completedUnits);
          job.currentPath = String(progress?.currentPath || '');
        },
      },
    );

    if (job.totalUnits <= 0) job.totalUnits = Number((execution as any).totalUnits || 0);
    job.completedUnits = Math.min(job.totalUnits, Math.max(job.completedUnits, job.totalUnits));
    job.results = [...job.results, ...((execution as any).results || [])];
    await syncGallerySidecarsAfterTransfer(job.results as Array<Record<string, unknown>>, 'move');
    syncGalleryDbAfterTransfer(job.results as Array<Record<string, unknown>>, 'move');
    job.status = 'completed';
    job.finishedAt = Date.now();
    const movedTargets = ((execution as any).results || [])
      .filter((entry) => entry.success)
      .map((entry) => String(entry.newPath || '').trim())
      .filter((entry) => entry.length > 0);
    invalidateFsListCacheForPaths([
      job.destination,
      ...job.paths,
      ...movedTargets,
    ], 'move');
  } catch (error: any) {
    job.status = 'failed';
    job.error = error?.message || 'Move job failed';
    job.finishedAt = Date.now();
  } finally {
    scheduleFsMoveJobCleanup(job.id);
  }
}

