async function handleFsMove(req: Request): Promise<Response> {
  try {
    const {
      paths,
      destination,
      transferMode,
      trackProgress,
    } = await req.json() as {
      paths: string[];
      destination: string;
      transferMode?: MoveTransferMode;
      trackProgress?: boolean;
    };
    if (!paths || !Array.isArray(paths) || !destination) return json({ error: 'Missing parameters' }, 400);

    const mode = sanitizeMoveTransferMode(transferMode);
    if (trackProgress) {
      const job = createFsMoveJob(paths, destination, mode);
      invalidateFsListCacheForPaths([destination, ...paths], 'move');
      void runFsMoveJob(job);
      return json({ success: true, jobId: job.id });
    }

    const destinationResolved = resolvePath(destination);
    if (!destinationResolved) return json({ error: 'Invalid destination path' }, 400);

    const resolvedItems = paths.map((sourcePath) => {
      const sourceResolved = resolvePath(sourcePath);
      return sourceResolved
        ? { sourcePath, sourceFullPath: sourceResolved.fullPath }
        : null;
    });
    const invalidPaths = resolvedItems
      .map((item, index) => item ? null : paths[index])
      .filter((value): value is string => !!value);
    const validItems = resolvedItems.filter((item): item is NonNullable<typeof item> => !!item);
    if (validItems.length === 0) {
      return json({ error: 'No valid source paths' }, 400);
    }

    const execution = await fsWorkerService.move({
      items: validItems,
      destination,
      destinationFullPath: destinationResolved.fullPath,
      transferMode: mode,
    });
    const results = [
      ...invalidPaths.map((sourcePath) => ({ path: sourcePath, success: false, error: 'Invalid source path' })),
      ...(((execution as any).results || []) as any[]),
    ];
    const movedTargets = results
      .filter((entry) => entry.success)
      .map((entry) => String(entry.newPath || '').trim())
      .filter((entry) => entry.length > 0);
    await syncGallerySidecarsAfterTransfer(results as Array<Record<string, unknown>>, 'move');
    syncGalleryDbAfterTransfer(results as Array<Record<string, unknown>>, 'move');
    invalidateFsListCacheForPaths([destination, ...paths, ...movedTargets], 'move');
    return json({
      success: true,
      results,
      moved: results.filter((entry) => entry.success).length,
      total: paths.length,
    });
  } catch (error: any) {
    console.error('[Move] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsCopy(req: Request): Promise<Response> {
  try {
    const { paths, destination, trackProgress } = await req.json() as { paths: string[]; destination: string; trackProgress?: boolean };
    if (!paths || !Array.isArray(paths) || !destination) return json({ error: 'Missing parameters' }, 400);

    if (trackProgress) {
      const job = createFsCopyJob(paths, destination);
      invalidateFsListCacheForPaths([destination, ...paths], 'copy');
      void runFsCopyJob(job);
      return json({ success: true, jobId: job.id });
    }

    const destinationResolved = resolvePath(destination);
    if (!destinationResolved) return json({ error: 'Invalid destination path' }, 400);

    const resolvedItems = paths.map((sourcePath) => {
      const sourceResolved = resolvePath(sourcePath);
      return sourceResolved
        ? { sourcePath, sourceFullPath: sourceResolved.fullPath }
        : null;
    });
    const invalidPaths = resolvedItems
      .map((item, index) => item ? null : paths[index])
      .filter((value): value is string => !!value);
    const validItems = resolvedItems.filter((item): item is NonNullable<typeof item> => !!item);
    if (validItems.length === 0) {
      return json({ error: 'No valid source paths' }, 400);
    }

    const execution = await fsWorkerService.copy({
      items: validItems,
      destination,
      destinationFullPath: destinationResolved.fullPath,
    });
    const results = [
      ...invalidPaths.map((sourcePath) => ({ path: sourcePath, success: false, error: 'Invalid source path' })),
      ...(((execution as any).results || []) as any[]),
    ];

    const copiedTargets = results
      .filter((entry) => entry.success)
      .map((entry) => String((entry as any).newPath || '').trim())
      .filter((entry) => entry.length > 0)
      .map((entry) => toClientPath(entry));
    await syncGallerySidecarsAfterTransfer(results as Array<Record<string, unknown>>, 'copy');
    syncGalleryDbAfterTransfer(results as Array<Record<string, unknown>>, 'copy');
    invalidateFsListCacheForPaths([destination, ...paths, ...copiedTargets], 'copy');
    return json({ success: true, results, copied: results.filter(r => r.success).length, total: paths.length });
  } catch (error: any) {
    console.error('[Copy] Error:', error);
    return json({ error: error.message }, 500);
  }
}

async function handleFsUpload(req: Request): Promise<Response> {
  try {
    const formData = await req.formData();
    const files = formData.getAll('files') as File[];
    const rawDestination = (formData.get('destination') as string || '').trim();
    let destination = (!rawDestination || rawDestination === 'Library')
      ? getDefaultOutputRootPath()
      : normalizeOutputPathInput(rawDestination);
    const checkDuplicates = formData.get('checkDuplicates') === 'true';

    if (!files || files.length === 0) return json({ error: 'No files provided' }, 400);

    const resolved = resolvePath(destination);
    if (!resolved) return json({ error: 'Invalid target path' }, 400);
    if (!isPathInsideAllowedRoots(resolved.fullPath)) {
      return json({ error: 'Upload destination is outside allowed roots' }, 403);
    }

    await fs.mkdir(resolved.fullPath, { recursive: true });

    // Check for duplicates if requested
    if (checkDuplicates) {
      const duplicates = [];
      for (const file of files) {
        const filePath = join(resolved.fullPath, file.name);
        try {
          await fs.access(filePath);
          // File exists - check if it's actually the same file using hash
          const existingBuffer = await Bun.file(filePath).arrayBuffer();
          const newBuffer = await file.arrayBuffer();

          const existingHash = Bun.hash(existingBuffer);
          const newHash = Bun.hash(newBuffer);

          duplicates.push({
            name: file.name,
            exists: true,
            identical: existingHash === newHash,
            size: file.size,
            existingSize: existingBuffer.byteLength
          });
        } catch {
          // File doesn't exist, not a duplicate
        }
      }

      if (duplicates.length > 0) {
        return json({ duplicates, needsConfirmation: true }, 409);
      }

      // No duplicates found - return success WITHOUT saving files
      // The client will then proceed with the actual upload
      return json({ noDuplicates: true, checked: files.length }, 200);
    }

    // Process uploads
    const results = await Promise.all(files.map(async (file) => {
      try {
        let filePath = join(resolved.fullPath, file.name);
        const strategy = formData.get(`strategy_${file.name}`) as string || 'keepBoth';

        // Handle duplicate strategy
        if (strategy === 'skip') {
          return { name: file.name, success: true, skipped: true };
        } else if (strategy === 'keepBoth') {
          // Auto-rename if file exists
          let counter = 1;
          const ext = file.name.substring(file.name.lastIndexOf('.'));
          const baseName = file.name.substring(0, file.name.lastIndexOf('.'));

          while (await fs.access(filePath).then(() => true).catch(() => false)) {
            filePath = join(resolved.fullPath, `${baseName} (${counter})${ext}`);
            counter++;
          }
        }
        // strategy === 'replace' will just overwrite

        const buffer = await file.arrayBuffer();
        await fsWorkerService.write({
          fullPath: filePath,
          content: Buffer.from(buffer).toString('base64'),
          encoding: 'base64',
        });
        return { name: file.name, success: true, path: filePath };
      } catch (error: any) {
        return { name: file.name, success: false, error: error.message };
      }
    }));

    const uploadedTargets = results
      .filter((entry) => entry.success && !entry.skipped)
      .map((entry) => String((entry as any).path || '').trim())
      .filter((entry) => entry.length > 0)
      .map((entry) => toClientPath(entry));
    invalidateFsListCacheForPaths([destination, ...uploadedTargets], 'upload');
    return json({ success: true, results, uploaded: results.filter(r => r.success && !r.skipped).length, total: files.length });
  } catch (error: any) {
    console.error('[Upload] Error:', error);
    return json({ error: error.message }, 500);
  }
}

// ============================================
// IMAGE EDITOR
// ============================================

async function handleEditorSave(req: Request): Promise<Response> {
  try {
    const { path: relativePath } = await req.json() as { path: string };

    if (!relativePath) {
      return json({ error: 'No path provided' }, 400);
    }

    const resolved = resolvePath(relativePath);
    if (!resolved) {
      return json({ error: 'Invalid path' }, 400);
    }

    const { fullPath } = resolved;

    if (!existsSync(fullPath)) {
      return json({ error: 'File not found' }, 404);
    }

    // Check if it's an image
    const ext = extname(fullPath).toLowerCase();
    if (!['.jpg', '.jpeg', '.png', '.webp', '.bmp', '.tiff'].includes(ext)) {
      return json({ error: 'Only image files can be edited' }, 400);
    }

    // Simplified server mode: server-side editor output is disabled.
    return json({ error: 'Image editing disabled in simplified mode' }, 501);
  } catch (error: any) {
    console.error('[Editor Save] Error:', error);
    return json({ error: error.message }, 500);
  }
}

// ============================================
// MAIN SERVER
// ============================================

// Initialize Editor Database after the server binds so SQLite contention cannot
// make startup look dead.

/** Embed AI generation metadata from source image into exported buffer */
async function embedMetadataIntoBuffer(buffer: Buffer, sourcePath: string, filename: string): Promise<Buffer> {
  try {
    // Resolve source path to read metadata
    let fullSourcePath = sourcePath;
    if (!sourcePath.startsWith('/')) {
      fullSourcePath = join(USER_DIR, sourcePath);
      if (!existsSync(fullSourcePath)) fullSourcePath = join(ROOT_DIR, sourcePath);
    }
    if (!existsSync(fullSourcePath)) return buffer;

    const metadata = await MetadataParser.parse(fullSourcePath);
    if (!metadata.positive_prompt && !metadata.model && !metadata.seed) return buffer;

    // Build metadata text
    const metaText = [
      metadata.positive_prompt ? `Prompt: ${metadata.positive_prompt}` : '',
      metadata.negative_prompt ? `Negative: ${metadata.negative_prompt}` : '',
      metadata.model ? `Model: ${metadata.model}` : '',
      metadata.seed != null ? `Seed: ${metadata.seed}` : '',
      metadata.steps ? `Steps: ${metadata.steps}` : '',
      metadata.sampler ? `Sampler: ${metadata.sampler}` : '',
      metadata.cfg != null ? `CFG: ${metadata.cfg}` : '',
    ].filter(Boolean).join(', ');

    if (!metaText) return buffer;

    const sharp = (await import('sharp')).default;
    const ext = filename.split('.').pop()?.toLowerCase();

    if (ext === 'png') {
      // For PNG: embed as tEXt chunks
      return await sharp(buffer)
        .withMetadata({})
        .png()
        .toBuffer()
        .then(async (buf: Buffer) => {
          // Sharp doesn't directly support PNG tEXt chunks, so we manually inject them
          return injectPngTextChunk(buf, 'parameters', metaText);
        });
    } else {
      // For JPEG/WebP: embed in EXIF UserComment via sharp
      return await sharp(buffer)
        .withMetadata({
          exif: {
            IFD0: { ImageDescription: metaText },
          },
        })
        .toBuffer();
    }
  } catch (err) {
    console.error('[Export] Metadata embedding failed:', err);
    return buffer;
  }
}

/** Inject a tEXt chunk into a PNG buffer */
function injectPngTextChunk(pngBuffer: Buffer, keyword: string, text: string): Buffer {
  // PNG structure: 8-byte signature, then chunks
  // We insert the tEXt chunk right after the IHDR chunk (first chunk after signature)
  // Read IHDR chunk (starts at offset 8)
  const ihdrLen = pngBuffer.readUInt32BE(8);
  const ihdrEnd = 8 + 4 + 4 + ihdrLen + 4; // length(4) + type(4) + data + crc(4)

  // Build tEXt chunk: keyword + null byte + text
  const keyBuf = Buffer.from(keyword, 'latin1');
  const textBuf = Buffer.from(text, 'latin1');
  const chunkData = Buffer.concat([keyBuf, Buffer.from([0]), textBuf]);

  const chunkLen = Buffer.alloc(4);
  chunkLen.writeUInt32BE(chunkData.length, 0);
  const chunkType = Buffer.from('tEXt', 'ascii');

  // CRC covers type + data
  const crcInput = Buffer.concat([chunkType, chunkData]);
  const crc = crc32(crcInput);
  const crcBuf = Buffer.alloc(4);
  crcBuf.writeUInt32BE(crc >>> 0, 0);

  const textChunk = Buffer.concat([chunkLen, chunkType, chunkData, crcBuf]);

  // Insert after IHDR
  const before = pngBuffer.subarray(0, ihdrEnd);
  const after = pngBuffer.subarray(ihdrEnd);

  return Buffer.concat([before, textChunk, after]);
}

/** Inject an uncompressed UTF-8 iTXt chunk into a PNG buffer. */
function injectPngInternationalTextChunk(pngBuffer: Buffer, keyword: string, text: string): Buffer {
  const ihdrLen = pngBuffer.readUInt32BE(8);
  const ihdrEnd = 8 + 4 + 4 + ihdrLen + 4;
  const keyBuf = Buffer.from(String(keyword || '').replace(/\0/g, '').slice(0, 79), 'latin1');
  const textBuf = Buffer.from(String(text || ''), 'utf8');
  const chunkData = Buffer.concat([
    keyBuf,
    Buffer.from([0, 0, 0, 0, 0]),
    textBuf,
  ]);
  const chunkLen = Buffer.alloc(4);
  chunkLen.writeUInt32BE(chunkData.length, 0);
  const chunkType = Buffer.from('iTXt', 'ascii');
  const crcBuf = Buffer.alloc(4);
  crcBuf.writeUInt32BE(crc32(Buffer.concat([chunkType, chunkData])) >>> 0, 0);
  return Buffer.concat([
    pngBuffer.subarray(0, ihdrEnd),
    chunkLen,
    chunkType,
    chunkData,
    crcBuf,
    pngBuffer.subarray(ihdrEnd),
  ]);
}

/** CRC32 for PNG chunk validation */
function crc32(buf: Buffer): number {
  let crc = 0xFFFFFFFF;
  for (let i = 0; i < buf.length; i++) {
    crc ^= buf[i];
    for (let j = 0; j < 8; j++) {
      crc = (crc >>> 1) ^ (crc & 1 ? 0xEDB88320 : 0);
    }
  }
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

const server = Bun.serve<any>({
  port: PORT,
  hostname: HOST,
  idleTimeout: 120,

  async fetch(req, server) {
    const requestStartedAt = Date.now();
    let responseStatus = 0;
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;
    const rawOrigin = req.headers.get('origin');
    const resolvedOrigin = resolveCorsOrigin(rawOrigin, req);

    if (rawOrigin && !resolvedOrigin) {
      return new Response('CORS origin denied', {
        status: 403,
        headers: createCorsHeadersForOrigin(DEFAULT_CORS_ORIGIN),
      });
    }

    try {
      const response = await corsOriginContext.run(resolvedOrigin || DEFAULT_CORS_ORIGIN, async () => {
      try {
        // CORS preflight
        if (method === 'OPTIONS') return new Response(null, { headers: getCorsHeaders() });

        if (!IS_UMBRA_DEV_MODE && isRemoteRequest(req, url, server) && !isTailscaleRequest(req, url, server)) {
          return json({ ok: false, remoteDisabled: true, error: 'Umbra Remote is available through Tailscale only in published builds.' }, 403);
        }

        if (!isPublishedRemoteRequestAllowed(req, url, server) && (path === '/api/remote' || path.startsWith('/api/remote/'))) {
          return json({ ok: false, remoteDisabled: true, error: 'Umbra Remote is available through Tailscale only in published builds.' }, 404);
        }

        const loadedRemoteAuthConfig = loadRemoteAuthConfig();
        let effectiveRemoteAuthConfig = loadedRemoteAuthConfig ? pruneRemoteSessions(loadedRemoteAuthConfig) : null;
        if (loadedRemoteAuthConfig && effectiveRemoteAuthConfig) {
          if ((loadedRemoteAuthConfig.sessions || []).length !== (effectiveRemoteAuthConfig.sessions || []).length) {
            saveRemoteAuthConfig(effectiveRemoteAuthConfig);
          }
        }

        if (method === 'GET' && path === '/api/remote/auth/status') {
          return json(createRemoteAuthStatus(req, url, effectiveRemoteAuthConfig, server));
        }

        if (method === 'GET' && path === '/api/remote/metrics/ping') {
          const serverReceivedAt = Date.now();
          return json({
            ok: true,
            clientId: String(url.searchParams.get('clientId') || '').slice(0, 120),
            clientSentAt: Number(url.searchParams.get('sentAt') || 0) || 0,
            serverReceivedAt,
            serverSentAt: Date.now(),
          });
        }

        if (method === 'POST' && path === '/api/remote/auth/setup') {
          if (isRemoteRequest(req, url, server)) {
            return json({ error: 'Remote auth setup is only available from the host browser.' }, 403);
          }
          const body = await req.json().catch(() => ({} as any));
          const username = String(body?.username || '').trim();
          const password = String(body?.password || '');
          if (username.length < 3) return json({ error: 'Username must be at least 3 characters.' }, 400);
          if (password.length < 8) return json({ error: 'Password must be at least 8 characters.' }, 400);
          const now = Date.now();
          const salt = randomBytes(16).toString('hex');
          const nextConfig: RemoteAuthConfig = {
            version: 1,
            username,
            salt,
            passwordHash: hashRemotePassword(password, salt, REMOTE_AUTH_PBKDF2_ITERATIONS),
            iterations: REMOTE_AUTH_PBKDF2_ITERATIONS,
            createdAt: effectiveRemoteAuthConfig?.createdAt || now,
            updatedAt: now,
            sessions: [],
            devices: [],
            pairTokens: [],
          };
          const handshake = createRemoteHandshake(nextConfig, req, body?.deviceLabel);
          const session = createRemoteSession(handshake.config, { deviceId: handshake.deviceId });
          saveRemoteAuthConfig(session.config);
          console.log(`[UmbraRemote] Remote login configured for user "${username}"`);
          return json({
            ok: true,
            configured: true,
            username,
            device: { trusted: true },
            storagePath: join('User', 'Config', 'UmbraRemote', 'auth.json'),
          }, {
            headers: {
              'Set-Cookie': [
                createRemoteDeviceCookie(handshake.deviceToken, req),
                createRemoteSessionCookie(session.token, req),
              ],
            },
          });
        }

        if (method === 'POST' && path === '/api/remote/auth/pair-token') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const config = effectiveRemoteAuthConfig;
          if (!config) return json({ error: 'Remote auth is not configured on the host yet.' }, 409);
          const body = await req.json().catch(() => ({} as any));
          const pair = createRemotePairToken(config, body?.deviceLabel || 'Remote device');
          saveRemoteAuthConfig(pair.config);
          console.log(`[UmbraRemote] Pair link created for ${String(body?.deviceLabel || 'Remote device').slice(0, 80)}`);
          return json({
            ok: true,
            token: pair.token,
            expiresAt: pair.expiresAt,
            path: `/api/remote/auth/pair?token=${encodeURIComponent(pair.token)}`,
          });
        }

        if (method === 'GET' && path === '/api/remote/auth/pair') {
          const config = effectiveRemoteAuthConfig;
          if (!config) return json({ error: 'Remote auth is not configured on the host yet.' }, 409);
          const token = String(url.searchParams.get('token') || '').trim();
          if (!token) return json({ error: 'Pair token is missing.' }, 400);
          const consumed = consumeRemotePairToken(config, token);
          if (!consumed.ok) {
            saveRemoteAuthConfig(consumed.config);
            console.warn(`[UmbraRemote] Pair link rejected secure=${isSecureRemoteRequest(req)} host="${req.headers.get('host') || ''}" from=${getRemoteRequestAddress(req)}`);
            return json({ error: 'Pair link expired or already used.' }, 401);
          }
          const handshake = createRemoteHandshake(consumed.config, req, consumed.label || 'Paired remote device');
          const session = createRemoteSession(handshake.config, { deviceId: handshake.deviceId });
          saveRemoteAuthConfig(session.config);
          console.log(`[UmbraRemote] Pair link accepted for "${config.username}" (${getRemoteDeviceLabel(req, consumed.label)})`);
          return createRemoteRedirectWithCookies('/?remotePaired=1', [
            createRemoteDeviceCookie(handshake.deviceToken, req),
            createRemoteSessionCookie(session.token, req),
          ]);
        }

        if (method === 'POST' && path === '/api/remote/auth/login') {
          const config = effectiveRemoteAuthConfig;
          if (!config) return json({ error: 'Remote auth is not configured on the host yet.' }, 409);
          const body = await req.json().catch(() => ({} as any));
          const username = String(body?.username || '').trim();
          const password = String(body?.password || '');
          const rateLimit = getRemoteLoginRateLimit(req, username);
          if (rateLimit.limited) {
            console.warn(`[UmbraRemote] Login rate limited for ${getRemoteRequestAddress(req)}`);
            return json({ error: `Too many failed login attempts. Try again in ${rateLimit.retryAfterSeconds}s.`, retryAfterSeconds: rateLimit.retryAfterSeconds }, {
              status: 429,
              headers: { 'Retry-After': String(rateLimit.retryAfterSeconds) },
            });
          }
          const candidateHash = hashRemotePassword(password, config.salt, config.iterations || REMOTE_AUTH_PBKDF2_ITERATIONS);
          const usernameMatches = username === config.username;
          const passwordMatches = safeEqualHex(candidateHash, config.passwordHash);
          if (!usernameMatches || !passwordMatches) {
            recordRemoteLoginFailure(req, username);
            const reason = !usernameMatches ? 'username_mismatch' : 'password_mismatch';
            console.warn(
              `[UmbraRemote] Failed login reason=${reason} typedUser="${username || 'empty'}" configuredUser="${config.username}" ` +
              `passwordLength=${password.length} secure=${isSecureRemoteRequest(req)} host="${req.headers.get('host') || ''}" from=${getRemoteRequestAddress(req)}`
            );
            return json({
              error: reason === 'username_mismatch'
                ? `Configured remote account is "${config.username}".`
                : 'Password did not match the configured remote account.',
              reason,
              username: config.username,
              passwordLength: password.length,
            }, 401);
          }
          clearRemoteLoginFailures(req, username);
          const handshake = createRemoteHandshake(config, req, body?.deviceLabel);
          const session = createRemoteSession(handshake.config, { deviceId: handshake.deviceId });
          saveRemoteAuthConfig(session.config);
          console.log(`[UmbraRemote] Trusted device handshake for "${username}" (${getRemoteDeviceLabel(req, body?.deviceLabel)})`);
          return json({
            ok: true,
            authenticated: true,
            username: config.username,
            device: { trusted: true },
          }, {
            headers: {
              'Set-Cookie': [
                createRemoteDeviceCookie(handshake.deviceToken, req),
                createRemoteSessionCookie(session.token, req),
              ],
            },
          });
        }

        if (method === 'POST' && path === '/api/remote/auth/logout') {
          const config = effectiveRemoteAuthConfig;
          const body = await req.json().catch(() => ({} as any));
          const forgetDevice = body?.forgetDevice !== false;
          const sessionToken = getRemoteSessionToken(req);
          const sessionHash = sessionToken ? hashRemoteSessionToken(sessionToken) : '';
          const deviceToken = getRemoteDeviceToken(req);
          const deviceId = deviceToken ? hashRemoteSessionToken(deviceToken) : '';
          if (config) {
            saveRemoteAuthConfig({
              ...config,
              sessions: (config.sessions || []).filter((session) => {
                if (sessionHash && safeEqualHex(session.hash, sessionHash)) return false;
                if (forgetDevice && deviceId && session.deviceId && safeEqualHex(session.deviceId, deviceId)) return false;
                return true;
              }),
              devices: forgetDevice && deviceId
                ? (config.devices || []).filter((device) => !safeEqualHex(device.id, deviceId))
                : (config.devices || []),
              updatedAt: Date.now(),
            });
          }
          console.log(`[UmbraRemote] Remote session logged out${forgetDevice ? ' and device forgotten' : ''}`);
          return json({
            ok: true,
            deviceForgotten: forgetDevice,
          }, {
            headers: {
              'Cache-Control': 'no-store',
              'Set-Cookie': [
                clearRemoteSessionCookie(req),
                ...(forgetDevice ? [clearRemoteDeviceCookie(req)] : []),
              ],
            },
          });
        }

        if (method === 'POST' && path === '/api/remote/settings') {
          if (isRemoteRequest(req, url, server)) {
            return json({ error: 'Remote connection settings are only editable from the host browser.' }, 403);
          }
          const body = await req.json().catch(() => ({} as any));
          const now = Date.now();
          const publishedTailscaleOnly = !IS_UMBRA_DEV_MODE;
          const settings: RemoteConnectionSettings = {
            version: 1,
            bindHost: normalizeBindHost(body?.bindHost, HOST),
            port: clampPort(body?.port || PORT, PORT),
            preferredMode: publishedTailscaleOnly ? 'private-vpn' : (isRemoteConnectionMode(body?.preferredMode) ? body.preferredMode : 'auto'),
            manualLanUrl: publishedTailscaleOnly ? '' : normalizeRemoteUrl(body?.manualLanUrl),
            tailscaleHttpsUrl: normalizeHttpsUrl(body?.tailscaleHttpsUrl),
            reverseProxyUrl: publishedTailscaleOnly ? '' : normalizeHttpsUrl(body?.reverseProxyUrl),
            publicBaseUrl: normalizeHttpsUrl(publishedTailscaleOnly ? body?.tailscaleHttpsUrl : (body?.publicBaseUrl || body?.reverseProxyUrl || body?.tailscaleHttpsUrl)),
            allowedOrigins: publishedTailscaleOnly ? [] : normalizeAllowedOrigins(body?.allowedOrigins),
            preferHttps: body?.preferHttps !== false,
            hideHttpWhenHttpsAvailable: body?.hideHttpWhenHttpsAvailable !== false,
            trustProxyHeaders: publishedTailscaleOnly ? false : Boolean(body?.trustProxyHeaders),
            requireRemoteAuth: body?.requireRemoteAuth !== false,
            sessionTtlDays: normalizeSessionTtlDays(body?.sessionTtlDays),
            updatedAt: now,
          };
          saveRemoteConnectionSettings(settings);
          console.log(`[UmbraRemote] Connection mode set to ${settings.preferredMode}`);
          return json({
            ok: true,
            settings,
            storagePath: join('User', 'Config', 'UmbraRemote', 'settings.json'),
          });
        }

        if (method === 'GET' && path === '/api/remote/devices') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const config = effectiveRemoteAuthConfig;
          return json({
            ok: true,
            devices: (config?.devices || [])
              .map(sanitizeRemoteDevice)
              .sort((left, right) => (right.lastAuthenticatedAt || right.lastSeenAt || 0) - (left.lastAuthenticatedAt || left.lastSeenAt || 0)),
          });
        }

        if (method === 'POST' && path === '/api/remote/devices/rename') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const config = effectiveRemoteAuthConfig;
          if (!config) return json({ error: 'Remote auth is not configured.' }, 409);
          const body = await req.json().catch(() => ({} as any));
          const id = String(body?.id || '').trim();
          const label = String(body?.label || '').trim().slice(0, 80);
          if (!id || !label) return json({ error: 'Device id and label are required.' }, 400);
          const devices = (config.devices || []).map((device) => safeEqualHex(device.id, id) ? { ...device, label, lastSeenAt: Date.now() } : device);
          saveRemoteAuthConfig({ ...config, devices, updatedAt: Date.now() });
          console.log(`[UmbraRemote] Trusted device renamed to "${label}"`);
          return json({ ok: true, devices: devices.map(sanitizeRemoteDevice) });
        }

        if (method === 'POST' && path === '/api/remote/devices/revoke') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const config = effectiveRemoteAuthConfig;
          if (!config) return json({ error: 'Remote auth is not configured.' }, 409);
          const body = await req.json().catch(() => ({} as any));
          const id = String(body?.id || '').trim();
          if (!id) return json({ error: 'Device id is required.' }, 400);
          const devices = (config.devices || []).filter((device) => !safeEqualHex(device.id, id));
          const sessions = (config.sessions || []).filter((session) => !session.deviceId || !safeEqualHex(session.deviceId, id));
          saveRemoteAuthConfig({ ...config, devices, sessions, updatedAt: Date.now() });
          console.log('[UmbraRemote] Trusted device revoked');
          return json({ ok: true, devices: devices.map(sanitizeRemoteDevice) });
        }

        if (method === 'POST' && path === '/api/remote/test-url') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const body = await req.json().catch(() => ({} as any));
          return json(await testRemoteUrl(body?.url));
        }

        if (method === 'POST' && path === '/api/remote/tailscale/serve') {
          const guard = withRemoteAdminGuard(req, url, server);
          if (guard) return guard;
          const tailscaleAccess = await getTailscaleAccessInfo(PORT);
          const command = tailscaleAccess.serveCommand || `tailscale serve --bg ${buildTailscaleServeOrigin(HOST, PORT)}`;
          if (!tailscaleAccess.installed) {
            return json({
              ok: false,
              code: 'TAILSCALE_NOT_AVAILABLE',
              command,
              message: 'Tailscale is not available on this host.',
              details: 'Install Tailscale, sign in, and then try again.',
            }, 409);
          }
          if (!tailscaleAccess.connected) {
            return json({
              ok: false,
              code: 'TAILSCALE_OFFLINE',
              command,
              message: 'Tailscale is not connected on this host.',
              details: tailscaleAccess.health[0] || 'Turn on Tailscale, wait for it to connect, and then try again.',
            }, 409);
          }
          try {
            const { stdout, stderr } = await execAsync(command, { timeout: 15000, windowsHide: true });
            console.log(`[UmbraRemote] Tailscale Serve configured for port ${PORT}`);
            return json({ ok: true, command, stdout: stdout.trim(), stderr: stderr.trim() });
          } catch (error: any) {
            const stdout = String(error?.stdout || '').trim();
            const stderr = String(error?.stderr || '').trim();
            const message = String(error?.message || 'Tailscale Serve failed');
            const combined = `${stdout}\n${stderr}\n${message}`;
            const enableUrl = parseTailscaleServeEnableUrl(combined);
            if (enableUrl || /Serve is not enabled/i.test(combined)) {
              return json({
                ok: false,
                code: 'TAILSCALE_SERVE_NOT_ENABLED',
                command,
                enableUrl,
                message: 'Tailscale Serve is not enabled for this tailnet yet.',
                details: 'Open the Tailscale admin link, enable Serve for this host, then run Enable again.',
                stdout,
                stderr,
              }, 409);
            }
            return json({
              ok: false,
              command,
              code: 'TAILSCALE_SERVE_FAILED',
              message: 'Tailscale Serve could not be configured.',
              error: message,
              stdout,
              stderr,
            }, 500);
          }
        }

        if (shouldBlockRemoteRequest(req, url, effectiveRemoteAuthConfig, server)) {
          return json({ error: 'Umbra Remote login required', remoteAuthRequired: true }, 401);
        }

        if (method === 'POST' && path === '/api/remote/metrics') {
          const payload: any = await req.json().catch(() => ({} as any));
          const stats = recordRemoteTelemetryBatch(req, payload);
          return json({ ok: true, clientId: stats.clientId, accepted: Array.isArray(payload?.events) ? payload.events.length : 0 });
        }

        if (method === 'GET' && path === '/api/remote/metrics') {
          return json(createRemoteTelemetrySnapshot());
        }

        if (path === '/comfy' && method === 'GET') {
          return new Response(null, {
            status: 302,
            headers: {
              ...getCorsHeaders(),
              Location: '/comfy/',
            },
          });
        }

        if ((path === '/ws' || path === '/comfy/ws') && method === 'GET') {
          if (!COMFY_PROXY_WEBSOCKET_ENABLED) {
            return json({
              error: 'ComfyUI websocket proxy disabled',
              message: 'Umbra avoids tunneling ComfyUI browser websockets through Bun in published builds. Use the direct Tailscale ComfyUI URL for full live ComfyUI browser status.',
            }, 426);
          }
          const upgraded = server.upgrade(req, {
            data: {
              endpoint: '/comfy/ws',
              targetUrl: getComfyProxyWsUrl(url.search),
            },
          });
          if (upgraded) return undefined;
          return new Response('ComfyUI websocket upgrade failed', { status: 400 });
        }

        if (path.startsWith('/comfy/') || isComfyRootProxyPath(path)) {
          const targetPath = path.startsWith('/comfy/')
            ? `/${path.slice('/comfy/'.length)}`
            : path;
          const staticResponse = method === 'GET' || method === 'HEAD'
            ? await serveComfyStaticFile(targetPath, method)
            : null;
          if (staticResponse) return staticResponse;
          return await proxyComfyHttp(req, url, targetPath === '/' ? '/' : targetPath);
        }

        if (method === 'GET' && (path === '/health' || path === '/api/healthz' || path === '/api/healthz/live')) {
          return json({
            ok: true,
            live: true,
            runtimeRoot: ROOT_DIR,
            now: Date.now(),
            uptimeMs: Math.max(0, Math.floor(process.uptime() * 1000)),
          });
        }

      if (path === '/api/local-server-proxy/health' && method === 'GET') {
          return await localServerHealth(url.searchParams.get('url'));
      }
      if (path === '/api/local-server-apps/open-folder' && method === 'POST') {
          return await handleLocalServerOpenFolder(req, server);
      }

        if (path.startsWith(LOCAL_SERVER_PROXY_PREFIX) && method === 'GET' && req.headers.get('upgrade')?.toLowerCase() === 'websocket') {
          const targetUrl = getLocalServerProxyWsUrl(url);
          if (!targetUrl) return new Response('Invalid local server websocket target', { status: 400 });
          const upgraded = server.upgrade(req, {
            data: {
              endpoint: '/local-server-proxy/ws',
              targetUrl,
            },
          });
          if (upgraded) return undefined;
          return new Response('Local server websocket upgrade failed', { status: 400 });
        }

        if (path.startsWith(LOCAL_SERVER_PROXY_PREFIX)) {
          return await proxyLocalServerHttp(req, url);
        }

        if (path === '/api/healthz/ready' && method === 'GET') {
          const controlPlane = getCachedBackendControlPlaneStatus();
          const stats = getCachedSystemStats();
          return json({
            ok: true,
            live: true,
            ready: true,
            runtimeRoot: ROOT_DIR,
            now: Date.now(),
            uptimeMs: Math.max(0, Math.floor(process.uptime() * 1000)),
            controlPlane: {
              sampledAt: controlPlane.sampledAt,
              sampleAgeMs: controlPlane.sampleAgeMs,
              stale: controlPlane.stale,
              refreshing: controlPlane.refreshing,
              backends: controlPlane.backends,
            },
            systemStats: {
              timestamp: stats.timestamp,
              sampleAgeMs: stats.sampleAgeMs,
              stale: stats.stale,
              refreshing: stats.refreshing,
            },
          });
        }

        if (path === '/api/remote/status' && method === 'GET') {
          const remoteSettings = loadRemoteConnectionSettings();
          const publishedTailscaleOnly = !IS_UMBRA_DEV_MODE;
          const remoteStatusRequest = isRemoteRequest(req, url, server);
          if (remoteStatusRequest && remoteSettings.requireRemoteAuth !== false) {
            if (!effectiveRemoteAuthConfig || !isRemoteRequestAuthenticated(req, effectiveRemoteAuthConfig)) {
              return json({ error: 'Umbra Remote login required', remoteAuthRequired: true }, 401);
            }
          }
          const tailscaleAccess = await getTailscaleAccessInfo(PORT);
          const requestVisibleOrigin = getRequestVisibleOrigin(req, url);
          const currentTailscaleOrigin = isTailscaleHostname(requestVisibleOrigin) ? requestVisibleOrigin : '';
          const currentTailscaleHttpsUrl = currentTailscaleOrigin && isHttpsRemoteUrl(currentTailscaleOrigin) ? currentTailscaleOrigin : '';
          const currentTailscaleHttpUrl = currentTailscaleOrigin && !isHttpsRemoteUrl(currentTailscaleOrigin) ? currentTailscaleOrigin : '';
          const tailscaleConnected = tailscaleAccess.connected || Boolean(currentTailscaleOrigin);
          const allowDirectNetworkRemote = IS_LAN_BIND;
          const detectedTailscaleUrls = tailscaleConnected ? Array.from(new Set([
            ...tailscaleAccess.httpUrls,
            currentTailscaleHttpUrl,
          ].filter(Boolean) as string[])) : [];
          const tailscaleUrls = allowDirectNetworkRemote
            ? detectedTailscaleUrls
            : currentTailscaleHttpUrl
              ? [currentTailscaleHttpUrl]
              : [];
          const tailscaleHttpsUrls = Array.from(new Set([
            tailscaleConnected ? currentTailscaleHttpsUrl : '',
            tailscaleAccess.serveEnabled ? remoteSettings.tailscaleHttpsUrl : '',
            ...tailscaleAccess.httpsUrls,
          ].filter(Boolean) as string[]));
          const allowTailscaleRemote = tailscaleConnected
            && (allowDirectNetworkRemote || tailscaleAccess.serveEnabled || Boolean(currentTailscaleOrigin));
          const suggestedTailscaleHttpsUrls = tailscaleConnected ? Array.from(new Set([
            remoteSettings.tailscaleHttpsUrl,
            ...tailscaleAccess.suggestedHttpsUrls,
          ].filter(Boolean) as string[])) : [];
          const lanUrls = IS_LAN_BIND && !publishedTailscaleOnly
            ? getPrivateLanUrls(PORT).filter((remoteUrl) => !/^http:\/\/100\.(6[4-9]|[7-9]\d|1[01]\d|12[0-7])\./.test(remoteUrl))
            : [];
          const manualLanUrls = IS_LAN_BIND && !publishedTailscaleOnly && remoteSettings.manualLanUrl ? [remoteSettings.manualLanUrl] : [];
          const publicBaseIsInactiveTailscale = isTailscaleDnsHttpsUrl(remoteSettings.publicBaseUrl || '', tailscaleAccess.knownDnsName) && !tailscaleAccess.serveEnabled;
          const reverseProxyUrls = Array.from(new Set([
            !publishedTailscaleOnly && !publicBaseIsInactiveTailscale ? remoteSettings.publicBaseUrl : '',
            !publishedTailscaleOnly ? remoteSettings.reverseProxyUrl : '',
          ].filter(Boolean) as string[]));
          const activeReverseProxyUrl = reverseProxyUrls[0] || '';
          const httpsAvailable = [...tailscaleHttpsUrls, ...reverseProxyUrls].some(isHttpsRemoteUrl);
          const hideHttpUrls = remoteSettings.preferHttps
            && remoteSettings.hideHttpWhenHttpsAvailable !== false
            && httpsAvailable;
          const advertisedTailscaleUrls = hideHttpUrls ? [] : tailscaleUrls;
          const advertisedLanUrls = hideHttpUrls ? [] : lanUrls;
          const advertisedManualLanUrls = hideHttpUrls
            ? manualLanUrls.filter(isHttpsRemoteUrl)
            : manualLanUrls;
          const hiddenHttpUrls = hideHttpUrls
            ? Array.from(new Set([
              ...tailscaleUrls,
              ...lanUrls,
              ...manualLanUrls,
            ].filter((remoteUrl) => remoteUrl && !isHttpsRemoteUrl(remoteUrl))))
            : [];
          const urls = Array.from(new Set([
            ...(allowTailscaleRemote ? tailscaleHttpsUrls : []),
            ...(allowDirectNetworkRemote ? advertisedTailscaleUrls : []),
            ...(IS_LAN_BIND ? advertisedLanUrls : []),
            ...advertisedManualLanUrls,
            ...reverseProxyUrls,
          ]));
          const selectedUrl = pickRemoteConnectionUrl({
            ...remoteSettings,
            preferredMode: publishedTailscaleOnly ? 'private-vpn' : remoteSettings.preferredMode,
          }, {
            tailscaleUrls: allowDirectNetworkRemote ? advertisedTailscaleUrls : [],
            tailscaleHttpsUrls: allowTailscaleRemote ? tailscaleHttpsUrls : [],
            lanUrls: Array.from(new Set([...advertisedManualLanUrls, ...advertisedLanUrls])),
            reverseProxyUrl: activeReverseProxyUrl,
          });
          const remoteReady = tailscaleConnected && allowTailscaleRemote && urls.length > 0;
          const directRuntimeOverride = process.env.UMBRA_WEB_LAUNCHER !== '1';
          const runtimeOverrides = {
            bindHost: directRuntimeOverride && Boolean(process.env.UMBRA_HOST || process.env.HOST),
            port: directRuntimeOverride && Boolean(process.env.UMBRA_PORT),
          };
          const pendingRestart = shouldRemoteSettingsRequireRestart({
            savedBindHost: remoteSettings.bindHost,
            savedPort: remoteSettings.port,
            activeBindHost: HOST,
            activePort: PORT,
            runtimeOverrides,
            suppressRestart: publishedTailscaleOnly && Boolean(currentTailscaleOrigin),
          });
          return json({
            ok: true,
            bindHost: HOST,
            port: PORT,
            localUrl: buildListenerOrigin(HOST, PORT),
            remoteEnabled: allowTailscaleRemote,
            tailscaleDetected: tailscaleAccess.installed,
            tailscaleInstalled: tailscaleAccess.installed,
            tailscaleConnected,
            tailscaleOnline: tailscaleConnected && tailscaleAccess.online,
            tailscaleBackendState: tailscaleAccess.backendState,
            tailscaleHealth: tailscaleAccess.health,
            remoteReady,
            selectedUrl,
            urls,
            lanUrls,
            tailscaleUrls,
            tailscaleHttpsUrls,
            httpUrlsHidden: hideHttpUrls,
            hiddenHttpUrls,
            suggestedTailscaleHttpsUrls,
            tailscaleDnsName: tailscaleAccess.dnsName,
            tailscaleKnownDnsName: tailscaleAccess.knownDnsName,
            tailscaleServeConfigured: tailscaleAccess.serveConfigured,
            tailscaleServeTargets: tailscaleAccess.serveTargets,
            tailscaleServeExpectedTarget: tailscaleAccess.serveExpectedTarget,
            tailscaleServeTargetMatches: tailscaleAccess.serveTargetMatches,
            tailscaleServeEnabled: tailscaleAccess.serveEnabled,
            tailscaleServeCommand: tailscaleAccess.serveCommand,
            reverseProxyUrls,
            settings: {
              ...remoteSettings,
              storagePath: join('User', 'Config', 'UmbraRemote', 'settings.json'),
              active: {
                bindHost: HOST,
                port: PORT,
                runtimeOverrides,
              },
              pendingRestart,
            },
            accessModes: publishedTailscaleOnly ? [
              {
                id: 'private-vpn',
                label: 'Private VPN',
                available: allowTailscaleRemote && (tailscaleUrls.length > 0 || tailscaleHttpsUrls.length > 0),
                recommended: true,
                provider: 'tailscale',
              },
            ] : [
              {
                id: 'lan',
                label: 'LAN',
                available: allowDirectNetworkRemote && (lanUrls.length > 0 || manualLanUrls.length > 0),
                recommended: false,
              },
              {
                id: 'private-vpn',
                label: 'Private VPN',
                available: allowTailscaleRemote && (tailscaleUrls.length > 0 || tailscaleHttpsUrls.length > 0),
                recommended: true,
                provider: 'tailscale',
              },
              {
                id: 'reverse-proxy',
                label: 'Reverse Proxy / Tunnel',
                available: Boolean(remoteSettings.reverseProxyUrl),
                recommended: false,
              },
            ],
            cors: {
              loopback: true,
              privateLan: IS_LAN_BIND && !publishedTailscaleOnly,
              tailscale: allowTailscaleRemote,
            },
            security: {
              transport: hideHttpUrls ? 'https-front-door' : 'standard-http-websocket',
              recommended: publishedTailscaleOnly
                ? 'Published builds expose Umbra Remote through Tailscale only. Use Tailscale Serve for HTTPS inside your tailnet.'
                : 'Use HTTPS for browser-facing remote access. Tailscale Serve or an authenticated HTTPS reverse proxy can terminate TLS and forward to Umbra locally. Do not expose Umbra HTTP directly to the public internet.',
              appAuthEnabled: Boolean(effectiveRemoteAuthConfig),
            },
            auth: createRemoteAuthStatus(req, url, effectiveRemoteAuthConfig, server),
          });
        }

        // WebSocket upgrade
        if (path.startsWith('/ws/')) {
          const upgraded = server.upgrade(req, {
            data: {
              endpoint: path,
              remoteClient: isRemoteRequest(req, url, server),
            },
          });
          if (upgraded) return undefined;
          return new Response('WebSocket upgrade failed', { status: 400 });
        }

        // ============================================
        // FILE SYSTEM API
        // ============================================
      if (path === '/api/gallery-bridge/fs/list-progressive' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/list-progressive',
          () => handleFsListProgressive(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/tree' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/tree',
          () => handleFsTree(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/folder-summary' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/folder-summary',
          () => handleFsFolderSummary(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/search' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/search',
          () => handleFsSearch(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/search-suggestions' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/search-suggestions',
          () => handleFsSearchSuggestions(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/empty-folders/preview' && method === 'POST') {
        return proxyGalleryBridgeFsPost(req, '/api/fs/empty-folders/preview');
      }
      if (path === '/api/gallery-bridge/fs/empty-folders/delete' && method === 'POST') {
        return proxyGalleryBridgeFsPost(req, '/api/fs/empty-folders/delete');
      }
      if (path === '/api/gallery-bridge/fs/tags/add' && method === 'POST') return handleFsTagsAdd(req);
      if (path === '/api/gallery-bridge/fs/tags/set' && method === 'POST') return handleFsTagsSet(req);
      if (path === '/api/gallery-bridge/fs/tags/summary' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/tags/summary',
          () => handleFsTagsSummary(url),
        );
      }
      if (path === '/api/gallery-bridge/fs/thumbnail' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/thumbnail',
          () => handleFsThumbnail(req, url, server),
          server,
        );
      }
      if (path === '/api/gallery-bridge/fs/image' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/image',
          () => handleFsImage(req, url, server),
          server,
        );
      }
      if (path === '/api/gallery-bridge/fs/metadata' && method === 'GET') {
        return proxyGalleryBridgeFsGet(
          req,
          url,
          '/api/fs/metadata',
          () => handleFsMetadata(url),
        );
      }

      if (path === '/api/fs/list' && method === 'GET') return handleFsList(url);
      if (path === '/api/fs/list-progressive' && method === 'GET') return handleFsListProgressive(url);
      if (path === '/api/fs/thumbnail' && method === 'GET') return handleFsThumbnail(req, url, server);
      if (path === '/api/fs/preview' && method === 'GET') return handleFsPreview(url);
      if (path === '/api/fs/image' && method === 'GET') return handleFsImage(req, url, server);
      if (path === '/api/fs/download-zip' && method === 'POST') return handleFsDownloadZip(req);
      if (path === '/api/fs/download-jpeg-zip' && method === 'POST') return handleFsDownloadJpegZip(req);
      if (path === '/api/fs/metadata' && method === 'GET') return handleFsMetadata(url);
      if (path === '/api/fs/read' && method === 'GET') return handleFsRead(url);
      if (path === '/api/fs/tree' && method === 'GET') return handleFsTree(url);
      if (path === '/api/fs/folder-summary' && method === 'GET') return handleFsFolderSummary(url);
      if (path === '/api/fs/search' && method === 'GET') return handleFsSearch(url);
      if (path === '/api/fs/search-suggestions' && method === 'GET') return handleFsSearchSuggestions(url);
      if (path === '/api/fs/reveal' && method === 'POST') return handleFsReveal(req, server);
      if (path === '/api/fs/mkdir' && method === 'POST') return handleFsMkdir(req);
      if (path === '/api/fs/rename' && method === 'POST') return handleFsRename(req);
      if (path === '/api/fs/rename/batch' && method === 'POST') return handleFsRenameBatch(req);
      if (path === '/api/fs/move' && method === 'POST') return handleFsMove(req);
      if (path === '/api/fs/move/status' && method === 'GET') return handleFsMoveStatus(url);
      if (path === '/api/fs/copy' && method === 'POST') return handleFsCopy(req);
      if (path === '/api/fs/copy/status' && method === 'GET') return handleFsCopyStatus(url);
      if (path === '/api/fs/upload' && method === 'POST') return handleFsUpload(req);
      if (path === '/api/fs/write' && method === 'POST') return handleFsWrite(req);
      if (path === '/api/fs/reorder' && method === 'POST') return handleFsReorder(req);
      if (path === '/api/fs/tags/add' && method === 'POST') return handleFsTagsAdd(req);
      if (path === '/api/fs/tags/set' && method === 'POST') return handleFsTagsSet(req);
      if (path === '/api/fs/tags/summary' && method === 'GET') return handleFsTagsSummary(url);

      // ============================================
      // MODEL MANAGER API
      // ============================================
      if (path === '/api/model-manager/roots' && method === 'GET') return handleModelManagerRoots();
      if (path === '/api/model-manager/tree' && method === 'GET') return handleModelManagerTree(url);
      if (path === '/api/model-manager/list' && method === 'GET') return handleModelManagerList(url);
      if (path === '/api/model-manager/reconcile' && method === 'POST') return handleModelManagerReconcile(req);
      if (path === '/api/model-manager/inspect' && method === 'POST') return handleModelManagerInspect(req);
      if (path === '/api/model-manager/fs/move' && method === 'POST') return handleModelManagerFsMove(req);
      if (path === '/api/model-manager/fs/move/status' && method === 'GET') return handleModelManagerFsTransferStatus(url);
      if (path === '/api/model-manager/fs/copy' && method === 'POST') return handleModelManagerFsCopy(req);
      if (path === '/api/model-manager/fs/copy/status' && method === 'GET') return handleModelManagerFsTransferStatus(url);
      if (path === '/api/model-manager/fs/rename' && method === 'POST') return handleModelManagerFsRename(req);
      if (path === '/api/model-manager/fs/delete' && method === 'POST') return handleModelManagerFsDelete(req);
      if (path === '/api/model-manager/fs/mkdir' && method === 'POST') return handleModelManagerFsMkdir(req);
      if (path === '/api/model-manager/fs/reveal' && method === 'POST') return handleModelManagerFsReveal(req, server);
      if (path === '/api/model-manager/civitai/auth' && method === 'GET') return handleModelManagerCivitaiAuthGet();
      if (path === '/api/model-manager/civitai/auth' && method === 'POST') return handleModelManagerCivitaiAuthPost(req);
      if (path === '/api/model-manager/civitai/auth' && method === 'DELETE') return handleModelManagerCivitaiAuthDelete();
      if (path === '/api/model-manager/civitai/search' && method === 'GET') return handleModelManagerCivitaiSearch(url);
      if (path === '/api/model-manager/civitai/model' && method === 'GET') return handleModelManagerCivitaiModel(url);
      if (path === '/api/model-manager/civitai/version' && method === 'GET') return handleModelManagerCivitaiVersion(url);
      if (path === '/api/model-manager/civitai/download' && method === 'POST') return handleModelManagerCivitaiDownload(req);
      if (path === '/api/model-manager/media' && method === 'GET') return handleModelManagerMedia(url);
      if (path === '/api/model-manager/opened-models' && method === 'GET') return handleModelManagerOpenedModelsGet();
      if (path === '/api/model-manager/opened-models' && method === 'POST') return handleModelManagerOpenedModelsPost(req);
      if (path === '/api/model-manager/opened-models/refresh' && method === 'POST') return handleModelManagerOpenedModelsRefresh(req);
      if (path === '/api/model-manager/opened-models/delete' && method === 'POST') return handleModelManagerOpenedModelsDelete(req);
      const modelDownloadMatch = path.match(/^\/api\/model-manager\/downloads\/([^/]+)$/);
      if (modelDownloadMatch && method === 'GET') {
        const jobId = decodeURIComponent(modelDownloadMatch[1]);
        return handleModelManagerDownloadStatus(jobId);
      }
      const modelDownloadCancelMatch = path.match(/^\/api\/model-manager\/downloads\/([^/]+)\/cancel$/);
      if (modelDownloadCancelMatch && method === 'POST') {
        const jobId = decodeURIComponent(modelDownloadCancelMatch[1]);
        return handleModelManagerDownloadCancel(jobId);
      }

      // ============================================
      // EXPORT API
      // ============================================
      if (path === '/api/export/save' && method === 'POST') {
        try {
          const formData = await req.formData();
          const file = formData.get('file') as File;
          const outputFolder = formData.get('outputFolder') as string;
          const filename = formData.get('filename') as string;
          const shouldEmbedMeta = formData.get('embedMetadata') === 'true';
          const sourcePath = formData.get('sourcePath') as string | null;

          if (!file || !outputFolder || !filename) {
            return json({ error: 'Missing file, outputFolder, or filename' }, 400);
          }

          // Sanitize filename
          const safeFilename = filename.replace(/[<>:"/\\|?*]/g, '_');

          // Resolve output folder — support both absolute and relative paths
          let targetDir: string;
          if (outputFolder.startsWith('/') || /^[a-zA-Z]:\\/.test(outputFolder)) {
            // Absolute path — use directly
            targetDir = outputFolder;
          } else {
            // Relative path — resolve within ROOT_DIR
            const normalizedFolder = outputFolder.replace(/\.\./g, '');
            const resolved = resolvePath(normalizedFolder);
            if (!resolved) return json({ error: 'Invalid output path' }, 400);
            targetDir = resolved.fullPath;
          }

          // Create directory if needed
          await fs.mkdir(targetDir, { recursive: true });

          const rawBuffer = Buffer.from(await file.arrayBuffer());
          const outputBuffer = shouldEmbedMeta && sourcePath
            ? await embedMetadataIntoBuffer(rawBuffer, sourcePath, safeFilename)
            : rawBuffer;

          // Write file
          const filePath = join(targetDir, safeFilename);
          await Bun.write(filePath, outputBuffer);

          return json({ success: true, path: filePath });
        } catch (err: any) {
          console.error('[Export] Save failed:', err);
          return json({ error: err.message }, 500);
        }
      }

      // Embed metadata and return file (for single-image download export)
      if (path === '/api/export/embed-metadata' && method === 'POST') {
        try {
          const formData = await req.formData();
          const file = formData.get('file') as File;
          const sourcePath = formData.get('sourcePath') as string;

          if (!file || !sourcePath) {
            return json({ error: 'Missing file or sourcePath' }, 400);
          }

          const rawBuffer = Buffer.from(await file.arrayBuffer());
          const outputBuffer = await embedMetadataIntoBuffer(rawBuffer, sourcePath, file.name);

          return new Response(new Uint8Array(outputBuffer), {
            headers: {
              'Content-Type': file.type || 'application/octet-stream',
              'Content-Length': String(outputBuffer.length),
            },
          });
        } catch (err: any) {
          console.error('[Export] Embed metadata failed:', err);
          return json({ error: err.message }, 500);
        }
      }

      // POST /api/export/browse-folder — Open native folder picker dialog
      if (path === '/api/export/browse-folder' && method === 'POST') {
        if (!isHostRequest(req, url, server)) {
          return json({ error: 'Native folder selection is only available from the host PC.' }, 403);
        }
        return handleNativeFolderBrowse(req, 'Select Export Folder');
      }

      // POST /api/export/batch-zip — Create a ZIP from multiple exported blobs
      if (path === '/api/export/batch-zip' && method === 'POST') {
        try {
          const formData = await req.formData();
          const files = formData.getAll('files') as File[];

          if (!files || files.length === 0) {
            return json({ error: 'No files provided' }, 400);
          }

          // Use a temporary directory approach
          const tmpDir = join(ROOT_DIR, 'User', '.tmp_export_' + Date.now());
          await fs.mkdir(tmpDir, { recursive: true });

          // Write all files to temp dir
          for (const file of files) {
            const buffer = Buffer.from(await file.arrayBuffer());
            await Bun.write(join(tmpDir, file.name), buffer);
          }

          // Use tar/zip command available on system
          const zipPath = tmpDir + '.zip';
          const proc = Bun.spawn(['zip', '-j', zipPath, ...files.map(f => join(tmpDir, f.name))], {
            cwd: tmpDir,
          });
          await proc.exited;

          // Read the zip file
          const zipFile = Bun.file(zipPath);
          const zipBuffer = await zipFile.arrayBuffer();

          // Cleanup
          await fs.rm(tmpDir, { recursive: true, force: true });
          await fs.rm(zipPath, { force: true });

          return new Response(zipBuffer, {
            headers: {
              'Content-Type': 'application/zip',
              'Content-Disposition': 'attachment; filename="export.zip"',
              'Content-Length': String(zipBuffer.byteLength),
            },
          });
        } catch (err: any) {
          console.error('[Export] Batch ZIP failed:', err);
          return json({ error: err.message }, 500);
        }
      }

      // ============================================
      // EDITOR CONFIG API
      // ============================================

      // GET /api/editor/config/:key
      if (path.startsWith('/api/editor/config/') && method === 'GET') {
        try {
          const key = path.replace('/api/editor/config/', '');
          if (!key) return json({ error: 'Missing key' }, 400);
          const value = EditorDb.getEditorConfig(key);
          if (value === null) return json({ error: 'Not found' }, 404);
          return json({ value: JSON.parse(value) });
        } catch (err: any) {
          return json({ error: err.message }, 500);
        }
      }

      // POST /api/editor/config — upsert { key, value }
      if (path === '/api/editor/config' && method === 'POST') {
        try {
          const body = await req.json();
          const { key, value } = body;
          if (!key) return json({ error: 'Missing key' }, 400);
          EditorDb.setEditorConfig(key, JSON.stringify(value));
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, 500);
        }
      }

      // ============================================
      // EDITOR DATABASE API (Custom Order)
      // ============================================
      if (path === '/api/editor/order/get' && method === 'GET') {
        const folderPath = url.searchParams.get('folder');
        if (!folderPath) {
          return json({ error: 'Missing folder parameter' }, { status: 400 });
        }
        try {
          const order = EditorDb.getCustomOrder(folderPath);
          return json({ folder: folderPath, order });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path === '/api/editor/order/set' && method === 'POST') {
        try {
          const body = await req.json() as { folder: string; order: string[] };
          if (!body.folder || !Array.isArray(body.order)) {
            return json({ error: 'Invalid request body' }, { status: 400 });
          }
          EditorDb.setCustomOrder(body.folder, body.order);
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path === '/api/editor/order/clear' && method === 'POST') {
        try {
          const body = await req.json() as { folder: string };
          if (!body.folder) {
            return json({ error: 'Missing folder parameter' }, { status: 400 });
          }
          EditorDb.clearCustomOrder(body.folder);
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // Thumbnail cache stats and precache progress
      if (path === '/api/cache/stats' && method === 'GET') {
        const stats = thumbnailService.getCacheStats();
        const progress = thumbnailService.getPrecacheProgress();
        return new Response(JSON.stringify({ ...stats, precache: progress }), {
          headers: { ...getCorsHeaders(), 'Content-Type': 'application/json' }
        });
      }

      // ============================================
      // IMAGE EDITOR API
      // ============================================
      if (path === '/api/editor/save' && method === 'POST') return handleEditorSave(req);

      // --- Sidecar editor adjustments (DB-backed; migrates legacy .umbra files) ---
      if (path === '/api/editor/sidecar/read' && method === 'POST') {
        try {
          const body = await req.json() as { path: string };
          if (!body.path) return json({ error: 'Missing path' }, { status: 400 });

          const dbSidecar = EditorDb.getEditorAdjustment(body.path);
          if (dbSidecar) {
            return json({ sidecar: JSON.parse(dbSidecar) });
          }

          // Legacy fallback: migrate existing .umbra file into DB on first read.
          const legacySidecarPath = join(ROOT_DIR, body.path + '.umbra');
          if (existsSync(legacySidecarPath)) {
            const legacyContent = await Bun.file(legacySidecarPath).text();
            const parsed = JSON.parse(legacyContent);
            EditorDb.setEditorAdjustment(body.path, JSON.stringify(parsed));
            await fs.unlink(legacySidecarPath).catch(() => { });
            return json({ sidecar: parsed });
          }

          return json({ sidecar: null });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path === '/api/editor/sidecar/write' && method === 'POST') {
        try {
          const body = await req.json() as { path: string; sidecar: any };
          if (!body.path || body.sidecar == null) return json({ error: 'Missing path or sidecar' }, { status: 400 });
          EditorDb.setEditorAdjustment(body.path, JSON.stringify(body.sidecar));

          // Cleanup legacy file if it still exists.
          const legacySidecarPath = join(ROOT_DIR, body.path + '.umbra');
          if (existsSync(legacySidecarPath)) {
            await fs.unlink(legacySidecarPath).catch(() => { });
          }

          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path === '/api/editor/sidecar/delete' && method === 'POST') {
        try {
          const body = await req.json() as { path: string };
          if (!body.path) return json({ error: 'Missing path' }, { status: 400 });

          EditorDb.deleteEditorAdjustment(body.path);

          // Cleanup legacy file if present.
          const legacySidecarPath = join(ROOT_DIR, body.path + '.umbra');
          if (existsSync(legacySidecarPath)) {
            await fs.unlink(legacySidecarPath).catch(() => { });
          }

          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // --- Presets ---
      if (path === '/api/editor/presets' && method === 'GET') {
        try {
          const presets = EditorDb.listPresets();
          return json({ presets: presets.map(p => ({ ...p, adjustments: JSON.parse(p.adjustments) })) });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path === '/api/editor/presets' && method === 'POST') {
        try {
          const body = await req.json() as { name: string; adjustments: any; category?: string };
          if (!body.name || !body.adjustments) return json({ error: 'Missing name or adjustments' }, { status: 400 });
          const result = EditorDb.upsertPreset(body.name, JSON.stringify(body.adjustments), body.category);
          return json({ id: result.id, created: result.created, success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path.startsWith('/api/editor/presets/') && method === 'PUT') {
        try {
          const id = parseInt(path.split('/').pop() || '0');
          if (!id) return json({ error: 'Invalid preset ID' }, { status: 400 });
          const body = await req.json() as { name: string; adjustments: any; category?: string };
          EditorDb.updatePreset(id, body.name, JSON.stringify(body.adjustments), body.category);
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      if (path.startsWith('/api/editor/presets/') && method === 'DELETE') {
        try {
          const id = parseInt(path.split('/').pop() || '0');
          if (!id) return json({ error: 'Invalid preset ID' }, { status: 400 });
          EditorDb.deletePreset(id);
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // ============================================
      // IMAGE META API (compatibility for tags)
      // ============================================

      // GET /api/editor/meta?path=... — compatibility read (tags + empty meta)
      if (path === '/api/editor/meta' && method === 'GET') {
        try {
          const imagePath = url.searchParams.get('path');
          if (!imagePath) return json({ error: 'Missing path' }, { status: 400 });
          const tags = EditorDb.getImageTags(imagePath);
          return json({ meta: { path: imagePath, has_edits: 0 }, tags });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // POST /api/editor/meta — deprecated compatibility no-op
      if (path === '/api/editor/meta' && method === 'POST') {
        try {
          const body = await req.json();
          const { path: imagePath } = body;
          if (!imagePath) return json({ error: 'Missing path' }, { status: 400 });
          return json({ success: true, deprecated: true, ignored: ['rating', 'colorLabel', 'hasEdits'] });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // POST /api/editor/meta/batch — deprecated compatibility handler
      if (path === '/api/editor/meta/batch' && method === 'POST') {
        try {
          const body = await req.json();
          const { paths, updates } = body;

          // Batch read: return compatibility metas plus tags for requested paths
          if (paths && Array.isArray(paths)) {
            const normalizedPaths = paths
              .map((imagePath: string) => String(imagePath || '').trim())
              .filter(Boolean);
            const tagsByPath = EditorDb.getImageTagsBatch(normalizedPaths);
            const metas = normalizedPaths.map((imagePath: string) => ({
              path: imagePath,
              has_edits: 0,
              tags: tagsByPath[imagePath] || [],
            }));
            return json({ metas, tagsByPath });
          }

          // Legacy batch write: accepted but ignored
          if (updates && Array.isArray(updates)) {
            return json({ success: true, deprecated: true, ignored: updates.length });
          }

          return json({ error: 'Provide paths (for GET) or updates (for SET)' }, { status: 400 });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // ============================================
      // TAGS API
      // ============================================

      // GET /api/editor/tags — list all tags
      if (path === '/api/editor/tags' && method === 'GET') {
        try {
          const tags = EditorDb.listTags();
          return json({ tags });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // POST /api/editor/tags — create a tag
      if (path === '/api/editor/tags' && method === 'POST') {
        try {
          const body = await req.json();
          const { name, color } = body;
          if (!name) return json({ error: 'Missing tag name' }, { status: 400 });
          const id = EditorDb.createTag(name, color || '');
          return json({ id });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // DELETE /api/editor/tags/:id — delete a tag
      if (path.startsWith('/api/editor/tags/') && method === 'DELETE') {
        try {
          const id = parseInt(path.split('/').pop() || '0');
          if (!id) return json({ error: 'Invalid tag ID' }, { status: 400 });
          EditorDb.deleteTag(id);
          return json({ success: true });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // POST /api/editor/image-tags — set tags for an image
      if (path === '/api/editor/image-tags' && method === 'POST') {
        try {
          const body = await req.json();
          const { imagePath, tagIds, addTagId, removeTagId } = body;
          if (!imagePath) return json({ error: 'Missing imagePath' }, { status: 400 });

          if (tagIds !== undefined) {
            EditorDb.setImageTags(imagePath, tagIds);
          } else if (addTagId !== undefined) {
            EditorDb.addImageTag(imagePath, addTagId);
          } else if (removeTagId !== undefined) {
            EditorDb.removeImageTag(imagePath, removeTagId);
          } else {
            return json({ error: 'Provide tagIds, addTagId, or removeTagId' }, { status: 400 });
          }

          const tags = EditorDb.getImageTags(imagePath);
          return json({ success: true, tags });
        } catch (err: any) {
          return json({ error: err.message }, { status: 500 });
        }
      }

      // GET /api/editor/search?q=...&root=Tools/ComfyUI/output — search albums and tagged images
      if (path === '/api/editor/search' && method === 'GET') {
        return handleEditorSearch(url);
      }

      // ============================================
      // TRASH API
      // ============================================
      if (path === '/api/trash/delete' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.deleteToTrash);
      if (path === '/api/fs/trash/move' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.deleteToTrash); // Alias
      if (path === '/api/trash/list' && method === 'GET') return trashRoutes.listTrash(req, url, routeContext);
      if (path === '/api/trash/retention' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.updateTrashRetention);
      if (path === '/api/trash/restore' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.restoreFromTrash);
      if (
        isRemoteRequest(req, url, server)
        && (
          path === '/api/trash/empty'
          || path === '/api/trash/permanent-delete'
          || path === '/api/trash/delete-direct'
          || path === '/api/trash/system'
        )
      ) {
        return json({ error: 'Remote clients can only move files to Umbra Trash or restore them.' }, 403);
      }
      if (path === '/api/trash/empty' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.emptyTrash);
      if (path === '/api/trash/permanent-delete' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.permanentlyDelete);
      if (path === '/api/trash/delete-direct' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.permanentlyDeleteDirect);
      if (path === '/api/trash/system' && method === 'POST') return handleTrashMutationWithCacheInvalidation(req, url, trashRoutes.deleteToSystemTrash);

      // ============================================
      // BACKEND API (ComfyUI)
      // ============================================
      if (path === '/api/umbrabridge/status' && method === 'GET') {
        if (url.searchParams.get('refresh') === 'true') {
          await forceRefreshBackendControlPlaneStatus();
        }
        const controlPlane = getCachedBackendControlPlaneStatus();
        const stats = getCachedSystemStats();
        const gpu = stats.gpus[0];
        return json({
          sampledAt: controlPlane.sampledAt,
          sampleAgeMs: controlPlane.sampleAgeMs,
          stale: controlPlane.stale,
          refreshing: controlPlane.refreshing,
          backends: {
            comfyui: controlPlane.backends.comfyui,
            gallery: controlPlane.backends.gallery
          },
          vram: {
            total_gb: gpu ? (gpu.memory.total / 1024) : 0,
            used_gb: gpu ? (gpu.memory.used / 1024) : 0,
            free_gb: gpu ? ((gpu.memory.total - gpu.memory.used) / 1024) : 0,
            percent: gpu ? gpu.memory.percent : 0,
            gpu_name: gpu ? gpu.name : 'Unknown',
            sampledAt: stats.timestamp,
            sampleAgeMs: stats.sampleAgeMs ?? 0,
            stale: stats.stale === true,
            refreshing: stats.refreshing === true
          }
        });
      }

      if (path === '/api/gallery-bridge/status' && method === 'GET') {
        const controlPlane = getCachedBackendControlPlaneStatus();
        return json({
          ...controlPlane.backends.gallery,
          sampledAt: controlPlane.sampledAt,
          sampleAgeMs: controlPlane.sampleAgeMs,
          stale: controlPlane.stale,
          refreshing: controlPlane.refreshing,
        });
      }

      if (path === '/api/data-forge/ai-toolkit/status' && method === 'GET') {
        const detected = detectAIToolkit();
        const config = getBackendConfig().aitoolkit;
        const status = await getBackendStatusAsync('aitoolkit', 900);
        const nodeCapability = getAIToolkitNodeCapability();
        return json({
          installed: detected.detected,
          detected: detected.detected,
          path: detected.path,
          uiPath: detected.uiPath || '',
          url: config.url,
          port: config.port,
          running: status.running,
          healthy: status.healthy,
          pid: status.pid,
          uptime: status.uptime,
          ownership: status.ownership,
          nodeAvailable: nodeCapability.available,
          nodeVersion: nodeCapability.version,
          uiDependenciesInstalled: Boolean(config.cwd && existsSync(join(config.cwd, 'node_modules'))),
          datasetsPath: join(ROOT_DIR, 'User', 'Datasets'),
        });
      }

      if (path === '/api/umbrabridge/vram/status' && method === 'GET') {
        const stats = getCachedSystemStats();
        const gpu = stats.gpus[0];
        return json({
          total_vram_gb: gpu ? (gpu.memory.total / 1024) : 0,
          used_vram_gb: gpu ? (gpu.memory.used / 1024) : 0,
          free_vram_gb: gpu ? ((gpu.memory.total - gpu.memory.used) / 1024) : 0,
          percent: gpu ? gpu.memory.percent : 0,
          gpu_name: gpu ? gpu.name : 'Unknown'
        });
      }

      // ============================================
      // TOOLS AUTO-DETECTION API
      // ============================================
      if (path === '/api/healthz' && method === 'GET') {
        return json({
          ok: true,
          runtimeRoot: ROOT_DIR,
          now: Date.now(),
          uptimeMs: Math.max(0, Math.floor(process.uptime() * 1000)),
        });
      }

      if (path === '/api/tools/detect' && method === 'GET') {
        const detected = detectAllTools();
        const config = getBackendConfig();

        return json({
          runtimeRoot: ROOT_DIR,
          comfyui: {
            detected: detected.comfyui.detected,
            path: detected.comfyui.path,
            port: config.comfyui.port,
            status: detected.comfyui.detected ? 'ready' : 'not_installed'
          },
          aitoolkit: {
            detected: detected.aitoolkit.detected,
            path: detected.aitoolkit.path,
            port: config.aitoolkit.port,
            status: detected.aitoolkit.detected ? 'ready' : 'not_installed'
          },
        });
      }

      // ============================================
      // UPDATE CHECK API
      // ============================================
      if (path === '/api/tools/updates' && method === 'GET') {
        const forceRefresh = url.searchParams.get('refresh') === 'true';

        // Clear cache if forced refresh
        if (forceRefresh) {
          updateCache = null;
        }

        const updates = await checkAllUpdates();
        const pendingUpdates = updates.tools.filter(u => u.hasUpdate);

        return json({
          lastChecked: updates.lastChecked,
          pytorch: {
            latestVersion: updates.pytorch.latestVersion,
            cudaVersion: updates.pytorch.cudaVersion
          },
          updates: updates.tools,
          pendingCount: pendingUpdates.length,
          hasPendingUpdates: pendingUpdates.length > 0
        });
      }

      if (path === '/api/tools/updates/summary' && method === 'GET') {
        // Quick summary endpoint for UI notifications
        const updates = await checkAllUpdates();
        const pendingUpdates = updates.tools.filter(u => u.hasUpdate);

        return json({
          pendingCount: pendingUpdates.length,
          hasPendingUpdates: pendingUpdates.length > 0,
          updates: pendingUpdates.map(u => ({
            tool: u.tool,
            type: u.updateType,
            from: u.currentVersion,
            to: u.latestVersion
          }))
        });
      }

      const toolVersionsMatch = path.match(/^\/api\/tools\/(comfyui)\/versions$/);
      if (toolVersionsMatch && method === 'GET') {
        const tool = String(toolVersionsMatch[1]) as ToolVersionTarget;
        const config = getToolVersionConfig(tool);
        const limit = parseInt(url.searchParams.get('limit') || '300', 10);
        const catalog = await getToolVersionCatalog(tool, limit);
        if (!catalog.available) {
          return json(catalog);
        }

        const portableRoot = getPortablePathForToolVersionTarget(tool);
        if (!isPathWithin(portableRoot, catalog.path)) {
          return json({
            ...catalog,
            available: false,
            unavailableReason: `${config.displayName} version switching is only available for portable installs under ${portableRoot.replace(/\\/g, '/')}.`,
            path: catalog.path
          });
        }

        return json(catalog);
      }

      const toolVersionSetMatch = path.match(/^\/api\/tools\/(comfyui)\/version$/);
      if (toolVersionSetMatch && method === 'POST') {
        if (isRemoteRequest(req, url, server)) {
          return json({ error: 'Tool version switching is only available from the host PC.' }, 403);
        }
        const tool = String(toolVersionSetMatch[1]) as ToolVersionTarget;
        const config = getToolVersionConfig(tool);
        const body = await req.json() as { ref?: string };
        const ref = String(body?.ref || '').trim();
        if (!ref) {
          return json({ error: 'Version reference is required' }, 400);
        }
        if (!/^[A-Za-z0-9._/-]+$/.test(ref) || ref.startsWith('-')) {
          return json({ error: 'Invalid version reference format' }, 400);
        }

        const catalog = await getToolVersionCatalog(tool, 1);
        if (!catalog.available) {
          return json({ error: catalog.unavailableReason || `${config.displayName} versions are unavailable.` }, 404);
        }

        const portableRoot = getPortablePathForToolVersionTarget(tool);
        if (!isPathWithin(portableRoot, catalog.path)) {
          return json({
            error: `${config.displayName} version switching is only available for portable installs under ${portableRoot.replace(/\\/g, '/')}.`,
            path: catalog.path
          }, 400);
        }

        const backendStatus = await getBackendStatusAsync(tool);
        if (backendStatus.running) {
          return json({ error: `Stop ${config.displayName} before switching versions.` }, 400);
        }

        const actionMap: Record<ToolVersionTarget, { action: string; command: string }> = {
          comfyui: { action: 'set_comfyui_version', command: 'set-comfyui-version' },
        };
        const selected = actionMap[tool];
        updateCache = null;
        const job = createToolAction(selected.action, [selected.command, ref], tool);
        return json({
          success: true,
          actionId: job.id,
          status: job.status,
          action: selected.action,
          tool,
          ref
        });
      }

      if (path === '/api/tools/actions' && method === 'POST') {
        if (isRemoteRequest(req, url, server)) {
          return json({ error: 'Tool install and update actions are only available from the host PC.' }, 403);
        }
        const body = await req.json() as {
          action: 'install' | 'update' | 'custom_nodes' | 'repair_shortcuts' | 'update_pytorch' | 'install_sageattention';
          tool?: 'comfyui' | 'aitoolkit';
        };
        const rawAction = String((body as any)?.action || '').toLowerCase();
        const normalizedAction =
          rawAction === 'update-pytorch' ||
            rawAction === 'update_cuda' ||
            rawAction === 'update-cuda' ||
            rawAction === 'pytorch' ||
            rawAction === 'cuda' ||
            rawAction === 'update_torch'
            ? 'update_pytorch'
            : rawAction === 'install-sageattention' ||
              rawAction === 'install_sageattention' ||
              rawAction === 'install-sage-attention' ||
              rawAction === 'sageattention' ||
              rawAction === 'sage_attention'
              ? 'install_sageattention'
            : rawAction;

        if (normalizedAction === 'repair_shortcuts') {
          const job = createToolAction('repair_shortcuts', ['shortcuts']);
          return json({ success: true, actionId: job.id, status: job.status });
        }

        if (!body.tool) {
          return json({ error: 'Tool is required for this action' }, 400);
        }

        const tool = body.tool;
        let job: ToolActionJob | null = null;

        if (normalizedAction === 'install') {
          const backendStatus = await getBackendStatusAsync(tool);
          if (backendStatus.running) {
            return json({ error: `Stop ${tool === 'comfyui' ? 'ComfyUI' : 'AI-Toolkit'} before installing or repairing it.` }, 400);
          }
          updateCache = null;
          job = createToolAction('install', [tool], tool);
        } else if (normalizedAction === 'update') {
          const backendStatus = await getBackendStatusAsync(tool);
          if (backendStatus.running) {
            return json({ error: `Stop ${tool === 'comfyui' ? 'ComfyUI' : 'AI-Toolkit'} before running update.` }, 400);
          }
          updateCache = null;
          job = createToolAction('update', [`update-${tool}`], tool);
        } else if (normalizedAction === 'update_pytorch') {
          const backendStatus = await getBackendStatusAsync(tool);
          if (backendStatus.running) {
            return json({ error: `Stop ${tool === 'comfyui' ? 'ComfyUI' : 'AI-Toolkit'} before updating CUDA/PyTorch.` }, 400);
          }
          updateCache = null;
          job = createToolAction('update_pytorch', [`update-pytorch-${tool}`], tool);
        } else if (normalizedAction === 'install_sageattention') {
          if (tool !== 'comfyui') {
            return json({ error: 'SageAttention install is only available for ComfyUI.' }, 400);
          }
          const backendStatus = await getBackendStatusAsync('comfyui');
          if (backendStatus.running) {
            return json({ error: 'Stop ComfyUI before installing SageAttention.' }, 400);
          }
          updateCache = null;
          job = createToolAction('install_sageattention', ['install-sageattention-comfyui'], tool);
        } else if (normalizedAction === 'custom_nodes') {
          if (tool === 'comfyui') {
            job = createToolAction('custom_nodes', ['comfy-nodes'], tool);
          } else {
            return json({ error: 'Custom nodes are only available for ComfyUI workflows' }, 400);
          }
        } else {
          return json({ error: 'Invalid action' }, 400);
        }

        return json({
          success: true,
          actionId: job.id,
          status: job.status,
          action: normalizedAction,
          tool
        });
      }

      if (path.match(/^\/api\/tools\/actions\/[^/]+$/) && method === 'GET') {
        const actionId = path.split('/').pop()!;
        const job = toolActionJobs.get(actionId);

        if (!job) {
          return json({ error: 'Action not found' }, 404);
        }

        return json({
          id: job.id,
          action: job.action,
          tool: job.tool,
          status: job.status,
          startedAt: job.startedAt,
          endedAt: job.endedAt,
          exitCode: job.exitCode,
          error: job.error,
          verifyFailure: job.verifyFailure,
          logs: job.logs
        });
      }

      if (path === '/api/umbrabridge/backend/start' && method === 'POST') {
        const { backend } = await req.json() as { backend: string };
        if (backend === 'comfyui') return json(await startComfyUI());
        if (backend === 'aitoolkit') return json(await startAIToolkit());
        if (backend === 'gallery') return json(await startGalleryBridge());
        return json({ error: 'Invalid backend' }, 400);
      }

      if (path === '/api/umbrabridge/backend/stop' && method === 'POST') {
        const { backend } = await req.json() as { backend: string };
        appendPowerPrompterQueueLog('backend_stop_endpoint_called', {
          backend,
          path,
          userAgent: req.headers.get('user-agent') || '',
          referer: req.headers.get('referer') || '',
        });
        if (backend === 'comfyui') return json(await stopComfyUI());
        if (backend === 'aitoolkit') return json(await stopAIToolkit());
        if (backend === 'gallery') return json(await stopGalleryBridge());
        return json({ error: 'Invalid backend' }, 400);
      }

      // Stop all backends (keeps server running)
      if (path === '/api/umbrabridge/backend/stop-all' && method === 'POST') {
        console.log('\x1b[33m[Server]\x1b[0m Stopping all backends...');
        appendPowerPrompterQueueLog('backend_stop_all_endpoint_called', {
          path,
          userAgent: req.headers.get('user-agent') || '',
          referer: req.headers.get('referer') || '',
        });
        const results = {
          comfyui: await stopComfyUI(),
          aitoolkit: await stopAIToolkit(),
          gallery: await stopGalleryBridge()
        };
        console.log('\x1b[32m[Server]\x1b[0m All backends stopped');
        return json({ success: true, results });
      }

      // Graceful shutdown endpoint
      if (path === '/api/server/shutdown' && method === 'POST') {
        // Send response before shutting down
        const response = json({ success: true, message: 'Server shutting down...' });

        // Schedule shutdown after response is sent
        setTimeout(() => gracefulShutdown('API'), 100);

        return response;
      }

      // Poll backend until server responds or timeout
      if (path === '/api/umbrabridge/backend/wait-ready' && method === 'POST') {
        const { backend, timeout = null } = await req.json() as { backend: string; timeout?: number | null };
        const requestedTimeout = Number(timeout);
        const effectiveTimeout = timeout === null || timeout === undefined
          ? null
          : (Number.isFinite(requestedTimeout)
          ? Math.max(5000, Math.min(30 * 60 * 1000, Math.floor(requestedTimeout)))
          : null);
        const startTime = Date.now();
        const galleryPollInterval = 1000;
        const comfyPollInterval = 300;
        const aitoolkitPollInterval = 500;
        const hasTimedOut = () => effectiveTimeout !== null && (Date.now() - startTime) >= effectiveTimeout;

        if (backend === 'gallery') {
          while (!hasTimedOut()) {
            const status = await getGalleryStatusAsync();
            if (status.healthy) {
              return json({
                ready: true,
                backend,
                host: status.host,
                port: status.port,
                url: status.url,
                elapsed: Date.now() - startTime,
              });
            }
            await new Promise((resolve) => setTimeout(resolve, galleryPollInterval));
          }

          const status = await getGalleryStatusAsync();
          return json({
            ready: false,
            backend,
            host: status.host,
            port: status.port,
            url: status.url,
            error: 'Timeout waiting for gallery bridge',
            elapsed: Date.now() - startTime,
          });
        }

        let host = '127.0.0.1';
        let port = 0;
        let readyUrl = '';
        if (backend === 'comfyui') {
          const config = getComfyProxyTarget();
          host = config.host;
          port = config.port;
          readyUrl = `http://${host}:${port}/queue`;
        }
        else if (backend === 'aitoolkit') {
          const config = getBackendConfig().aitoolkit;
          host = config.host;
          port = config.port;
          readyUrl = config.url;
        }
        else return json({ error: 'Invalid backend' }, 400);

        while (!hasTimedOut()) {
          try {
            const response = await fetch(readyUrl, {
              method: 'GET',
              signal: AbortSignal.timeout(1200),
            });
            if (response.ok) {
              void forceRefreshBackendControlPlaneStatus();
              return json({ ready: true, backend, port, url: readyUrl, elapsed: Date.now() - startTime });
            }
          } catch {
            // continue polling
          }
          await new Promise(r => setTimeout(r, backend === 'aitoolkit' ? aitoolkitPollInterval : comfyPollInterval));
        }

        return json({ ready: false, backend, port, url: readyUrl, error: 'Timeout waiting for server', elapsed: Date.now() - startTime });
      }

      if (path === '/api/umbrabridge/comfyui/queue' && method === 'GET') {
        try {
          const config = getComfyProxyTarget();
          const response = await fetch(`http://${config.host}:${config.port}/queue`, {
          });
          if (!response.ok) {
            return json({
              success: false,
              unavailable: true,
              message: 'ComfyUI queue is not available yet',
              queue_running: [],
              queue_pending: [],
            });
          }
          return json(await response.json());
        } catch {
          return json({
            success: false,
            unavailable: true,
            message: 'ComfyUI queue is unreachable or timed out',
            queue_running: [],
            queue_pending: [],
          });
        }
      }

      if (path === '/api/umbrabridge/comfyui/interrupt' && method === 'POST') {
        try {
          const config = getComfyProxyTarget();
          const response = await fetch(`http://${config.host}:${config.port}/interrupt`, {
            method: 'POST',
          });
          if (!response.ok) {
            return json({ success: false, error: `ComfyUI interrupt failed (${response.status})` }, 502);
          }
          return json({ success: true });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'ComfyUI unreachable' }, 502);
        }
      }

      if (path === '/api/umbrabridge/comfyui/queue/clear' && method === 'POST') {
        try {
          const config = getComfyProxyTarget();
          const queueUrl = `http://${config.host}:${config.port}/queue`;
          let cleared = false;
          const clearResponse = await fetch(queueUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ clear: true }),
          });
          if (clearResponse.ok) {
            cleared = true;
          } else {
            const snapshotResponse = await fetch(queueUrl, {
              method: 'GET',
            });
            if (!snapshotResponse.ok) {
              return json({ success: false, error: `ComfyUI queue read failed (${snapshotResponse.status})` }, 502);
            }
            const snapshot = await snapshotResponse.json() as any;
            const pendingRows = Array.isArray(snapshot?.queue_pending) ? snapshot.queue_pending : [];
            const pendingPromptIds = pendingRows
              .map((row: any) => {
                if (!Array.isArray(row) || row.length === 0) return '';
                return String(row[1] || row[0] || '').trim();
              })
              .filter((value: string) => value.length > 0);
            if (pendingPromptIds.length > 0) {
              const deleteResponse = await fetch(queueUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ delete: pendingPromptIds }),
              });
              cleared = deleteResponse.ok;
            } else {
              cleared = true;
            }
          }
          if (!cleared) {
            return json({ success: false, error: 'Failed to clear queued prompts.' }, 502);
          }
          return json({ success: true });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'ComfyUI unreachable' }, 502);
        }
      }

      // List files in a directory
      if (path === '/api/files' && method === 'GET') {
        const relativePath = url.searchParams.get('path') || '';

        // Support both User/ relative paths and absolute paths
        let targetPath = relativePath;
        if (!relativePath.startsWith('/')) {
          targetPath = join(ROOT_DIR, relativePath);
        }

        try {
          if (!existsSync(targetPath)) {
            return json({ files: [], error: 'Directory not found' });
          }

          const stat = statSync(targetPath);
          if (!stat.isDirectory()) {
            return json({ files: [], error: 'Not a directory' });
          }

          const entries = await fs.readdir(targetPath, { withFileTypes: true });
          const files = entries
            .filter(e => e.isFile())
            .map(e => ({
              name: e.name,
              path: join(targetPath, e.name),
              isDirectory: false
            }));

          const directories = entries
            .filter(e => e.isDirectory())
            .map(e => ({
              name: e.name,
              path: join(targetPath, e.name),
              isDirectory: true
            }));

          return json({ files, directories, path: targetPath });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // ============================================
      // BOORU PROXY ENDPOINTS (for CORS)
      // ============================================

      // Booru search proxy
      if (path === '/api/booru/search' && method === 'GET') {
        const startedAt = Date.now();
        const source = String(url.searchParams.get('source') || 'danbooru').toLowerCase();
        // Normalize tags: trim, collapse multiple spaces, convert commas to spaces
        const rawTags = url.searchParams.get('tags') || '';
        const tags = rawTags.trim().replace(/,/g, ' ').replace(/\s+/g, ' ');
        const page = parseInt(url.searchParams.get('page') || '1');
        const limit = Math.min(parseInt(url.searchParams.get('limit') || '40'), 100);

        console.log(`[Booru] Search started source=${source} tags="${tags}" page=${page} limit=${limit}`);

        try {
          const apiKeys = await loadStoredApiKeys();
          const sourceFetchers: Record<string, () => Promise<unknown[]>> = {
            danbooru: () => fetchDanbooruPosts(tags, limit, page, apiKeys.danbooru),
            gelbooru: () => fetchGelbooruPosts(tags, limit, page, apiKeys.gelbooru),
            rule34: () => fetchRule34Posts(tags, limit, page, apiKeys.rule34),
            e621: () => fetchE621Posts(tags, limit, page, apiKeys.e621),
          };
          const fetchSource = sourceFetchers[source];
          if (!fetchSource) {
            return json({ error: `Unsupported Data Forge source: ${source}` }, 400);
          }
          const data = await fetchSource();

          console.log(`[Booru] Search completed source=${source} results=${Array.isArray(data) ? data.length : 0} ms=${Date.now() - startedAt}`);
          return json(data);
        } catch (error: any) {
          console.error(`[Booru] Search error for ${source}:`, error.message);
          const status = /requires a valid .*api key/i.test(String(error?.message || '')) ? 401 : 502;
          return json({ error: error.message }, status);
        }
      }

      if (path === '/api/booru/research' && method === 'GET') {
        return handleBooruDatasetResearch(url);
      }

      if (path === '/api/booru/dataset-generator/run' && method === 'POST') {
        return handleBooruDatasetGeneratorRun(req);
      }

      if (path === '/api/booru/dataset-generator/status' && method === 'GET') {
        return handleBooruDatasetGeneratorStatus(url);
      }

      // Booru autocomplete proxy
      if (path === '/api/booru/autocomplete' && method === 'GET') {
        const source = String(url.searchParams.get('source') || 'danbooru').toLowerCase();
        const query = String(url.searchParams.get('query') || '').trim();

        if (query.length < 2) {
          return json([]);
        }

        try {
          const autocompleteUrls: Record<string, string> = {
            danbooru: `https://danbooru.donmai.us/autocomplete.json?search[query]=${encodeURIComponent(query)}&search[type]=tag_query&limit=10`,
            gelbooru: `https://gelbooru.com/index.php?page=autocomplete2&type=tag_query&term=${encodeURIComponent(query)}&limit=10`,
            rule34: `https://api.rule34.xxx/autocomplete.php?q=${encodeURIComponent(query)}`,
            e621: `https://e621.net/tags.json?search[name_matches]=${encodeURIComponent(`${query}*`)}&search[order]=count&limit=10`,
          };
          const autocompleteUrl = autocompleteUrls[source];
          if (!autocompleteUrl) return json([]);

          const res = await fetch(autocompleteUrl, {
            headers: {
              'User-Agent': 'UmbraStudio (Data Forge; local application)',
              Accept: 'application/json',
            },
            signal: AbortSignal.timeout(10000),
          });
          if (!res.ok) return json([]);
          const data = await res.json() as any;
          const entries = Array.isArray(data) ? data : Array.isArray(data?.tags) ? data.tags : [];
          const values = entries
            .map((entry: any) => String(entry?.value || entry?.name || entry?.label || entry?.tag || entry || '').trim())
            .filter(Boolean)
            .slice(0, 10);
          return json(values);
        } catch (error: any) {
          return json([]);
        }
      }

      if (path === '/api/booru/image-proxy' && method === 'GET') {
        return handleBooruImageProxy(req, url);
      }

      // Booru download to dataset
      if (path === '/api/booru/download' && method === 'POST') {
        try {
          const body = await req.json() as {
            url: string;
            md5: string;
            ext: string;
            tags?: string[];
            dataset: string;
            concept: string;
          };

          if (!body.url || !body.md5 || !body.dataset || !body.concept) {
            return json({ error: 'url, md5, dataset, and concept required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!datasetName || !conceptName) {
            return json({ error: 'Invalid dataset or concept path' }, 400);
          }

          const datasetPath = resolveDatasetPathSafe(datasetName);
          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!datasetPath || !conceptPath) {
            return json({ error: 'Invalid dataset path' }, 400);
          }

          // Ensure concept folder exists
          if (!existsSync(conceptPath)) {
            await fs.mkdir(conceptPath, { recursive: true });
          }

          // Download image
          const md5 = String(body.md5 || '').trim().replace(/[^a-fA-F0-9]/g, '');
          if (!md5) {
            return json({ error: 'Invalid md5 value' }, 400);
          }
          const extSafe = String(body.ext || 'jpg').trim().toLowerCase().replace(/[^a-z0-9]/g, '') || 'jpg';
          const filename = `${md5}.${extSafe}`;
          const imagePath = join(conceptPath, filename);

          // Skip if already exists
          if (existsSync(imagePath)) {
            return json({ success: true, message: 'Already exists', path: imagePath });
          }

          const sourceUrl = normalizeBooruMediaUrl(body.url);
          if (!sourceUrl) {
            return json({ error: 'The image URL is not from a configured Data Forge source.' }, 400);
          }
          const imgRes = await fetch(sourceUrl, {
            headers: { 'User-Agent': 'UmbraStudio (Data Forge; local application)' },
            signal: AbortSignal.timeout(30000),
          });

          if (!imgRes.ok) {
            throw new Error(`Failed to download: ${imgRes.status}`);
          }

          const buffer = await imgRes.arrayBuffer();
          await fs.writeFile(imagePath, Buffer.from(buffer));

          // Save tags as caption if provided
          if (body.tags && body.tags.length > 0) {
            const captionPath = join(conceptPath, `${md5}.txt`);
            await fs.writeFile(captionPath, body.tags.join(', '));
          }

          return json({ success: true, path: imagePath });
        } catch (error: any) {
          console.error('[Booru] Download error:', error.message);
          return json({ error: error.message }, 500);
        }
      }

      // ============================================
      // DATASET ENDPOINTS
      // ============================================

      // List datasets with concepts.
      if (path === '/api/datasets' && method === 'GET') {
        const datasetsDir = join(ROOT_DIR, 'User', 'Datasets');
        try {
          if (!existsSync(datasetsDir)) {
            await fs.mkdir(datasetsDir, { recursive: true });
            return json({ datasets: [] });
          }

          const entries = await fs.readdir(datasetsDir, { withFileTypes: true });
          const datasets = await Promise.all(
            entries
              .filter(e => e.isDirectory())
              .map(async (dir) => {
                const datasetPath = join(datasetsDir, dir.name);
                const datasetStats = await fs.stat(datasetPath).catch(() => null);
                const archivePath = join(datasetsDir, `${dir.name}.zip`);
                const archiveStats = await fs.stat(archivePath).catch(() => null);
                const subEntries = await fs.readdir(datasetPath, { withFileTypes: true });

                // Parse concept folders (e.g., "10_base", "1_reg_face")
                const concepts = await Promise.all(
                  subEntries
                    .filter(e => e.isDirectory())
                    .map(async (conceptDir) => {
                      const match = conceptDir.name.match(/^(\d+)_(reg_)?(.+)$/);
                      if (!match) return null;

                      const [, repeatsStr, regPrefix, name] = match;
                      const conceptPath = join(datasetPath, conceptDir.name);
                      const conceptStats = await fs.stat(conceptPath).catch(() => null);
                      const files = await fs.readdir(conceptPath);
                      const imageFiles = files.filter(f => /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f));

                      return {
                        name,
                        repeats: parseInt(repeatsStr),
                        isReg: !!regPrefix,
                        folder: conceptDir.name,
                        modifiedMs: conceptStats?.mtimeMs || 0,
                        images: imageFiles.map((filename) => ({ filename })),
                      };
                    })
                );
                const sortedConcepts = concepts
                  .filter(Boolean)
                  .sort((a: any, b: any) => Number(b?.modifiedMs || 0) - Number(a?.modifiedMs || 0));

                return {
                  name: dir.name,
                  path: datasetPath,
                  modifiedMs: datasetStats?.mtimeMs || 0,
                  archive: archiveStats?.isFile()
                    ? {
                        path: archivePath,
                        size: archiveStats.size,
                        modifiedMs: archiveStats.mtimeMs,
                      }
                    : null,
                  concepts: sortedConcepts,
                };
              })
          );

          datasets.sort((a: any, b: any) => Number(b?.modifiedMs || 0) - Number(a?.modifiedMs || 0));
          return json({ datasets });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Create new dataset
      if (path === '/api/datasets' && method === 'POST') {
        try {
          const body = await req.json() as { name: string };
          if (!body.name) return json({ error: 'Dataset name required' }, 400);

          const sanitizedName = body.name.replace(/[^a-zA-Z0-9_-]/g, '_');
          const datasetPath = resolveDatasetPathSafe(sanitizedName);
          if (!datasetPath) return json({ error: 'Invalid dataset name' }, 400);

          if (existsSync(datasetPath)) {
            return json({ error: 'Dataset already exists' }, 400);
          }

          await fs.mkdir(datasetPath, { recursive: true });
          return json({ success: true, name: sanitizedName });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Create or replace a maximum-compression, lossless dataset share archive.
      const datasetArchiveMatch = path.match(/^\/api\/datasets\/([^/]+)\/archive$/);
      if (datasetArchiveMatch && method === 'POST') {
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(datasetArchiveMatch[1] || ''));
        if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
        const datasetPath = resolveDatasetPathSafe(datasetName);
        if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);
        if (!existsSync(datasetPath)) return json({ error: 'Dataset not found' }, 404);

        const archiveKey = normalizePathForCompare(datasetPath);
        if (datasetArchiveBuilds.has(archiveKey)) {
          return json({ error: 'This dataset archive is already being built.' }, 409);
        }

        const archivePath = join(dirname(datasetPath), `${datasetName}.zip`);
        datasetArchiveBuilds.add(archiveKey);
        try {
          const result = await createDatasetArchive({ datasetPath, datasetName, archivePath });
          const savedBytes = Math.max(0, result.sourceBytes - result.archiveBytes);
          const compressionPercent = result.sourceBytes > 0
            ? Math.max(0, Math.round((savedBytes / result.sourceBytes) * 1000) / 10)
            : 0;
          return json({
            success: true,
            ...result,
            savedBytes,
            compressionPercent,
          });
        } catch (error: any) {
          console.error(`[Datasets] Failed to archive ${datasetName}:`, error);
          return json({ error: error?.message || 'Failed to create dataset archive' }, 500);
        } finally {
          datasetArchiveBuilds.delete(archiveKey);
        }
      }

      // Delete dataset
      if (path.match(/^\/api\/datasets\/[^/]+$/) && method === 'DELETE') {
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(path.split('/')[3] || ''));
        if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
        const datasetPath = resolveDatasetPathSafe(datasetName);
        if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);

        try {
          if (!existsSync(datasetPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          await fs.rm(datasetPath, { recursive: true, force: true });
          await fs.rm(join(dirname(datasetPath), `${datasetName}.zip`), { force: true });
          return json({ success: true });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Rename dataset
      if (path.match(/^\/api\/datasets\/[^/]+\/rename$/) && method === 'POST') {
        const oldName = sanitizeDatasetSegment(decodeURIComponent(path.split('/')[3] || ''));
        if (!oldName) return json({ error: 'Invalid dataset name' }, 400);
        const oldPath = resolveDatasetPathSafe(oldName);
        if (!oldPath) return json({ error: 'Invalid dataset path' }, 400);

        try {
          const body = await req.json() as { newName: string };
          if (!body.newName) return json({ error: 'New name required' }, 400);

          if (!existsSync(oldPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          const sanitizedName = body.newName.replace(/[^a-zA-Z0-9_-]/g, '_');
          const newPath = resolveDatasetPathSafe(sanitizedName);
          if (!newPath) return json({ error: 'Invalid dataset name' }, 400);

          if (existsSync(newPath)) {
            return json({ error: 'A dataset with that name already exists' }, 400);
          }

          await fs.rename(oldPath, newPath);
          const oldArchivePath = join(dirname(oldPath), `${oldName}.zip`);
          const newArchivePath = join(dirname(newPath), `${sanitizedName}.zip`);
          let archiveRenamed = false;
          if (existsSync(oldArchivePath) && !existsSync(newArchivePath)) {
            try {
              await fs.rename(oldArchivePath, newArchivePath);
              archiveRenamed = true;
            } catch (error) {
              console.warn('[Datasets] Dataset renamed but its share archive could not be renamed:', error);
            }
          }
          return json({ success: true, name: sanitizedName, archiveRenamed });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Create concept folder
      if (path.match(/^\/api\/datasets\/[^/]+\/concept$/) && method === 'POST') {
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(path.split('/')[3] || ''));
        if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
        const datasetPath = resolveDatasetPathSafe(datasetName);
        if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);

        try {
          const body = await req.json() as { name: string; repeats?: number; isReg?: boolean };
          if (!body.name) return json({ error: 'Concept name required' }, 400);

          if (!existsSync(datasetPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          const repeats = body.repeats || 10;
          const folderName = sanitizeDatasetSegment(`${repeats}_${body.isReg ? 'reg_' : ''}${body.name}`);
          if (!folderName) return json({ error: 'Invalid concept name' }, 400);
          const conceptPath = resolveDatasetPathSafe(datasetName, folderName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);

          if (existsSync(conceptPath)) {
            return json({ error: 'Concept folder already exists' }, 400);
          }

          await fs.mkdir(conceptPath, { recursive: true });
          return json({ success: true, folder: folderName });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Delete concept folder
      if (path.match(/^\/api\/datasets\/[^/]+\/concept\/[^/]+$/) && method === 'DELETE') {
        const parts = path.split('/');
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(parts[3] || ''));
        const conceptFolder = sanitizeDatasetSegment(decodeURIComponent(parts[5] || ''));
        if (!datasetName || !conceptFolder) return json({ error: 'Invalid dataset or concept path' }, 400);
        const conceptPath = resolveDatasetPathSafe(datasetName, conceptFolder);
        if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);

        try {
          if (!existsSync(conceptPath)) {
            return json({ error: 'Concept not found' }, 404);
          }

          await fs.rm(conceptPath, { recursive: true, force: true });
          return json({ success: true });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Get images in concept folder
      if (path.match(/^\/api\/datasets\/[^/]+\/concept\/[^/]+\/images$/) && method === 'GET') {
        const parts = path.split('/');
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(parts[3] || ''));
        const conceptFolder = sanitizeDatasetSegment(decodeURIComponent(parts[5] || ''));
        if (!datasetName || !conceptFolder) return json({ error: 'Invalid dataset or concept path' }, 400);
        const conceptPath = resolveDatasetPathSafe(datasetName, conceptFolder);
        if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);

        try {
          if (!existsSync(conceptPath)) {
            return json({ error: 'Concept not found' }, 404);
          }

          const files = await fs.readdir(conceptPath);
          const images = await Promise.all(
            files
              .filter(f => /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f))
              .map(async (f) => {
                const baseName = f.replace(/\.[^.]+$/, '');
                const captionPath = join(conceptPath, baseName + '.txt');
                let caption = '';
                let tags: string[] = [];

                if (existsSync(captionPath)) {
                  caption = await fs.readFile(captionPath, 'utf-8');
                  tags = caption.split(',').map(t => t.trim()).filter(Boolean);
                }

                return {
                  filename: f,
                  path: `/User/Datasets/${datasetName}/${conceptFolder}/${f}`,
                  caption,
                  tags,
                };
              })
          );

          return json({ images });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Get/save per-concept caption and auto-tagger settings.
      if (path.match(/^\/api\/datasets\/[^/]+\/concept\/[^/]+\/settings$/) && (method === 'GET' || method === 'PUT')) {
        const parts = path.split('/');
        const datasetName = sanitizeDatasetSegment(decodeURIComponent(parts[3] || ''));
        const conceptFolder = sanitizeDatasetSegment(decodeURIComponent(parts[5] || ''));
        if (!datasetName || !conceptFolder) return json({ error: 'Invalid dataset or concept path' }, 400);
        const conceptPath = resolveDatasetPathSafe(datasetName, conceptFolder);
        if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);

        try {
          if (!existsSync(conceptPath)) return json({ error: 'Concept not found' }, 404);
          if (method === 'GET') {
            const settings = await readDatasetConceptSettings(datasetName, conceptFolder, conceptPath);
            return json({ settings });
          }

          const body = await req.json().catch(() => ({})) as Record<string, unknown>;
          const settings = await writeDatasetConceptSettings(datasetName, conceptFolder, conceptPath, body);
          return json({ success: true, settings });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Move images between concepts
      if (path === '/api/datasets/move-images' && method === 'POST') {
        try {
          const body = await req.json() as {
            dataset: string;
            images: string[];
            from: string;
            to: string;
          };

          if (!body.dataset || !body.images?.length || !body.from || !body.to) {
            return json({ error: 'dataset, images, from, and to required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const fromConcept = sanitizeDatasetSegment(body.from);
          const toConcept = sanitizeDatasetSegment(body.to);
          if (!datasetName || !fromConcept || !toConcept) {
            return json({ error: 'Invalid dataset or concept path' }, 400);
          }
          const fromPath = resolveDatasetPathSafe(datasetName, fromConcept);
          const toPath = resolveDatasetPathSafe(datasetName, toConcept);
          if (!fromPath || !toPath) {
            return json({ error: 'Invalid dataset path' }, 400);
          }

          if (!existsSync(fromPath) || !existsSync(toPath)) {
            return json({ error: 'Source or destination concept not found' }, 404);
          }

          for (const img of body.images) {
            const safeImgName = sanitizeDatasetSegment(img);
            if (!safeImgName) continue;
            const srcImg = join(fromPath, safeImgName);
            const destImg = join(toPath, safeImgName);

            if (existsSync(srcImg)) {
              await fs.rename(srcImg, destImg);

              // Also move caption file if exists
              const baseName = safeImgName.replace(/\.[^.]+$/, '');
              const srcCaption = join(fromPath, baseName + '.txt');
              const destCaption = join(toPath, baseName + '.txt');

              if (existsSync(srcCaption)) {
                await fs.rename(srcCaption, destCaption);
              }
            }
          }

          return json({ success: true, moved: body.images.length });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Delete images from concept
      if (path === '/api/datasets/delete-images' && method === 'POST') {
        try {
          const body = await req.json() as {
            dataset: string;
            concept: string;
            images: string[];
          };

          if (!body.dataset || !body.concept || !body.images?.length) {
            return json({ error: 'dataset, concept, and images required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!datasetName || !conceptName) {
            return json({ error: 'Invalid dataset or concept path' }, 400);
          }
          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);

          if (!existsSync(conceptPath)) {
            return json({ error: 'Concept not found' }, 404);
          }

          for (const img of body.images) {
            const safeImgName = sanitizeDatasetSegment(img);
            if (!safeImgName) continue;
            const imgPath = join(conceptPath, safeImgName);

            if (existsSync(imgPath)) {
              await fs.unlink(imgPath);

              // Also delete caption file if exists
              const baseName = safeImgName.replace(/\.[^.]+$/, '');
              const captionPath = join(conceptPath, baseName + '.txt');

              if (existsSync(captionPath)) {
                await fs.unlink(captionPath);
              }
            }
          }

          return json({ success: true, deleted: body.images.length });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Batch prepend trigger text and optionally run the selected dataset caption model.
      if (path === '/api/datasets/auto-tag-captions' && method === 'POST') {
        try {
          const imageExts = new Set(['.png', '.jpg', '.jpeg', '.webp', '.bmp', '.gif']);
          const parseBool = (value: unknown, fallback: boolean): boolean => {
            if (typeof value === 'boolean') return value;
            if (typeof value === 'number') return value !== 0;
            if (typeof value === 'string') {
              const lowered = value.trim().toLowerCase();
              if (['1', 'true', 'yes', 'on'].includes(lowered)) return true;
              if (['0', 'false', 'no', 'off'].includes(lowered)) return false;
            }
            return fallback;
          };
          const parseNumber = (value: unknown, fallback: number, min: number, max: number): number => {
            const parsed = typeof value === 'number' ? value : Number(String(value ?? '').trim());
            if (!Number.isFinite(parsed)) return fallback;
            return Math.max(min, Math.min(max, parsed));
          };
          const parseInteger = (value: unknown, fallback: number, min: number, max: number): number => {
            const parsed = Number(String(value ?? '').trim());
            if (!Number.isFinite(parsed)) return fallback;
            return Math.max(min, Math.min(max, Math.floor(parsed)));
          };
          const normalizeCaptionTag = (value: unknown, useSpaces: boolean): string => {
            const text = String(value ?? '').trim();
            if (!text) return '';
            return useSpaces
              ? text.replace(/_/g, ' ').replace(/\s+/g, ' ').trim()
              : text.replace(/\s+/g, '_');
          };
          const parseTagList = (value: unknown, useSpaces = false): string[] => {
            const text = Array.isArray(value) ? value.join(',') : String(value ?? '');
            if (!text.trim()) return [];
            const parts = text.includes(',')
              ? text.split(',')
              : text.split(/\s+/);
            return parts
              .map((part) => normalizeCaptionTag(part, useSpaces))
              .filter(Boolean);
          };
          const mergeTags = (...groups: string[][]): string[] => {
            const merged: string[] = [];
            const seen = new Set<string>();
            for (const group of groups) {
              for (const rawTag of group) {
                const tag = String(rawTag || '').trim();
                if (!tag) continue;
                const key = tag.toLowerCase();
                if (seen.has(key)) continue;
                seen.add(key);
                merged.push(tag);
              }
            }
            return merged;
          };
          const mergeCaptionSegments = (...values: unknown[]): string => {
            const segments: string[] = [];
            const seen = new Set<string>();
            for (const value of values) {
              const segment = String(value || '').replace(/\s+/g, ' ').trim().replace(/^,+|,+$/g, '').trim();
              if (!segment) continue;
              const key = segment.toLowerCase();
              if (seen.has(key)) continue;
              seen.add(key);
              segments.push(segment);
            }
            return segments.join(', ');
          };
          const tagsFromEntries = (entries: unknown, useSpaces: boolean): string[] => {
            if (!Array.isArray(entries)) return [];
            return entries
              .map((entry) => {
                if (typeof entry === 'string') return normalizeCaptionTag(entry, useSpaces);
                if (entry && typeof entry === 'object' && 'tag' in entry) {
                  return normalizeCaptionTag((entry as { tag?: unknown }).tag, useSpaces);
                }
                return '';
              })
              .filter(Boolean);
          };
          const ratingTagsFromResult = (result: any, useSpaces: boolean): string[] => {
            if (!result || typeof result !== 'object' || !result.rating || typeof result.rating !== 'object') return [];
            return Object.keys(result.rating)
              .map((tag) => normalizeCaptionTag(tag, useSpaces))
              .filter(Boolean);
          };
          const generatedTagsFromWaifuResult = (
            result: any,
            useSpaces: boolean,
            include: {
              general: boolean;
              character: boolean;
              copyright: boolean;
              artist: boolean;
              meta: boolean;
              rating: boolean;
            },
          ): string[] => {
            if (!result || typeof result !== 'object') return [];
            const hasCategoryFields = ['general', 'character', 'copyright', 'artist', 'meta', 'rating']
              .some((field) => Object.prototype.hasOwnProperty.call(result, field));
            const categoryTags = mergeTags(
              include.character ? tagsFromEntries(result.character, useSpaces) : [],
              include.general ? tagsFromEntries(result.general, useSpaces) : [],
              include.copyright ? tagsFromEntries(result.copyright, useSpaces) : [],
              include.artist ? tagsFromEntries(result.artist, useSpaces) : [],
              include.meta ? tagsFromEntries(result.meta, useSpaces) : [],
              include.rating ? ratingTagsFromResult(result, useSpaces) : [],
            );
            if (hasCategoryFields) return categoryTags;
            if (!include.general && !include.character && !include.copyright && !include.artist && !include.meta && !include.rating) {
              return [];
            }
            return Array.isArray(result?.booruTags)
              ? result.booruTags.map((tag: unknown) => normalizeCaptionTag(tag, useSpaces)).filter(Boolean)
              : parseTagList(result?.booruTagString || '', useSpaces);
          };

          const body = await req.json() as Record<string, unknown>;
          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!datasetName || !conceptName) {
            return json({ error: 'dataset and concept required' }, 400);
          }

          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);
          if (!existsSync(conceptPath)) return json({ error: 'Concept not found' }, 404);

          const autoTag = parseBool(body.autoTag, true);
          const preserveExisting = parseBool(body.preserveExisting, true);
          const captionMode = body.captionMode === 'natural' ? 'natural' : 'tags';
          const modelRepo = String(body.modelRepo || 'SmilingWolf/wd-vit-tagger-v3').trim() || 'SmilingWolf/wd-vit-tagger-v3';
          const naturalModelRepo = String(body.naturalModelRepo || 'prithivMLmods/Qwen2-VL-2B-Abliterated-Caption-it').trim()
            || 'prithivMLmods/Qwen2-VL-2B-Abliterated-Caption-it';
          const naturalDevice = body.naturalDevice === 'cpu' || body.naturalDevice === 'cuda' ? body.naturalDevice : 'auto';
          const naturalMaxNewTokens = parseInteger(body.naturalMaxNewTokens, 192, 32, 512);
          const generalThreshold = parseNumber(body.generalThreshold, 0.35, 0, 1);
          const characterThreshold = parseNumber(body.characterThreshold, 0.85, 0, 1);
          const ratingThreshold = parseNumber(body.ratingThreshold, 0.25, 0, 1);
          const generalMcutEnabled = parseBool(body.generalMcutEnabled, false);
          const characterMcutEnabled = parseBool(body.characterMcutEnabled, false);
          const includeGeneralTags = parseBool(body.includeGeneralTags, true);
          const includeCharacterTags = parseBool(body.includeCharacterTags, true);
          const includeCopyrightTags = parseBool(body.includeCopyrightTags, false);
          const includeArtistTags = parseBool(body.includeArtistTags, false);
          const includeMetaTags = parseBool(body.includeMetaTags, false);
          const includeRatingTags = parseBool(body.includeRatingTags, false);
          const maxTags = parseInteger(body.maxTags, 120, 1, 500);
          const replaceUnderscoresWithSpaces = parseBool(body.replaceUnderscoresWithSpaces, false);
          const triggerTags = parseTagList(body.triggerTags, replaceUnderscoresWithSpaces);
          const prependTags = parseTagList(body.prependTags, replaceUnderscoresWithSpaces);
          const prefixTags = mergeTags(triggerTags, prependTags);
          await writeDatasetConceptSettings(datasetName, conceptName, conceptPath, {
            triggerTags: String(body.triggerTags ?? ''),
            prependTags: String(body.prependTags ?? ''),
            captionMode,
            modelRepo,
            naturalModelRepo,
            naturalDevice,
            naturalMaxNewTokens,
            generalThreshold,
            characterThreshold,
            ratingThreshold,
            generalMcutEnabled,
            characterMcutEnabled,
            includeGeneralTags,
            includeCharacterTags,
            includeCopyrightTags,
            includeArtistTags,
            includeMetaTags,
            includeRatingTags,
            maxTags,
            preserveExisting,
            replaceUnderscoresWithSpaces,
          }).catch((error) => {
            console.warn('[Datasets] Failed to persist concept auto-tag settings:', error);
          });

          const requestedImages = Array.isArray(body.images)
            ? body.images.map((entry) => sanitizeDatasetSegment(entry)).filter(Boolean)
            : [];
          const allFiles = await fs.readdir(conceptPath);
          const imageFiles = allFiles
            .filter((file) => imageExts.has(extname(file).toLowerCase()))
            .filter((file) => requestedImages.length === 0 || requestedImages.includes(file))
            .sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));

          if (imageFiles.length === 0) {
            return json({ error: 'No images found to caption' }, 400);
          }

          const naturalCaptionResults = new Map<string, { caption?: string; error?: string }>();
          if (autoTag && captionMode === 'natural') {
            const naturalRun = await runNaturalCaptioner({
              imagePaths: imageFiles.map((filename) => join(conceptPath, filename)),
              modelRepo: naturalModelRepo,
              device: naturalDevice,
              maxNewTokens: naturalMaxNewTokens,
            });
            for (const entry of naturalRun.results || []) {
              const filename = String(entry?.filename || '').trim();
              if (!filename) continue;
              naturalCaptionResults.set(filename, entry?.success
                ? { caption: String(entry?.caption || '').trim() }
                : { error: String(entry?.error || 'Natural caption failed') });
            }
          }

          const results: Array<{
            filename: string;
            success: boolean;
            caption?: string;
            tagCount?: number;
            error?: string;
          }> = [];

          for (const filename of imageFiles) {
            const imagePath = join(conceptPath, filename);
            const baseName = filename.replace(/\.[^.]+$/, '');
            const captionPath = join(conceptPath, `${baseName}.txt`);

            try {
              const existingCaption = existsSync(captionPath)
                ? await fs.readFile(captionPath, 'utf8').catch(() => '')
                : '';
              const existingTags = preserveExisting && captionMode === 'tags'
                ? parseTagList(existingCaption, replaceUnderscoresWithSpaces)
                : [];
              let generatedTags: string[] = [];

              if (autoTag && captionMode === 'tags') {
                const result = await runWaifuTagger({
                  imagePath,
                  modelRepo,
                  generalThreshold,
                  characterThreshold,
                  ratingThreshold,
                  generalMcutEnabled,
                  characterMcutEnabled,
                  maxTags,
                });
                if (result && typeof result === 'object' && result.error) {
                  throw new Error(String(result.error));
                }
                generatedTags = generatedTagsFromWaifuResult(result, replaceUnderscoresWithSpaces, {
                  general: includeGeneralTags,
                  character: includeCharacterTags,
                  copyright: includeCopyrightTags,
                  artist: includeArtistTags,
                  meta: includeMetaTags,
                  rating: includeRatingTags,
                });
              }

              let caption = '';
              let tagCount = 0;
              if (captionMode === 'natural') {
                const naturalResult = naturalCaptionResults.get(filename);
                if (autoTag && (!naturalResult || naturalResult.error || !naturalResult.caption)) {
                  throw new Error(naturalResult?.error || 'Natural caption result was missing');
                }
                caption = mergeCaptionSegments(
                  prefixTags.join(', '),
                  autoTag ? naturalResult?.caption : '',
                  preserveExisting ? existingCaption : '',
                );
                tagCount = prefixTags.length + (autoTag && naturalResult?.caption ? 1 : 0);
              } else {
                const mergedTags = mergeTags(prefixTags, generatedTags, existingTags);
                caption = mergedTags.join(', ');
                tagCount = mergedTags.length;
              }
              await fs.writeFile(captionPath, caption, 'utf8');
              results.push({
                filename,
                success: true,
                caption,
                tagCount,
              });
            } catch (error: any) {
              results.push({
                filename,
                success: false,
                error: error?.message || 'Caption update failed',
              });
            }
          }

          return json({
            success: true,
            dataset: datasetName,
            concept: conceptName,
            captionMode,
            total: imageFiles.length,
            updated: results.filter((entry) => entry.success).length,
            failed: results.filter((entry) => !entry.success).length,
            results,
          });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Import browser/OS dropped image files to dataset concepts
      if (path === '/api/datasets/import-uploaded-image' && method === 'POST') {
        try {
          const formData = await req.formData();
          const datasetName = sanitizeDatasetSegment(formData.get('dataset'));
          const conceptName = sanitizeDatasetSegment(formData.get('concept'));
          const file = formData.get('image');

          if (!datasetName || !conceptName || !(file instanceof File)) {
            return json({ error: 'dataset, concept, and image file required' }, 400);
          }

          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);
          if (!existsSync(conceptPath)) {
            await fs.mkdir(conceptPath, { recursive: true });
          }

          const fallbackExt = file.type.split('/')[1] ? `.${file.type.split('/')[1].replace('jpeg', 'jpg')}` : '.png';
          const originalName = sanitizeDatasetSegment(basename(file.name || `image${fallbackExt}`)) || `image${fallbackExt}`;
          const parsedExt = extname(originalName) || fallbackExt;
          const parsedBase = basename(originalName, extname(originalName)) || 'image';
          let filename = `${parsedBase}${parsedExt}`;
          let destPath = join(conceptPath, filename);
          let counter = 1;
          while (existsSync(destPath)) {
            filename = `${parsedBase}_${counter}${parsedExt}`;
            destPath = join(conceptPath, filename);
            counter += 1;
          }

          const buffer = Buffer.from(await file.arrayBuffer());
          await fs.writeFile(destPath, buffer);
          return json({ success: true, filename });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Import browser dropped image URLs to dataset concepts
      if (path === '/api/datasets/import-image-url' && method === 'POST') {
        try {
          const body = await req.json() as {
            url: string;
            dataset: string;
            concept: string;
          };

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!body.url || !datasetName || !conceptName) {
            return json({ error: 'url, dataset, and concept required' }, 400);
          }

          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);
          if (!existsSync(conceptPath)) {
            await fs.mkdir(conceptPath, { recursive: true });
          }

          let buffer: Buffer;
          let contentType = '';
          if (body.url.startsWith('data:image/')) {
            const match = body.url.match(/^data:(image\/[^;,]+);base64,(.+)$/);
            if (!match) return json({ error: 'Invalid image data URL' }, 400);
            contentType = match[1];
            buffer = Buffer.from(match[2], 'base64');
          } else {
            let parsedUrl: URL;
            try {
              parsedUrl = new URL(body.url);
            } catch {
              return json({ error: 'Invalid image URL' }, 400);
            }
            if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
              return json({ error: 'Only HTTP image URLs are supported' }, 400);
            }

            const response = await fetch(parsedUrl.toString(), {
              headers: { 'User-Agent': 'UmbraStudio/1.0 (dataset-builder)' },
            });
            if (!response.ok) {
              return json({ error: `Failed to download image: ${response.status}` }, 400);
            }
            contentType = response.headers.get('content-type') || '';
            if (contentType && !contentType.toLowerCase().startsWith('image/')) {
              return json({ error: 'Dropped URL did not return an image' }, 400);
            }
            buffer = Buffer.from(await response.arrayBuffer());
          }

          const extensionFromType = (() => {
            const subtype = contentType.split('/')[1]?.split(';')[0]?.toLowerCase();
            if (!subtype) return '.jpg';
            if (subtype === 'jpeg') return '.jpg';
            if (subtype === 'svg+xml') return '.svg';
            return `.${subtype}`;
          })();

          let baseName = 'image';
          try {
            const parsedUrl = new URL(body.url);
            const pathBase = decodeURIComponent(basename(parsedUrl.pathname || ''));
            baseName = basename(pathBase, extname(pathBase)) || baseName;
          } catch {
            // Data URLs keep the default base name.
          }

          const safeBaseName = sanitizeDatasetSegment(baseName) || 'image';
          const safeExt = extensionFromType.replace(/[^.a-zA-Z0-9]/g, '') || '.jpg';
          let filename = `${safeBaseName}${safeExt}`;
          let destPath = join(conceptPath, filename);
          let counter = 1;
          while (existsSync(destPath)) {
            filename = `${safeBaseName}_${counter}${safeExt}`;
            destPath = join(conceptPath, filename);
            counter += 1;
          }

          await fs.writeFile(destPath, buffer);
          return json({ success: true, filename });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Import image to dataset (copy from another location)
      if (path === '/api/datasets/import-image' && method === 'POST') {
        try {
          const body = await req.json() as {
            sourcePath: string;
            dataset: string;
            concept: string;
          };

          if (!body.sourcePath || !body.dataset || !body.concept) {
            return json({ error: 'sourcePath, dataset, and concept required' }, 400);
          }

          const sourcePath = resolveDatasetImportSourcePath(body.sourcePath);
          if (!sourcePath || !existsSync(sourcePath)) {
            return json({ error: 'Source file not found' }, 404);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!datasetName || !conceptName) {
            return json({ error: 'Invalid dataset or concept path' }, 400);
          }
          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);
          if (!existsSync(conceptPath)) {
            await fs.mkdir(conceptPath, { recursive: true });
          }

          const result = await copyLocalImageIntoDatasetConcept(sourcePath, conceptPath);

          return json({ success: true, ...result });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Batch import local gallery images to a dataset concept.
      if (path === '/api/datasets/import-images' && method === 'POST') {
        try {
          const body = await req.json() as {
            sourcePaths: string[];
            dataset: string;
            concept: string;
          };

          const sourcePaths = Array.isArray(body.sourcePaths)
            ? body.sourcePaths.map((entry) => String(entry || '').trim()).filter(Boolean)
            : [];
          if (sourcePaths.length === 0 || !body.dataset || !body.concept) {
            return json({ error: 'sourcePaths, dataset, and concept required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          const conceptName = sanitizeDatasetSegment(body.concept);
          if (!datasetName || !conceptName) {
            return json({ error: 'Invalid dataset or concept path' }, 400);
          }
          const conceptPath = resolveDatasetPathSafe(datasetName, conceptName);
          if (!conceptPath) return json({ error: 'Invalid concept path' }, 400);
          if (!existsSync(conceptPath)) {
            await fs.mkdir(conceptPath, { recursive: true });
          }

          const results: Array<{
            sourcePath: string;
            success: boolean;
            filename?: string;
            copiedSidecars?: string[];
            error?: string;
          }> = [];

          for (const rawSourcePath of sourcePaths) {
            try {
              const sourcePath = resolveDatasetImportSourcePath(rawSourcePath);
              if (!sourcePath) throw new Error('Invalid source path');
              const result = await copyLocalImageIntoDatasetConcept(sourcePath, conceptPath);
              results.push({
                sourcePath: rawSourcePath,
                success: true,
                filename: result.filename,
                copiedSidecars: result.copiedSidecars,
              });
            } catch (error: any) {
              results.push({
                sourcePath: rawSourcePath,
                success: false,
                error: error?.message || 'Import failed',
              });
            }
          }

          const imported = results.filter((entry) => entry.success).length;
          const failed = results.length - imported;
          return json({
            success: imported > 0,
            dataset: datasetName,
            concept: conceptName,
            total: results.length,
            imported,
            failed,
            results,
          }, imported > 0 ? 200 : 400);
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // ============================================
      // WORKSPACE COPY ENDPOINTS
      // Copy images to workspace input folders (COPY action)
      // ============================================

      // Copy image to ComfyUI input folder
      if (path === '/api/comfy/copy-image' && method === 'POST') {
        try {
          const body = await req.json() as { sourcePath: string };
          if (!body.sourcePath) {
            return json({ error: 'sourcePath required' }, 400);
          }

          // Handle both absolute paths and relative paths
          let sourcePath = body.sourcePath;
          if (!isAbsolute(sourcePath)) {
            sourcePath = join(ROOT_DIR, sourcePath);
          }

          if (!existsSync(sourcePath)) {
            return json({ error: 'Source file not found' }, 404);
          }

          const comfyInputDir = getComfyInputRootFast();
          if (!existsSync(comfyInputDir)) {
            await fs.mkdir(comfyInputDir, { recursive: true });
          }

          const filename = basename(sourcePath) || 'image.png';
          const destPath = join(comfyInputDir, filename);

          // Copy the file
          await fs.copyFile(sourcePath, destPath);

          // Best-effort sync: also hit ComfyUI's upload API so new inputs are immediately indexed.
          let comfyUploadSynced = false;
          let comfyUploadError: string | null = null;
          try {
            const config = getBackendConfig().comfyui;
            const uploadUrl = `http://${config.host}:${config.port}/upload/image`;
            const fileBuffer = await fs.readFile(sourcePath);
            const formData = new FormData();
            formData.append('image', new Blob([fileBuffer]), filename);
            formData.append('type', 'input');
            formData.append('overwrite', 'true');

            const uploadResponse = await fetch(uploadUrl, {
              method: 'POST',
              body: formData,
            });

            if (!uploadResponse.ok) {
              const details = (await uploadResponse.text().catch(() => '')).slice(0, 200);
              throw new Error(`HTTP ${uploadResponse.status}${details ? `: ${details}` : ''}`);
            }

            comfyUploadSynced = true;
          } catch (error: any) {
            comfyUploadError = error?.message || String(error);
            console.warn(`[ComfyUI] upload/image sync failed for ${filename}: ${comfyUploadError}`);
          }

          return json({
            success: true,
            filename,
            destPath,
            uploadApi: {
              attempted: true,
              synced: comfyUploadSynced,
              error: comfyUploadError,
            },
          });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      if (path === '/api/comfy/copy-media' && method === 'POST') {
        try {
          const body = await req.json() as { sourcePath?: string; kind?: string };
          if (!body.sourcePath) return json({ error: 'sourcePath required' }, 400);
          let sourcePath = String(body.sourcePath || '').trim();
          if (!isAbsolute(sourcePath)) sourcePath = join(ROOT_DIR, sourcePath);
          sourcePath = resolve(sourcePath);
          if (!existsSync(sourcePath) || !statSync(sourcePath).isFile()) {
            return json({ error: 'Source media file not found' }, 404);
          }
          const extension = extname(sourcePath).toLowerCase();
          const detectedKind = UMBRA_UI_VIDEO_EXTENSIONS.has(extension)
            ? 'video'
            : UMBRA_UI_AUDIO_EXTENSIONS.has(extension)
              ? 'audio'
              : UMBRA_UI_IMAGE_EXTENSIONS.has(extension)
                ? 'image'
                : '';
          const requestedKind = String(body.kind || '').trim().toLowerCase();
          if (!detectedKind || (requestedKind && requestedKind !== detectedKind)) {
            return json({ error: `Unsupported ${requestedKind || 'media'} file: ${basename(sourcePath)}` }, 400);
          }
          const comfyInputDir = getComfyInputRootFast();
          await fs.mkdir(comfyInputDir, { recursive: true });
          const filename = `${Date.now().toString(36)}-${randomBytes(4).toString('hex')}-${basename(sourcePath)}`;
          const destPath = join(comfyInputDir, filename);
          await fs.copyFile(sourcePath, destPath);
          return json({ success: true, filename, destPath, kind: detectedKind });
        } catch (error: any) {
          return json({ error: error?.message || 'Failed to stage media for ComfyUI.' }, 500);
        }
      }

      if (path === '/api/comfy/upload-media' && method === 'POST') {
        let tempPath = '';
        try {
          const requestedKind = String(req.headers.get('x-umbra-media-kind') || '').trim().toLowerCase();
          if (requestedKind !== 'image' && requestedKind !== 'video' && requestedKind !== 'audio') {
            return json({ error: 'An image, video, or audio media kind is required.' }, 400);
          }
          let originalName = String(req.headers.get('x-umbra-file-name') || '').trim();
          try {
            originalName = decodeURIComponent(originalName);
          } catch {
            // Keep the original header when it was not URI encoded.
          }
          const safeName = basename(originalName || `umbra-${requestedKind}`)
            .replace(/[<>:"/\\|?*\x00-\x1f]/g, '_')
            .trim();
          const extension = extname(safeName).toLowerCase();
          const allowed = requestedKind === 'image'
            ? UMBRA_UI_IMAGE_EXTENSIONS
            : requestedKind === 'video'
              ? UMBRA_UI_VIDEO_EXTENSIONS
              : UMBRA_UI_AUDIO_EXTENSIONS;
          if (!safeName || !allowed.has(extension)) {
            return json({ error: `Unsupported ${requestedKind} file: ${safeName || '(unnamed)'}` }, 400);
          }
          if (!req.body) return json({ error: 'The uploaded media file was empty.' }, 400);

          const comfyInputDir = getComfyInputRootFast();
          await fs.mkdir(comfyInputDir, { recursive: true });
          const filename = `${Date.now().toString(36)}-${randomBytes(4).toString('hex')}-${safeName}`;
          const destPath = join(comfyInputDir, filename);
          tempPath = `${destPath}.upload`;
          const handle = await fs.open(tempPath, 'w');
          let totalBytes = 0;
          try {
            const bodyStream = req.body as any;
            if (typeof bodyStream.getReader === 'function') {
              const reader = bodyStream.getReader();
              while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                if (!value?.byteLength) continue;
                await handle.write(value);
                totalBytes += value.byteLength;
              }
            } else if (typeof bodyStream[Symbol.asyncIterator] === 'function') {
              for await (const value of bodyStream) {
                const bytes = value instanceof Uint8Array ? value : new Uint8Array(value);
                if (!bytes.byteLength) continue;
                await handle.write(bytes);
                totalBytes += bytes.byteLength;
              }
            } else {
              const bytes = new Uint8Array(await req.arrayBuffer());
              if (bytes.byteLength) {
                await handle.write(bytes);
                totalBytes = bytes.byteLength;
              }
            }
            if (typeof handle.sync === 'function') await handle.sync();
          } finally {
            await handle.close();
          }
          if (totalBytes <= 0) {
            await fs.rm(tempPath, { force: true });
            return json({ error: 'The uploaded media file was empty.' }, 400);
          }
          await fs.rename(tempPath, destPath);
          tempPath = '';
          return json({
            success: true,
            filename,
            sourcePath: destPath.replace(/\\/g, '/'),
            kind: requestedKind,
            size: totalBytes,
          });
        } catch (error: any) {
          if (tempPath) await fs.rm(tempPath, { force: true }).catch(() => undefined);
          return json({ error: error?.message || 'Failed to upload media for ComfyUI.' }, 500);
        }
      }

      // Save caption for image in concept folder
      if (path === '/api/dataset/save-caption' && method === 'POST') {
        try {
          const body = await req.json() as { dataset: string; concept?: string; image: string; caption: string };
          if (!body.dataset || !body.image) {
            return json({ error: 'Dataset and image name required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
          const conceptName = body.concept ? sanitizeDatasetSegment(body.concept) : '';
          if (body.concept && !conceptName) return json({ error: 'Invalid concept name' }, 400);

          // Support both flat datasets and concept folders
          const basePath = body.concept
            ? resolveDatasetPathSafe(datasetName, conceptName)
            : resolveDatasetPathSafe(datasetName);
          if (!basePath) return json({ error: 'Invalid dataset path' }, 400);

          if (!existsSync(basePath)) {
            return json({ error: 'Dataset/concept not found' }, 404);
          }

          const safeImageName = sanitizeDatasetSegment(body.image);
          if (!safeImageName) return json({ error: 'Invalid image filename' }, 400);
          const imagePath = join(basePath, safeImageName);
          if (!existsSync(imagePath)) {
            return json({ error: 'Image not found' }, 404);
          }

          // Use baseName.txt format next to the image.
          const baseName = safeImageName.replace(/\.[^.]+$/, '');
          const captionPath = join(basePath, baseName + '.txt');

          await fs.writeFile(captionPath, body.caption.trim());

          return json({ success: true, path: captionPath });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // List training datasets (legacy endpoint - kept for compatibility)
      if (path === '/api/dataset/list' && method === 'GET') {
        const datasetsDir = join(ROOT_DIR, 'User', 'Datasets');
        try {
          if (!existsSync(datasetsDir)) {
            await fs.mkdir(datasetsDir, { recursive: true });
            return json([]);
          }

          const entries = await fs.readdir(datasetsDir, { withFileTypes: true });
          const datasets = await Promise.all(
            entries
              .filter(e => e.isDirectory())
              .map(async (dir) => {
                const dirPath = join(datasetsDir, dir.name);
                const subEntries = await fs.readdir(dirPath, { withFileTypes: true });

                // Count images directly in dataset folder
                let imageCount = subEntries.filter(f =>
                  f.isFile() && /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f.name)
                ).length;

                // Count concepts (subfolders) and images in them
                const concepts: string[] = [];
                for (const sub of subEntries) {
                  if (sub.isDirectory()) {
                    concepts.push(sub.name);
                    const conceptPath = join(dirPath, sub.name);
                    const conceptFiles = await fs.readdir(conceptPath);
                    imageCount += conceptFiles.filter(f =>
                      /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f)
                    ).length;
                  }
                }

                return {
                  name: dir.name,
                  imageCount,
                  conceptCount: concepts.length,
                  concepts
                };
              })
          );
          return json(datasets);
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Create new dataset
      if (path === '/api/dataset/create' && method === 'POST') {
        try {
          const body = await req.json() as { name: string };
          if (!body.name) return json({ error: 'Dataset name required' }, 400);

          const sanitizedName = body.name.replace(/[^a-zA-Z0-9_-]/g, '_');
          const datasetPath = resolveDatasetPathSafe(sanitizedName);
          if (!datasetPath) return json({ error: 'Invalid dataset name' }, 400);

          if (existsSync(datasetPath)) {
            return json({ error: 'Dataset already exists' }, 400);
          }

          await fs.mkdir(datasetPath, { recursive: true });
          return json({ success: true, name: sanitizedName, path: datasetPath });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Delete dataset
      if (path === '/api/dataset/delete' && method === 'POST') {
        try {
          const body = await req.json() as { name: string };
          if (!body.name) return json({ error: 'Dataset name required' }, 400);

          const datasetName = sanitizeDatasetSegment(body.name);
          if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
          const datasetPath = resolveDatasetPathSafe(datasetName);
          if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);

          if (!existsSync(datasetPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          await fs.rm(datasetPath, { recursive: true, force: true });
          return json({ success: true, message: `Dataset ${body.name} deleted` });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Get images in dataset
      if (path === '/api/dataset/images' && method === 'GET') {
        const datasetName = url.searchParams.get('name');
        if (!datasetName) return json({ error: 'Dataset name required' }, 400);

        const safeDatasetName = sanitizeDatasetSegment(datasetName);
        if (!safeDatasetName) return json({ error: 'Invalid dataset name' }, 400);
        const datasetPath = resolveDatasetPathSafe(safeDatasetName);
        if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);

        try {
          if (!existsSync(datasetPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          const files = await fs.readdir(datasetPath);
          const images = await Promise.all(
            files
              .filter(f => /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f))
              .map(async (f) => {
                const baseName = f.replace(/\.[^.]+$/, '');
                // Gallery-dl creates .jpg.txt and .jpg.json, not .txt and .json
                const hasCaption = files.includes(f + '.txt') || files.includes(baseName + '.txt');
                const hasMetadata = files.includes(f + '.json') || files.includes(baseName + '.json');

                // Try to read tags from metadata JSON if it exists
                let tags: string[] = [];
                let captionText = '';

                // Try to read caption text from .txt file
                const captionPaths = [
                  join(datasetPath, f + '.txt'),      // gallery-dl format: image.jpg.txt
                  join(datasetPath, baseName + '.txt') // standard format: image.txt
                ];

                for (const captionPath of captionPaths) {
                  if (existsSync(captionPath)) {
                    try {
                      // Read caption as-is (keep underscores for training compatibility)
                      captionText = (await fs.readFile(captionPath, 'utf-8')).trim();
                      break;
                    } catch {
                      // Ignore read errors
                    }
                  }
                }

                // Check both possible metadata file patterns
                const metaPaths = [
                  join(datasetPath, f + '.json'),      // gallery-dl format: image.jpg.json
                  join(datasetPath, baseName + '.json') // standard format: image.json
                ];

                for (const metaPath of metaPaths) {
                  if (existsSync(metaPath)) {
                    try {
                      const metaContent = await fs.readFile(metaPath, 'utf-8');
                      const meta = JSON.parse(metaContent);

                      // Danbooru format - tag_string contains all tags
                      if (meta.tag_string) {
                        tags = meta.tag_string.split(' ').filter(Boolean);
                        break;
                      }
                      // Alternative: separate tag strings
                      if (meta.tag_string_general) {
                        tags = [...tags, ...meta.tag_string_general.split(' ')];
                      }
                      if (meta.tag_string_character) {
                        tags = [...tags, ...meta.tag_string_character.split(' ')];
                      }
                      if (meta.tag_string_copyright) {
                        tags = [...tags, ...meta.tag_string_copyright.split(' ')];
                      }
                      if (meta.tag_string_artist) {
                        tags = [...tags, ...meta.tag_string_artist.split(' ')];
                      }
                      // Generic tags field
                      if (meta.tags) {
                        if (typeof meta.tags === 'string') {
                          tags = [...tags, ...meta.tags.split(/[,\s]+/).filter(Boolean)];
                        } else if (Array.isArray(meta.tags)) {
                          tags = [...tags, ...meta.tags];
                        }
                      }
                      if (tags.length > 0) break;
                    } catch {
                      // Ignore metadata read errors
                    }
                  }
                }

                // If no tags from JSON, extract from caption text (comma-separated)
                if (tags.length === 0 && captionText) {
                  tags = captionText.split(',').map(t => t.trim()).filter(Boolean);
                }

                return {
                  name: f,
                  path: `/api/files/datasets/${safeDatasetName}/${f}`,
                  caption: hasCaption,
                  captionText: captionText, // Full caption text
                  hasMetadata,
                  tags: [...new Set(tags)].slice(0, 50) // Dedupe and limit to 50 tags
                };
              })
          );

          return json({ images });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Preview search results (fetch image URLs without downloading)
      if (path === '/api/dataset/preview' && method === 'POST') {
        try {
          const body = await req.json() as { url: string; limit?: number; tags?: string };
          if (!body.url && !body.tags) {
            return json({ error: 'URL or tags required' }, 400);
          }

          const limit = Math.min(body.limit || 24, 100);
          const apiKeys = await loadStoredApiKeys();

          // Detect site from URL and use direct API
          const url = body.url || '';
          let images: Array<{ url: string; fullUrl?: string; id: string; tags?: string[]; rating?: string }> = [];

          try {
            if (url.includes('danbooru.donmai.us') || url.includes('danbooru:')) {
              // Extract tags from URL
              const urlMatch = url.match(/tags=([^&]+)/);
              const tags = urlMatch ? decodeURIComponent(urlMatch[1]) : (body.tags || 'solo');
              console.log('[Preview] Fetching from Danbooru:', tags);
              images = await fetchDanbooruPosts(tags.replace(/\+/g, ' '), limit, 1, apiKeys.danbooru);
            }
            else {
              // Unsupported site - return empty result
              console.log('[Preview] Unsupported site:', url);
              return json({ images: [], error: 'Unsupported site. Use Danbooru.' });
            }

            console.log(`[Preview] Found ${images.length} images`);
            return json({ images });
          } catch (err: any) {
            console.error('[Preview] API error:', err.message);
            return json({ images: [], error: err.message });
          }
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Get API keys configuration (without exposing full keys)
      if (path === '/api/dataset/api-keys' && method === 'GET') {
        try {
          const config = await loadStoredApiKeys();
          // Return masked keys for display
          const masked: Record<string, any> = {};
          if (config.danbooru?.username) {
            masked.danbooru = {
              username: config.danbooru.username,
              hasApiKey: !!config.danbooru.apiKey
            };
          }
          if (config.gelbooru?.userId) {
            masked.gelbooru = {
              userId: config.gelbooru.userId,
              hasApiKey: !!config.gelbooru.apiKey
            };
          }
          if (config.rule34?.userId) {
            masked.rule34 = {
              userId: config.rule34.userId,
              hasApiKey: !!config.rule34.apiKey
            };
          }
          if (config.e621?.username) {
            masked.e621 = {
              username: config.e621.username,
              hasApiKey: !!config.e621.apiKey
            };
          }
          if (config.civitai?.apiToken || config.civitai?.apiKey) {
            const token = String(config.civitai.apiToken || config.civitai.apiKey || '').trim();
            masked.civitai = {
              hasApiKey: Boolean(token),
              maskedKey: maskCivitaiToken(token)
            };
          }
          return json({ config: masked });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Save API keys configuration
      if (path === '/api/dataset/api-keys' && method === 'POST') {
        try {
          const body = await req.json() as BooruApiConfig;
          const existing = await loadStoredApiKeys();

          // Merge with existing, only update what's provided
          const merged: BooruApiConfig = { ...existing };

          if (body.danbooru) {
            merged.danbooru = {
              username: body.danbooru.username || existing.danbooru?.username || '',
              apiKey: body.danbooru.apiKey || existing.danbooru?.apiKey || ''
            };
          }
          if (body.gelbooru) {
            merged.gelbooru = {
              userId: body.gelbooru.userId || existing.gelbooru?.userId || '',
              apiKey: body.gelbooru.apiKey || existing.gelbooru?.apiKey || ''
            };
          }
          if (body.rule34) {
            merged.rule34 = {
              userId: body.rule34.userId || existing.rule34?.userId || '',
              apiKey: body.rule34.apiKey || existing.rule34?.apiKey || ''
            };
          }
          if (body.e621) {
            merged.e621 = {
              username: body.e621.username || existing.e621?.username || '',
              apiKey: body.e621.apiKey || existing.e621?.apiKey || ''
            };
          }
          if (body.civitai) {
            const apiToken = String(body.civitai.apiToken || body.civitai.apiKey || existing.civitai?.apiToken || existing.civitai?.apiKey || '').trim();
            if (apiToken) merged.civitai = { apiToken };
          }

          await saveStoredApiKeys(merged);
          console.log('[API Keys] Configuration saved');
          return json({ success: true });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Delete API keys for a site
      if (path === '/api/dataset/api-keys' && method === 'DELETE') {
        try {
          const body = await req.json() as { site: string };
          const config = await loadStoredApiKeys();

          if (body.site === 'danbooru') delete config.danbooru;
          if (body.site === 'gelbooru') delete config.gelbooru;
          if (body.site === 'rule34') delete config.rule34;
          if (body.site === 'e621') delete config.e621;
          if (body.site === 'civitai') delete config.civitai;

          await saveStoredApiKeys(config);
          return json({ success: true });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Download selected images with captions
      if (path === '/api/dataset/download-selected' && method === 'POST') {
        const startedAt = Date.now();
        try {
          const body = await req.json() as {
            dataset: string;
            images: Array<{ id: string; url: string; fullUrl?: string; tags?: string[] }>;
          };

          if (!body.dataset || !body.images || body.images.length === 0) {
            return json({ error: 'Dataset and images required' }, 400);
          }

          const datasetName = sanitizeDatasetSegment(body.dataset);
          if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
          const datasetPath = resolveDatasetPathSafe(datasetName);
          if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);
          if (!existsSync(datasetPath)) {
            await fs.mkdir(datasetPath, { recursive: true });
          }

          let downloaded = 0;
          let errors = 0;
          console.log(`[Download] Batch started dataset=${datasetName} images=${body.images.length}`);

          // Download each image and create caption file
          for (const img of body.images) {
            try {
              // Use fullUrl for download if available, otherwise fall back to preview url
              const downloadUrl = img.fullUrl || img.url;

              // Fetch the image with proper headers
              const response = await fetch(downloadUrl, {
                headers: { 'User-Agent': 'UmbraLab/1.0 (dataset-builder)' }
              });
              if (!response.ok) {
                console.error(`[Download] Failed to fetch ${downloadUrl}: ${response.status}`);
                errors++;
                continue;
              }

              // Determine file extension from URL or content-type
              const contentType = response.headers.get('content-type') || '';
              let ext = 'jpg';
              if (contentType.includes('png')) ext = 'png';
              else if (contentType.includes('webp')) ext = 'webp';
              else if (contentType.includes('gif')) ext = 'gif';
              else if (downloadUrl.match(/\.(png|jpg|jpeg|webp|gif)$/i)) {
                ext = downloadUrl.match(/\.(png|jpg|jpeg|webp|gif)$/i)![1].toLowerCase();
                if (ext === 'jpeg') ext = 'jpg';
              }

              const filename = `${img.id}.${ext}`;
              const imagePath = join(datasetPath, filename);
              const captionPath = join(datasetPath, `${img.id}.txt`);

              // Save image
              const buffer = await response.arrayBuffer();
              await fs.writeFile(imagePath, Buffer.from(buffer));

              // Save caption (tags joined with commas for training)
              if (img.tags && img.tags.length > 0) {
                // Format tags for training: replace underscores, join with commas
                const caption = img.tags
                  .map(tag => tag.replace(/_/g, ' '))
                  .join(', ');
                await fs.writeFile(captionPath, caption);
              }

              downloaded++;
            } catch (err) {
              console.error(`[Download] Error downloading ${img.id}:`, err);
              errors++;
            }
          }

          console.log(`[Download] Batch completed dataset=${datasetName} downloaded=${downloaded} errors=${errors} ms=${Date.now() - startedAt}`);
          return json({
            success: true,
            downloaded,
            errors,
            message: `Downloaded ${downloaded} images with captions`
          });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // Get available captioning models
      if (path === '/api/dataset/caption-models' && method === 'GET') {
        const models = [];

        // Multi-model captioning options.
        models.push({
          id: 'florence',
          name: 'Florence-2',
          description: 'Microsoft detailed captions',
          type: 'natural',
          color: 'emerald'
        });

        models.push({
          id: 'qwen',
          name: 'Qwen2-VL',
          description: 'Alibaba vision-language model',
          type: 'natural',
          color: 'orange'
        });

        models.push({
          id: 'joycaption',
          name: 'JoyCaption',
          description: 'Detailed creative captions',
          type: 'natural',
          color: 'pink'
        });

        return json({ models });
      }

      // Auto-caption images in dataset
      if (path === '/api/dataset/auto-caption' && method === 'POST') {
        try {
          const body = await req.json() as {
            dataset: string;
            method?: string;
            threshold?: number;
            selectedFiles?: string[];
            prependTags?: string;
          };
          if (!body.dataset) return json({ error: 'Dataset name required' }, 400);

          const datasetName = sanitizeDatasetSegment(body.dataset);
          if (!datasetName) return json({ error: 'Invalid dataset name' }, 400);
          const datasetPath = resolveDatasetPathSafe(datasetName);
          if (!datasetPath) return json({ error: 'Invalid dataset path' }, 400);
          if (!existsSync(datasetPath)) {
            return json({ error: 'Dataset not found' }, 404);
          }

          const captionMethod = body.method || 'florence';
          const selectedFiles = body.selectedFiles;
          const prependTags = body.prependTags;

          // Special method: just prepend tags to existing captions (no AI)
          if (captionMethod === 'prepend') {
            if (!prependTags) {
              return json({ error: 'Prepend tags required for prepend method' }, 400);
            }

            const files = await fs.readdir(datasetPath);
            const targetFiles = selectedFiles
              ? selectedFiles.filter(f => files.includes(f))
              : files.filter(f => /\.(jpg|jpeg|png|webp|bmp|gif)$/i.test(f));

            let processed = 0;
            for (const imgFile of targetFiles) {
              const captionPath = join(datasetPath, imgFile + '.txt');
              const altCaptionPath = join(datasetPath, imgFile.replace(/\.[^.]+$/, '.txt'));

              let actualPath = '';
              if (existsSync(captionPath)) {
                actualPath = captionPath;
              } else if (existsSync(altCaptionPath)) {
                actualPath = altCaptionPath;
              }

              if (actualPath) {
                try {
                  const content = await fs.readFile(actualPath, 'utf-8');
                  // Check if tags are already prepended
                  if (!content.startsWith(prependTags)) {
                    await fs.writeFile(actualPath, `${prependTags}, ${content}`);
                    processed++;
                  }
                } catch (e) {
                  console.error(`[Prepend] Failed to update ${imgFile}:`, e);
                }
              }
            }

            return json({
              success: true,
              message: `Prepended tags to ${processed} caption files`,
              method: 'prepend',
              processed
            });
          }

          if (captionMethod === 'florence' || captionMethod === 'qwen' || captionMethod === 'joycaption') {
            // Multi-model captioning (Florence, Qwen, JoyCaption)
            const multiModelScript = join(ROOT_DIR, 'Tools', 'caption_models.py');
            const pythonCandidate = getPythonCommandCandidates()[0];
            if (!pythonCandidate) {
              return json({ error: 'No Python runtime available for captioning' }, 500);
            }

            const args = [
              ...pythonCandidate.prefixArgs,
              multiModelScript,
              datasetPath,
              '--model', captionMethod,
              '--extension', '.txt',
              '--overwrite'
            ];

            // Add selected files if provided
            if (selectedFiles && selectedFiles.length > 0) {
              args.push('--files', selectedFiles.join(','));
            }

            // Add prepend tags if provided
            if (prependTags) {
              args.push('--prepend', prependTags);
            }

            console.log(`[Auto-Caption] Starting ${captionMethod} captioner:`, [pythonCandidate.command, ...args].join(' '));

            const captionProc = spawn(pythonCandidate.command, args, {
              cwd: ROOT_DIR,
              env: { ...process.env },
              stdio: ['ignore', 'pipe', 'pipe']
            });

            captionProc.stdout?.on('data', (data) => {
              broadcastToClients('caption_progress', { message: data.toString().trim() });
            });

            captionProc.stderr?.on('data', (data) => {
              broadcastToClients('caption_progress', { message: data.toString().trim() });
            });

            captionProc.on('exit', (code) => {
              broadcastToClients('caption_complete', { code, method: captionMethod });
            });

            return json({ success: true, message: `${captionMethod} captioning started`, method: captionMethod });
          } else {
            return json({ error: 'Unsupported caption method. Use: florence, qwen, joycaption, or prepend' }, 400);
          }
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }





      // ============================================
      // UMBRA UI AGENT PROMPT AUTHORING
      // ============================================
      if (path === '/api/umbra-ui/mcp') {
        if (isRemoteRequest(req, url, server)) {
          return json({ error: 'Umbra UI MCP is only available on the host machine.' }, 403);
        }
        return handleUmbraUiMcpHttp(req);
      }

      if (path === '/api/umbra-ui/agent/settings' && method === 'GET') {
        const guard = withRemoteAdminGuard(req, url, server);
        if (guard) return guard;
        try {
          await loadUmbraUiAgentInstructions();
          const settings = await loadUmbraUiAgentSettings();
          const endpoint = `http://127.0.0.1:${PORT}/api/umbra-ui/mcp`;
          return json({
            success: true,
            endpoint,
            token: settings.token,
            updatedAt: settings.updatedAt,
            hermesConfig: {
              mcp_servers: {
                umbra_ui: {
                  url: endpoint,
                  headers: { Authorization: `Bearer ${settings.token}` },
                },
              },
            },
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to load Umbra UI agent settings.' }, 500);
        }
      }

      if (path === '/api/umbra-ui/agent/settings/regenerate-token' && method === 'POST') {
        const guard = withRemoteAdminGuard(req, url, server);
        if (guard) return guard;
        try {
          const settings = await loadUmbraUiAgentSettings(true);
          return json({ success: true, token: settings.token, updatedAt: settings.updatedAt });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to regenerate the Umbra UI MCP token.' }, 500);
        }
      }

      if (path === '/api/umbra-ui/agent/context' && method === 'POST') {
        const guard = withRemoteAdminGuard(req, url, server);
        if (guard) return guard;
        try {
          const body = await req.json();
          umbraUiAgentContext = normalizeUmbraUiAgentContext(body);
          return json({ success: true, updatedAt: umbraUiAgentContext.updatedAt });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to update Umbra UI agent context.' }, 400);
        }
      }

      if (path === '/api/umbra-ui/agent/generate' && method === 'POST') {
        if (!isPublishedRemoteRequestAllowed(req, url, server)) {
          return json({ success: false, error: 'Agent prompt generation is available only to the host and trusted Umbra Remote clients.' }, 403);
        }
        const contentLength = Math.max(0, Number(req.headers.get('content-length')) || 0);
        if (contentLength > 100_000) return json({ success: false, error: 'Agent prompt request is too large.' }, 413);
        try {
          const result = await generateUmbraUiPromptWithHermes(await req.json());
          return json({ success: true, ...result });
        } catch (error: any) {
          const message = error?.message || 'Hermes failed to compose the prompt.';
          const status = /already composing/i.test(message) ? 409 : /required|must be|enter a prompt/i.test(message) ? 400 : 500;
          return json({ success: false, error: message }, status);
        }
      }

      if (path === '/api/umbra-ui/agent/drafts' && method === 'GET') {
        const guard = withRemoteAdminGuard(req, url, server);
        if (guard) return guard;
        return json({ success: true, drafts: listUmbraUiAgentDrafts() });
      }

      if (path.startsWith('/api/umbra-ui/agent/drafts/') && method === 'DELETE') {
        const guard = withRemoteAdminGuard(req, url, server);
        if (guard) return guard;
        const draftId = decodeURIComponent(path.slice('/api/umbra-ui/agent/drafts/'.length)).trim();
        if (!draftId) return json({ success: false, error: 'Draft id is required.' }, 400);
        const removed = umbraUiAgentDrafts.delete(draftId);
        return json({ success: true, removed });
      }

      // ============================================
      // APP SETTINGS API
      // ============================================
      if (path === '/api/user-config' && method === 'GET') {
        try {
          const key = url.searchParams.get('key');
          if (!resolveUserConfigPath(key)) {
            return json({ success: false, error: 'Unknown user config key' }, 400);
          }
          const value = await readUserConfigValue(key);
          return json({ success: true, key, value });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to load user config' }, 500);
        }
      }

      if (path === '/api/user-config' && method === 'POST') {
        try {
          const body = await req.json() as { key?: string; value?: unknown };
          const normalizedKey = String(body?.key || '').trim().toLowerCase();
          if (!resolveUserConfigPath(normalizedKey)) {
            return json({ success: false, error: 'Unknown user config key' }, 400);
          }
          let value = body.value ?? null;
          if (
            (normalizedKey === 'gallery-ui-session' || normalizedKey === 'remote-ui-session' || normalizedKey === 'powerprompter-ui')
            && value
            && typeof value === 'object'
          ) {
            const incomingUpdatedAt = Math.max(0, Math.floor(Number((value as Record<string, unknown>).updatedAt) || 0));
            const existing = await readUserConfigValue(normalizedKey) as Record<string, unknown> | null;
            const existingUpdatedAt = existing && typeof existing === 'object'
              ? Math.max(0, Math.floor(Number(existing.updatedAt) || 0))
              : 0;
            if (incomingUpdatedAt > 0 && existingUpdatedAt > incomingUpdatedAt) {
              return json({ success: true, key: normalizedKey, value: existing, stale: true });
            }
            if (normalizedKey === 'gallery-ui-session') {
              const incoming = value as Record<string, unknown>;
              const currentFolder = String(incoming.currentFolder || '').replace(/\\/g, '/').replace(/\/+$/, '').trim();
              const focusedFolder = String(incoming.focusedFolder || '').replace(/\\/g, '/').replace(/\/+$/, '').trim();
              const existingCurrentFolder = existing && typeof existing === 'object'
                ? String(existing.currentFolder || '').replace(/\\/g, '/').replace(/\/+$/, '').trim()
                : '';
              if (
                focusedFolder
                && currentFolder
                && focusedFolder !== currentFolder
                && existingCurrentFolder
                && currentFolder === existingCurrentFolder
              ) {
                value = {
                  ...incoming,
                  currentFolder: focusedFolder,
                };
              }
            }
          }
          await writeUserConfigValue(normalizedKey, value);
          broadcastUiSessionUpdate(normalizedKey, value);
          return json({ success: true, key: normalizedKey, value });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to save user config' }, 500);
        }
      }

      if (path === '/api/user-config' && method === 'DELETE') {
        try {
          const key = String(url.searchParams.get('key') || '').trim().toLowerCase();
          if (!resolveUserConfigPath(key)) {
            return json({ success: false, error: 'Unknown user config key' }, 400);
          }
          await deleteUserConfigValue(key);
          broadcastUiSessionUpdate(key, null);
          return json({ success: true, key });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to delete user config' }, 500);
        }
      }

      if (path === '/api/settings' && method === 'GET') {
        const currentSettings = settingsManager.getAppSettings();
        const portableSettings = normalizeGalleryAppSettingsForStorage(currentSettings);
        if (JSON.stringify(portableSettings) !== JSON.stringify(currentSettings)) {
          settingsManager.updateAppSettings(portableSettings);
        }
        return json({ settings: normalizeAppSettingsForClient(portableSettings) });
      }

      if (path === '/api/settings' && method === 'POST') {
        try {
          const body = await req.json() as { settings?: Record<string, unknown> } | Record<string, unknown>;
          const nextSettings = (body && typeof body === 'object' && !Array.isArray(body) && 'settings' in body)
            ? ((body as any).settings || {})
            : body;
          if (!nextSettings || typeof nextSettings !== 'object' || Array.isArray(nextSettings)) {
            return json({ error: 'Invalid settings payload' }, 400);
          }
          const mergedNextSettings = normalizeGalleryAppSettingsForStorage({
            ...nextSettings,
          } as Record<string, unknown>);

          settingsManager.updateAppSettings(mergedNextSettings);
          let comfySecurityResult: ComfySecurityApplyResult | undefined;
          if (Object.prototype.hasOwnProperty.call(mergedNextSettings, 'comfyui.securityLevel') ||
            Object.prototype.hasOwnProperty.call(mergedNextSettings, 'comfyui.path')) {
            comfySecurityResult = applyComfySecurityLevelSetting();
          }
          await saveUserSettingsBundleSnapshot({
            appSettings: settingsManager.getAppSettings(),
          });
          return json({
            success: true,
            settings: normalizeAppSettingsForClient(settingsManager.getAppSettings()),
            ...(comfySecurityResult ? { comfySecurity: comfySecurityResult } : {})
          });
        } catch (error: any) {
          return json({ error: error?.message || 'Failed to update settings' }, 500);
        }
      }

      if (path === '/api/settings/bundle' && method === 'GET') {
        try {
          const bundle = await loadUserSettingsBundleSnapshot();
          return json({ success: true, bundle });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to load settings bundle' }, 500);
        }
      }

      if (path === '/api/settings/bundle' && method === 'POST') {
        try {
          const body = await req.json() as { bundle?: unknown } | Record<string, unknown>;
          const rawBundle = (body && typeof body === 'object' && !Array.isArray(body) && 'bundle' in body)
            ? (body as any).bundle
            : body;
          const currentBundle = await loadUserSettingsBundleSnapshot();
          const nextBundle = normalizeUmbraUserSettingsBundle(rawBundle, currentBundle);

          const portableBundleAppSettings = normalizeGalleryAppSettingsForStorage(nextBundle.appSettings);
          settingsManager.updateAppSettings(portableBundleAppSettings);
          nextBundle.appSettings = portableBundleAppSettings;
          await savePPSettings(nextBundle.powerPrompterSettings);

          let comfySecurityResult: ComfySecurityApplyResult | undefined;
          if (
            Object.prototype.hasOwnProperty.call(nextBundle.appSettings, 'comfyui.securityLevel') ||
            Object.prototype.hasOwnProperty.call(nextBundle.appSettings, 'comfyui.path')
          ) {
            comfySecurityResult = applyComfySecurityLevelSetting();
          }

          const savedBundle = await saveUserSettingsBundleSnapshot(nextBundle);
          return json({
            success: true,
            bundle: savedBundle,
            settings: settingsManager.getAppSettings(),
            ...(comfySecurityResult ? { comfySecurity: comfySecurityResult } : {}),
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to import settings bundle' }, 500);
        }
      }

      if (path === '/api/app/update/status' && method === 'GET') {
        try {
          const refresh = url.searchParams.get('refresh') === 'true';
          const status = await getUmbraAppGitStatus({ refresh });
          return json({ success: true, ...status });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to check update status' }, 500);
        }
      }

      if (path === '/api/app/update/run' && method === 'POST') {
        if (isRemoteRequest(req, url, server)) {
          return json({ success: false, error: 'Umbra updates are only available from the host PC.' }, 403);
        }
        try {
          const status: any = await getUmbraAppGitStatus({ refresh: true });

          if (status.updaterMode === 'release') {
            if (!status.updateSourceReady || !status.packageUrl || !status.latestVersion) {
              return json({
                success: false,
                error: status.message || 'Release update feed is not configured or not ready.',
                status,
              }, 400);
            }

            if (!status.needsUpdate) {
              return json({
                success: true,
                output: 'Umbra Studio is already on the latest release channel version.',
                status,
              });
            }

            const backupPath = await createAppUpdateSafetyBackup(status);
            const manifest: ReleaseManifest = {
              version: String(status.latestVersion),
              packageUrl: String(status.packageUrl),
              channel: status.releaseChannel === 'beta' ? 'beta' : 'stable',
              notes: typeof status.releaseNotes === 'string' ? status.releaseNotes : undefined,
              publishedAt: typeof status.publishedAt === 'string' ? status.publishedAt : undefined,
              releaseNotesUrl: typeof status.releaseNotesUrl === 'string' ? status.releaseNotesUrl : undefined,
              packageName: typeof status.packageName === 'string' ? status.packageName : undefined,
              feedUrl: typeof status.releaseFeedResolvedUrl === 'string' ? status.releaseFeedResolvedUrl : String(status.releaseFeedUrl || ''),
              sha256: typeof status.sha256 === 'string' ? status.sha256 : undefined,
            };
            const staged = await stageReleaseUpdatePackage(manifest, status);
            const nextStatus: any = await getUmbraAppGitStatus({ refresh: true });
            return json({
              success: true,
              output: `Downloaded Umbra Studio ${manifest.version} to a protected staging folder. Review the staged package and apply it without replacing User/ or Tools/.`,
              backupPath,
              stagingPath: staged.stagingDir,
              packagePath: staged.packagePath,
              manifestPath: staged.metadataPath,
              instructionsPath: staged.instructionsPath,
              packageSha256: staged.packageSha256,
              status: nextStatus,
            });
          }

          if (!status.gitInstalled) {
            return json({ success: false, error: 'Git is required to update Umbra Studio.' }, 400);
          }
          if (!status.repoDetected) {
            return json({ success: false, error: 'Update source is not configured for this Umbra Studio installation.' }, 400);
          }
          if (!status.trackingBranch) {
            return json({
              success: false,
              error: 'Update source is not fully configured. Reinstall or relink your Umbra Studio update source.',
              status,
            }, 400);
          }
          if (!status.clean) {
            return json({
              success: false,
              error: 'Working tree has uncommitted changes. Commit or stash changes before updating.',
              status,
            }, 409);
          }

          const backupPath = await createAppUpdateSafetyBackup(status);
          const pull = await runGitCommand(['pull', '--ff-only']);
          const nextStatus: any = await getUmbraAppGitStatus({ refresh: false });

          if (!pull.ok) {
            return json({
              success: false,
              error: pull.stderr || 'git pull failed',
              output: pull.stdout,
              backupPath,
              status: nextStatus,
            }, 500);
          }

          return json({
            success: true,
            output: pull.stdout,
            backupPath,
            status: nextStatus,
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to update Umbra Studio' }, 500);
        }
      }

      // ============================================
      // POWER PROMPTER API
      // ============================================
      if (path === '/api/powerprompter/search' && method === 'GET') {
        const q = url.searchParams.get('q') || '';
        const page = parseInt(url.searchParams.get('page') || '0');
        const limit = parseInt(url.searchParams.get('limit') || '100');
        const csvs = (url.searchParams.get('csvs')?.split(',') || [])
          .map((entry) => String(entry || '').trim())
          .filter((entry) => entry.length > 0);
        const scope = url.searchParams.get('scope') || 'scoped';
        const cardType = url.searchParams.get('cardType') || '';
        const fast = url.searchParams.get('fast') || '';
        if (ppIndex.length === 0 && !ppIndexingPromise) {
          void indexPowerPrompterCSVs().catch((error) => {
            console.warn('[PowerPrompter] Lazy index warning:', error);
          });
        }
        return json(searchPP(q, page, limit, csvs, { scope, cardType, fast }));
      }

      if (path === '/api/powerprompter/api-workflows' && method === 'GET') {
        const items = await listPPApiWorkflows();
        return json({ success: true, items });
      }

      if (path === '/api/umbra-ui/pipelines' && method === 'GET') {
        const pipelines = await listUmbraUiPipelines();
        return json({
          success: true,
          autoPipelineId: UMBRA_UI_AUTO_PIPELINE_ID,
          pipelines,
        });
      }

      if (path === '/api/umbra-ui/pipelines/resolve' && method === 'GET') {
        try {
          const resolved = await resolveUmbraUiPipeline(
            url.searchParams.get('feature'),
            url.searchParams.get('modelFamily'),
            url.searchParams.get('modelSource'),
          );
          return json({ success: true, pipeline: resolved.pipeline, item: resolved.loaded.item });
        } catch (error: any) {
          return json({ success: false, error: String(error?.message || error || 'Failed to resolve the Umbra UI pipeline.') }, 400);
        }
      }

      if (path === '/api/umbra-ui/video-controls' && method === 'GET') {
        return json({ success: true, video: getUmbraUiVideoControlsSession() });
      }

      if (path === '/api/umbra-ui/video-controls' && (method === 'PUT' || method === 'POST')) {
        try {
          const body = await req.json() as { video?: unknown };
          const video = saveUmbraUiVideoControlsSession(body?.video);
          return json({ success: true, video });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to save Umbra UI video controls.' }, 400);
        }
      }

      if (path === '/api/umbra-ui/video-jobs' && method === 'GET') {
        return json({
          success: true,
          jobs: await listUmbraUiVideoReviewJobs(url.searchParams.get('limit')),
        });
      }

      if (path === '/api/umbra-ui/video-jobs' && method === 'DELETE') {
        const id = url.searchParams.get('id');
        if (!id) return json({ success: false, error: 'Video job id is required.' }, 400);
        return json({ success: true, removed: await deleteUmbraUiVideoReviewJob(id) });
      }

      if (path === '/api/umbra-ui/catalog' && method === 'GET') {
        return handleUmbraUiCatalog(url);
      }

      if (path === '/api/umbra-ui/catalog/info' && method === 'GET') {
        return handleUmbraUiCatalogInfo(url);
      }

      if (path === '/api/umbra-ui/upscale' && method === 'POST') {
        return handleUmbraUiUpscaleSubmit(req, isHostRequest(req, url, server));
      }

      if (path === '/api/umbra-ui/upscale/browse-output-folder' && method === 'POST') {
        if (!isHostRequest(req, url, server)) {
          return json({ error: 'Native folder selection is only available from the host PC.' }, 403);
        }
        return handleNativeFolderBrowse(req, 'Select Upscale Output Folder');
      }

      if (path === '/api/umbra-ui/upscale/stage' && method === 'POST') {
        return handleUmbraUiUpscaleStage(req);
      }

      if (path === '/api/umbra-ui/upscale/stage/cleanup' && method === 'POST') {
        return handleUmbraUiUpscaleStageCleanup(req);
      }

      if (path === '/api/umbra-ui/inpaint' && method === 'POST') {
        return handleUmbraUiInpaintSubmit(req);
      }

      if (path === '/api/umbra-ui/inpaint/control-preprocess' && method === 'POST') {
        return handleUmbraUiControlPreprocess(req);
      }

      if (path === '/api/umbra-ui/inpaint/layer-upscale' && method === 'POST') {
        return handleUmbraUiLayerUpscale(req);
      }

      if (path === '/api/umbra-ui/inpaint/remove-background' && method === 'POST') {
        return handleUmbraUiBackgroundRemoval(req);
      }

      if (path === '/api/umbra-ui/canvas/save' && method === 'POST') {
        return handleUmbraUiCanvasSave(req);
      }

      if (path === '/api/umbra-ui/image/replace-source' && method === 'POST') {
        return handleUmbraUiReplaceImageSource(req);
      }

      if (path === '/api/umbra-ui/inpaint/models' && method === 'GET') {
        const objectInfo = await getPPComfyObjectInfoForValidation();
        const nodeTypes = new Set(Object.keys(objectInfo || {}));
        return json({
          success: true,
          verified: !!objectInfo,
          models: listUmbraUiInpaintModels(),
          features: {
            modelInfill: nodeTypes.has('INPAINT_LoadInpaintModel') && nodeTypes.has('INPAINT_InpaintWithModel'),
            maskedFill: nodeTypes.has('INPAINT_MaskedFill'),
            maskExpand: nodeTypes.has('INPAINT_ExpandMask'),
            colorMatch: nodeTypes.has('INPAINT_ColorMatch'),
            differentialDiffusion: nodeTypes.has('DifferentialDiffusion'),
            softInpaintComposite: nodeTypes.has('UmbraSoftInpaintComposite'),
            colorPrefill: nodeTypes.has('EmptyImage'),
            tilePrefill: nodeTypes.has('UmbraTileInfill'),
            seamless: nodeTypes.has('UmbraSeamlessTiling'),
            maskedOutput: nodeTypes.has('InvertMask') && nodeTypes.has('JoinImageWithAlpha'),
            backgroundRemoval: nodeTypes.has('Image Rembg (Remove Background)'),
            semanticCutout: nodeTypes.has('Image Rembg (Remove Background)')
              && nodeTypes.has('SplitImageWithAlpha')
              && nodeTypes.has('MaskComposite')
              && nodeTypes.has('InvertMask')
              && nodeTypes.has('JoinImageWithAlpha'),
          },
        });
      }

      if (path === '/api/umbra-ui/inpaint/projects' && method === 'GET') {
        return handleUmbraUiInpaintProjectList();
      }

      if (path.startsWith('/api/umbra-ui/inpaint/projects/')) {
        const projectSuffix = path.slice('/api/umbra-ui/inpaint/projects/'.length);
        const assetMarker = '/assets/';
        const assetIndex = projectSuffix.indexOf(assetMarker);
        if (assetIndex > 0 && method === 'GET') {
          return handleUmbraUiInpaintProjectAsset(
            decodeURIComponent(projectSuffix.slice(0, assetIndex)),
            decodeURIComponent(projectSuffix.slice(assetIndex + assetMarker.length)),
            url.searchParams.get('thumb') === '1',
          );
        }
        const projectSegments = projectSuffix.split('/').filter(Boolean).map((segment) => decodeURIComponent(segment));
        if (projectSegments.length >= 2 && projectSegments[1] === 'snapshots') {
          const projectId = projectSegments[0];
          if (projectSegments.length === 2 && method === 'GET') return handleUmbraUiInpaintProjectSnapshotList(projectId);
          if (projectSegments.length === 2 && method === 'POST') return handleUmbraUiInpaintProjectSnapshotCreate(req, projectId);
          if (projectSegments.length === 3 && method === 'DELETE') return handleUmbraUiInpaintProjectSnapshotDelete(projectId, projectSegments[2]);
          if (projectSegments.length === 4 && projectSegments[3] === 'restore' && method === 'POST') {
            return handleUmbraUiInpaintProjectSnapshotRestore(projectId, projectSegments[2]);
          }
          return json({ success: false, error: 'Unsupported canvas restore-point operation.' }, 405);
        }
        const projectId = decodeURIComponent(projectSuffix).trim();
        if (method === 'GET') return handleUmbraUiInpaintProjectGet(projectId);
        if (method === 'PUT' || method === 'POST') return handleUmbraUiInpaintProjectSave(req, projectId);
        if (method === 'DELETE') return handleUmbraUiInpaintProjectDelete(projectId);
      }

      if (path === '/api/umbra-ui/inpaint/jobs' && method === 'GET') {
        return json({ success: true, jobs: umbraUiInpaintService.listJobs() });
      }

      if (path.startsWith('/api/umbra-ui/inpaint/jobs/') && method === 'GET') {
        return handleUmbraUiInpaintJob(path);
      }

      if (path.startsWith('/api/umbra-ui/inpaint/jobs/') && path.endsWith('/cancel') && method === 'POST') {
        return handleUmbraUiInpaintJobCancel(path);
      }

      if (path === '/api/umbra-ui/upscale/jobs' && method === 'GET') {
        return json({ success: true, jobs: umbraUiUpscaleService.listJobs() });
      }

      if (path.startsWith('/api/umbra-ui/upscale/jobs/') && method === 'GET') {
        return handleUmbraUiUpscaleJob(path);
      }

      if (path === '/api/powerprompter/api-workflows/open' && method === 'GET') {
        const workflowId = url.searchParams.get('id') || url.searchParams.get('workflowId') || '';
        let loaded: LoadedPPApiWorkflow | null = null;
        try {
          if (parsePPApiWorkflowId(workflowId) === UMBRA_UI_AUTO_PIPELINE_ID) {
            const resolved = await resolveUmbraUiPipeline(
              url.searchParams.get('feature') || 'txt2img',
              url.searchParams.get('modelFamily'),
              url.searchParams.get('modelSource') || 'checkpoint',
            );
            loaded = resolved.loaded;
          } else {
            loaded = await loadPPApiWorkflowById(workflowId);
          }
        } catch (error: any) {
          return json({ success: false, error: String(error?.message || error || 'Failed to resolve the API workflow.') }, 400);
        }
        if (!loaded) {
          return json({ success: false, error: 'API workflow was not found.' }, 404);
        }
        return json({
          success: true,
          item: loaded.item,
          document: loaded.document,
        });
      }

      if (path === '/api/powerprompter/api-workflows/import' && method === 'POST') {
        try {
          const formData = await req.formData();
          const file = formData.get('file');
          if (!(file instanceof File)) {
            return json({ success: false, error: 'Missing workflow file upload.' }, 400);
          }

          const rawName = String(file.name || 'api-workflow').trim();
          const baseName = sanitizePPApiWorkflowBaseName(rawName);
          const rawText = await file.text();
          let parsed: unknown = null;
          try {
            parsed = JSON.parse(rawText);
          } catch {
            return json({ success: false, error: 'Invalid JSON file.' }, 400);
          }

          const objectInfo = await getPPComfyObjectInfoForValidation();
          const validation = validatePPApiWorkflowDocument(
            parsed,
            objectInfo ? new Set(Object.keys(objectInfo)) : null,
          );
          if (!validation.ok) {
            return json({
              success: false,
              error: `Workflow is not compatible.${validation.missing.length > 0 ? ` Missing: ${validation.missing.join(', ')}` : ''}`,
            }, 400);
          }

          ensurePPApiWorkflowDirSync();
          const baseFileName = `${baseName}.json`;
          let finalFileName = baseFileName;
          let attempt = 1;
          while (existsSync(join(PP_API_WORKFLOWS_DIR, finalFileName))) {
            finalFileName = `${baseName} (${attempt}).json`;
            attempt += 1;
          }
          const fullPath = join(PP_API_WORKFLOWS_DIR, finalFileName);
          await fs.writeFile(fullPath, JSON.stringify(parsed, null, 2), 'utf-8');

          const loaded = await loadPPApiWorkflowById(finalFileName);
          if (!loaded) {
            return json({ success: false, error: 'Imported workflow could not be loaded.' }, 500);
          }

          return json({
            success: true,
            item: loaded.item,
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to import API workflow.' }, 500);
        }
      }

      if (path === '/api/powerprompter/settings' && method === 'GET') {
        return json(await loadPPSettings());
      }

      if (path === '/api/powerprompter/settings' && method === 'POST') {
        const settings = await req.json() as PowerPrompterSettings;
        await savePPSettings(settings);
        await saveUserSettingsBundleSnapshot({
          powerPrompterSettings: normalizePPSettingsPayload(settings),
        });
        return json({ success: true });
      }

      if (path === '/api/powerprompter/queue-prompts/build' && method === 'POST') {
        const startedAt = Date.now();
        try {
          const body = await req.json().catch(() => ({})) as {
            file?: unknown;
            document?: unknown;
            mode?: unknown;
            options?: unknown;
          };
          const rawFile = String(body?.file || '').trim().replace(/\\/g, '/');
          const rawMode = String(body?.mode || '').trim();
          const mode: PowerPrompterQueueMode = rawMode === 'prompt' || rawMode === 'variants' ? rawMode : 'selected';

          let document: PowerPrompterCardDocument | null = null;
          if (body?.document && typeof body.document === 'object') {
            const documentFile = String((body.document as any)?.file || rawFile || '').trim().replace(/\\/g, '/') || null;
            document = normalizePPCardDocument(body.document, documentFile);
          } else if (rawFile) {
            const loaded = await loadPPCardDocumentForFile(rawFile);
            document = normalizePPCardDocument(loaded.document, loaded.document.file || rawFile);
          } else {
            const session = await ensurePowerPrompterDocumentSession(null);
            document = session.document
              ? normalizePPCardDocument(session.document, session.file)
              : null;
          }

          if (!document) {
            return json({ success: false, error: 'No Power Prompter document is open.' }, 400);
          }

          const options = body?.options && typeof body.options === 'object' && !Array.isArray(body.options)
            ? body.options as Record<string, unknown>
            : {};
          const result = buildQueuePromptsFromCards(document as any, mode as any, options as any);
          return json({
            success: true,
            result,
            source: 'backend',
            durationMs: Date.now() - startedAt,
          });
        } catch (error: any) {
          return json({
            success: false,
            error: error?.message || 'Failed to build queue prompts.',
            durationMs: Date.now() - startedAt,
          }, 400);
        }
      }

      if (path === '/api/powerprompter/queue-state' && method === 'GET') {
        return json({
          success: false,
          snapshot: null,
          error: 'Power Prompter queue-state snapshots have been removed. Use /api/powerprompter/backend-queue-debug for live backend queue state.',
          revision: ppQueueStateRevision,
        }, 410);
      }

      if (path === '/api/powerprompter/backend-queue-debug' && method === 'GET') {
        return json({
          success: true,
          queuedWork: backendPowerPrompterQueuedWork.map((entry, index) => ({
            index,
            requestId: entry.requestId,
            promptCount: entry.prompts.length,
            apiWorkflowId: entry.loaded.item.id,
            apiWorkflowName: entry.loaded.item.name,
          })),
          activeTasks: Array.from(backendPowerPrompterQueueTasks.entries()).map(([requestId, task]) => ({
            requestId,
            promptCount: task.prompts.length,
            activePromptIndex: task.activePromptIndex,
            canceled: task.canceled,
            stopAfterCurrent: task.stopAfterCurrent,
          })),
          controller: {
            version: powerPrompterQueueControllerState.version,
            activeRequestId: powerPrompterQueueControllerState.activeRequestId,
            activePromptIndex: powerPrompterQueueControllerState.activePromptIndex,
            paused: powerPrompterQueueControllerState.paused,
            requests: powerPrompterQueueControllerState.requests.map((request) => ({
              requestId: request.requestId,
              status: request.status,
              total: request.total,
              completed: request.completed,
              failed: request.failed,
              canceled: request.canceled,
              activeIndex: request.activeIndex,
              prompts: request.prompts.map((prompt) => ({
                promptIndex: prompt.promptIndex,
                status: prompt.status,
                setId: prompt.setId,
                promptId: prompt.promptId,
              })),
            })),
          },
          updatedAt: Date.now(),
        });
      }

      if (path === '/api/powerprompter/queue-state' && method === 'POST') {
        await clearPPQueueSnapshot();
        return json({
          success: false,
          snapshot: null,
          error: 'Power Prompter queue-state snapshots have been removed.',
          revision: ppQueueStateRevision,
        }, 410);
      }

      if (path === '/api/powerprompter/queue-state' && method === 'DELETE') {
        await clearPPQueueSnapshot();
        return json({
          success: true,
          snapshot: null,
          deleted: true,
          revision: ppQueueStateRevision,
        });
      }

      if (path === '/api/powerprompter/queue/mutate' && method === 'POST') {
        try {
          const body = await req.json().catch(() => ({})) as {
            op?: unknown;
            promptRemovals?: Array<{ requestId?: unknown; promptIndices?: unknown }>;
            requestId?: unknown;
            replacement?: unknown;
            group?: unknown;
          };
          const op = String(body?.op || '').trim();
          if (op === 'replace_group') {
            const requestId = String(body?.requestId || '').trim();
            if (!requestId) {
              return json({ success: false, error: 'Queue group request id is required.' }, 400);
            }
            const runtimeUpdate = await replacePersistedPPQueueGroup(requestId, body?.replacement, null);
            if (runtimeUpdate.runtimeUpdated) {
              refreshBackendPowerPrompterQueuedWorkFromController(requestId);
              return json({
                success: true,
                snapshot: null,
                requestId,
                replacementRequestId: requestId,
                promptCount: runtimeUpdate.promptCount,
                runtimeUpdated: true,
                lockedPromptCount: runtimeUpdate.lockedPromptCount,
                request: runtimeUpdate.request
                  ? {
                      ...runtimeUpdate.request,
                      prompts: runtimeUpdate.request.prompts.map((prompt) => ({ ...prompt })),
                    }
                  : null,
                revision: ppQueueStateRevision,
              });
            }
            return json({
              success: false,
              error: 'This queue group is no longer available in the backend queue. Reopen the queue editor from the current Queue Manager state.',
              staleQueueEditor: true,
              revision: ppQueueStateRevision,
            }, 409);
          }
          if (op === 'add_group') {
            const requestId = String(body?.requestId || '').trim();
            if (!requestId) {
              return json({ success: false, error: 'Source queue group request id is required.' }, 400);
            }
            const added = await addPowerPrompterQueueControllerGroup(requestId, body?.group, null);
            return json({
              success: true,
              snapshot: null,
              sourceRequestId: requestId,
              requestId: added.request.requestId,
              promptCount: added.promptCount,
              runtimeUpdated: true,
              request: added.request,
              sourceCleanup: added.sourceCleanup,
              revision: ppQueueStateRevision,
            });
          }
          if (op !== 'remove_prompts') {
            return json({ success: false, error: 'Unsupported queue mutation.' }, 400);
          }
          const promptRemovals = Array.isArray(body?.promptRemovals)
            ? body.promptRemovals
              .map((entry) => ({
                requestId: String(entry?.requestId || '').trim(),
                promptIndices: Array.isArray(entry?.promptIndices)
                  ? Array.from(new Set(
                    entry.promptIndices
                      .map((value: unknown) => Number(value))
                      .filter((value: number) => Number.isFinite(value))
                      .map((value: number) => Math.max(0, Math.floor(value)))
                  )).sort((a, b) => a - b)
                  : [],
              }))
              .filter((entry) => entry.requestId && entry.promptIndices.length > 0)
            : [];
          if (promptRemovals.length <= 0) {
            return json({ success: false, error: 'No queue prompts were selected.' }, 400);
          }
          const runtimeResult = applyPowerPrompterQueueControllerPromptRemovals({ promptRemovals }, null);
          if (runtimeResult.affectedRequestIds.length > 0 || runtimeResult.removedRequestIds.length > 0) {
            return json({
              success: true,
              snapshot: null,
              removedRequestIds: runtimeResult.removedRequestIds,
              promptRemovals: runtimeResult.promptRemovals,
              runtimeUpdated: true,
              revision: ppQueueStateRevision,
            });
          }
          return json({
            success: false,
            error: 'No matching backend queue prompts were available to remove.',
            removedRequestIds: [],
            promptRemovals: [],
            revision: ppQueueStateRevision,
          }, 409);
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to mutate queue.' }, 400);
        }
      }

      if (path === '/api/powerprompter/queues' && method === 'GET') {
        const id = url.searchParams.get('id') || '';
        if (id) {
          const document = await loadPPSavedQueue(id);
          if (!document) return json({ success: false, error: 'Saved queue not found.' }, 404);
          return json({ success: true, item: document });
        }
        return json({ success: true, items: await listPPSavedQueues() });
      }

      if (path === '/api/powerprompter/queues' && method === 'POST') {
        const body = await req.json() as { name?: unknown; snapshot?: unknown };
        const document = await savePPSavedQueue(body?.name, body?.snapshot);
        if (!document) {
          return json({ success: false, error: 'Queue snapshot did not contain any prompts.' }, 400);
        }
        return json({ success: true, item: document });
      }

      if (path === '/api/powerprompter/queues' && method === 'DELETE') {
        const id = url.searchParams.get('id') || '';
        if (!id) return json({ success: false, error: 'id is required' }, 400);
        const deleted = await deletePPSavedQueue(id);
        return json({ success: true, deleted });
      }

      if (path === '/api/powerprompter/queue-history' && method === 'GET') {
        const id = url.searchParams.get('id') || '';
        if (id) {
          const document = await loadPPQueueHistory(id);
          if (!document) return json({ success: false, error: 'Queue history item not found.' }, 404);
          return json({ success: true, item: document });
        }
        return json({ success: true, items: await listPPQueueHistory() });
      }

      if (path === '/api/powerprompter/queue-history' && method === 'POST') {
        const body = await req.json() as { name?: unknown; snapshot?: unknown; status?: unknown; previewImages?: unknown };
        const document = await savePPQueueHistory(body?.name, body?.snapshot, body?.status, body?.previewImages);
        if (!document) {
          return json({ success: false, error: 'Queue history snapshot did not contain any prompts.' }, 400);
        }
        return json({ success: true, item: document });
      }

      if (path === '/api/powerprompter/queue-history' && method === 'PATCH') {
        const id = url.searchParams.get('id') || '';
        if (!id) return json({ success: false, error: 'id is required' }, 400);
        const body = await req.json().catch(() => ({}));
        const document = await updatePPQueueHistory(id, body);
        if (!document) return json({ success: false, error: 'Queue history item not found.' }, 404);
        return json({ success: true, item: document });
      }

      if (path === '/api/powerprompter/queue-history' && method === 'DELETE') {
        const id = url.searchParams.get('id') || '';
        if (!id) return json({ success: false, error: 'id is required' }, 400);
        const deleted = await deletePPQueueHistory(id);
        return json({ success: true, deleted });
      }

      if (path === '/api/powerprompter/diagnostics-log' && method === 'POST') {
        if (!isBackendDiagnosticLoggingEnabled()) return json({ success: true, skipped: true });
        const body = await req.json().catch(() => ({})) as {
          event?: unknown;
          seq?: unknown;
          at?: unknown;
          detail?: unknown;
          snapshot?: unknown;
        };
        const eventName = String(body?.event || 'powerprompter:diagnostic').trim().slice(0, 160);
        appendPowerPrompterDiagnosticsLog(eventName || 'powerprompter:diagnostic', {
          seq: Math.max(0, Math.floor(Number(body?.seq) || 0)),
          clientAt: String(body?.at || '').trim(),
          detail: body?.detail && typeof body.detail === 'object' ? body.detail as Record<string, unknown> : {},
          snapshot: body?.snapshot && typeof body.snapshot === 'object' ? body.snapshot as Record<string, unknown> : {},
          userAgent: req.headers.get('user-agent') || '',
        });
        return json({ success: true });
      }

      if (path === '/api/powerprompter/selections' && method === 'GET') {
        const file = normalizePPSelectionFileKey(url.searchParams.get('file') || '');
        if (!file) return json({ error: 'file is required' }, 400);

        const selections = await loadPPSelections();
        const hasStoredSelection = Object.prototype.hasOwnProperty.call(selections, file);
        const activeIndices = sanitizePPSelectionIndices(selections[file] || []);
        return json({ file, activeIndices, hasStoredSelection });
      }

      if (path === '/api/powerprompter/selections' && method === 'POST') {
        const body = await req.json() as { file?: string; activeIndices?: unknown };
        const file = normalizePPSelectionFileKey(body?.file || '');
        if (!file) return json({ error: 'file is required' }, 400);

        const selections = await loadPPSelections();
        selections[file] = sanitizePPSelectionIndices(body?.activeIndices);
        await savePPSelections(selections);
        return json({ success: true, file, activeIndices: selections[file], hasStoredSelection: true });
      }

      if (path === '/api/powerprompter/cards' && method === 'GET') {
        const file = String(url.searchParams.get('file') || '').trim();
        if (!file) return json({ error: 'file is required' }, 400);

        try {
          const loaded = await loadPPCardDocumentForFile(file);
          return json({
            success: true,
            document: loaded.document,
            fromSidecar: loaded.fromSidecar,
            healed: loaded.healed,
            composedPrompt: composePPPromptFromCards(loaded.document.cards),
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to load card document' }, 400);
        }
      }

      if (path === '/api/powerprompter/session' && method === 'GET') {
        try {
          const file = String(url.searchParams.get('file') || '').trim();
          await ensurePowerPrompterDocumentSession(file || null);
          return json({ success: true, ...clonePowerPrompterDocumentSession(file ? 'document_requested' : 'session_requested') });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to load Power Prompter session' }, 400);
        }
      }

      if (path === '/api/powerprompter/session/open' && method === 'POST') {
        try {
          const body = await req.json() as { file?: string; clientId?: string };
          const file = String(body?.file || '').trim();
          if (!file) return json({ success: false, error: 'file is required' }, 400);
          await openPowerPrompterDocumentSession(file, {
            sourceClientId: String(body?.clientId || '').trim(),
            reason: 'document_opened',
          });
          return json({ success: true, ...clonePowerPrompterDocumentSession('document_opened') });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to open Power Prompter session' }, 400);
        }
      }

      if (path === '/api/powerprompter/session' && method === 'PATCH') {
        try {
          const body = await req.json() as {
            file?: string;
            document?: unknown;
            save?: boolean;
            intent?: string;
            clientId?: string;
            forceOverwrite?: boolean;
          };
          const file = String(body?.file || '').trim();
          if (!file) return json({ success: false, error: 'file is required' }, 400);
          await updatePowerPrompterDocumentSession(file, body?.document, {
            save: body?.save === true,
            intent: String(body?.intent || (body?.save === true ? 'session-autosave' : 'session-update')).trim(),
            sourceClientId: String(body?.clientId || '').trim(),
            forceOverwrite: body?.forceOverwrite === true,
            reason: body?.save === true ? 'document_saved' : 'document_updated',
          });
          return json({ success: true, ...clonePowerPrompterDocumentSession(body?.save === true ? 'document_saved' : 'document_updated') });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to update Power Prompter session' }, 400);
        }
      }

      if (path === '/api/powerprompter/session' && method === 'DELETE') {
        try {
          const clientId = String(url.searchParams.get('clientId') || '').trim();
          await clearPowerPrompterDocumentSession({ sourceClientId: clientId, reason: 'document_cleared' });
          return json({ success: true, ...clonePowerPrompterDocumentSession('document_cleared') });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to clear Power Prompter session' }, 400);
        }
      }

      if (path === '/api/powerprompter/cards' && method === 'POST') {
        const body = await req.json() as { file?: string; document?: unknown; forceOverwrite?: boolean; intent?: string };
        const file = String(body?.file || '').trim();
        if (!file) return json({ error: 'file is required' }, 400);
        const intent = String(body?.intent || '').trim();
        const allowedIntents = new Set(['editor-save', 'editor-autosave', 'create-card', 'sidebar-card-operation']);
        if (!allowedIntents.has(intent)) {
          return json({
            success: false,
            error: 'Card document saves require an explicit editor/sidebar intent.',
          }, 400);
        }

        try {
          const saved = await savePPCardDocumentForFile(file, body?.document, { forceOverwrite: body?.forceOverwrite === true });
          return json({
            success: true,
            document: saved,
            composedPrompt: composePPPromptFromCards(saved.cards),
          });
        } catch (error: any) {
          return json({ success: false, error: error?.message || 'Failed to save card document' }, 400);
        }
      }

      if (path === '/api/powerprompter/csv/list' && method === 'GET') {
        const tags = existsSync(PP_CSV_TAGS_DIR) ? readdirSync(PP_CSV_TAGS_DIR).filter(f => f.endsWith('.csv')) : [];
        const chars = existsSync(PP_CSV_CHARS_DIR) ? readdirSync(PP_CSV_CHARS_DIR).filter(f => f.endsWith('.csv')) : [];
        return json({ tags, characters: chars });
      }

      if (path === '/api/powerprompter/index' && method === 'POST') {
        await indexPowerPrompterCSVs();
        return json({ success: true, count: ppIndex.length });
      }

      // Favorites endpoints
      if (path === '/api/powerprompter/favorites' && method === 'GET') {
        const favorites = await loadPPFavorites();
        return json({ favorites });
      }

      if (path === '/api/powerprompter/favorites' && method === 'POST') {
        const body = await req.json() as PPFavorite;
        const favorites = await loadPPFavorites();

        // Check if already exists
        const exists = favorites.some(f => f.tag === body.tag && f.type === body.type);
        if (exists) {
          return json({ success: false, error: 'Already favorited' }, 400);
        }

        favorites.push({
          tag: body.tag,
          category: body.category,
          extra: body.extra,
          type: body.type,
          addedAt: Date.now()
        });

        await savePPFavorites(favorites);
        return json({ success: true, favorites });
      }

      if (path === '/api/powerprompter/favorites' && method === 'DELETE') {
        const body = await req.json() as { tag: string; type: string };
        const favorites = await loadPPFavorites();

        const newFavorites = favorites.filter(f => !(f.tag === body.tag && f.type === body.type));
        await savePPFavorites(newFavorites);

        return json({ success: true, favorites: newFavorites });
      }

      // ============================================
      // METADATA API
      // ============================================
      if (path === '/api/metadata/scan' && method === 'POST') {
        try {
          const body = await req.json() as { path: string };
          if (!body.path) return json({ error: 'Path required' }, 400);

          let fullPath = body.path;
          if (!isAbsolute(body.path)) {
            fullPath = join(USER_DIR, body.path);
            if (!existsSync(fullPath)) fullPath = join(ROOT_DIR, body.path);
          }

          if (!existsSync(fullPath)) return json({ error: 'File not found', path: fullPath }, 404);

          const stats = statSync(fullPath);
          if (!stats.isFile()) return json({ error: 'Not a file' }, 400);

          const metadata = await MetadataParser.parse(fullPath);
          const fileExt = extname(fullPath).toLowerCase();
          const videoExts = new Set(['.mp4', '.webm', '.mov', '.avi', '.mkv', '.m4v', '.flv', '.wmv']);
          const mediaType = videoExts.has(fileExt) ? 'video' : 'image';
          return json({ type: mediaType, name: body.path.split('/').pop(), size: stats.size, ...metadata });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      if (path === '/api/metadata/scan-upload' && method === 'POST') {
        let cleanupPath: string | null = null;
        try {
          const form = await req.formData();
          const uploaded = form.get('file') || form.get('image');
          if (!(uploaded instanceof Blob)) {
            return json({ error: 'Image file required' }, 400);
          }

          const uploadName = String((uploaded as any)?.name || 'upload.png').trim() || 'upload.png';
          const uploadExt = extname(uploadName).toLowerCase();
          const allowedExts = new Set(['.png', '.jpg', '.jpeg', '.webp', '.bmp', '.gif', '.mp4', '.webm', '.mov', '.avi', '.mkv', '.m4v', '.flv', '.wmv']);
          const safeExt = allowedExts.has(uploadExt) ? uploadExt : '.png';
          const tempDir = join(os.tmpdir(), 'umbra-metadata-scan');
          await fs.mkdir(tempDir, { recursive: true });
          cleanupPath = join(tempDir, `${Date.now()}-${crypto.randomUUID()}${safeExt}`);
          const fileBuffer = Buffer.from(await uploaded.arrayBuffer());
          await fs.writeFile(cleanupPath, fileBuffer);

          const metadata = await MetadataParser.parse(cleanupPath);
          const mediaType = ['.mp4', '.webm', '.mov', '.avi', '.mkv', '.m4v', '.flv', '.wmv'].includes(safeExt)
            ? 'video'
            : 'image';
          return json({
            type: mediaType,
            name: uploadName,
            size: fileBuffer.length,
            ...metadata,
          });
        } catch (error: any) {
          return json({ error: String(error?.message || 'Failed to parse uploaded metadata') }, 500);
        } finally {
          if (cleanupPath) {
            await fs.unlink(cleanupPath).catch(() => null);
          }
        }
      }

      if (path === '/api/metadata/tag-waifu' && method === 'POST') {
        let cleanupUploadPath: string | null = null;
        try {
          const imageExts = new Set(['.png', '.jpg', '.jpeg', '.webp', '.bmp', '.gif']);
          const maxUploadBytes = 32 * 1024 * 1024;
          const parseBool = (value: unknown, fallback: boolean): boolean => {
            if (typeof value === 'boolean') return value;
            if (typeof value === 'number') return value !== 0;
            if (typeof value === 'string') {
              const lowered = value.trim().toLowerCase();
              if (lowered === '1' || lowered === 'true' || lowered === 'yes' || lowered === 'on') return true;
              if (lowered === '0' || lowered === 'false' || lowered === 'no' || lowered === 'off') return false;
            }
            return fallback;
          };
          const parseNumber = (value: unknown, fallback: number, min: number, max: number): number => {
            const parsed = typeof value === 'number' ? value : Number(String(value ?? '').trim());
            if (!Number.isFinite(parsed)) return fallback;
            return Math.max(min, Math.min(max, parsed));
          };
          const parseInteger = (value: unknown, fallback: number, min: number, max: number): number => {
            const parsed = Number(String(value ?? '').trim());
            if (!Number.isFinite(parsed)) return fallback;
            return Math.max(min, Math.min(max, Math.floor(parsed)));
          };

          let imagePath = '';
          let sourcePath = '';
          let sourceName = '';
          let modelRepo = 'SmilingWolf/wd-vit-tagger-v3';
          let generalThreshold = 0.35;
          let characterThreshold = 0.85;
          let ratingThreshold = 0.25;
          let generalMcutEnabled = false;
          let characterMcutEnabled = false;
          let maxTags = 120;

          const contentType = req.headers.get('content-type') || '';
          if (contentType.includes('multipart/form-data')) {
            const form = await req.formData();
            const uploaded = form.get('image');
            if (!(uploaded instanceof Blob)) {
              return json({ error: 'Image file required' }, 400);
            }
            if (uploaded.size > maxUploadBytes) {
              return json({
                error: `Upload is too large. Max ${Math.round(maxUploadBytes / 1024 / 1024)} MB.`,
                size: uploaded.size,
              }, 413);
            }

            const uploadedName = String((uploaded as any)?.name || 'upload.png').trim() || 'upload.png';
            sourceName = uploadedName;
            const uploadedExt = extname(uploadedName).toLowerCase();
            const safeExt = imageExts.has(uploadedExt) ? uploadedExt : '.png';
            const tempDir = join(os.tmpdir(), 'umbra-waifu-tagger');
            await fs.mkdir(tempDir, { recursive: true });
            cleanupUploadPath = join(tempDir, `${Date.now()}-${crypto.randomUUID()}${safeExt}`);
            const fileBuffer = Buffer.from(await uploaded.arrayBuffer());
            if (fileBuffer.length > 32 * 1024 * 1024) {
              return json({ error: 'Upload is too large. Max 32 MB.', size: fileBuffer.length }, 400);
            }
            const detectedFormat = detectWaifuTaggerImageFormat(fileBuffer);
            if (!detectedFormat) {
              return json({
                error: 'Waifu tagger could not read this upload as an image. Drop the original image file or use a saved file path.',
                name: uploadedName,
                size: fileBuffer.length,
              }, 400);
            }
            await fs.writeFile(cleanupUploadPath, fileBuffer);
            imagePath = cleanupUploadPath;

            modelRepo = String(form.get('modelRepo') || modelRepo).trim() || modelRepo;
            generalThreshold = parseNumber(form.get('generalThreshold'), generalThreshold, 0, 1);
            characterThreshold = parseNumber(form.get('characterThreshold'), characterThreshold, 0, 1);
            ratingThreshold = parseNumber(form.get('ratingThreshold'), ratingThreshold, 0, 1);
            generalMcutEnabled = parseBool(form.get('generalMcutEnabled'), false);
            characterMcutEnabled = parseBool(form.get('characterMcutEnabled'), false);
            maxTags = parseInteger(form.get('maxTags'), maxTags, 1, 500);
          } else {
            const body = await req.json() as Record<string, unknown>;
            const rawPath = String(body.path || '').trim();
            if (!rawPath) return json({ error: 'Path required' }, 400);
            sourcePath = rawPath;
            sourceName = basename(rawPath);

            const resolved = resolvePath(rawPath, { allowOutsideRoot: true });
            if (resolved?.fullPath) {
              imagePath = resolved.fullPath;
            } else {
              let fullPath = rawPath;
              if (!isAbsolutePathInput(rawPath)) {
                fullPath = join(USER_DIR, rawPath);
                if (!existsSync(fullPath)) fullPath = join(ROOT_DIR, rawPath);
              }
              imagePath = fullPath;
            }

            modelRepo = String(body.modelRepo || modelRepo).trim() || modelRepo;
            generalThreshold = parseNumber(body.generalThreshold, generalThreshold, 0, 1);
            characterThreshold = parseNumber(body.characterThreshold, characterThreshold, 0, 1);
            ratingThreshold = parseNumber(body.ratingThreshold, ratingThreshold, 0, 1);
            generalMcutEnabled = parseBool(body.generalMcutEnabled, false);
            characterMcutEnabled = parseBool(body.characterMcutEnabled, false);
            maxTags = parseInteger(body.maxTags, maxTags, 1, 500);
          }

          if (!imagePath || !existsSync(imagePath)) {
            return json({ error: 'Image file not found', path: sourcePath || imagePath }, 404);
          }

          const imageStats = statSync(imagePath);
          if (!imageStats.isFile()) return json({ error: 'Not a file' }, 400);
          if (imageStats.size <= 0) return json({ error: 'Image file is empty', path: sourcePath || imagePath }, 400);
          if (imageStats.size > maxUploadBytes) {
            return json({
              error: `Image file is too large. Max ${Math.round(maxUploadBytes / 1024 / 1024)} MB.`,
              path: sourcePath || imagePath,
              size: imageStats.size,
            }, 413);
          }

          const imageExt = extname(imagePath).toLowerCase();
          if (!imageExts.has(imageExt)) {
            return json({ error: `Unsupported image type: ${imageExt || 'unknown'}` }, 400);
          }

          const headerBuffer = await fs.readFile(imagePath).then((buffer) => buffer.subarray(0, 32)).catch(() => Buffer.alloc(0));
          if (!detectWaifuTaggerImageFormat(Buffer.from(headerBuffer))) {
            return json({
              error: 'Waifu tagger could not identify this image file. The file may be incomplete, a placeholder, or a non-image saved with an image extension.',
              path: sourcePath || imagePath,
              size: imageStats.size,
            }, 400);
          }

          const result = await runWaifuTagger({
            imagePath,
            modelRepo,
            generalThreshold,
            characterThreshold,
            ratingThreshold,
            generalMcutEnabled,
            characterMcutEnabled,
            maxTags,
          });

          if (result && typeof result === 'object' && result.error) {
            return json({ error: String(result.error), details: result.traceback || null }, 500);
          }

          return json({
            success: true,
            sourcePath: sourcePath || sourceName,
            name: sourceName || basename(imagePath),
            ...result,
          });
        } catch (error: any) {
          return json({ error: error?.message || 'Failed to tag image' }, 500);
        } finally {
          if (cleanupUploadPath) {
            await fs.rm(cleanupUploadPath, { force: true }).catch(() => undefined);
          }
        }
      }

      // ============================================
      // DEBUG/LOGS API
      // ============================================
      if (path === '/api/debug/log') return logRoutes.handleConsoleLogs(req, url, routeContext);

      // ============================================
      // SYSTEM API
      // ============================================
      if (path === '/api/system/stats' && method === 'GET') {
        try {
          const stats = await refreshSystemStats();
          return json(stats);
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // ============================================
      // DATABASE API
      // ============================================
      if (path === '/api/images' && method === 'GET') {
        const limit = url.searchParams.get('limit') || '100';
        const offset = url.searchParams.get('offset') || '0';
        const folder = url.searchParams.get('folder');

        try {
          let sql = 'SELECT * FROM images';
          if (folder) sql += ` WHERE folder LIKE '%${folder.replace(/'/g, "''")}%'`;
          sql += ` ORDER BY modified DESC LIMIT ${limit} OFFSET ${offset}`;

          // const images = db.query(sql);
          // const total = db.query('SELECT COUNT(*) as count FROM images')[0]?.count || 0;
          return json({ images: [], total: 0, limit: Number(limit), offset: Number(offset) });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      if (path === '/api/search' && method === 'GET') {
        const q = url.searchParams.get('q');

        if (!q) return json({ error: 'Search query required' }, 400);

        try {
          // const results = db.query(`...`);
          return json({ results: [], total: 0, query: q });
        } catch (error: any) {
          return json({ error: error.message }, 500);
        }
      }

      // ============================================
      // STATIC FILES & SPA FALLBACK
      // ============================================
      if (path.startsWith('/assets/')) {
        const filePath = join(PUBLIC_DIR, path);
        if (existsSync(filePath) && statSync(filePath).isFile()) {
          const ext = extname(filePath).toLowerCase();
          const contentType = GALLERY_STATIC_MIME_TYPES[ext] || 'application/octet-stream';
          const acceptedEncodings = String(req.headers.get('accept-encoding') || '').toLowerCase();
          const brotliPath = `${filePath}.br`;
          const gzipPath = `${filePath}.gz`;
          const encodedPath = acceptedEncodings.includes('br') && existsSync(brotliPath)
            ? brotliPath
            : (acceptedEncodings.includes('gzip') && existsSync(gzipPath) ? gzipPath : filePath);
          const contentEncoding = encodedPath === brotliPath
            ? 'br'
            : (encodedPath === gzipPath ? 'gzip' : '');
          const immutableAsset = /-[a-z0-9]{8,}\.[^.]+$/i.test(basename(filePath));
          const headers: Record<string, string> = {
            'Content-Type': contentType,
            'Cache-Control': immutableAsset
              ? 'public, max-age=31536000, immutable'
              : 'public, max-age=0, must-revalidate',
          };
          if (contentEncoding) {
            headers['Content-Encoding'] = contentEncoding;
            headers.Vary = 'Accept-Encoding';
          }
          return new Response(Bun.file(encodedPath), {
            headers,
          });
        }
        return new Response('Not found', { status: 404 });
      }

      // Serve dataset images
      if (path.startsWith('/api/files/datasets/')) {
        const encodedRelativePath = path.replace('/api/files/datasets/', '');
        const decodedRelativePath = decodeURIComponent(encodedRelativePath);
        const safeRelativePath = sanitizeDatasetRelativePath(decodedRelativePath);
        if (!safeRelativePath) {
          return json({ error: 'Invalid dataset file path' }, 400);
        }
        const filePath = resolveDatasetPathSafe(...safeRelativePath.split('/'));
        if (!filePath) {
          return json({ error: 'Access denied' }, 403);
        }

        if (existsSync(filePath) && statSync(filePath).isFile()) {
          const ext = filePath.split('.').pop()?.toLowerCase() || '';
          const mimeTypes: Record<string, string> = {
            'jpg': 'image/jpeg',
            'jpeg': 'image/jpeg',
            'png': 'image/png',
            'webp': 'image/webp',
            'bmp': 'image/bmp',
            'gif': 'image/gif',
            'mp4': 'video/mp4',
            'webm': 'video/webm',
            'mov': 'video/quicktime',
            'avi': 'video/x-msvideo',
            'mkv': 'video/x-matroska'
          };
          const contentType = mimeTypes[ext] || 'application/octet-stream';
          return new Response(Bun.file(filePath), {
            headers: { 'Content-Type': contentType, 'Cache-Control': 'public, max-age=3600' }
          });
        }
        return new Response('Not found', { status: 404 });
      }

      if (path === '/gallery' || path.startsWith('/gallery/')) {
        const requested = path === '/gallery' ? '/index.html' : path.slice('/gallery'.length) || '/index.html';
        const normalizedRequest = requested.startsWith('/') ? requested : `/${requested}`;
        const staticRoot = resolve(GALLERY_PUBLIC_DIR);
        const staticRootForCompare = process.platform === 'win32' ? staticRoot.toLowerCase() : staticRoot;
        const resolvedPath = resolve(staticRoot, `.${normalizedRequest}`);
        const resolvedForCompare = process.platform === 'win32' ? resolvedPath.toLowerCase() : resolvedPath;
        if (!(resolvedForCompare === staticRootForCompare || resolvedForCompare.startsWith(`${staticRootForCompare}/`) || resolvedForCompare.startsWith(`${staticRootForCompare}\\`))) {
          return new Response('Access denied', { status: 403 });
        }

        if (existsSync(resolvedPath) && statSync(resolvedPath).isFile()) {
          const ext = extname(resolvedPath).toLowerCase();
          const contentType = GALLERY_STATIC_MIME_TYPES[ext] || 'application/octet-stream';
          const cacheControl = ext === '.html' ? 'no-store' : 'public, max-age=3600';
          return new Response(Bun.file(resolvedPath), {
            headers: {
              'Content-Type': contentType,
              'Cache-Control': cacheControl,
            },
          });
        }

        if (!extname(resolvedPath)) {
          const indexPath = resolve(staticRoot, 'index.html');
          if (existsSync(indexPath) && statSync(indexPath).isFile()) {
            return new Response(Bun.file(indexPath), {
              headers: {
                'Content-Type': 'text/html; charset=utf-8',
                'Cache-Control': 'no-store',
              },
            });
          }
        }

        return new Response('Not found', { status: 404 });
      }

      if (path.startsWith('/api/')) return json({ error: 'Not found' }, 404);

      const indexPath = join(PUBLIC_DIR, 'index.html');
      if (existsSync(indexPath)) {
        return new Response(Bun.file(indexPath), {
          headers: {
            'Content-Type': 'text/html; charset=utf-8',
            'Cache-Control': 'no-store',
          },
        });
      }

      return new Response('Not found', { status: 404 });
      } catch (error: any) {
        console.error('[Server] Unhandled error in fetch handler:', error);
        return json({ error: 'Internal server error', message: error.message }, 500);
      }
      });
      responseStatus = response?.status ?? 101;
      return response;
    } finally {
      appendBackendRouteTimingLog(method, path, responseStatus, Date.now() - requestStartedAt);
    }
  },

  websocket: {
    perMessageDeflate: {
      compress: 'shared',
      decompress: 'shared',
    },
    open(ws) {
      const endpoint = (ws.data as any)?.endpoint || '/ws/unknown';
      if (endpoint === '/comfy/ws') {
        const targetUrl = String((ws.data as any)?.targetUrl || getComfyProxyWsUrl());
        const queuedMessages: Array<string | Buffer> = [];
        (ws.data as any).queuedMessages = queuedMessages;
        void (async () => {
          try {
            if (!(await isComfyWsTargetReachable(targetUrl))) {
              logComfyProxyWsError(new Error('ComfyUI websocket target is not ready yet.'), targetUrl);
              try { ws.close(); } catch {}
              return;
            }
            if (ws.readyState !== 1) return;
            const upstream = new WebSocket(targetUrl);
            (ws.data as any).upstream = upstream;
            upstream.binaryType = 'arraybuffer';
            upstream.onopen = () => {
              for (const queued of queuedMessages.splice(0)) upstream.send(queued as any);
            };
            upstream.onmessage = (event) => {
              try {
              const data = event.data;
                if (typeof data === 'string') {
                  ws.send(data);
                  recordRemoteTransport('/comfy/ws', 'out', Buffer.byteLength(data));
                } else if (data instanceof ArrayBuffer) {
                  const buffer = Buffer.from(data);
                  ws.send(buffer);
                  recordRemoteTransport('/comfy/ws', 'out', buffer.byteLength);
                } else if (data instanceof Blob) {
                  data.arrayBuffer().then((buffer) => {
                    const relayBuffer = Buffer.from(buffer);
                    ws.send(relayBuffer);
                    recordRemoteTransport('/comfy/ws', 'out', relayBuffer.byteLength);
                  }).catch(() => undefined);
                }
              } catch (error) {
                console.warn('[ComfyProxy] Failed to relay websocket message:', error);
              }
            };
            upstream.onclose = () => {
              try { ws.close(); } catch {}
            };
            upstream.onerror = (error) => {
              logComfyProxyWsError(error, targetUrl);
              try { ws.close(); } catch {}
            };
          } catch (error) {
            logComfyProxyWsError(error, targetUrl);
            try { ws.close(); } catch {}
          }
        })();
        return;
      }
      if (endpoint === '/local-server-proxy/ws') {
        const targetUrl = String((ws.data as any)?.targetUrl || '');
        const queuedMessages: Array<string | Buffer> = [];
        (ws.data as any).queuedMessages = queuedMessages;
        try {
          if (!targetUrl) {
            ws.close();
            return;
          }
          const upstream = new WebSocket(targetUrl);
          (ws.data as any).upstream = upstream;
          upstream.binaryType = 'arraybuffer';
          upstream.onopen = () => {
            for (const queued of queuedMessages.splice(0)) upstream.send(queued as any);
          };
          upstream.onmessage = (event) => {
            try {
              const data = event.data;
              if (typeof data === 'string') {
                ws.send(data);
                recordRemoteTransport('/local-server-proxy/ws', 'out', Buffer.byteLength(data));
              } else if (data instanceof ArrayBuffer) {
                const buffer = Buffer.from(data);
                ws.send(buffer);
                recordRemoteTransport('/local-server-proxy/ws', 'out', buffer.byteLength);
              } else if (data instanceof Blob) {
                data.arrayBuffer().then((buffer) => {
                  const relayBuffer = Buffer.from(buffer);
                  ws.send(relayBuffer);
                  recordRemoteTransport('/local-server-proxy/ws', 'out', relayBuffer.byteLength);
                }).catch(() => undefined);
              }
            } catch (error) {
              console.warn('[LocalServerProxy] Failed to relay websocket message:', error);
            }
          };
          upstream.onclose = () => {
            try { ws.close(); } catch {}
          };
          upstream.onerror = (error) => {
            console.warn(`[LocalServerProxy] Upstream websocket unavailable at ${targetUrl}:`, error);
            try { ws.close(); } catch {}
          };
        } catch (error) {
          console.warn(`[LocalServerProxy] Failed to open websocket at ${targetUrl}:`, error);
          try { ws.close(); } catch {}
        }
        return;
      }
      handleWsConnection(ws, endpoint);
    },
    close(ws) {
      const endpoint = (ws.data as any)?.endpoint || '/ws/unknown';
      if (endpoint === '/comfy/ws') {
        try { (ws.data as any)?.upstream?.close?.(); } catch {}
        return;
      }
      if (endpoint === '/local-server-proxy/ws') {
        try { (ws.data as any)?.upstream?.close?.(); } catch {}
        return;
      }
      handleWsDisconnection(ws, endpoint);
    },
    message(ws, message) {
      const endpoint = (ws.data as any)?.endpoint;
      if (endpoint === '/comfy/ws') {
        const upstream = (ws.data as any)?.upstream as WebSocket | undefined;
        const payload = typeof message === 'string'
          ? message
          : Buffer.isBuffer(message)
            ? message
            : Buffer.from(message as ArrayBuffer);
        recordRemoteTransport('/comfy/ws', 'in', estimateMessageBytes(payload));
        if (upstream?.readyState === WebSocket.OPEN) {
          upstream.send(payload as any);
        } else {
          ((ws.data as any).queuedMessages ||= []).push(payload);
        }
        return;
      }
      if (endpoint === '/local-server-proxy/ws') {
        const upstream = (ws.data as any)?.upstream as WebSocket | undefined;
        const payload = typeof message === 'string'
          ? message
          : Buffer.isBuffer(message)
            ? message
            : Buffer.from(message as ArrayBuffer);
        recordRemoteTransport('/local-server-proxy/ws', 'in', estimateMessageBytes(payload));
        if (upstream?.readyState === WebSocket.OPEN) {
          upstream.send(payload as any);
        } else {
          ((ws.data as any).queuedMessages ||= []).push(payload);
        }
        return;
      }
      try {
        const msgStr = typeof message === 'string'
          ? message
          : Buffer.isBuffer(message)
            ? message.toString('utf-8')
            : new TextDecoder().decode(message as ArrayBuffer);
        recordRemoteTransport(String(endpoint || '/ws/unknown'), 'in', Buffer.byteLength(msgStr));
        const data = JSON.parse(msgStr);

        if (endpoint === '/ws/prompter') {
          handlePrompterMessage(ws, data);
        }
      } catch (err) {
        console.error('[WS] Message parse error:', err);
      }
    }
  }
});

