// Backend status and system stats sampling are intentionally lazy; eager probes
// can block the single Bun event loop when a child process or local service is wedged.

async function autoLaunchConfiguredBackends() {
  const appSettings = settingsManager.getAppSettings();
  const shouldAutoLaunch = (key: string) => appSettings[key] === true;
  const launchQueue: Array<{ key: string; label: string; launch: () => Promise<any> }> = [
    { key: 'comfyui.autoLaunch', label: 'ComfyUI', launch: startComfyUI },
  ];

  for (const item of launchQueue) {
    if (!shouldAutoLaunch(item.key)) continue;
    try {
      console.log(`[Startup] Auto-launch enabled for ${item.label}`);
      const result = await item.launch();
      if (!result?.success) {
        console.warn(`[Startup] Failed to auto-launch ${item.label}:`, result?.error || result?.message || 'Unknown error');
      }
    } catch (error) {
      console.warn(`[Startup] Failed to auto-launch ${item.label}:`, error);
    }
  }
}

setTimeout(() => {
  const appSettings = settingsManager.getAppSettings();
  if (appSettings['comfyui.autoLaunch'] === true) {
    console.warn('[Startup] ComfyUI auto-launch is deferred; start it from the app to keep the web server responsive.');
  }
}, 60000);

// ============================================
// GRACEFUL SHUTDOWN
// ============================================

async function gracefulShutdown(signal: string) {
  if (isShuttingDown) {
    console.log('\x1b[33m[Shutdown]\x1b[0m Already shutting down...');
    return;
  }
  isShuttingDown = true;

  console.log(`\n\x1b[36m━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\x1b[0m`);
  console.log(`  \x1b[1mGraceful Shutdown (${signal})\x1b[0m`);
  console.log(`\x1b[36m━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\x1b[0m\n`);

  try {
    await umbraUiInpaintService.flushPersistence();
  } catch (error) {
    console.error('\x1b[31m[Shutdown]\x1b[0m Failed to flush the inpaint recovery ledger:', error);
  }

  // Stop file watchers first
  console.log('\x1b[33m[Shutdown]\x1b[0m Stopping file watchers...');
  stopSystemStatsSampler();
  stopBackendStatusSampler();

  // Stop all running tools
  const toolsToStop = [
    { name: 'ComfyUI', stop: stopComfyUI, process: comfyProcess },
    { name: 'AI-Toolkit', stop: stopAIToolkit, process: aitoolkitProcess },
    { name: 'Gallery', stop: stopGalleryBridge, process: null }
  ];

  for (const tool of toolsToStop) {
    console.log(`\x1b[33m[Shutdown]\x1b[0m Stopping ${tool.name}...`);
    try {
      await tool.stop();
      console.log(`\x1b[32m[Shutdown]\x1b[0m ${tool.name} stopped`);
    } catch (err) {
      console.error(`\x1b[31m[Shutdown]\x1b[0m Failed to stop ${tool.name}:`, err);
    }
  }

  // Give processes a moment to fully exit
  await new Promise(resolve => setTimeout(resolve, 500));

  // Close WebSocket connections
  console.log('\x1b[33m[Shutdown]\x1b[0m Closing WebSocket connections...');
  const allSets = [wsClients.system, wsClients.logs, wsClients.generation, wsClients.prompter];
  let closedCount = 0;
  for (const clientSet of allSets) {
    for (const ws of clientSet) {
      try {
        ws.close(1001, 'Server shutting down');
        closedCount++;
      } catch { }
    }
    clientSet.clear();
  }
  console.log(`\x1b[32m[Shutdown]\x1b[0m Closed ${closedCount} WebSocket connections`);

  // Stop the server
  console.log('\x1b[33m[Shutdown]\x1b[0m Stopping server...');
  server.stop();

  console.log(`\n\x1b[32m━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\x1b[0m`);
  console.log(`  \x1b[1m\x1b[32m✓ Umbra Server shut down cleanly\x1b[0m`);
  console.log(`\x1b[32m━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\x1b[0m\n`);

  process.exit(0);
}

// Handle termination signals
process.on('SIGINT', () => gracefulShutdown('SIGINT'));   // Ctrl+C
process.on('SIGTERM', () => gracefulShutdown('SIGTERM')); // kill command

// Windows-specific: handle console close
if (process.platform === 'win32') {
  process.on('SIGHUP', () => gracefulShutdown('SIGHUP'));
}

// Handle uncaught errors gracefully
process.on('uncaughtException', async (err) => {
  console.error('\x1b[31m[Fatal]\x1b[0m Uncaught exception:', err);
  await gracefulShutdown('uncaughtException');
});

process.on('unhandledRejection', async (reason) => {
  console.error('\x1b[31m[Fatal]\x1b[0m Unhandled rejection:', reason);
  // Don't exit on unhandled rejections, just log them
});



